import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  STANDARD = 'Standard User',
  ADMIN_L1 = 'Admin Level 1',
  ADMIN_L2 = 'Super Admin',
  OWNER = 'Owner',
}

export enum RequestStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  isSpecialAdmin?: boolean; // Can process requests like owner
}

export interface InventoryItem {
  id: string;
  itemCode: string;
  name: string;
  description: string;
  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number; // Hidden from Standard users
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId: string;
  specificPurpose: string;
  status: RequestStatus;
  isEmergency: boolean; // "Item Already Taken"
  timestamp: string;
  claimedBy?: string; // Admin ID
  verifiedBy?: string; // Admin ID
  processedBy?: string; // Owner/Special Admin ID
  returnCondition?: 'Good' | 'Damaged';
}

export interface AuditLogEntry {
  id: string;
  timestamp: string;
  action: string;
  itemId: string;
  itemName: string;
  quantityChange: number;
  performedBy: string; // User Name
  details: string;
}

export interface PurchaseOrder {
  id: string;
  prNumber: string;
  poNumber: string;
  status: 'Draft' | 'Approved' | 'Ordered' | 'Received' | 'Closed';
  supplier: string;
  totalCost: number;
  date: string;
}

