import { InventoryItem, Request, RequestStatus, AuditLogEntry, User } from '../types';

export const canViewPrices = (user: User): boolean => {
  return user.role === 'Owner' || user.role === 'Super Admin';
};

export const canProcessRequest = (user: User): boolean => {
  return user.role === 'Owner' || !!user.isSpecialAdmin;
};

export const canVerifyRequest = (user: User): boolean => {
  return user.role !== 'Standard User';
};

export const canEditStock = (user: User): boolean => {
    return user.role === 'Owner' || user.role === 'Super Admin' || !!user.isSpecialAdmin;
};

// Helper to generate IDs
