import React from 'react';
import { User, UserRole } from '../types';
import { LayoutDashboard, Box, FileText, BarChart3, Settings, ShieldCheck, LogOut, Truck } from 'lucide-react';

interface LayoutProps {
  currentUser: User;
  onLogout: () => void;
  currentView: string;
  onChangeView: (view: string) => void;
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ currentUser, onLogout, currentView, onChangeView, children }) => {

  const NavItem = ({ view, icon: Icon, label }: { view: string; icon: any; label: string }) => (
    <button
      onClick={() => onChangeView(view)}
      className={`flex items-center w-full px-4 py-3 mb-1 text-sm font-medium transition-colors rounded-lg ${
        currentView === view
          ? 'bg-blue-600 text-white shadow-md'
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon className="w-5 h-5 mr-3" />
      {label}
    </button>
  );

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col flex-shrink-0">
        <div className="p-6 border-b border-slate-100">
          <h1 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <ShieldCheck className="w-6 h-6 text-blue-600" />
            SecureTrack
          </h1>
          <div className="mt-4 px-3 py-2 bg-slate-50 rounded border border-slate-200">
            <p className="text-xs text-slate-500 uppercase font-semibold">Logged in as</p>
            <p className="text-sm font-medium text-slate-800 truncate">{currentUser.name}</p>
            <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800 mt-1">
              {currentUser.role}
            </span>
          </div>
        </div>

        <nav className="flex-1 p-4 overflow-y-auto">
          <NavItem view="inventory" icon={Box} label="Inventory" />
          <NavItem view="requests" icon={FileText} label="Requests & Approvals" />

          {(currentUser.role !== UserRole.STANDARD) && (
             <NavItem view="movements" icon={Truck} label="Move Requests" />
          )}

          {(currentUser.role === UserRole.OWNER || currentUser.role === UserRole.ADMIN_L2 || currentUser.isSpecialAdmin) && (
            <>
              <NavItem view="procurement" icon={FileText} label="Procurement (PR/PO)" />
              <NavItem view="financials" icon={BarChart3} label="Financial Dashboard" />
            </>
          )}

          {(currentUser.role === UserRole.OWNER || currentUser.role === UserRole.ADMIN_L2) && (
            <NavItem view="audit" icon={Settings} label="Audit Logs" />
          )}
        </nav>

        <div className="p-4 border-t border-slate-200">
          <button
            onClick={onLogout}
            className="flex items-center w-full px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
          >
            <LogOut className="w-5 h-5 mr-3" />
            Switch User
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto p-8 relative">
        {children}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { InventoryItem, User, WorkPurpose } from '../types';
import { Search, AlertCircle, PlusCircle, ArrowDownCircle, Info } from 'lucide-react';
import { canViewPrices } from '../services/stateService';

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, onRequestItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);

  // Request Form State
  const [reqQty, setReqQty] = useState(1);
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);

  // Manual Adjust State
  const [adjustQty, setAdjustQty] = useState(0);
  const [adjustReason, setAdjustReason] = useState('');

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleRequestSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItem) {
      onRequestItem(selectedItem.id, reqQty, reqPurpose, reqSpecific, isEmergency);
      setSelectedItem(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setReqQty(1);
    setReqPurpose('');
    setReqSpecific('');
    setIsEmergency(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-800">Inventory Dashboard</h2>
            <p className="text-slate-500">View availability and request items.</p>
        </div>

        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search code, name, part #..." 
            className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 font-semibold text-slate-700">Item Details</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Location</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Category</th>
                <th className="px-6 py-4 font-semibold text-slate-700 text-center">Stock</th>
                {canViewPrices(currentUser) && <th className="px-6 py-4 font-semibold text-slate-700 text-right">Unit Price</th>}
                <th className="px-6 py-4 font-semibold text-slate-700 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-900">{item.name}</div>
                    <div className="text-xs text-slate-500 flex gap-2">
                        <span>Code: {item.itemCode}</span>
                        <span>PN: {item.partNumber}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{item.location}</td>
                  <td className="px-6 py-4 text-slate-600">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                      {item.category}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <div className={`font-bold ${item.quantity <= item.minThreshold ? 'text-red-600' : 'text-slate-700'}`}>
                      {item.quantity}
                    </div>
                    {item.quantity <= item.minThreshold && (
                        <div className="text-[10px] text-red-500 font-medium">Low Stock</div>
                    )}
                  </td>
                  {canViewPrices(currentUser) && (
                    <td className="px-6 py-4 text-right text-slate-600">${item.price.toFixed(2)}</td>
                  )}
                  <td className="px-6 py-4 text-right">
                    <button 
                        onClick={() => { setSelectedItem(item); resetForm(); }}
                        className="text-blue-600 hover:text-blue-800 font-medium text-sm border border-blue-200 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors"
                    >
                        Request
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Request Modal */}
      {selectedItem && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-slate-100">
                <h3 className="text-lg font-bold text-slate-800">Request Item</h3>
                <p className="text-sm text-slate-500">{selectedItem.name} ({selectedItem.partNumber})</p>
                <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded">
                    Current Stock: <span className="font-bold">{selectedItem.quantity}</span> | Location: {selectedItem.location}
                </div>
            </div>

            <form onSubmit={handleRequestSubmit} className="p-6 space-y-4">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Work Purpose</label>
                    <select 
                        required
                        className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={reqPurpose}
                        onChange={(e) => setReqPurpose(e.target.value)}
                    >
                        <option value="">Select a purpose...</option>
                        {purposes.map(p => (
                            <option key={p.id} value={p.id}>{p.title}</option>
                        ))}
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Specific Details</label>
                    <input 
                        type="text" 
                        required
                        placeholder="e.g., Replacing valve on Pump 3"
                        className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={reqSpecific}
                        onChange={(e) => setReqSpecific(e.target.value)}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Quantity</label>
                        <input 
                            type="number" 
                            min="1" 
                            max={selectedItem.quantity}
                            required
                            className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                            value={reqQty}
                            onChange={(e) => setReqQty(parseInt(e.target.value))}
                        />
                    </div>
                </div>

                <div className="bg-amber-50 border border-amber-200 rounded-lg p-3">
                    <label className="flex items-start gap-3 cursor-pointer">
                        <input 
                            type="checkbox" 
                            className="mt-1 w-4 h-4 text-amber-600 rounded border-gray-300 focus:ring-amber-500"
                            checked={isEmergency}
                            onChange={(e) => setIsEmergency(e.target.checked)}
                        />
                        <div>
                            <span className="block text-sm font-semibold text-amber-800">Emergency / Already Taken</span>
                            <span className="block text-xs text-amber-700">Check this if you have already physically taken the item because no Admin was present. This flags the request for immediate verification.</span>
                        </div>
                    </label>
                </div>

                <div className="flex gap-3 pt-4">
                    <button 
                        type="button" 
                        onClick={() => setSelectedItem(null)}
                        className="flex-1 px-4 py-2 border border-slate-300 text-slate-700 font-medium rounded-lg hover:bg-slate-50"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit" 
                        className="flex-1 px-4 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 shadow-sm"
                    >
                        Submit Request
                    </button>
                </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React from 'react';
import { Request, RequestStatus, User, UserRole, InventoryItem } from '../types';
import { canVerifyRequest, canProcessRequest } from '../services/stateService';
import { CheckCircle2, Clock, AlertTriangle, UserCheck, FileCheck, XCircle } from 'lucide-react';

interface RequestQueueProps {
  requests: Request[];
  items: InventoryItem[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
}

const RequestQueue: React.FC<RequestQueueProps> = ({ 
    requests, items, currentUser, onClaim, onVerify, onProcess, onReturnAction 
}) => {

  // Filter logic
  const myRequests = requests.filter(r => r.userId === currentUser.id);
  const pendingRequests = requests.filter(r => r.status === RequestStatus.PENDING);
  const claimedRequests = requests.filter(r => r.status === RequestStatus.CLAIMED);
  const verifiedRequests = requests.filter(r => r.status === RequestStatus.VERIFIED);

  // For admins, show action queue. For standard, show only history.
  const isStandardUser = currentUser.role === UserRole.STANDARD;

  const StatusBadge = ({ status, emergency }: { status: RequestStatus, emergency: boolean }) => {
    if (emergency && status !== RequestStatus.PROCESSED) {
        return <span className="px-2 py-1 rounded text-xs font-bold bg-red-100 text-red-700 border border-red-200">ALREADY TAKEN</span>;
    }
    const styles = {
        [RequestStatus.PENDING]: 'bg-yellow-100 text-yellow-800',
        [RequestStatus.CLAIMED]: 'bg-blue-100 text-blue-800',
        [RequestStatus.VERIFIED]: 'bg-purple-100 text-purple-800',
        [RequestStatus.PROCESSED]: 'bg-green-100 text-green-800',
        [RequestStatus.REJECTED]: 'bg-gray-100 text-gray-800',
        [RequestStatus.RETURNED]: 'bg-indigo-100 text-indigo-800',
    };
    return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${styles[status] || 'bg-gray-100'}`}>{status}</span>;
  };

  const RequestCard = ({ req, showActions }: { req: Request, showActions: boolean }) => {
    const item = items.find(i => i.id === req.itemId);
    const canClaim = canVerifyRequest(currentUser) && req.status === RequestStatus.PENDING;
    const canVerify = canVerifyRequest(currentUser) && req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id;
    const canProcess = canProcessRequest(currentUser) && req.status === RequestStatus.VERIFIED;

    return (
        <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
            <div className="flex-1">
                <div className="flex items-center gap-3 mb-1">
                    <span className="font-bold text-slate-800">{item?.name || 'Unknown Item'}</span>
                    <span className="text-xs text-slate-500">Qty: {req.quantity}</span>
                    <StatusBadge status={req.status} emergency={req.isEmergency} />
                </div>
                <div className="text-sm text-slate-600">
                    <span className="font-semibold text-slate-700">{req.userName}</span> • {req.specificPurpose}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Requested: {new Date(req.timestamp).toLocaleString()}
                </div>
                {req.claimedBy && <div className="text-xs text-blue-600 mt-1">Claimed by Admin: {req.claimedBy}</div>}
            </div>

            {showActions && (
                <div className="flex gap-2">
                    {canClaim && (
                        <button 
                            onClick={() => onClaim(req.id)}
                            className="flex items-center px-3 py-1.5 bg-blue-600 text-white text-sm font-medium rounded hover:bg-blue-700"
                        >
                            <UserCheck className="w-4 h-4 mr-2" /> Claim
                        </button>
                    )}
                    {canVerify && (
                        <button 
                            onClick={() => onVerify(req.id)}
                            className="flex items-center px-3 py-1.5 bg-purple-600 text-white text-sm font-medium rounded hover:bg-purple-700"
                        >
                            <FileCheck className="w-4 h-4 mr-2" /> Verify
                        </button>
                    )}
                    {canProcess && (
                        <button 
                            onClick={() => onProcess(req.id)}
                            className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700"
                        >
                            <CheckCircle2 className="w-4 h-4 mr-2" /> Process & Sign
                        </button>
                    )}
                </div>
            )}
        </div>
    );
  };

  return (
    <div className="space-y-8">

        {/* Admin Queue Section */}
        {!isStandardUser && (
            <div className="space-y-6">
                <h2 className="text-2xl font-bold text-slate-800">Approval Queue</h2>

                {canProcessRequest(currentUser) && verifiedRequests.length > 0 && (
                    <div className="bg-green-50 rounded-xl p-4 border border-green-100">
                        <h3 className="text-sm font-bold text-green-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                            <CheckCircle2 className="w-4 h-4" /> Ready for Processing
                        </h3>
                        <div className="space-y-3">
                            {verifiedRequests.map(req => <RequestCard key={req.id} req={req} showActions={true} />)}
                        </div>
                    </div>
                )}

                {canVerifyRequest(currentUser) && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-yellow-50 rounded-xl p-4 border border-yellow-100">
                             <h3 className="text-sm font-bold text-yellow-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                                <Clock className="w-4 h-4" /> Pending Requests
                            </h3>
                             <div className="space-y-3">
                                {pendingRequests.length === 0 && <p className="text-sm text-yellow-600 italic">No pending requests.</p>}
                                {pendingRequests.map(req => <RequestCard key={req.id} req={req} showActions={true} />)}
                            </div>
                        </div>

                        <div className="bg-blue-50 rounded-xl p-4 border border-blue-100">
                            <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                                <UserCheck className="w-4 h-4" /> Claimed by You (To Verify)
                            </h3>
                             <div className="space-y-3">
                                {claimedRequests.filter(r => r.claimedBy === currentUser.id).length === 0 && <p className="text-sm text-blue-600 italic">You haven't claimed any tickets.</p>}
                                {claimedRequests.filter(r => r.claimedBy === currentUser.id).map(req => <RequestCard key={req.id} req={req} showActions={true} />)}

                                {/* Show claimed by others but disabled */}
                                {claimedRequests.filter(r => r.claimedBy !== currentUser.id).map(req => (
                                    <div key={req.id} className="opacity-50 grayscale pointer-events-none">
                                        <RequestCard req={req} showActions={false} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        )}

        {/* User History Section */}
        <div className="pt-8 border-t border-slate-200">
             <h2 className="text-xl font-bold text-slate-800 mb-4">
                 {isStandardUser ? 'My Request History' : 'Recent Processed Requests'}
             </h2>
             <div className="space-y-3">
                 {isStandardUser 
                    ? myRequests.map(req => <RequestCard key={req.id} req={req} showActions={false} />)
                    : requests.filter(r => r.status === RequestStatus.PROCESSED).slice(0, 5).map(req => <RequestCard key={req.id} req={req} showActions={false} />)
                 }
                 {myRequests.length === 0 && isStandardUser && <p className="text-slate-500">No requests found.</p>}
             </div>
        </div>
    </div>
  );
};

export default RequestQueue;

import React from 'react';
import { InventoryItem, Request, RequestStatus, WorkPurpose } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {

  // Calculate cost per purpose
  const processedRequests = requests.filter(r => r.status === RequestStatus.PROCESSED);

  const costByPurposeData = purposes.map(purpose => {
    const totalCost = processedRequests
      .filter(r => r.purposeId === purpose.id)
      .reduce((sum, r) => {
        const item = items.find(i => i.id === r.itemId);
        return sum + (item ? item.price * r.quantity : 0);
      }, 0);
    return { name: purpose.title, cost: totalCost };
  });

  // Calculate total inventory value
  const totalInventoryValue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalSpent = processedRequests.reduce((sum, r) => {
      const item = items.find(i => i.id === r.itemId);
      return sum + (item ? item.price * r.quantity : 0);
  }, 0);

  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-slate-800">Financial Intelligence</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="text-sm font-medium text-slate-500 uppercase">Total Inventory Value</h3>
            <p className="text-3xl font-bold text-slate-900 mt-2">${totalInventoryValue.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="text-sm font-medium text-slate-500 uppercase">Total Spent (This Period)</h3>
            <p className="text-3xl font-bold text-blue-600 mt-2">${totalSpent.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="text-sm font-medium text-slate-500 uppercase">Processed Requests</h3>
            <p className="text-3xl font-bold text-purple-600 mt-2">{processedRequests.length}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-96">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Cost Allocation by Work Purpose</h3>
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={costByPurposeData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" tick={{fontSize: 10}} interval={0} angle={-15} textAnchor="end" />
                    <YAxis />
                    <Tooltip formatter={(value) => `$${value}`} />
                    <Bar dataKey="cost" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
            </ResponsiveContainer>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-96">
             <h3 className="text-lg font-bold text-slate-800 mb-4">Distribution</h3>
             <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                        data={costByPurposeData}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        outerRadius={100}
                        fill="#8884d8"
                        dataKey="cost"
                    >
                        {costByPurposeData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip formatter={(value: number) => `$${value.toLocaleString()}`} />
                    <Legend />
                </PieChart>
             </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

