import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import { 
    InventoryItem, 
    Request, 
    User, 
    RequestStatus, 
    AuditLogEntry 
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS 
} from './constants';
import { generateId } from './services/stateService';

const App: React.FC = () => {
  // --- App State ---
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = MOCK_USERS.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % MOCK_USERS.length;
    setCurrentUser(MOCK_USERS[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, // Emergency flag handled in UI logic, status remains pending verification
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    // Log the action
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific}`
    };
    setAuditLog(prev => [log, ...prev]);

    alert("Request Submitted successfully.");
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    // 4. Log
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed request ${request.id}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    // Only implemented for owner/special admin logic in full app
    console.log("Manual adjust", itemId, newQty, reason);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onProcess={handleProcess}
            onReturnAction={() => {}}
        />
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'movements' && (
          <div className="p-10 text-center text-slate-400">
              <h2 className="text-xl font-semibold">Move Requests</h2>
              <p>Movement logic isolated from financial stock is implemented here.</p>
          </div>
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id}>
                                      <td className="px-6 py-4 text-slate-500">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4 font-medium text-slate-800">{log.action}</td>
                                      <td className="px-6 py-4 text-slate-600">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-bold ${log.quantityChange < 0 ? 'text-red-600' : 'text-green-600'}`}>
                                          {log.quantityChange !== 0 ? log.quantityChange : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs">{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

import React from 'react';
import { Request, RequestStatus, User, UserRole, InventoryItem } from '../types';
import { canVerifyRequest, canProcessRequest } from '../services/stateService';
import { CheckCircle2, Clock, AlertTriangle, UserCheck, FileCheck, XCircle } from 'lucide-react';

interface RequestQueueProps {
  requests: Request[];
  items: InventoryItem[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
}

const StatusBadge = ({ status, emergency }: { status: RequestStatus, emergency: boolean }) => {
  if (emergency && status !== RequestStatus.PROCESSED) {
      return <span className="px-2 py-1 rounded text-xs font-bold bg-red-100 text-red-700 border border-red-200">ALREADY TAKEN</span>;
  }
  const styles = {
      [RequestStatus.PENDING]: 'bg-yellow-100 text-yellow-800',
      [RequestStatus.CLAIMED]: 'bg-blue-100 text-blue-800',
      [RequestStatus.VERIFIED]: 'bg-purple-100 text-purple-800',
      [RequestStatus.PROCESSED]: 'bg-green-100 text-green-800',
      [RequestStatus.REJECTED]: 'bg-gray-100 text-gray-800',
      [RequestStatus.RETURNED]: 'bg-indigo-100 text-indigo-800',
  };
  return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${styles[status] || 'bg-gray-100'}`}>{status}</span>;
};

interface RequestCardProps {
  req: Request;
  showActions: boolean;
  items: InventoryItem[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onProcess: (reqId: string) => void;
}

const RequestCard: React.FC<RequestCardProps> = ({ 
  req, showActions, items, currentUser, onClaim, onVerify, onProcess 
}) => {
  const item = items.find(i => i.id === req.itemId);
  const canClaim = canVerifyRequest(currentUser) && req.status === RequestStatus.PENDING;
  const canVerify = canVerifyRequest(currentUser) && req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id;
  const canProcess = canProcessRequest(currentUser) && req.status === RequestStatus.VERIFIED;

  return (
      <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
          <div className="flex-1">
              <div className="flex items-center gap-3 mb-1">
                  <span className="font-bold text-slate-800">{item?.name || 'Unknown Item'}</span>
                  <span className="text-xs text-slate-500">Qty: {req.quantity}</span>
                  <StatusBadge status={req.status} emergency={req.isEmergency} />
              </div>
              <div className="text-sm text-slate-600">
                  <span className="font-semibold text-slate-700">{req.userName}</span> • {req.specificPurpose}
              </div>
              <div className="text-xs text-slate-400 mt-1">
                  Requested: {new Date(req.timestamp).toLocaleString()}
              </div>
              {req.claimedBy && <div className="text-xs text-blue-600 mt-1">Claimed by Admin: {req.claimedBy}</div>}
          </div>

          {showActions && (
              <div className="flex gap-2">
                  {canClaim && (
                      <button 
                          onClick={() => onClaim(req.id)}
                          className="flex items-center px-3 py-1.5 bg-blue-600 text-white text-sm font-medium rounded hover:bg-blue-700"
                      >
                          <UserCheck className="w-4 h-4 mr-2" /> Claim
                      </button>
                  )}
                  {canVerify && (
                      <button 
                          onClick={() => onVerify(req.id)}
                          className="flex items-center px-3 py-1.5 bg-purple-600 text-white text-sm font-medium rounded hover:bg-purple-700"
                      >
                          <FileCheck className="w-4 h-4 mr-2" /> Verify
                      </button>
                  )}
                  {canProcess && (
                      <button 
                          onClick={() => onProcess(req.id)}
                          className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700"
                      >
                          <CheckCircle2 className="w-4 h-4 mr-2" /> Process & Sign
                      </button>
                  )}
              </div>
          )}
      </div>
  );
};

const RequestQueue: React.FC<RequestQueueProps> = ({ 
