import React, { useState } from 'react';
import { InventoryItem, User } from '../types';
import { canManageInventory } from '../services/stateService';
import { Search, Plus, Save } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');

  // State for Add Stock
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState(0);
  const [addNote, setAddNote] = useState('');

  // State for New Item
  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItem && addQty > 0) {
        onAddStock(selectedItem.id, addQty, addNote);
        setSelectedItem(null);
        setAddQty(0);
        setAddNote('');
    }
  };

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateItem(newItem);
    setNewItem({
        itemCode: '',
        name: '',
        description: '',
        partNumber: '',
        location: '',
        quantity: 0,
        minThreshold: 5,
        price: 0,
        category: ''
    });
    alert("Item Created Successfully");
  };

  if (isReadOnly) {
      return (
          <div className="space-y-6">
              <div className="bg-amber-50 border border-amber-200 p-4 rounded-lg flex items-center gap-3">
                  <div className="text-amber-600 font-medium">Read Only Access</div>
                  <div className="text-amber-700 text-sm">Super Admins can view inventory but cannot add stock or create items.</div>
              </div>

              <h2 className="text-2xl font-bold text-slate-800">Inventory Overview</h2>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                        <th className="px-6 py-4 font-semibold text-slate-700">Code</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Name</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Stock</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Location</th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                    {items.map(item => (
                        <tr key={item.id}>
                            <td className="px-6 py-4 text-slate-600">{item.itemCode}</td>
                            <td className="px-6 py-4 font-medium text-slate-900">{item.name}</td>
                            <td className="px-6 py-4 font-bold text-slate-800">{item.quantity}</td>
                            <td className="px-6 py-4 text-slate-600">{item.location}</td>
                        </tr>
                    ))}
                    </tbody>
                </table>
            </div>
          </div>
      );
  }

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-slate-800">Add to Inventory</h2>

      <div className="flex gap-4 border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('existing')}
            className={`px-4 py-2 font-medium text-sm border-b-2 transition-colors ${activeTab === 'existing' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
              Add Stock to Existing
          </button>
          <button 
            onClick={() => setActiveTab('new')}
            className={`px-4 py-2 font-medium text-sm border-b-2 transition-colors ${activeTab === 'new' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
              Create New Item
          </button>
      </div>

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                        type="text" 
                        placeholder="Search to select item..." 
                        className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <div className="bg-white rounded-lg border border-slate-200 max-h-96 overflow-y-auto">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)}
                            className={`p-3 border-b border-slate-100 cursor-pointer hover:bg-slate-50 ${selectedItem?.id === item.id ? 'bg-blue-50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div className="font-medium text-slate-800">{item.name}</div>
                              <div className="text-xs text-slate-500 flex justify-between">
                                  <span>{item.itemCode}</span>
                                  <span>Current: {item.quantity}</span>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>

              <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
                  <h3 className="text-lg font-bold text-slate-800 mb-4">Add Stock Details</h3>
                  {selectedItem ? (
                      <form onSubmit={handleStockSubmit} className="space-y-4">
                          <div className="p-3 bg-slate-50 rounded border border-slate-200 text-sm">
                              <span className="font-semibold">{selectedItem.name}</span>
                              <div className="text-slate-500 text-xs mt-1">PN: {selectedItem.partNumber} | Loc: {selectedItem.location}</div>
                          </div>
                          <div>
                              <label className="block text-sm font-medium text-slate-700 mb-1">Quantity to Add</label>
                              <input 
                                type="number" 
                                min="1" 
                                required
                                className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                                value={addQty}
                                onChange={(e) => setAddQty(parseInt(e.target.value))}
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-medium text-slate-700 mb-1">Source / Reason</label>
                              <input 
                                type="text" 
                                placeholder="e.g. PO-8821 Arrival" 
                                required
                                className="w-full border border-slate-300 rounded-lg p-2.5 focus:ring-2 focus:ring-blue-500 outline-none"
                                value={addNote}
                                onChange={(e) => setAddNote(e.target.value)}
                              />
                          </div>
                          <button type="submit" className="w-full py-2 bg-green-600 text-white font-medium rounded-lg hover:bg-green-700">
                              Confirm Add Stock
                          </button>
                      </form>
                  ) : (
                      <div className="text-center text-slate-400 py-10">Select an item from the list to add stock.</div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 max-w-2xl mx-auto">
              <h3 className="text-lg font-bold text-slate-800 mb-6">Create New Inventory Item</h3>
              <form onSubmit={handleCreateSubmit} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Item Code</label>
                          <input type="text" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                             value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                      </div>
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Part Number</label>
                          <input type="text" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                             value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                      </div>
                  </div>
                  <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Item Name</label>
                      <input type="text" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                          value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
                      <textarea className="w-full border border-slate-300 rounded-lg p-2.5" 
                          value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Location</label>
                          <input type="text" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                             value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                      </div>
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                          <input type="text" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                             value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Initial Qty</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-lg p-2.5" 
                             value={newItem.quantity} onChange={e => setNewItem({...newItem, quantity: parseInt(e.target.value)})} />
                      </div>
                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Min Threshold</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-lg p-2.5" 
