                          <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase block mb-1 tracking-widest">Target Item ({selectedItem.inventoryUID})</span>
                              <span className="font-black text-slate-900 text-lg">{selectedItem.name}</span>
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Quantity to Add</label>
                              <input type="number" min="1" required className="w-full border border-slate-300 rounded-xl p-4 text-lg font-bold focus:ring-4 focus:ring-blue-500/10 outline-none" value={addQty} onChange={(e) => setAddQty(parseInt(e.target.value))} />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Internal Note / PO Reference</label>
                              <input type="text" placeholder="e.g. Received from Supplier X" required className="w-full border border-slate-300 rounded-xl p-4 text-base focus:ring-4 focus:ring-blue-500/10 outline-none" value={addNote} onChange={(e) => setAddNote(e.target.value)} />
                          </div>
                          <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all hover:bg-blue-700">
                              Confirm Adjustment
                          </button>
                      </form>
                  ) : (
                      <div className="text-center py-12">
                        <Package className="w-16 h-16 text-slate-100 mx-auto mb-4" />
                        <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">Select an item from the list</p>
                      </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-6 lg:p-10 rounded-3xl shadow-sm border border-slate-200 max-w-3xl mx-auto">
              <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-blue-100 rounded-2xl flex items-center justify-center">
                      <Plus className="w-6 h-6 text-blue-600" />
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-slate-900">Register New Item</h3>
                      <p className="text-sm text-slate-500">Assigning unique inventory tracking code.</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] block mb-1">Generated ID</span>
                    <span className="inline-flex items-center px-3 py-1 bg-blue-600 text-white rounded-lg font-mono font-bold text-sm">
                      <Fingerprint className="w-4 h-4 mr-2" /> {previewUID}
                    </span>
                  </div>
              </div>

              <form onSubmit={handleCreateSubmit} className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Item Code</label>
                          <input type="text" required placeholder="e.g. HYD-001" className="w-full border border-slate-300 rounded-xl p-4 text-base bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Part Number</label>
                          <input type="text" required placeholder="Manufacturer PN" className="w-full border border-slate-300 rounded-xl p-4 text-base bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                      </div>
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Full Item Name</label>
                      <input type="text" required placeholder="e.g. Caterpillar Hydraulic Seal" className="w-full border border-slate-300 rounded-xl p-4 text-base bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Technical Description</label>
                      <textarea placeholder="Dimensions, material, or compatibility notes..." className="w-full border border-slate-300 rounded-xl p-4 text-base bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Warehouse Location</label>
