                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Inventory Category</label>
                          <input type="text" required placeholder="e.g. Hydraulics" className="w-full border border-slate-300 rounded-xl p-4 text-base bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
