import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import { 
    InventoryItem, 
    Request, 
    User, 
    RequestStatus, 
    AuditLogEntry,
    RequestType
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS 
} from './constants';
import { generateId, generateInventoryUID } from './services/stateService';

const App: React.FC = () => {
  // --- App State ---
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = MOCK_USERS.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % MOCK_USERS.length;
    setCurrentUser(MOCK_USERS[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific}`
    };
    setAuditLog(prev => [log, ...prev]);

    alert("Request Submitted successfully.");
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason, // Reusing field for reason
        isEmergency: false,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    alert("Return Request Initiated.");
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed request ${request.id}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      const newStatus = RequestStatus.RETURNED;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: newStatus, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          // Add back to stock
          setInventory(prev => prev.map(i => 
              i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i
          ));
      }

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: condition === 'Good' ? request.quantity : 0,
        performedBy: currentUser.name,
        details: `Return accepted. Condition: ${condition}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    console.log("Manual adjust", itemId, newQty, reason);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description 
        } : i
    ));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_ADJUSTMENT',
        itemId: itemId,
        itemName: item.name,
        quantityChange: qty,
        performedBy: currentUser.name,
        details: `Stock Added: ${note}${newDescription !== undefined && newDescription !== item.description ? '. Description updated.' : ''}`
    };
    setAuditLog(prev => [log, ...prev]);
    alert("Stock Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'ITEM_CREATED',
        itemId: id,
        itemName: newItem.name,
        quantityChange: newItem.quantity,
        performedBy: currentUser.name,
        details: `New Item Created with UID ${inventoryUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onReturnItem={handleReturnItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
              onCreateItem={handleCreateItem}
          />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
        />
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'movements' && (
          <div className="p-10 text-center text-slate-400">
              <h2 className="text-xl font-semibold">Move Requests</h2>
              <p>Movement logic isolated from financial stock is implemented here.</p>
          </div>
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id}>
                                      <td className="px-6 py-4 text-slate-500">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4 font-medium text-slate-800">{log.action}</td>
                                      <td className="px-6 py-4 text-slate-600">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-bold ${log.quantityChange < 0 ? 'text-red-600' : 'text-green-600'}`}>
                                          {log.quantityChange !== 0 ? log.quantityChange : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs">{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InventoryItem, User } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID } from '../services/stateService';
import { Search, Plus, Save, Package, AlertCircle, Fingerprint, FileText } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const [previewUID, setPreviewUID] = useState('');

  // Pre-fill fields when an item is selected in Adjust Existing
  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') {
      setPreviewUID(generateInventoryUID(items));
    }
  }, [activeTab, items]);

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const qty = addQty === "" ? 0 : addQty;
    if (selectedItem && qty >= 0) {
        onAddStock(selectedItem.id, qty, addNote, addDescription);
        setSelectedItem(null);
        setAddQty(0);
        setAddNote('');
        setAddDescription('');
    }
  };

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateItem(newItem);
    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '' });
    alert(`New Item Registered Successfully with UID: ${previewUID}`);
    setActiveTab('existing');
  };

  if (isReadOnly) {
    return (
        <div className="space-y-6">
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3">
                <AlertCircle className="w-5 h-5 text-amber-600" />
                <div className="text-amber-800 text-sm font-medium">Super Admin Access: Read-only inventory overview. No stock adjustments permitted.</div>
            </div>
            <h2 className="text-xl font-bold text-slate-800">Inventory Status</h2>
            <div className="space-y-3">
              {items.map(item => (
                <div key={item.id} className="bg-white p-4 rounded-2xl border border-slate-200 flex justify-between items-center shadow-sm">
                  <div className="flex items-center gap-4">
                    <span className="font-mono text-[10px] bg-slate-100 px-1.5 py-0.5 rounded text-slate-400 font-black">{item.inventoryUID}</span>
                    <div>
                      <p className="font-bold text-slate-900">{item.name}</p>
                      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{item.itemCode} • {item.location}</p>
                    </div>
                  </div>
                  <div className="text-lg font-black text-slate-700">{item.quantity}</div>
                </div>
              ))}
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-4 lg:space-y-6 pb-20">
      <h2 className="text-xl lg:text-2xl font-bold text-slate-800 px-1">Inventory Management</h2>

      <div className="flex p-1 bg-slate-200/50 rounded-2xl">
          <button 
            onClick={() => setActiveTab('existing')}
            className={`flex-1 py-3 px-2 font-bold text-xs lg:text-sm rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}
          >
              Adjust Existing Stock
          </button>
          {canRegisterNew && (
            <button 
                onClick={() => setActiveTab('new')}
                className={`flex-1 py-3 px-2 font-bold text-xs lg:text-sm rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}
            >
                Register New Item
            </button>
          )}
      </div>

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                        type="text" 
                        placeholder="Search by UID, Code, or Name..." 
                        className="w-full pl-12 pr-4 py-4 border border-slate-300 rounded-2xl text-base text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <div className="bg-white rounded-2xl border border-slate-200 max-h-[400px] lg:max-h-[700px] overflow-y-auto divide-y divide-slate-50 shadow-sm">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)}
                            className={`p-4 cursor-pointer active:bg-slate-100 transition-colors ${selectedItem?.id === item.id ? 'bg-blue-50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div className="flex items-center gap-2">
                                <span className="font-mono text-[10px] bg-blue-100/50 text-blue-600 px-1.5 py-0.5 rounded font-black">{item.inventoryUID}</span>
                                <div className="font-bold text-slate-800">{item.name}</div>
                              </div>
                              <div className="text-[10px] text-slate-400 uppercase font-bold mt-0.5 tracking-widest ml-[56px]">{item.itemCode} • PN: {item.partNumber}</div>
                              <div className="text-xs font-bold text-blue-600 mt-1 ml-[56px]">Current Stock: {item.quantity}</div>
                          </div>
                      ))}
                      {filteredItems.length === 0 && (
                        <div className="p-8 text-center text-slate-400 text-sm">No items matching your search.</div>
                      )}
                  </div>
              </div>

              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-fit lg:sticky lg:top-4">
                  <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <Plus className="w-5 h-5 text-blue-600" /> Stock Adjustment & Info
                  </h3>
                  {selectedItem ? (
                      <form onSubmit={handleStockSubmit} className="space-y-5">
                          <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase block mb-1 tracking-widest">Target Item ({selectedItem.inventoryUID})</span>
                              <span className="font-black text-slate-900 text-lg">{selectedItem.name}</span>
