                                value={addDescription} 
                                onChange={(e) => setAddDescription(e.target.value)} 
                              />
                            </div>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Quantity to Add</label>
                                <input 
                                  type="number" 
                                  min="0" 
                                  required 
                                  className="w-full border border-slate-300 rounded-xl p-4 text-lg font-bold text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none bg-slate-50 focus:bg-white transition-all" 
                                  value={addQty === 0 ? '' : addQty} 
                                  onChange={(e) => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                  placeholder="0"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Internal Note / PO</label>
                                <input type="text" placeholder="Ref PO-8821" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none bg-slate-50 focus:bg-white transition-all" value={addNote} onChange={(e) => setAddNote(e.target.value)} />
                            </div>
                          </div>

                          <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all hover:bg-blue-700">
                              Confirm Adjustment
                          </button>
                      </form>
                  ) : (
                      <div className="text-center py-12">
                        <Package className="w-16 h-16 text-slate-100 mx-auto mb-4" />
                        <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">Select an item from the list</p>
                      </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-6 lg:p-10 rounded-3xl shadow-sm border border-slate-200 max-w-3xl mx-auto">
              <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-blue-100 rounded-2xl flex items-center justify-center">
                      <Plus className="w-6 h-6 text-blue-600" />
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-slate-900">Register New Item</h3>
                      <p className="text-sm text-slate-500">Assigning unique inventory tracking code.</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] block mb-1">Generated ID</span>
                    <span className="inline-flex items-center px-3 py-1 bg-blue-600 text-white rounded-lg font-mono font-bold text-sm">
                      <Fingerprint className="w-4 h-4 mr-2" /> {previewUID}
                    </span>
                  </div>
              </div>

              <form onSubmit={handleCreateSubmit} className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Item Code</label>
                          <input type="text" required placeholder="e.g. HYD-001" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Part Number</label>
                          <input type="text" required placeholder="Manufacturer PN" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                      </div>
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Full Item Name</label>
                      <input type="text" required placeholder="e.g. Caterpillar Hydraulic Seal" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Technical Description</label>
                      <textarea placeholder="Dimensions, material, or compatibility notes..." className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Warehouse Location</label>
                          <input type="text" required placeholder="e.g. Bin B4-12" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Inventory Category</label>
                          <input type="text" required placeholder="e.g. Hydraulics" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 lg:grid-cols-3 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Opening Qty</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Min Alert Level</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.minThreshold === 0 ? '' : newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="col-span-2 lg:col-span-1 space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Unit Cost ($)</label>
                          <input type="number" step="0.01" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: e.target.value === '' ? 0 : parseFloat(e.target.value)})} />
                      </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl mt-6 active:scale-[0.98] transition-all hover:bg-blue-700 flex items-center justify-center gap-3">
                      <Save className="w-5 h-5" /> Register Item Record
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

export default AddInventoryView;

import React, { useState } from 'react';
import { InventoryItem, User, WorkPurpose } from '../types';
import { Search, Info, RotateCcw, Box, MapPin, Tag, Fingerprint, X } from 'lucide-react';
import { canViewPrices } from '../services/stateService';

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onReturnItem: (itemId: string, qty: number, reason: string) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, onRequestItem, onReturnItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [mode, setMode] = useState<'request' | 'return' | 'info'>('request');

  const [reqQty, setReqQty] = useState<number | "">(1);
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);
  const [returnReason, setReturnReason] = useState('');

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItem) {
      const qty = reqQty === "" ? 0 : reqQty;
      if (mode === 'request') {
          onRequestItem(selectedItem.id, qty, reqPurpose, reqSpecific, isEmergency);
      } else if (mode === 'return') {
          onReturnItem(selectedItem.id, qty, returnReason);
      }
      setSelectedItem(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setReqQty(1);
    setReqPurpose('');
    setReqSpecific('');
    setIsEmergency(false);
    setReturnReason('');
  };

  const openModal = (item: InventoryItem, action: 'request' | 'return' | 'info') => {
      setSelectedItem(item);
      setMode(action);
      resetForm();
  }

  return (
    <div className="space-y-4 lg:space-y-6 pb-12">
      <div className="flex flex-col gap-4">
        <div>
            <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Inventory Dashboard</h2>
            <p className="text-sm text-slate-500">View, request, or return items. Click Info to see technical details.</p>
        </div>

        <div className="relative w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search by UID, code, name, part #..." 
            className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-base text-slate-900"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      {/* Desktop Table */}
      <div className="hidden lg:block bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 font-semibold text-slate-700">Internal ID</th>
              <th className="px-6 py-4 font-semibold text-slate-700">Item Details</th>
              <th className="px-6 py-4 font-semibold text-slate-700">Location</th>
              <th className="px-6 py-4 font-semibold text-slate-700">Category</th>
              <th className="px-6 py-4 font-semibold text-slate-700 text-center">Stock</th>
              {canViewPrices(currentUser) && <th className="px-6 py-4 font-semibold text-slate-700 text-right">Unit Price</th>}
              <th className="px-6 py-4 font-semibold text-slate-700 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredItems.map(item => (
              <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-mono text-blue-600 font-bold">{item.inventoryUID}</td>
                <td className="px-6 py-4">
                  <div className="font-medium text-slate-900">{item.name}</div>
                  <div className="text-xs text-slate-500">Code: {item.itemCode} | PN: {item.partNumber}</div>
                </td>
                <td className="px-6 py-4 text-slate-600">{item.location}</td>
                <td className="px-6 py-4 text-slate-600">
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                    {item.category}
                  </span>
                </td>
                <td className="px-6 py-4 text-center font-bold text-slate-900">{item.quantity}</td>
                {canViewPrices(currentUser) && <td className="px-6 py-4 text-right text-slate-600 font-medium">${item.price.toFixed(2)}</td>}
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => openModal(item, 'info')} className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="View Info">
                      <Info className="w-5 h-5" />
                    </button>
                    <button onClick={() => openModal(item, 'request')} className="text-blue-600 font-medium px-3 py-1.5 border border-blue-200 rounded-lg hover:bg-blue-50">Request</button>
                    <button onClick={() => openModal(item, 'return')} className="text-slate-600 px-2 py-1.5 border border-slate-200 rounded-lg hover:bg-slate-50" title="Return Item">
                      <RotateCcw className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Mobile Cards */}
      <div className="lg:hidden space-y-3">
        {filteredItems.map(item => (
          <div key={item.id} className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 space-y-3">
            <div className="flex justify-between items-start">
              <div className="space-y-1">
                <span className="inline-flex items-center px-2 py-0.5 rounded bg-blue-50 text-blue-700 text-[10px] font-black uppercase tracking-wider">
                  <Fingerprint className="w-3 h-3 mr-1" /> {item.inventoryUID}
                </span>
                <h3 className="font-bold text-slate-900 leading-tight">{item.name}</h3>
                <p className="text-xs text-slate-500">{item.itemCode} • PN: {item.partNumber}</p>
              </div>
              <div className="flex flex-col items-end gap-2">
                <div className={`px-3 py-1 rounded-lg text-sm font-bold ${item.quantity <= item.minThreshold ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-700'}`}>
                  {item.quantity}
                </div>
                <button onClick={() => openModal(item, 'info')} className="p-2 bg-slate-100 text-slate-500 rounded-xl" title="View Info">
                   <Info className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 text-xs text-slate-600">
              <div className="flex items-center gap-1.5 bg-slate-50 p-2 rounded-lg">
                <MapPin className="w-3 h-3 text-slate-400" />
                <span>{item.location}</span>
              </div>
              <div className="flex items-center gap-1.5 bg-slate-50 p-2 rounded-lg">
                <Tag className="w-3 h-3 text-slate-400" />
                <span className="truncate">{item.category}</span>
              </div>
            </div>

            {canViewPrices(currentUser) && (
              <div className="text-sm font-semibold text-slate-800">
                Unit Price: ${item.price.toFixed(2)}
              </div>
            )}

            <div className="flex gap-2 pt-1">
              <button 
                onClick={() => openModal(item, 'request')}
                className="flex-1 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-sm"
              >
                Request
              </button>
              <button 
                onClick={() => openModal(item, 'return')}
                className="px-4 py-3 border border-slate-200 text-slate-600 rounded-xl flex items-center justify-center"
              >
                <RotateCcw className="w-5 h-5" />
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {selectedItem && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-end lg:items-center justify-center z-[100] p-0 lg:p-4 backdrop-blur-sm">
          <div className="bg-white rounded-t-3xl lg:rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className={`p-6 border-b ${mode === 'request' ? 'border-slate-100' : mode === 'info' ? 'border-blue-100 bg-blue-50/30' : 'border-indigo-100 bg-indigo-50'}`}>
                <div className="flex justify-between items-center">
                    <h3 className={`text-lg font-bold ${mode === 'request' ? 'text-slate-800' : mode === 'info' ? 'text-blue-800' : 'text-indigo-800'}`}>
                        {mode === 'request' ? 'Request Item' : mode === 'info' ? 'Item Information' : 'Return Item'}
                    </h3>
                    <button onClick={() => setSelectedItem(null)} className="text-slate-400 p-1 hover:text-slate-600 transition-colors">
                      <X className="w-6 h-6" />
                    </button>
                </div>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-bold bg-white/50 border border-slate-200 px-1.5 py-0.5 rounded text-slate-500 uppercase tracking-widest">{selectedItem.inventoryUID}</span>
                  <p className="text-sm text-slate-500 font-medium">{selectedItem.name}</p>
                </div>
            </div>

            {mode === 'info' ? (
               <div className="p-6 space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technical Description</label>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-slate-700 text-sm leading-relaxed whitespace-pre-wrap">
                      {selectedItem.description || "No technical description available for this item."}
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Part Number</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.partNumber}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Item Code</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.itemCode}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Warehouse Bin</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.location}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Category</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.category}</span>
                    </div>
                  </div>

                  <button 
                    onClick={() => setSelectedItem(null)}
                    className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl shadow-lg mt-2"
                  >
                    Close
                  </button>
               </div>
            ) : (
              <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
                  {mode === 'request' ? (
                      <>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Work Purpose</label>
                              <select required className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900" value={reqPurpose} onChange={(e) => setReqPurpose(e.target.value)}>
                                  <option value="">Select a purpose...</option>
                                  {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1 text-base">Specific Details</label>
                              <input type="text" required placeholder="e.g., Pump 3 maintenance" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900" value={reqSpecific} onChange={(e) => setReqSpecific(e.target.value)} />
                          </div>
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-sm font-bold text-slate-700 mb-1">Quantity</label>
                                  <input 
                                    type="number" 
                                    min="1" 
                                    max={selectedItem.quantity} 
                                    required 
                                    className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-bold" 
                                    value={reqQty === 0 ? '' : reqQty} 
                                    onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                    placeholder="0"
                                  />
                              </div>
                          </div>
                          <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
                              <label className="flex items-start gap-3 cursor-pointer">
                                  <input type="checkbox" className="mt-1 w-5 h-5 text-amber-600 rounded-lg border-gray-300" checked={isEmergency} onChange={(e) => setIsEmergency(e.target.checked)} />
                                  <div>
                                      <span className="block text-sm font-bold text-amber-800">Item Already Taken</span>
                                      <span className="block text-xs text-amber-700">Flag as an emergency pick-up for verification.</span>
                                  </div>
                              </label>
                          </div>
                      </>
                  ) : (
                      <>
                          <div className="bg-indigo-50 p-4 rounded-xl text-sm text-indigo-700 font-medium">Admin will verify condition on receipt.</div>
                           <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Return Quantity</label>
                              <input 
                                type="number" 
                                min="1" 
                                required 
                                className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-bold" 
                                value={reqQty === 0 ? '' : reqQty} 
                                onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                placeholder="0"
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Reason</label>
                              <textarea required placeholder="e.g. Excess stock" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 min-h-[100px]" value={returnReason} onChange={(e) => setReturnReason(e.target.value)} />
                          </div>
                      </>
                  )}

                  <div className="flex flex-col-reverse lg:flex-row gap-3 pt-4">
                      <button type="button" onClick={() => setSelectedItem(null)} className="w-full py-4 border border-slate-300 text-slate-700 font-bold rounded-xl">Cancel</button>
                      <button type="submit" className={`w-full py-4 text-white font-bold rounded-xl shadow-lg ${mode === 'request' ? 'bg-blue-600' : 'bg-indigo-600'}`}>
                          {mode === 'request' ? 'Submit Request' : 'Submit Return'}
                      </button>
                  </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

