            ) : (
              <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
                  {mode === 'request' ? (
                      <>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Work Purpose</label>
                              <select required className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-bold" value={reqPurpose} onChange={(e) => setReqPurpose(e.target.value)}>
                                  <option value="">Select a purpose...</option>
                                  {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1 text-base">Specific Details</label>
                              <input type="text" required placeholder="e.g., Pump 3 maintenance" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-medium" value={reqSpecific} onChange={(e) => setReqSpecific(e.target.value)} />
                          </div>
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-sm font-bold text-slate-700 mb-1">Quantity</label>
                                  <input 
                                    type="number" 
                                    min="1" 
                                    max={selectedItem.quantity} 
                                    required 
                                    className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-black text-lg" 
                                    value={reqQty === 0 ? '' : reqQty} 
                                    onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                    placeholder="0"
                                  />
                              </div>
                          </div>
                          <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
                              <label className="flex items-start gap-3 cursor-pointer">
                                  <input type="checkbox" className="mt-1 w-5 h-5 text-amber-600 rounded-lg border-gray-300" checked={isEmergency} onChange={(e) => setIsEmergency(e.target.checked)} />
                                  <div>
                                      <span className="block text-sm font-black text-amber-800">Item Already Taken</span>
                                      <span className="block text-xs text-amber-700 font-medium">Flag as an emergency pick-up for verification.</span>
                                  </div>
                              </label>
                          </div>
                      </>
                  ) : (
                      <>
                          <div className="bg-indigo-50 p-4 rounded-xl text-sm text-indigo-700 font-bold">Admin will verify condition on receipt.</div>
                           <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Return Quantity</label>
                              <input 
                                type="number" 
                                min="1" 
                                required 
                                className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-black text-lg" 
                                value={reqQty === 0 ? '' : reqQty} 
                                onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                placeholder="0"
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Reason</label>
                              <textarea required placeholder="e.g. Excess stock" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-medium min-h-[100px]" value={returnReason} onChange={(e) => setReturnReason(e.target.value)} />
                          </div>
                      </>
                  )}

                  <div className="flex flex-col-reverse lg:flex-row gap-3 pt-4">
                      <button type="button" onClick={() => setSelectedItem(null)} className="w-full py-4 border border-slate-300 text-slate-700 font-bold rounded-xl active:bg-slate-50">Cancel</button>
                      <button type="submit" className={`w-full py-4 text-white font-black rounded-xl shadow-lg transition-transform active:scale-95 ${mode === 'request' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                          {mode === 'request' ? 'Submit Request' : 'Submit Return'}
                      </button>
                  </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

export enum UserRole {
  STANDARD = 'Standard User',
  ADMIN_L1 = 'Admin Level 1',
  ADMIN_L2 = 'Super Admin',
  OWNER = 'Owner',
}

export enum RequestStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export enum RequestType {
  TAKE = 'Take',
  RETURN = 'Return'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  isSpecialAdmin?: boolean; // Can process requests like owner
}

export interface InventoryItem {
  id: string;
  inventoryUID: string; // Unique generated internal code (e.g. ST-0001)
  itemCode: string;
  name: string;
  description: string;
  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number; // Hidden from Standard users
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId?: string; // Optional for returns
  specificPurpose?: string; // Optional for returns
  status: RequestStatus;
  type: RequestType;
  isEmergency: boolean; // "Item Already Taken" (Only for Takes)
  timestamp: string;
  claimedBy?: string; // Admin ID
  verifiedBy?: string; // Admin ID
  processedBy?: string; // Owner/Special Admin ID
  returnCondition?: 'Good' | 'Damaged';
}

export interface AuditLogEntry {
  id: string;
  timestamp: string;
  action: string;
  itemId: string;
  itemName: string;
  quantityChange: number;
  performedBy: string; // User Name
  details: string;
}

export interface PurchaseOrder {
  id: string;
  prNumber: string;
  prDate: string;
  poNumber: string;
  status: 'Draft' | 'Approved' | 'Ordered' | 'Received' | 'Closed';
  supplier: string;
  totalCost: number;
  date: string; // PO Creation Date
  receivedDate?: string;
}

