import React, { useState, useEffect } from 'react';
import { InventoryItem, User } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID } from '../services/stateService';
import { Search, Plus, Save, Package, AlertCircle, Fingerprint, FileText } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const [previewUID, setPreviewUID] = useState('');

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') {
      setPreviewUID(generateInventoryUID(items));
    }
  }, [activeTab, items]);

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const qty = addQty === "" ? 0 : addQty;
    if (selectedItem && qty >= 0) {
        onAddStock(selectedItem.id, qty, addNote, addDescription);
        setSelectedItem(null);
        setAddQty(0);
        setAddNote('');
        setAddDescription('');
    }
  };

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateItem(newItem);
    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '' });
    alert(`Record Created Successfully: ${previewUID}`);
    setActiveTab('existing');
  };

  if (isReadOnly) {
    return (
        <div className="space-y-8">
            <div className="bg-red-900 border-4 border-black p-6 flex items-center gap-6 shadow-[8px_8px_0px_0px_#000]">
                <AlertCircle className="w-10 h-10 text-white" />
                <div className="text-white">
                  <h4 className="font-black text-lg uppercase tracking-widest">Terminal Restricted</h4>
                  <p className="text-xs font-medium uppercase opacity-80">Super Admin Access: Read-only inventory overview. Stock adjustments are locked.</p>
                </div>
            </div>
            <h2 className="text-2xl font-black text-slate-800 uppercase italic">Stock Ledger</h2>
            <div className="space-y-4">
              {items.map(item => (
                <div key={item.id} className="bg-white p-6 border-4 border-slate-900 flex justify-between items-center">
                  <div className="flex items-center gap-6">
                    <span className="font-mono text-xs bg-slate-900 text-[#FACC15] px-2 py-1 font-black">{item.inventoryUID}</span>
                    <div>
                      <p className="font-black text-slate-900 uppercase italic tracking-tight">{item.name}</p>
                      <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.2em]">{item.itemCode} • {item.location}</p>
                    </div>
                  </div>
                  <div className="text-3xl font-black text-slate-900">{item.quantity}</div>
                </div>
              ))}
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-8 lg:space-y-12 pb-24">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <h2 className="text-3xl lg:text-4xl font-black text-[#1A1A1B] tracking-tighter uppercase italic">Supply<span className="text-slate-400">Terminal</span></h2>

        <div className="flex bg-slate-300 p-1 border-2 border-slate-900 h-14">
            <button 
              onClick={() => setActiveTab('existing')}
              className={`px-8 font-black text-[10px] uppercase tracking-[0.2em] transition-all ${activeTab === 'existing' ? 'bg-[#1A1A1B] text-[#FACC15]' : 'text-slate-600 hover:text-slate-900'}`}
            >
                Stock Adjustment
            </button>
            {canRegisterNew && (
              <button 
                  onClick={() => setActiveTab('new')}
                  className={`px-8 font-black text-[10px] uppercase tracking-[0.2em] transition-all ${activeTab === 'new' ? 'bg-[#1A1A1B] text-[#FACC15]' : 'text-slate-600 hover:text-slate-900'}`}
              >
                  Register New Asset
              </button>
            )}
        </div>
      </div>

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
              <div className="lg:col-span-5 space-y-6">
                  <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-[#FACC15]" />
                    <input 
                        type="text" 
                        placeholder="INPUT UID / CODE / NAME..." 
                        className="w-full pl-14 pr-4 py-5 bg-white border-4 border-slate-900 text-xs font-black uppercase tracking-[0.2em] outline-none focus:border-[#FACC15] transition-all"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <div className="bg-white border-4 border-slate-900 max-h-[600px] overflow-y-auto divide-y-2 divide-slate-100 shadow-[12px_12px_0px_0px_rgba(0,0,0,0.05)]">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)}
                            className={`p-5 cursor-pointer hover:bg-slate-50 transition-all border-l-[12px] ${selectedItem?.id === item.id ? 'border-[#FACC15] bg-slate-50' : 'border-transparent'}`}
                          >
                              <div className="flex items-center gap-4">
                                <span className="font-mono text-[11px] bg-slate-900 text-[#FACC15] px-2 py-0.5 font-black">{item.inventoryUID}</span>
                                <div className="font-black text-slate-800 uppercase tracking-tight italic">{item.name}</div>
                              </div>
                              <div className="text-[10px] text-slate-400 font-black mt-2 tracking-widest flex justify-between">
                                <span>CODE: {item.itemCode}</span>
                                <span className="text-slate-900">CURR: {item.quantity}</span>
                              </div>
                          </div>
                      ))}
                      {filteredItems.length === 0 && (
                        <div className="p-12 text-center text-slate-300 text-xs font-black uppercase tracking-widest">Zero Results Matching Query</div>
                      )}
                  </div>
              </div>

              <div className="lg:col-span-7 bg-white p-8 lg:p-12 border-4 border-slate-900 shadow-[16px_16px_0px_0px_rgba(0,0,0,0.1)] relative">
                  <div className="absolute top-0 right-0 p-4 opacity-10">
                    <Package className="w-24 h-24" />
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-10 flex items-center gap-4 uppercase tracking-tighter italic">
                    <Plus className="w-6 h-6 p-1 bg-[#FACC15] border-2 border-slate-900" /> Stock Input Ledger
                  </h3>
                  {selectedItem ? (
                      <form onSubmit={handleStockSubmit} className="space-y-8">
                          <div className="p-6 bg-slate-900 text-white border-l-8 border-[#FACC15]">
                              <span className="text-[10px] font-black text-slate-500 uppercase block mb-1 tracking-widest">Terminal Selection</span>
                              <span className="font-black text-lg uppercase italic tracking-tighter">{selectedItem.name}</span>
                              <span className="block font-mono text-xs text-[#FACC15] mt-1">{selectedItem.inventoryUID}</span>
                          </div>

                          <div className="space-y-2">
                            <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest italic">Update Specification (Optional)</label>
                            <div className="relative">
                              <textarea 
                                placeholder="INPUT TECHNICAL UPDATES HERE..." 
                                className="w-full border-4 border-slate-900 p-5 text-xs font-bold bg-[#F0F1F2] focus:bg-white transition-all outline-none min-h-[120px] uppercase tracking-wide" 
                                value={addDescription} 
                                onChange={(e) => setAddDescription(e.target.value)} 
                              />
                            </div>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 italic">Add Qty</label>
                                <input 
                                  type="number" 
                                  min="0" 
                                  required 
                                  className="w-full border-4 border-slate-900 p-6 text-3xl font-black text-slate-900 focus:ring-8 focus:ring-[#FACC15]/10 outline-none bg-[#F0F1F2] focus:bg-white transition-all" 
                                  value={addQty === 0 ? '' : addQty} 
                                  onChange={(e) => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                  placeholder="000"
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2 italic">Ref ID / Notes</label>
                                <input type="text" placeholder="PO-XXXX / SUPPLIER REF" required className="w-full border-4 border-slate-900 p-6 text-xs font-black uppercase tracking-widest outline-none bg-[#F0F1F2] focus:bg-white transition-all" value={addNote} onChange={(e) => setAddNote(e.target.value)} />
                            </div>
                          </div>

                          <button type="submit" className="w-full py-6 bg-slate-900 text-[#FACC15] font-black text-sm uppercase tracking-[0.4em] shadow-[8px_8px_0px_0px_#000] active:scale-[0.98] transition-all">
                              EXECUTE RECORD ENTRY
                          </button>
                      </form>
                  ) : (
                      <div className="text-center py-20 border-4 border-dashed border-slate-200">
                        <Package className="w-20 h-20 text-slate-100 mx-auto mb-6" />
                        <p className="text-xs text-slate-400 font-black uppercase tracking-[0.3em]">Awaiting Asset Selection from Ledger</p>
                      </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-8 lg:p-16 border-4 border-slate-900 shadow-[20px_20px_0px_0px_rgba(0,0,0,0.1)] max-w-4xl mx-auto">
              <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-12 border-b-4 border-slate-900 pb-10">
                  <div className="flex items-center gap-6">
                    <div className="w-16 h-16 bg-slate-900 flex items-center justify-center border-4 border-[#FACC15] rotate-3">
                      <Plus className="w-8 h-8 text-[#FACC15]" />
                    </div>
                    <div>
                      <h3 className="text-3xl font-black text-slate-900 uppercase italic tracking-tighter">New Asset Registration</h3>
                      <p className="text-[10px] text-slate-500 font-black tracking-[0.3em] uppercase">Initializing Secure UID Sequence</p>
                    </div>
                  </div>
                  <div className="bg-[#FACC15] p-4 border-4 border-slate-900 shadow-[4px_4px_0px_0px_#000]">
                    <span className="text-[9px] font-black text-slate-900 uppercase tracking-widest block mb-1">Assigned UID</span>
                    <span className="flex items-center font-mono font-black text-lg text-slate-900">
                      <Fingerprint className="w-5 h-5 mr-2" /> {previewUID}
                    </span>
                  </div>
              </div>

              <form onSubmit={handleCreateSubmit} className="space-y-10">
