import React, { useState } from 'react';
import { InventoryItem, User, WorkPurpose } from '../types';
import { Search, Info, RotateCcw, Box, MapPin, Tag, Fingerprint, X, Filter, ChevronDown } from 'lucide-react';
import { canViewPrices } from '../services/stateService';

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onReturnItem: (itemId: string, qty: number, reason: string) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, onRequestItem, onReturnItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [mode, setMode] = useState<'request' | 'return' | 'info'>('request');

  const [reqQty, setReqQty] = useState<number | "">(1);
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);
  const [returnReason, setReturnReason] = useState('');

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedItem) {
      const qty = reqQty === "" ? 0 : reqQty;
      if (mode === 'request') {
          onRequestItem(selectedItem.id, qty, reqPurpose, reqSpecific, isEmergency);
      } else if (mode === 'return') {
          onReturnItem(selectedItem.id, qty, returnReason);
      }
      setSelectedItem(null);
      resetForm();
    }
  };

  const resetForm = () => {
    setReqQty(1);
    setReqPurpose('');
    setReqSpecific('');
    setIsEmergency(false);
    setReturnReason('');
  };

  const openModal = (item: InventoryItem, action: 'request' | 'return' | 'info') => {
      setSelectedItem(item);
      setMode(action);
