                                  <option value="">Select a purpose...</option>
                                  {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-2">Specific Details</label>
                              <input type="text" required placeholder="e.g., Pump 3 maintenance" className="w-full border border-slate-200 rounded-2xl p-4 bg-slate-50 text-slate-900 font-medium focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all" value={reqSpecific} onChange={(e) => setReqSpecific(e.target.value)} />
                          </div>
