                        </div>

                        <div className="bg-amber-50 border border-amber-100 rounded-2xl p-4 mt-2">
                            <label className="flex items-start gap-3 cursor-pointer">
                                <input type="checkbox" className="mt-1 w-5 h-5 border-slate-300 rounded text-amber-600 focus:ring-amber-500" checked={isEmergency} onChange={(e) => setIsEmergency(e.target.checked)} />
                                <div>
                                    <span className="block text-sm font-bold text-amber-900">Item Already Taken</span>
                                    <span className="block text-xs text-amber-700 mt-0.5">Flag as an emergency pick-up for logging.</span>
                                </div>
                            </label>
                        </div>
                      </>
                    ) : (
                      <>
                         <div>
                              <label className="block text-sm font-bold text-slate-700 mb-2">Return Quantity</label>
                              <input 
                                type="number" 
                                min="1" 
                                required 
                                className="w-32 border border-slate-200 rounded-2xl p-4 bg-slate-50 text-slate-900 font-bold text-xl text-center focus:ring-4 focus:ring-indigo-500/10 outline-none" 
                                value={reqQty === 0 ? '' : reqQty} 
                                onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                placeholder="0"
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-2">Reason for Return</label>
                              <textarea required placeholder="Briefly explain..." className="w-full border border-slate-200 rounded-2xl p-4 bg-slate-50 text-slate-900 font-medium min-h-[100px] outline-none focus:ring-4 focus:ring-indigo-500/10" value={returnReason} onChange={(e) => setReturnReason(e.target.value)} />
                          </div>
                      </>
                    )}

                    <div className="flex flex-col-reverse sm:flex-row gap-3 pt-6">
                        <button type="button" onClick={() => setSelectedItem(null)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl active:bg-slate-50 transition-colors">Cancel</button>
                        <button type="submit" className={`flex-1 py-4 text-white font-bold rounded-2xl shadow-lg active:scale-95 transition-all ${mode === 'request' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' : 'bg-purple-600 hover:bg-purple-700 shadow-purple-100'}`}>
                            {mode === 'request' ? 'Submit Request' : 'Submit Return'}
                        </button>
                    </div>
                 </form>
               )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React, { useState, useEffect } from 'react';
import { InventoryItem, User } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID } from '../services/stateService';
import { Search, Plus, Save, Package, AlertCircle, Fingerprint, FileText } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const [previewUID, setPreviewUID] = useState('');

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') {
      setPreviewUID(generateInventoryUID(items));
    }
  }, [activeTab, items]);

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const qty = addQty === "" ? 0 : addQty;
    if (selectedItem && qty >= 0) {
        onAddStock(selectedItem.id, qty, addNote, addDescription);
        setSelectedItem(null);
        setAddQty(0);
        setAddNote('');
        setAddDescription('');
    }
  };

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateItem(newItem);
    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '' });
    alert(`Asset Registered: ${previewUID}`);
    setActiveTab('existing');
  };

  if (isReadOnly) {
    return (
        <div className="space-y-6">
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-4">
                <AlertCircle className="w-6 h-6 text-amber-600" />
                <div className="text-amber-800 text-sm font-medium">Terminal restricted: Read-only ledger view enabled.</div>
            </div>
            <h2 className="text-2xl font-bold text-slate-900">Current Stock Ledger</h2>
            <div className="space-y-3">
              {items.map(item => (
                <div key={item.id} className="bg-white p-5 rounded-2xl border border-slate-200 flex justify-between items-center shadow-sm">
                  <div className="flex items-center gap-4">
                    <span className="font-mono text-xs bg-slate-100 px-2 py-1 rounded-lg text-slate-500 font-bold">{item.inventoryUID}</span>
                    <div>
                      <p className="font-bold text-slate-900">{item.name}</p>
                      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{item.itemCode} • {item.location}</p>
                    </div>
                  </div>
                  <div className="text-2xl font-black text-slate-800">{item.quantity}</div>
                </div>
              ))}
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h2 className="text-2xl font-bold text-slate-900">Supply Terminal</h2>
        <div className="flex p-1 bg-slate-200/50 rounded-2xl w-fit">
            <button 
              onClick={() => setActiveTab('existing')}
              className={`px-6 py-2.5 font-bold text-sm rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}
            >
                Stock Update
            </button>
            {canRegisterNew && (
              <button 
                  onClick={() => setActiveTab('new')}
                  className={`px-6 py-2.5 font-bold text-sm rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}
              >
                  Register New
              </button>
            )}
        </div>
      </div>

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
