                      </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-8 lg:p-12 rounded-[2.5rem] border border-slate-200 shadow-sm max-w-4xl mx-auto">
              <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-10 border-b border-slate-100 pb-10">
