                          <input type="text" required placeholder="Mechanical" className="w-full border border-slate-200 rounded-2xl p-4 bg-slate-50 focus:bg-white outline-none" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                      <div className="space-y-2">
                          <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest">Initial Qty</label>
                          <input type="number" required className="w-full border border-slate-200 rounded-2xl p-4 font-bold bg-white" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest">Min Threshold</label>
                          <input type="number" required className="w-full border border-slate-200 rounded-2xl p-4 font-bold bg-white" value={newItem.minThreshold === 0 ? '' : newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="col-span-2 lg:col-span-1 space-y-2">
                          <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest">Unit Price ($)</label>
                          <input type="number" step="0.01" required className="w-full border border-slate-200 rounded-2xl p-4 font-bold bg-white" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: e.target.value === '' ? 0 : parseFloat(e.target.value)})} />
                      </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-indigo-600 text-white font-bold rounded-[1.5rem] shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-[0.98] transition-all flex items-center justify-center gap-3">
                      <Save className="w-5 h-5" /> Confirm Registration
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

