                <RotateCcw className="w-5 h-5" />
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Modal remains the same */}
      {selectedItem && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-end lg:items-center justify-center z-[100] p-0 lg:p-4 backdrop-blur-sm">
          <div className="bg-white rounded-t-3xl lg:rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className={`p-6 border-b ${mode === 'request' ? 'border-slate-100' : mode === 'info' ? 'border-blue-100 bg-blue-50/30' : 'border-indigo-100 bg-indigo-50'}`}>
                <div className="flex justify-between items-center">
                    <h3 className={`text-lg font-bold ${mode === 'request' ? 'text-slate-800' : mode === 'info' ? 'text-blue-800' : 'text-indigo-800'}`}>
                        {mode === 'request' ? 'Request Item' : mode === 'info' ? 'Item Information' : 'Return Item'}
                    </h3>
                    <button onClick={() => setSelectedItem(null)} className="text-slate-400 p-1 hover:text-slate-600 transition-colors">
                      <X className="w-6 h-6" />
                    </button>
                </div>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-bold bg-white/50 border border-slate-200 px-1.5 py-0.5 rounded text-slate-500 uppercase tracking-widest">{selectedItem.inventoryUID}</span>
                  <p className="text-sm text-slate-500 font-medium">{selectedItem.name}</p>
                </div>
            </div>

            {mode === 'info' ? (
               <div className="p-6 space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Technical Description</label>
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 text-slate-700 text-sm leading-relaxed whitespace-pre-wrap font-medium">
                      {selectedItem.description || "No technical description available for this item."}
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Part Number</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.partNumber}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Item Code</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.itemCode}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Warehouse Bin</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.location}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Category</label>
                      <span className="text-sm font-bold text-slate-800">{selectedItem.category}</span>
                    </div>
                    {canViewPrices(currentUser) && (
                      <div className="bg-blue-50 p-3 rounded-xl border border-blue-100">
                        <label className="text-[9px] font-bold text-blue-400 uppercase tracking-widest block mb-0.5">Unit Price</label>
                        <span className="text-sm font-bold text-blue-800">${selectedItem.price.toFixed(2)}</span>
                      </div>
                    )}
                  </div>

                  <button 
                    onClick={() => setSelectedItem(null)}
                    className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl shadow-lg mt-2"
                  >
                    Close
                  </button>
               </div>
            ) : (
              <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
                  {mode === 'request' ? (
                      <>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Work Purpose</label>
                              <select required className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-bold" value={reqPurpose} onChange={(e) => setReqPurpose(e.target.value)}>
                                  <option value="">Select a purpose...</option>
                                  {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                              </select>
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1 text-base">Specific Details</label>
                              <input type="text" required placeholder="e.g., Pump 3 maintenance" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-medium" value={reqSpecific} onChange={(e) => setReqSpecific(e.target.value)} />
                          </div>
                          <div className="grid grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-sm font-bold text-slate-700 mb-1">Quantity</label>
                                  <input 
                                    type="number" 
                                    min="1" 
                                    max={selectedItem.quantity} 
                                    required 
                                    className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-black text-lg" 
                                    value={reqQty === 0 ? '' : reqQty} 
                                    onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                    placeholder="0"
                                  />
                              </div>
                          </div>
                          <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
                              <label className="flex items-start gap-3 cursor-pointer">
                                  <input type="checkbox" className="mt-1 w-5 h-5 text-amber-600 rounded-lg border-gray-300" checked={isEmergency} onChange={(e) => setIsEmergency(e.target.checked)} />
                                  <div>
                                      <span className="block text-sm font-black text-amber-800">Item Already Taken</span>
                                      <span className="block text-xs text-amber-700 font-medium">Flag as an emergency pick-up for verification.</span>
                                  </div>
                              </label>
                          </div>
                      </>
                  ) : (
                      <>
                          <div className="bg-indigo-50 p-4 rounded-xl text-sm text-indigo-700 font-bold">Admin will verify condition on receipt.</div>
                           <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Return Quantity</label>
                              <input 
                                type="number" 
                                min="1" 
                                required 
                                className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-black text-lg" 
                                value={reqQty === 0 ? '' : reqQty} 
                                onChange={(e) => setReqQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                placeholder="0"
                              />
                          </div>
                          <div>
                              <label className="block text-sm font-bold text-slate-700 mb-1">Reason</label>
                              <textarea required placeholder="e.g. Excess stock" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-medium min-h-[100px]" value={returnReason} onChange={(e) => setReturnReason(e.target.value)} />
                          </div>
                      </>
                  )}

                  <div className="flex flex-col-reverse lg:flex-row gap-3 pt-4">
                      <button type="button" onClick={() => setSelectedItem(null)} className="w-full py-4 border border-slate-300 text-slate-700 font-bold rounded-xl active:bg-slate-50">Cancel</button>
                      <button type="submit" className={`w-full py-4 text-white font-black rounded-xl shadow-lg transition-transform active:scale-95 ${mode === 'request' ? 'bg-blue-600 hover:bg-blue-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                          {mode === 'request' ? 'Submit Request' : 'Submit Return'}
                      </button>
                  </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React, { useState, useEffect } from 'react';
import { InventoryItem, User } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID, canViewPrices } from '../services/stateService';
import { Search, Plus, Save, Package, AlertCircle, Fingerprint, FileText } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const [previewUID, setPreviewUID] = useState('');

  // Pre-fill fields when an item is selected in Adjust Existing
  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') {
      setPreviewUID(generateInventoryUID(items));
    }
  }, [activeTab, items]);

  const filteredItems = items.filter(item => 
    item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.partNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.inventoryUID.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleStockSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const qty = addQty === "" ? 0 : addQty;
    if (selectedItem && qty >= 0) {
        onAddStock(selectedItem.id, qty, addNote, addDescription);
        setSelectedItem(null);
        setAddQty(0);
        setAddNote('');
        setAddDescription('');
    }
  };

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCreateItem(newItem);
    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '' });
    alert(`New Item Registered Successfully with UID: ${previewUID}`);
    setActiveTab('existing');
  };

  if (isReadOnly) {
    return (
        <div className="space-y-6">
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-3">
                <AlertCircle className="w-5 h-5 text-amber-600" />
                <div className="text-amber-800 text-sm font-medium">Super Admin Access: Read-only inventory overview. No stock adjustments permitted.</div>
            </div>
            <h2 className="text-xl font-bold text-slate-800">Inventory Status</h2>
            <div className="space-y-3">
              {items.map(item => (
                <div key={item.id} className="bg-white p-4 rounded-2xl border border-slate-200 flex justify-between items-center shadow-sm">
                  <div className="flex items-center gap-4">
                    <span className="font-mono text-[10px] bg-slate-100 px-1.5 py-0.5 rounded text-slate-400 font-black">{item.inventoryUID}</span>
                    <div>
                      <p className="font-bold text-slate-900">{item.name}</p>
                      <p className="text-xs text-slate-500 font-medium uppercase tracking-wider">{item.itemCode} • {item.location}</p>
                    </div>
                  </div>
                  <div className="flex flex-col items-end">
                    <div className="text-lg font-black text-slate-700">{item.quantity}</div>
                    {canViewPrices(currentUser) && (
                      <div className="text-[10px] font-bold text-slate-400 italic">${item.price.toFixed(2)} / unit</div>
                    )}
                  </div>
                </div>
              ))}
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-4 lg:space-y-6 pb-20">
      <h2 className="text-xl lg:text-2xl font-bold text-slate-800 px-1">Inventory Management</h2>

      <div className="flex p-1 bg-slate-200/50 rounded-2xl">
          <button 
            onClick={() => setActiveTab('existing')}
            className={`flex-1 py-3 px-2 font-bold text-xs lg:text-sm rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}
          >
              Adjust Existing Stock
          </button>
          {canRegisterNew && (
            <button 
                onClick={() => setActiveTab('new')}
                className={`flex-1 py-3 px-2 font-bold text-xs lg:text-sm rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}
            >
                Register New Item
            </button>
          )}
      </div>

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                        type="text" 
                        placeholder="Search by UID, Code, or Name..." 
                        className="w-full pl-12 pr-4 py-4 border border-slate-300 rounded-2xl text-base text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <div className="bg-white rounded-2xl border border-slate-200 max-h-[400px] lg:max-h-[700px] overflow-y-auto divide-y divide-slate-50 shadow-sm">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)}
                            className={`p-4 cursor-pointer active:bg-slate-100 transition-colors ${selectedItem?.id === item.id ? 'bg-blue-50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div className="flex items-center gap-2">
                                <span className="font-mono text-[10px] bg-blue-100/50 text-blue-600 px-1.5 py-0.5 rounded font-black">{item.inventoryUID}</span>
                                <div className="font-bold text-slate-800">{item.name}</div>
                              </div>
                              <div className="text-[10px] text-slate-400 uppercase font-bold mt-0.5 tracking-widest ml-[56px]">{item.itemCode} • PN: {item.partNumber}</div>
                              <div className="text-xs font-bold text-blue-600 mt-1 ml-[56px]">Current Stock: {item.quantity}</div>
                          </div>
                      ))}
                      {filteredItems.length === 0 && (
                        <div className="p-8 text-center text-slate-400 text-sm">No items matching your search.</div>
                      )}
                  </div>
              </div>

              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-fit lg:sticky lg:top-4">
                  <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <Plus className="w-5 h-5 text-blue-600" /> Stock Adjustment & Info
                  </h3>
                  {selectedItem ? (
                      <form onSubmit={handleStockSubmit} className="space-y-5">
                          <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                              <span className="text-[10px] font-bold text-slate-400 uppercase block mb-1 tracking-widest">Target Item ({selectedItem.inventoryUID})</span>
                              <span className="font-black text-slate-900 text-lg">{selectedItem.name}</span>
                          </div>

                          <div className="space-y-2">
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Update Technical Description</label>
                            <div className="relative">
                              <FileText className="absolute left-3 top-3 w-4 h-4 text-slate-400" />
                              <textarea 
                                placeholder="Edit technical specifications, dimensions, etc..." 
                                className="w-full border border-slate-300 rounded-xl pl-10 p-3 text-sm text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none transition-all min-h-[100px] bg-slate-50 focus:bg-white" 
                                value={addDescription} 
                                onChange={(e) => setAddDescription(e.target.value)} 
                              />
                            </div>
                          </div>

                          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Quantity to Add</label>
                                <input 
                                  type="number" 
                                  min="0" 
                                  required 
                                  className="w-full border border-slate-300 rounded-xl p-4 text-lg font-bold text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none bg-slate-50 focus:bg-white transition-all" 
                                  value={addQty === 0 ? '' : addQty} 
                                  onChange={(e) => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} 
                                  placeholder="0"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Internal Note / PO</label>
                                <input type="text" placeholder="Ref PO-8821" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 focus:ring-4 focus:ring-blue-500/10 outline-none bg-slate-50 focus:bg-white transition-all" value={addNote} onChange={(e) => setAddNote(e.target.value)} />
                            </div>
                          </div>

                          <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl active:scale-95 transition-all hover:bg-blue-700">
                              Confirm Adjustment
                          </button>
                      </form>
                  ) : (
                      <div className="text-center py-12">
                        <Package className="w-16 h-16 text-slate-100 mx-auto mb-4" />
                        <p className="text-sm text-slate-400 font-bold uppercase tracking-widest">Select an item from the list</p>
                      </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-6 lg:p-10 rounded-3xl shadow-sm border border-slate-200 max-w-3xl mx-auto">
              <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center gap-3">
                    <div className="w-12 h-12 bg-blue-100 rounded-2xl flex items-center justify-center">
                      <Plus className="w-6 h-6 text-blue-600" />
                    </div>
                    <div>
                      <h3 className="text-xl font-black text-slate-900">Register New Item</h3>
                      <p className="text-sm text-slate-500">Assigning unique inventory tracking code.</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] block mb-1">Generated ID</span>
                    <span className="inline-flex items-center px-3 py-1 bg-blue-600 text-white rounded-lg font-mono font-bold text-sm">
                      <Fingerprint className="w-4 h-4 mr-2" /> {previewUID}
                    </span>
                  </div>
              </div>

              <form onSubmit={handleCreateSubmit} className="space-y-6">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Item Code</label>
                          <input type="text" required placeholder="e.g. HYD-001" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Part Number</label>
                          <input type="text" required placeholder="Manufacturer PN" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                      </div>
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Full Item Name</label>
                      <input type="text" required placeholder="e.g. Caterpillar Hydraulic Seal" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Technical Description</label>
                      <textarea placeholder="Dimensions, material, or compatibility notes..." className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Warehouse Location</label>
                          <input type="text" required placeholder="e.g. Bin B4-12" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Inventory Category</label>
                          <input type="text" required placeholder="e.g. Hydraulics" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 lg:grid-cols-3 gap-6">
