export enum UserRole {
  STANDARD = 'Standard User',
  ADMIN_L1 = 'Admin Level 1',
  ADMIN_L2 = 'Super Admin',
  OWNER = 'Owner',
}

export enum RequestStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export enum RequestType {
  TAKE = 'Take',
  RETURN = 'Return'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  isSpecialAdmin?: boolean; // Can process requests like owner
}

export interface InventoryItem {
  id: string;
  inventoryUID: string; // Unique generated internal code (e.g. ST-0001)
  itemCode: string;
  name: string;
  description: string;
  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number; // Hidden from Standard users
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  requestUID: string; // Unique transaction number (e.g. REQ-1001)
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId?: string; // Optional for returns
  specificPurpose?: string; // Optional for returns
  status: RequestStatus;
  type: RequestType;
  isEmergency: boolean; // "Item Already Taken" (Only for Takes)
  timestamp: string;
  claimedBy?: string; // Admin ID
  verifiedBy?: string; // Admin ID
  processedBy?: string; // Owner/Special Admin ID
  returnCondition?: 'Good' | 'Damaged';
  referenceRequestUID?: string; // Linking a return to a specific Take request
}

export interface AuditLogEntry {
  id: string;
  timestamp: string;
  action: string;
  itemId: string;
  itemName: string;
  quantityChange: number;
  performedBy: string; // User Name
  details: string;
}

export interface PurchaseOrder {
  id: string;
  prNumber: string;
  prDate: string;
  poNumber: string;
  status: 'Draft' | 'Approved' | 'Ordered' | 'Received' | 'Closed';
  supplier: string;
  totalCost: number;
  date: string; // PO Creation Date
  receivedDate?: string;
}

import { InventoryItem, Request, RequestStatus, AuditLogEntry, User, UserRole } from '../types';

export const canViewPrices = (user: User): boolean => {
  // Everyone except Standard users can view prices, unless the user is a special admin
  return user.role !== UserRole.STANDARD || !!user.isSpecialAdmin;
};

// Only Owner and Special Admin can PROCESS (Final Deduct)
export const canProcessRequest = (user: User): boolean => {
  return user.role === UserRole.OWNER || !!user.isSpecialAdmin;
};

// Admin L1, Owner, Special Admin can CLAIM and VERIFY. 
// SUPER ADMIN (L2) CANNOT.
export const canVerifyRequest = (user: User): boolean => {
  return (user.role === UserRole.ADMIN_L1 || user.role === UserRole.OWNER || !!user.isSpecialAdmin) && user.role !== UserRole.ADMIN_L2;
};

// Admin L1, Owner, Special Admin can ADD STOCK/INVENTORY.
// SUPER ADMIN CANNOT (Read only).
export const canManageInventory = (user: User): boolean => {
    return (user.role === UserRole.ADMIN_L1 || user.role === UserRole.OWNER || !!user.isSpecialAdmin) && user.role !== UserRole.ADMIN_L2;
};

// Admin L1, Owner, Special Admin can REGISTER NEW ITEMS.
// SUPER ADMIN CANNOT.
export const canCreateNewItem = (user: User): boolean => {
    return (user.role === UserRole.ADMIN_L1 || user.role === UserRole.OWNER || !!user.isSpecialAdmin) && user.role !== UserRole.ADMIN_L2;
};

// Admin L1, Owner, Special Admin can PROCESS RETURNS.
// SUPER ADMIN CANNOT.
export const canProcessReturn = (user: User): boolean => {
    return (user.role === UserRole.ADMIN_L1 || user.role === UserRole.OWNER || !!user.isSpecialAdmin) && user.role !== UserRole.ADMIN_L2;
};

// Helper to generate IDs
export const generateId = () => Math.random().toString(36).substr(2, 9);

// Helper to generate Unique Inventory Internal Codes (ST-XXXX)
export const generateInventoryUID = (currentItems: InventoryItem[]) => {
  const existingUids = currentItems.map(item => item.inventoryUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/ST-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `ST-${nextNumber}`;
};

// Helper to generate Unique Request Internal Codes (REQ-XXXX)
export const generateRequestUID = (currentRequests: Request[]) => {
  const existingUids = currentRequests.map(req => req.requestUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/REQ-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `REQ-${nextNumber}`;
};

