                    </div>
                )}
            </div>
        )}

        {/* User History Section */}
        <div className="pt-8 border-t border-slate-200">
             <h2 className="text-xl font-bold text-slate-800 mb-4">
                 {isStandardUser ? 'My Request History' : 'Recent Completed History'}
             </h2>
             <div className="space-y-3">
                 {isStandardUser 
                    ? renderList(myRequests, "No history found.", false)
                    : renderList(requests.filter(r => r.status === RequestStatus.PROCESSED || r.status === RequestStatus.RETURNED).slice(0, 10), "No recent history.", false)
                 }
             </div>
        </div>
    </div>
  );
};

