interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

