                      {canViewThreshold(currentUser) && (
                        <div className="text-[10px] font-bold text-amber-600 uppercase tracking-tighter">Threshold: {item.minThreshold}</div>
                      )}
                      {canViewPrices(currentUser) && (
                        <div className="text-[10px] font-bold text-slate-400 italic">${item.price.toFixed(2)} / unit</div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
        </div>
    );
  }

  return (
