                      </div>
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Full Item Name</label>
                      <input type="text" required placeholder="e.g. Caterpillar Hydraulic Seal" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                      <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Technical Description</label>
                      <textarea placeholder="Dimensions, material, or compatibility notes..." className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Warehouse Location</label>
                          <input type="text" required placeholder="e.g. Bin B4-12" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Inventory Category</label>
                          <input type="text" required placeholder="e.g. Hydraulics" className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})} />
                      </div>
                  </div>
                  <div className="grid grid-cols-2 lg:grid-cols-3 gap-6">
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Opening Qty</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Min Alert Level</label>
                          <input type="number" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.minThreshold === 0 ? '' : newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: e.target.value === '' ? 0 : parseInt(e.target.value)})} />
                      </div>
                      <div className="col-span-2 lg:col-span-1 space-y-2">
                          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest">Unit Price ($)</label>
                          <input type="number" step="0.01" required className="w-full border border-slate-300 rounded-xl p-4 text-base text-slate-900 bg-slate-50 focus:bg-white transition-all outline-none focus:ring-4 focus:ring-blue-500/10" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: e.target.value === '' ? 0 : parseFloat(e.target.value)})} />
                      </div>
                  </div>
                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl mt-6 active:scale-[0.98] transition-all hover:bg-blue-700 flex items-center justify-center gap-3">
                      <Save className="w-5 h-5" /> Register Item Record
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

