                  />
                </th>
                <HeaderCell label="Inventory_ID" />
                <HeaderCell label="Item Code" />
                <HeaderCell label="Item Name" />
                <HeaderCell label="Item P/N" />
                <HeaderCell label="Location" />
                <HeaderCell label="Qty" />
                {canViewThreshold(currentUser) && <HeaderCell label="Min Level" />}
                {canViewPrices(currentUser) && <th className="px-4 py-3 border-r border-slate-400 font-bold text-slate-900 text-xs uppercase">Price</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredItems.map(item => (
                <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.has(item.id) ? 'bg-blue-50/50' : ''}`}>
                  <td className="px-4 py-4 border-r border-slate-100 text-center">
                    <input 
