                  </td>
                  <td className="px-4 py-4 font-mono text-blue-700 font-black border-r border-slate-100">{item.inventoryUID}</td>
                  <td className="px-4 py-4 text-slate-800 font-medium border-r border-slate-100">{item.itemCode}</td>
                  <td className="px-4 py-4 border-r border-slate-100">
                    <button 
                      onClick={() => openModal([item], 'info')}
                      className="font-bold text-slate-900 hover:text-blue-600 text-left hover:underline underline-offset-2 transition-all"
                    >
                      {item.name}
                    </button>
                    <div className="text-[10px] text-slate-400 truncate max-w-[150px]">{item.description}</div>
                  </td>
                  <td className="px-4 py-4 text-slate-700 border-r border-slate-100">{item.partNumber}</td>
                  <td className="px-4 py-4 text-slate-600 border-r border-slate-100 font-medium">{item.location}</td>
                  <td className="px-4 py-4 text-center border-r border-slate-100">
                    <span className={`inline-block px-2 py-1 rounded font-black ${item.quantity <= item.minThreshold ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-800'}`}>
                      {item.quantity}
                    </span>
                  </td>
                  {canViewThreshold(currentUser) && (
                    <td className="px-4 py-4 text-center border-r border-slate-100 text-slate-500 font-bold">
                      {item.minThreshold}
                    </td>
                  )}
                  {canViewPrices(currentUser) && <td className="px-4 py-4 border-r border-slate-100 font-bold text-slate-900">${item.price.toFixed(2)}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Mobile Cards */}
      <div className="lg:hidden space-y-3">
        {filteredItems.map(item => (
          <div 
            key={item.id} 
            onClick={() => toggleSelect(item.id)}
            className={`bg-white p-4 rounded-2xl shadow-sm border transition-all ${selectedIds.has(item.id) ? 'border-blue-500 ring-2 ring-blue-100 bg-blue-50/20' : 'border-slate-200'} space-y-3 relative`}
          >
            <div className="absolute top-4 right-4">
              <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all ${selectedIds.has(item.id) ? 'bg-blue-600 border-blue-600' : 'border-slate-300'}`}>
                {selectedIds.has(item.id) && <CheckCircle2 className="w-4 h-4 text-white" />}
              </div>
            </div>

            <div className="flex justify-between items-start">
              <div className="space-y-1">
                <div className="flex items-center gap-2">
                  <span className="inline-flex items-center px-2 py-0.5 rounded bg-blue-50 text-blue-700 text-[10px] font-black uppercase tracking-wider">
                    <Fingerprint className="w-3 h-3 mr-1" /> {item.inventoryUID}
                  </span>
                </div>
                <h3 className="font-bold text-slate-900 leading-tight">{item.name}</h3>
                <p className="text-xs text-slate-500">{item.itemCode} • PN: {item.partNumber}</p>
              </div>
              <div className="flex flex-col items-end gap-2 pr-8">
                <div className={`px-3 py-1 rounded-lg text-sm font-bold ${item.quantity <= item.minThreshold ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-700'}`}>
                  {item.quantity}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2 text-xs text-slate-600">
              <div className="flex items-center gap-1.5 bg-slate-50 p-2 rounded-lg">
                <MapPin className="w-3 h-3 text-slate-400" />
                <span className="font-bold">{item.location}</span>
              </div>
              <div className="flex items-center gap-1.5 bg-slate-50 p-2 rounded-lg">
                <Tag className="w-3 h-3 text-slate-400" />
                <span className="truncate">{item.category}</span>
              </div>
            </div>

            <div className="flex items-center justify-between pt-1">
              {canViewPrices(currentUser) && (
                <div className="text-sm font-black text-slate-800">
                  Cost: ${item.price.toFixed(2)}
                </div>
              )}
              {canViewThreshold(currentUser) && (
                <div className="text-[10px] font-bold text-slate-400 flex items-center gap-1">
                  <AlertCircle className="w-3 h-3" /> Min Alert: {item.minThreshold}
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {activeItems.length > 0 && (
