                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Warehouse Bin</label>
                      <span className="text-sm font-bold text-slate-800">{activeItems[0].location}</span>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                      <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block mb-0.5">Category</label>
                      <span className="text-sm font-bold text-slate-800">{activeItems[0].category}</span>
                    </div>
                    {canViewPrices(currentUser) && (
                      <div className="bg-blue-50 p-3 rounded-xl border border-blue-100">
                        <label className="text-[9px] font-bold text-blue-400 uppercase tracking-widest block mb-0.5">Unit Price</label>
                        <span className="text-sm font-bold text-blue-800">${activeItems[0].price.toFixed(2)}</span>
                      </div>
                    )}
                    {canViewThreshold(currentUser) && (
                      <div className="bg-amber-50 p-3 rounded-xl border border-amber-100">
                        <label className="text-[9px] font-bold text-amber-400 uppercase tracking-widest block mb-0.5">Re-order Level</label>
                        <span className="text-sm font-bold text-amber-800">{activeItems[0].minThreshold} units</span>
                      </div>
                    )}
                  </div>

                  <button 
                    onClick={() => setActiveItems([])}
                    className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl shadow-lg mt-2"
                  >
                    Close
                  </button>
               </div>
            ) : (
              <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto">
                  <div className="space-y-3">
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Quantities per Item</label>
                    <div className="space-y-2 max-h-[200px] overflow-y-auto border border-slate-100 rounded-xl bg-slate-50 p-2">
                        {activeItems.map(item => (
                           <div key={item.id} className="flex items-center justify-between p-2 bg-white rounded-lg border border-slate-100 shadow-sm">
                              <div className="flex-1 min-w-0 pr-4">
                                 <p className="text-xs font-bold text-slate-900 truncate">{item.name}</p>
                                 <p className="text-[10px] text-slate-400">Stock: {item.quantity}</p>
                              </div>
                              <input 
                                type="number" 
                                min="1" 
                                max={item.quantity} 
                                className="w-16 p-1 border border-slate-200 rounded text-center text-xs font-bold bg-slate-50"
                                value={reqQtyMap[item.id] || 1}
                                onChange={(e) => setReqQtyMap({...reqQtyMap, [item.id]: parseInt(e.target.value) || 1})}
                              />
                           </div>
                        ))}
                    </div>
                  </div>

                  <div className="space-y-4 pt-2">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-1">Work Purpose</label>
                        <select required className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-bold" value={reqPurpose} onChange={(e) => setReqPurpose(e.target.value)}>
                            <option value="">Select a purpose...</option>
                            {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-slate-700 mb-1 text-base">Specific Project Details</label>
                        <input type="text" required placeholder="e.g., Pump 3 maintenance" className="w-full border border-slate-300 rounded-xl p-3 bg-slate-50 text-slate-900 font-medium" value={reqSpecific} onChange={(e) => setReqSpecific(e.target.value)} />
                    </div>

                    <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
                        <label className="flex items-start gap-3 cursor-pointer">
                            <input type="checkbox" className="mt-1 w-5 h-5 text-amber-600 rounded-lg border-gray-300" checked={isEmergency} onChange={(e) => setIsEmergency(e.target.checked)} />
                            <div>
                                <span className="block text-sm font-black text-amber-800">Item(s) Already Taken</span>
                                <span className="block text-xs text-amber-700 font-medium">Mark as emergency pick-up for later verification.</span>
                            </div>
                        </label>
                    </div>
                  </div>

                  <div className="flex flex-col-reverse lg:flex-row gap-3 pt-4">
                      <button type="button" onClick={() => setActiveItems([])} className="w-full py-4 border border-slate-300 text-slate-700 font-bold rounded-xl active:bg-slate-50 transition-colors">Cancel</button>
                      <button type="submit" className="w-full py-4 text-white font-black rounded-xl shadow-lg transition-transform active:scale-95 bg-blue-600 hover:bg-blue-700">
                          Submit {activeItems.length > 1 ? 'Bulk ' : ''}Request
                      </button>
                  </div>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

