      {/* Modal */}
      {activeItems.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-end lg:items-center justify-center z-[100] p-0 lg:p-4 backdrop-blur-sm">
          <div className="bg-white rounded-t-3xl lg:rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in slide-in-from-bottom duration-300">
