            <div className={`p-6 border-b ${mode === 'request' ? 'border-slate-100' : 'border-blue-100 bg-blue-50/30'}`}>
                <div className="flex justify-between items-center">
                    <h3 className={`text-lg font-bold ${mode === 'request' ? 'text-slate-800' : 'text-blue-800'}`}>
                        {mode === 'request' ? (activeItems.length === 1 ? 'Request Item' : `Bulk Request (${activeItems.length} items)`) : 'Item Information'}
