                                        </span>
                                      </td>
                                      <td className="px-6 py-4 text-slate-600 font-medium">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600 truncate max-w-[150px]">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-black ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-400'}`}>
                                          {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs" title={log.details}>{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

import React from 'react';
import { InventoryItem, Request, RequestStatus, WorkPurpose, RequestType } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {
  // Filter for financial finalization events
  const processedTakes = requests.filter(r => r.status === RequestStatus.PROCESSED && r.type === RequestType.TAKE);
  const returnedItems = requests.filter(r => r.status === RequestStatus.RETURNED && r.type === RequestType.RETURN);

  // Calculate cost per purpose (Net: Takes - Returns)
  const costByPurposeData = purposes.map(purpose => {
    const totalTakes = processedTakes
      .filter(r => r.purposeId === purpose.id)
      .reduce((sum, r) => {
        const item = items.find(i => i.id === r.itemId);
        return sum + (item ? item.price * r.quantity : 0);
      }, 0);

    const totalReturns = returnedItems
      .filter(r => r.purposeId === purpose.id)
      .reduce((sum, r) => {
        const item = items.find(i => i.id === r.itemId);
        return sum + (item ? item.price * r.quantity : 0);
      }, 0);

    return { 
      name: purpose.title, 
      cost: Math.max(0, totalTakes - totalReturns),
      takes: totalTakes,
      returns: totalReturns
    };
  });

  const totalInventoryValue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const totalTakesValue = processedTakes.reduce((sum, r) => {
      const item = items.find(i => i.id === r.itemId);
      return sum + (item ? item.price * r.quantity : 0);
  }, 0);

  const totalReturnsValue = returnedItems.reduce((sum, r) => {
      const item = items.find(i => i.id === r.itemId);
      return sum + (item ? item.price * r.quantity : 0);
  }, 0);

  const totalSpent = totalTakesValue - totalReturnsValue;

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  return (
    <div className="space-y-4 lg:space-y-8 pb-10">
      <h2 className="text-xl lg:text-2xl font-bold text-slate-800 px-1">Financial Intelligence</h2>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Inventory Value</h3>
            <p className="text-2xl lg:text-3xl font-black text-slate-900 mt-1">${totalInventoryValue.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Net Expenditure</h3>
            <p className="text-2xl lg:text-3xl font-black text-blue-600 mt-1">${totalSpent.toLocaleString()}</p>
            <div className="mt-2 text-[10px] text-slate-500 font-bold flex items-center gap-2">
              <span className="text-green-600">-${totalReturnsValue.toLocaleString()} recovered</span>
            </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Returns Credit</h3>
            <p className="text-2xl lg:text-3xl font-black text-green-600 mt-1">${totalReturnsValue.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Takes Count</h3>
            <p className="text-2xl lg:text-3xl font-black text-purple-600 mt-1">{processedTakes.length}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 lg:gap-8">
        <div className="bg-white p-4 lg:p-8 rounded-2xl shadow-sm border border-slate-200 h-[400px]">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Allocation by Purpose (Net)</h3>
            <ResponsiveContainer width="100%" height="90%">
                <BarChart data={costByPurposeData} margin={{ top: 5, right: 30, left: 20, bottom: 60 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis dataKey="name" tick={{fontSize: 10}} interval={0} angle={-35} textAnchor="end" stroke="#94a3b8" />
                    <YAxis stroke="#94a3b8" tick={{fontSize: 10}} />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}} 
                      contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} 
                      formatter={(value: number) => [`$${value.toLocaleString()}`, 'Net Cost']}
                    />
                    <Bar dataKey="cost" fill="#3b82f6" radius={[6, 6, 0, 0]} />
                </BarChart>
            </ResponsiveContainer>
        </div>

        <div className="bg-white p-4 lg:p-8 rounded-2xl shadow-sm border border-slate-200 h-[400px]">
             <h3 className="text-lg font-bold text-slate-800 mb-6">Cost Distribution</h3>
             <ResponsiveContainer width="100%" height="90%">
                <PieChart>
                    <Pie
                        data={costByPurposeData.filter(d => d.cost > 0)}
                        cx="50%"
                        cy="45%"
                        innerRadius={60}
                        outerRadius={100}
                        paddingAngle={5}
                        dataKey="cost"
                    >
                        {costByPurposeData.filter(d => d.cost > 0).map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip formatter={(value: number) => [`$${value.toLocaleString()}`, 'Net Share']} />
                    <Legend verticalAlign="bottom" height={36} wrapperStyle={{fontSize: '12px', paddingTop: '20px'}} />
                </PieChart>
             </ResponsiveContainer>
        </div>
      </div>
