import React, { useState, useMemo } from 'react';
import { InventoryItem, Request, RequestStatus, WorkPurpose, RequestType } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { Filter, Calendar, ChevronDown, Landmark, TrendingUp, RefreshCw } from 'lucide-react';

interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {
  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 5 }, (_, i) => currentYear - i);
  const months = [
    { value: 0, label: 'January' },
    { value: 1, label: 'February' },
    { value: 2, label: 'March' },
    { value: 3, label: 'April' },
    { value: 4, label: 'May' },
    { value: 5, label: 'June' },
    { value: 6, label: 'July' },
    { value: 7, label: 'August' },
    { value: 8, label: 'September' },
    { value: 9, label: 'October' },
    { value: 10, label: 'November' },
    { value: 11, label: 'December' },
  ];

  // State for date filters
  const [fromYear, setFromYear] = useState<number>(currentYear);
  const [fromMonth, setFromMonth] = useState<number>(0); // Jan
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11); // Dec

  // Filter and Calculate Net Spending
  const filteredData = useMemo(() => {
    const startDate = new Date(fromYear, fromMonth, 1);
    const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);

    const processedTakes = requests.filter(r => {
      const date = new Date(r.timestamp);
      return r.status === RequestStatus.PROCESSED && 
             r.type === RequestType.TAKE &&
             date >= startDate && 
             date <= endDate;
    });

    const returnedItems = requests.filter(r => {
      const date = new Date(r.timestamp);
      return r.status === RequestStatus.RETURNED && 
             r.type === RequestType.RETURN &&
             date >= startDate && 
             date <= endDate;
    });

    const purposeCosts = purposes.map(purpose => {
      const takesVal = processedTakes
        .filter(r => r.purposeId === purpose.id)
        .reduce((sum, r) => {
          const item = items.find(i => i.id === r.itemId);
          return sum + (item ? item.price * r.quantity : 0);
        }, 0);

      const returnsVal = returnedItems
        .filter(r => r.purposeId === purpose.id)
        .reduce((sum, r) => {
          const item = items.find(i => i.id === r.itemId);
          return sum + (item ? item.price * r.quantity : 0);
        }, 0);

      return {
        name: purpose.title,
        cost: Math.max(0, takesVal - returnsVal),
        takes: takesVal,
        returns: returnsVal
      };
    });

    const totalTakesValue = processedTakes.reduce((sum, r) => {
      const item = items.find(i => i.id === r.itemId);
      return sum + (item ? item.price * r.quantity : 0);
    }, 0);

    const totalReturnsValue = returnedItems.reduce((sum, r) => {
      const item = items.find(i => i.id === r.itemId);
      return sum + (item ? item.price * r.quantity : 0);
    }, 0);

    return {
      purposeCosts,
      totalTakesValue,
      totalReturnsValue,
      totalSpent: totalTakesValue - totalReturnsValue,
      takesCount: processedTakes.length
    };
  }, [fromYear, fromMonth, toYear, toMonth, requests, items, purposes]);

  const totalInventoryValue = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  const SelectGroup = ({ label, yearValue, yearSetter, monthValue, monthSetter }: any) => (
    <div className="space-y-1.5 flex-1 min-w-[140px]">
      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</label>
      <div className="flex gap-2">
        <div className="relative flex-1">
          <select 
            value={monthValue} 
            onChange={(e) => monthSetter(parseInt(e.target.value))}
            className="w-full pl-3 pr-8 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
          >
            {months.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
          </select>
          <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative w-24">
          <select 
            value={yearValue} 
            onChange={(e) => yearSetter(parseInt(e.target.value))}
            className="w-full pl-3 pr-8 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
          >
            {years.map(y => <option key={y} value={y}>{y}</option>)}
          </select>
          <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 lg:space-y-8 pb-10">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-1">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Financial Intelligence</h2>
          <p className="text-sm text-slate-500">Expenditure tracking and project allocation.</p>
        </div>
        <div className="bg-blue-600 text-white px-4 py-2 rounded-xl text-xs font-bold shadow-lg flex items-center gap-2">
          <RefreshCw className="w-3 h-3" /> Auto-Updating
        </div>
      </div>

      {/* Date Range Selection Bar */}
      <div className="bg-white p-4 lg:p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden relative">
        <div className="absolute top-0 left-0 w-1 h-full bg-blue-600"></div>
        <div className="flex items-center gap-2 mb-4">
          <Filter className="w-4 h-4 text-blue-600" />
          <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest">Select Financial Period</h3>
        </div>
        <div className="flex flex-wrap gap-6 items-end">
          <SelectGroup 
            label="From Period" 
            yearValue={fromYear} 
            yearSetter={setFromYear} 
            monthValue={fromMonth} 
            monthSetter={setFromMonth} 
          />
          <div className="hidden md:flex items-center pb-3 text-slate-300">
             <div className="w-8 h-[2px] bg-slate-100"></div>
          </div>
          <SelectGroup 
            label="To Period" 
            yearValue={toYear} 
            yearSetter={setToYear} 
            monthValue={toMonth} 
            monthSetter={setToMonth} 
          />
          <div className="flex items-center gap-2 bg-blue-50 px-4 py-2 rounded-xl border border-blue-100 flex-1 sm:flex-none">
             <Calendar className="w-4 h-4 text-blue-500" />
             <span className="text-xs font-bold text-blue-700 whitespace-nowrap">
               {months[fromMonth].label} {fromYear} — {months[toMonth].label} {toYear}
             </span>
          </div>
