import React, { useState, useMemo } from 'react';
import { PurchaseOrder } from '../types';
import { FileSpreadsheet, RefreshCw, Calendar, Tag, Filter, X, ChevronDown } from 'lucide-react';

interface ProcurementTableProps {
  pos: PurchaseOrder[];
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos }) => {
  const [dateFrom, setDateFrom] = useState<string>(''); // Expected format: dd/mm/yyyy
  const [dateTo, setDateTo] = useState<string>('');     // Expected format: dd/mm/yyyy
  const [filterTarget, setFilterTarget] = useState<'prDate' | 'receivedDate'>('prDate');

  // Helper to parse dd/mm/yyyy string to Date object
  const parseDate = (dmy: string): Date | null => {
    if (!dmy) return null;
    const parts = dmy.split('/');
    if (parts.length !== 3) return null;
    const d = parseInt(parts[0], 10);
    const m = parseInt(parts[1], 10) - 1;
    const y = parseInt(parts[2], 10);
    const date = new Date(y, m, d);
    return isNaN(date.getTime()) ? null : date;
  };

  // Helper to format yyyy-mm-dd to dd/mm/yyyy for display
  const formatDateForDisplay = (dateStr: string): string => {
    if (!dateStr) return '-';
    // Handle both ISO and yyyy-mm-dd
    const datePart = dateStr.includes('T') ? dateStr.split('T')[0] : dateStr;
    const parts = datePart.split('-');
    if (parts.length !== 3) return dateStr;
    return `${parts[2]}/${parts[1]}/${parts[0]}`;
  };

  const filteredPos = useMemo(() => {
    const from = parseDate(dateFrom);
    const to = parseDate(dateTo);

    return pos.filter(po => {
      const targetDateStr = filterTarget === 'prDate' ? po.prDate : po.receivedDate;
      if (!targetDateStr) return false;

      const date = new Date(targetDateStr);

      if (from && date < from) return false;
      if (to) {
        // Set 'to' date to end of day for inclusive filtering
        const toEndOfDay = new Date(to);
        toEndOfDay.setHours(23, 59, 59, 999);
        if (date > toEndOfDay) return false;
      }

      return true;
    });
  }, [pos, dateFrom, dateTo, filterTarget]);

  const clearFilters = () => {
    setDateFrom('');
    setDateTo('');
  };

  // Basic auto-formatter for dd/mm/yyyy as user types
  const handleDateChange = (val: string, setter: (v: string) => void) => {
    let clean = val.replace(/[^\d]/g, '');
    if (clean.length > 8) clean = clean.slice(0, 8);

    let formatted = clean;
    if (clean.length > 2) {
      formatted = clean.slice(0, 2) + '/' + clean.slice(2);
    }
    if (clean.length > 4) {
      formatted = formatted.slice(0, 5) + '/' + clean.slice(4);
    }
    setter(formatted);
  };

  return (
    <div className="space-y-4 lg:space-y-6 pb-12">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
            <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Procurement (PR/PO)</h2>
            <p className="text-sm text-slate-500">Synced with Master Excel Tracker</p>
        </div>
        <button className="w-full lg:w-auto flex items-center justify-center px-4 py-3 bg-green-600 text-white font-bold rounded-xl hover:bg-green-700 shadow-lg transition-transform active:scale-95">
            <RefreshCw className="w-4 h-4 mr-2" /> Sync Records
        </button>
      </div>

      {/* Filter Bar with dd/mm/yyyy Text Inputs */}
      <div className="bg-white p-4 lg:p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
        <div className="flex items-center gap-2 mb-2">
          <Filter className="w-4 h-4 text-blue-600" />
          <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest">Filter Procurement Data</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
          <div className="space-y-1.5">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Filter By</label>
            <div className="relative">
              <select 
                value={filterTarget}
                onChange={(e) => setFilterTarget(e.target.value as any)}
                className="w-full pl-3 pr-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
              >
                <option value="prDate">PR Date</option>
                <option value="receivedDate">Received Date</option>
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">From (DD/MM/YYYY)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <input 
                type="text" 
                placeholder="DD/MM/YYYY"
                value={dateFrom}
                onChange={(e) => handleDateChange(e.target.value, setDateFrom)}
                className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none placeholder:text-slate-300"
              />
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">To (DD/MM/YYYY)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <input 
                type="text" 
                placeholder="DD/MM/YYYY"
                value={dateTo}
                onChange={(e) => handleDateChange(e.target.value, setDateTo)}
                className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none placeholder:text-slate-300"
              />
            </div>
          </div>

          <div className="flex gap-2">
            {(dateFrom || dateTo) && (
              <button 
                onClick={clearFilters}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 px-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors text-sm"
              >
                <X className="w-4 h-4" /> Clear
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 bg-green-50/50 border-b border-green-100 flex items-center justify-between">
            <span className="text-xs lg:text-sm text-green-800 font-bold flex items-center gap-2">
                <FileSpreadsheet className="w-4 h-4" /> Master_Procurement.xlsx
            </span>
            <span className="text-[10px] text-green-600 font-medium">Results: {filteredPos.length} records</span>
        </div>

        {/* Desktop Table View */}
        <div className="hidden lg:block overflow-x-auto">
            <table className="w-full text-left text-sm">
                <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                        <th className="px-6 py-4 font-semibold text-slate-700">PR Date</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">PR/PO #</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Supplier</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Status</th>
                        <th className="px-6 py-4 font-semibold text-slate-700">Received</th>
                        <th className="px-6 py-4 font-semibold text-slate-700 text-right">Cost</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                    {filteredPos.map(po => (
                        <tr key={po.id} className="hover:bg-slate-50 transition-colors">
                            <td className="px-6 py-4 text-slate-600 font-medium">{formatDateForDisplay(po.prDate)}</td>
                            <td className="px-6 py-4">
                                <div className="font-bold text-slate-800">{po.prNumber}</div>
                                <div className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">{po.poNumber || 'PO PENDING'}</div>
                            </td>
                            <td className="px-6 py-4 text-slate-600 font-medium">{po.supplier}</td>
                            <td className="px-6 py-4">
                                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider
                                    ${po.status === 'Received' ? 'bg-green-100 text-green-800 border border-green-200' : 
                                    po.status === 'Ordered' ? 'bg-blue-100 text-blue-800 border border-blue-200' : 'bg-slate-100 text-slate-600 border border-slate-200'}`}>
                                    {po.status}
                                </span>
                            </td>
                            <td className="px-6 py-4 text-slate-600 font-medium">{formatDateForDisplay(po.receivedDate || '')}</td>
                            <td className="px-6 py-4 text-right font-black text-slate-900">
                                {po.totalCost > 0 ? `$${po.totalCost.toLocaleString()}` : '-'}
                            </td>
                        </tr>
                    ))}
                    {filteredPos.length === 0 && (
                      <tr>
                        <td colSpan={6} className="px-6 py-20 text-center text-slate-400 italic">
                          No procurement records match the selected criteria.
                        </td>
                      </tr>
                    )}
                </tbody>
            </table>
        </div>

        {/* Mobile List View */}
        <div className="lg:hidden divide-y divide-slate-100">
            {filteredPos.map(po => (
                <div key={po.id} className="p-4 space-y-3 hover:bg-slate-50 transition-colors">
                    <div className="flex justify-between items-start">
                        <div>
                            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">PR Number</span>
                            <div className="font-black text-slate-900">{po.prNumber}</div>
                            {po.poNumber && <div className="text-[10px] font-bold text-blue-600">PO: {po.poNumber}</div>}
                        </div>
                        <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase border
                            ${po.status === 'Received' ? 'bg-green-100 text-green-800 border-green-200' : 'bg-blue-100 text-blue-800 border-blue-200'}`}>
                            {po.status}
                        </span>
                    </div>

                    <div className="grid grid-cols-2 gap-3 py-2 border-y border-slate-50">
                        <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-bold uppercase">
                                <Calendar className="w-3 h-3" /> PR Date
                            </div>
                            <div className="text-sm font-bold text-slate-700">{formatDateForDisplay(po.prDate)}</div>
                        </div>
                        <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-bold uppercase">
                                <Tag className="w-3 h-3" /> Cost
                            </div>
                            <div className="text-sm font-black text-slate-900">${po.totalCost.toLocaleString()}</div>
                        </div>
                    </div>

                    <div className="flex items-center justify-between text-xs">
                        <span className="text-slate-500">Supplier: <span className="font-bold text-slate-700">{po.supplier}</span></span>
                        {po.receivedDate && <span className="text-green-600 font-black">Rec: {formatDateForDisplay(po.receivedDate)}</span>}
                    </div>
                </div>
            ))}
            {filteredPos.length === 0 && (
              <div className="p-10 text-center text-slate-400 text-sm italic">
                No matching procurement records found.
              </div>
            )}
        </div>
      </div>
    </div>
  );
};

