  onDeleteUser: (id: string, reason: string) => void;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ users, currentUser, onAddUser, onUpdateUser, onDeleteUser }) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Modals
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deletingUser, setDeletingUser] = useState<User | null>(null);

  // Form States
  const [userName, setUserName] = useState('');
  const [userCardNum, setUserCardNum] = useState('');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.STANDARD);
  const [isSpecial, setIsSpecial] = useState(false);
  const [deleteReason, setDeleteReason] = useState('');

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.recordCardNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.role.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [users, searchTerm]);

  const openAddModal = () => {
    setUserName('');
    setUserCardNum('');
    setUserRole(UserRole.STANDARD);
    setIsSpecial(false);
    setIsAddModalOpen(true);
  };

  const openEditModal = (user: User) => {
    setEditingUser(user);
    setUserName(user.name);
    setUserCardNum(user.recordCardNumber);
    setUserRole(user.role);
    setIsSpecial(!!user.isSpecialAdmin);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userName.trim() || !userCardNum.trim()) return;
    onAddUser({ name: userName, recordCardNumber: userCardNum, role: userRole, isSpecialAdmin: isSpecial });
    setIsAddModalOpen(false);
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      onUpdateUser({ ...editingUser, name: userName, recordCardNumber: userCardNum, role: userRole, isSpecialAdmin: isSpecial });
      setEditingUser(null);
    }
  };

  const handleDeleteSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (deletingUser && deleteReason.trim()) {
      onDeleteUser(deletingUser.id, deleteReason);
      setDeletingUser(null);
      setDeleteReason('');
    }
  };

  const getRoleBadge = (role: UserRole, special?: boolean) => {
    const baseClasses = "px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ";
    switch (role) {
      case UserRole.OWNER:
        return <span className={baseClasses + "bg-purple-100 text-purple-700 border-purple-200"}>Owner</span>;
      case UserRole.ADMIN_L2:
        return <span className={baseClasses + "bg-red-100 text-red-700 border-red-200"}>Super Admin</span>;
      case UserRole.ADMIN_L1:
        return (
          <div className="flex gap-1 items-center">
            <span className={baseClasses + "bg-blue-100 text-blue-700 border-blue-200"}>Admin L1</span>
            {special && <span className={baseClasses + "bg-amber-100 text-amber-700 border-amber-200"}>Special</span>}
          </div>
        );
      default:
        return <span className={baseClasses + "bg-slate-100 text-slate-600 border-slate-200"}>Standard</span>;
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800">User Management</h2>
          <p className="text-sm text-slate-500">Configure access control and authority levels.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-700 transition-transform active:scale-95"
        >
          <UserPlus className="w-5 h-5" /> Add New User
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by name, record card or role..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-6 py-4">User Details</th>
                <th className="px-6 py-4">Security Level</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredUsers.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                        {user.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900">{user.name}</p>
                        <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-medium">
                            <IdCard className="w-3 h-3" />
                            <span>Card: {user.recordCardNumber}</span>
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {getRoleBadge(user.role, user.isSpecialAdmin)}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => openEditModal(user)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit User"
                      >
                        <Edit3 className="w-5 h-5" />
                      </button>
                      {user.id !== currentUser.id && user.role !== UserRole.OWNER && (
                        <button 
                          onClick={() => {
                            setDeletingUser(user);
                            setDeleteReason('');
                          }}
                          className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                          title="Delete User"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredUsers.length === 0 && (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400 italic">No users found matching your search.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit User Modal */}
      {(isAddModalOpen || editingUser) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                {editingUser ? <Edit3 className="w-5 h-5 text-blue-600" /> : <UserPlus className="w-5 h-5 text-blue-600" />}
                {editingUser ? 'Edit User Security' : 'Create New User'}
              </h3>
              <button onClick={() => { setIsAddModalOpen(false); setEditingUser(null); }} className="text-slate-400 hover:text-slate-600">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={editingUser ? handleEditSubmit : handleAddSubmit} className="p-6 space-y-5">
              <div className="grid grid-cols-1 gap-5">
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Name</label>
                  <input 
                    type="text" 
                    required 
                    placeholder="e.g. Michael Smith"
                    className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm"
                    value={userName}
                    onChange={(e) => setUserName(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Record Card Number</label>
                  <div className="relative">
                    <IdCard className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="text" 
                      required 
                      placeholder="e.g. RC-5001"
                      className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm"
                      value={userCardNum}
                      onChange={(e) => setUserCardNum(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Assigned Role</label>
                <div className="relative">
                  <select 
                    value={userRole}
                    onChange={(e) => setUserRole(e.target.value as UserRole)}
                    className="w-full pl-4 pr-10 py-3.5 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none cursor-pointer bg-slate-50"
                  >
                    <option value={UserRole.STANDARD}>Standard User</option>
                    <option value={UserRole.ADMIN_L1}>Admin Level 1</option>
                    <option value={UserRole.ADMIN_L2}>Super Admin (L2)</option>
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                </div>
              </div>

              {userRole === UserRole.ADMIN_L1 && (
                <div className="bg-amber-50 border border-amber-100 rounded-2xl p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-xs font-black text-amber-800 flex items-center gap-2">
                        <ShieldAlert className="w-4 h-4" /> Special Admin Status
                      </p>
                      <p className="text-[10px] text-amber-600 font-medium">Grant "Owner-level" processing rights.</p>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                      <input 
                        type="checkbox" 
                        className="sr-only peer" 
                        checked={isSpecial}
                        onChange={(e) => setIsSpecial(e.target.checked)}
                      />
                      <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-amber-500"></div>
                    </label>
                  </div>
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => { setIsAddModalOpen(false); setEditingUser(null); }} 
                  className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  {editingUser ? 'Save Changes' : 'Create User'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-red-50">
              <h3 className="text-lg font-bold text-red-800 flex items-center gap-2">
                <Trash2 className="w-5 h-5" /> Terminate User Access
              </h3>
              <button onClick={() => setDeletingUser(null)} className="text-slate-400 hover:text-slate-600">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleDeleteSubmit} className="p-6 space-y-5">
              <div className="flex items-start gap-3 bg-red-50 p-4 rounded-2xl border border-red-100">
                 <AlertCircle className="w-5 h-5 text-red-600 shrink-0 mt-0.5" />
                 <div>
                    <p className="text-sm font-bold text-red-900">Confirm permanent deletion</p>
                    <p className="text-xs text-red-700 mt-1">You are about to remove <strong>{deletingUser.name}</strong> from the system. This action is recorded in the master audit trail.</p>
                 </div>
              </div>

              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Reason for Deletion</label>
                <textarea 
                  required 
                  autoFocus
                  placeholder="e.g. Employee resignation, role change, end of contract..."
                  className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-red-500/10 outline-none transition-all shadow-sm min-h-[100px]"
                  value={deleteReason}
                  onChange={(e) => setDeleteReason(e.target.value)}
                />
              </div>

              <div className="flex gap-3 pt-2">
                <button 
                  type="button" 
                  onClick={() => setDeletingUser(null)} 
                  className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-red-600 text-white font-black rounded-xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all active:scale-95"
                >
                  Confirm Delete
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManagementView;

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Box, FileText, BarChart3, Settings, ShieldCheck, LogOut, Truck, PackagePlus, Menu, X, Users, User as UserIcon } from 'lucide-react';

interface LayoutProps {
