  const isOwner = currentUser.role === UserRole.OWNER;
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;
  const isAdminL1 = currentUser.role === UserRole.ADMIN_L1;
  const isSpecialAdmin = !!currentUser.isSpecialAdmin;

  // Permission groups
  const canWriteInventory = isOwner || isAdminL1 || isSpecialAdmin;
  const hasAdminOversight = isOwner || isSuperAdmin || isSpecialAdmin;
  const hasMoveRequestAccess = isOwner || isSuperAdmin || isAdminL1 || isSpecialAdmin;

  return (
    <div className="flex flex-col h-screen bg-slate-50 overflow-hidden">
      {/* Mobile Header */}
      <header className="lg:hidden flex items-center justify-between px-4 py-3 bg-white border-b border-slate-200 sticky top-0 z-30">
