            {hasMoveRequestAccess && <NavItem view="movements" icon={Truck} label="Move Requests" />}

            {canWriteInventory && <NavItem view="add-inventory" icon={PackagePlus} label="Add Inventory" />}

            {hasAdminOversight && (
