                </button>
              </div>
            </aside>
          </div>
        )}

        {/* Main Content */}
        <main className="flex-1 overflow-auto p-4 lg:p-8 pb-20 lg:pb-8 relative">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </main>
      </div>

      {/* Mobile Bottom Navigation */}
      <nav className="lg:hidden flex border-t border-slate-200 bg-white fixed bottom-0 w-full z-40 px-2 py-1 safe-area-bottom">
        <button 
          onClick={() => onChangeView('inventory')}
          className={`flex-1 flex flex-col items-center py-2 px-1 ${currentView === 'inventory' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <Box className="w-6 h-6" />
          <span className="text-[10px] mt-1 font-medium">Inventory</span>
        </button>
        <button 
          onClick={() => onChangeView('requests')}
          className={`flex-1 flex flex-col items-center py-2 px-1 ${currentView === 'requests' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <FileText className="w-6 h-6" />
          <span className="text-[10px] mt-1 font-medium">Requests</span>
        </button>
        {canWriteInventory && (
          <button 
            onClick={() => onChangeView('add-inventory')}
            className={`flex-1 flex flex-col items-center py-2 px-1 ${currentView === 'add-inventory' ? 'text-blue-600' : 'text-slate-500'}`}
          >
            <PackagePlus className="w-6 h-6" />
            <span className="text-[10px] mt-1 font-medium">Add Stock</span>
          </button>
