        <button 
          onClick={() => setIsMobileMenuOpen(true)}
          className="flex-1 flex flex-col items-center py-2 px-1 text-slate-500"
        >
          <Menu className="w-6 h-6" />
          <span className="text-[10px] mt-1 font-medium">More</span>
        </button>
      </nav>
    </div>
  );
};

export default Layout;

