  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific} [${newRequest.requestUID}]`
    };
    setAuditLog(prev => [log, ...prev]);

    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    // Lookup original purpose from reference request to ensure financial accuracy
    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) {
        purposeId = originalReq.purposeId;
      }
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId, // Carrying over purpose for financial tracking
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason, // Reusing field for reason
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { 
            ...req, 
            status: RequestStatus.REJECTED, 
            rejectedBy: currentUser.id,
            rejectionReason: reason 
        } : req
    ));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_REJECTED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Rejected request ${request.requestUID}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE [${request.requestUID}]:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed take request ${request.requestUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      const newStatus = RequestStatus.RETURNED;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: newStatus, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          // Add back to stock
          setInventory(prev => prev.map(i => 
              i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i
          ));
      }

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: condition === 'Good' ? request.quantity : 0,
        performedBy: currentUser.name,
        details: `Return ${request.requestUID} accepted. Condition: ${condition}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    console.log("Manual adjust", itemId, newQty, reason);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    const logDetails = [];
    if (qty !== 0) logDetails.push(`Stock Adjusted: ${qty > 0 ? '+' : ''}${qty} (${note})`);
    if (newDescription !== undefined && newDescription !== item.description) logDetails.push('Technical description updated');
    if (newLocation !== undefined && newLocation !== item.location) logDetails.push(`Location moved from ${item.location} to ${newLocation}`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'INVENTORY_ADJUSTMENT',
        itemId: itemId,
        itemName: item.name,
        quantityChange: qty,
        performedBy: currentUser.name,
        details: logDetails.join('. ') || 'No significant changes recorded.'
    };
    setAuditLog(prev => [log, ...prev]);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'ITEM_CREATED',
        itemId: id,
        itemName: newItem.name,
        quantityChange: newItem.quantity,
        performedBy: currentUser.name,
        details: `New Item Created with UID ${inventoryUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- User Management ---
  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_CREATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Created new user ${user.name} (Role: ${user.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));

    // If the updated user is the current user, update the state to reflect changes immediately
    if (updatedUser.id === currentUser.id) {
        setCurrentUser(updatedUser);
    }

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_UPDATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Updated security settings for ${updatedUser.name} (${updatedUser.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    if (id === currentUser.id) {
        alert("Cannot delete the currently logged in user.");
        return;
    }
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;

    setUsers(prev => prev.filter(u => u.id !== id));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_DELETED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Deleted user ${targetUser.name}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
              onCreateItem={handleCreateItem}
          />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onReject={handleReject}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
            onInitiateReturnById={handleReturnItem}
        />
      )}

      {currentView === 'movements' && (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                    <Truck className="w-6 h-6 text-blue-600" /> Stock Movements
                </h2>
                {currentUser.role === UserRole.ADMIN_L2 && (
                    <span className="text-[10px] font-black bg-blue-100 text-blue-700 px-2 py-1 rounded uppercase tracking-widest">Read Only Mode</span>
                )}
            </div>
            <RequestQueue 
                requests={requests} // Ideally this would filter for only movement-type requests if they were defined
                items={inventory}
                currentUser={currentUser}
                onClaim={handleClaim}
                onVerify={handleVerify}
                onReject={handleReject}
                onProcess={handleProcess}
                onReturnAction={handleReturnAction}
                onInitiateReturnById={handleReturnItem}
            />
        </div>
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'user-management' && (
        <UserManagementView 
          users={users} 
          currentUser={currentUser} 
          onAddUser={handleAddUser} 
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser} 
        />
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
                <button 
                  onClick={exportAuditLog}
                  className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <FileSpreadsheet className="w-4 h-4 text-green-400" /> Export CSV
                </button>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                      <td className="px-6 py-4 text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4">
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                                          log.action.includes('REJECTED') ? 'bg-red-100 text-red-700' :
                                          log.action.includes('CREATED') ? 'bg-blue-100 text-blue-700' :
                                          log.action.includes('DEDUCTED') ? 'bg-amber-100 text-amber-700' :
                                          'bg-slate-100 text-slate-700'
                                        }`}>
                                          {log.action.replace(/_/g, ' ')}
                                        </span>
                                      </td>
                                      <td className="px-6 py-4 text-slate-600 font-medium">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600 truncate max-w-[150px]">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-black ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-400'}`}>
                                          {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs" title={log.details}>{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Request, RequestStatus, User, UserRole, InventoryItem, RequestType } from '../types';
import { canVerifyRequest, canProcessRequest, canProcessReturn } from '../services/stateService';
import { CheckCircle2, Clock, AlertTriangle, UserCheck, FileCheck, XCircle, RotateCcw, ThumbsUp, ThumbsDown, Search, ArrowRight, X, Filter, History, ChevronDown } from 'lucide-react';

interface RequestQueueProps {
  requests: Request[];
  items: InventoryItem[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onReject: (reqId: string, reason: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
  onInitiateReturnById: (itemId: string, qty: number, reason: string, refUID: string) => void;
}

const StatusBadge = ({ status, emergency, type }: { status: RequestStatus, emergency: boolean, type: RequestType }) => {
  if (type === RequestType.TAKE && emergency && status !== RequestStatus.PROCESSED) {
      return <span className="px-2 py-1 rounded text-xs font-bold bg-red-100 text-red-700 border border-red-200">ALREADY TAKEN</span>;
  }
  const styles = {
      [RequestStatus.PENDING]: 'bg-yellow-100 text-yellow-800',
      [RequestStatus.CLAIMED]: 'bg-blue-100 text-blue-800',
      [RequestStatus.VERIFIED]: 'bg-purple-100 text-purple-800',
      [RequestStatus.PROCESSED]: 'bg-green-100 text-green-800',
      [RequestStatus.REJECTED]: 'bg-red-100 text-red-800',
      [RequestStatus.RETURNED]: 'bg-indigo-100 text-indigo-800',
  };
  return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${styles[status] || 'bg-gray-100'}`}>{status}</span>;
};

interface RequestCardProps {
  req: Request;
  showActions: boolean;
  items: InventoryItem[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onRejectTrigger: (reqId: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
}

const RequestCard: React.FC<RequestCardProps> = ({ 
  req, showActions, items, currentUser, onClaim, onVerify, onRejectTrigger, onProcess, onReturnAction 
}) => {
  const item = items.find(i => i.id === req.itemId);

  // Permissions
  const isTake = req.type === RequestType.TAKE;

  // Take Permissions
  const canClaim = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.PENDING;
  const canVerify = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id;
  const canProcess = isTake && canProcessRequest(currentUser) && req.status === RequestStatus.VERIFIED;
  const canReject = isTake && canVerifyRequest(currentUser) && (req.status === RequestStatus.PENDING || (req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id));

  // Return Permissions
  const canActionReturn = !isTake && canProcessReturn(currentUser) && req.status === RequestStatus.PENDING;

  return (
      <div className={`p-4 rounded-lg border shadow-sm flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between transition-all ${req.type === RequestType.RETURN ? 'bg-indigo-50 border-indigo-100' : (req.status === RequestStatus.REJECTED ? 'bg-red-50 border-red-100 shadow-inner' : 'bg-white border-slate-200 hover:border-slate-300')}`}>
          <div className="flex-1">
              <div className="flex items-center gap-3 mb-1">
                  <span className="font-mono text-[10px] bg-slate-100 px-1.5 py-0.5 rounded font-black text-slate-500">{req.requestUID}</span>
                  {req.type === RequestType.RETURN && <RotateCcw className="w-3 h-3 text-indigo-600" />}
                  <span className="font-bold text-slate-800">{item?.name || 'Unknown Item'}</span>
                  <span className="text-xs text-slate-500">Qty: {req.quantity}</span>
                  <StatusBadge status={req.status} emergency={req.isEmergency} type={req.type} />
              </div>
              <div className="text-sm text-slate-600">
                  <span className="font-semibold text-slate-700">{req.userName}</span> 
                  {req.specificPurpose ? ` • ${req.specificPurpose}` : ''}
                  {req.referenceRequestUID && <span className="text-xs text-indigo-600 font-bold ml-2">(Ref Take: {req.referenceRequestUID})</span>}
              </div>
              <div className="text-xs text-slate-400 mt-1">
                  {req.type === RequestType.TAKE ? 'Requested' : 'Return Initiated'}: {new Date(req.timestamp).toLocaleString()}
              </div>
              {req.claimedBy && <div className="text-xs text-blue-600 mt-1">Claimed by Admin ID: {req.claimedBy}</div>}
              {req.returnCondition && <div className="text-xs font-bold mt-1 text-slate-700">Condition: {req.returnCondition}</div>}
              {req.status === RequestStatus.REJECTED && req.rejectionReason && (
                <div className="mt-3 p-3 bg-red-100/40 rounded-xl text-xs text-red-700 font-medium border border-red-100 flex gap-2 items-start">
                   <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
                   <div>
                    <span className="font-bold uppercase tracking-tight text-[10px] block mb-0.5">Rejection Reason:</span>
                    {req.rejectionReason}
                   </div>
                </div>
              )}
          </div>

          {showActions && (
              <div className="flex gap-2 flex-wrap sm:flex-nowrap">
                  {/* Take Actions */}
                  {canClaim && (
                      <button onClick={() => onClaim(req.id)} className="flex items-center px-3 py-1.5 bg-blue-600 text-white text-sm font-medium rounded hover:bg-blue-700">
                          <UserCheck className="w-4 h-4 mr-2" /> Claim
                      </button>
                  )}
                  {canVerify && (
                      <button onClick={() => onVerify(req.id)} className="flex items-center px-3 py-1.5 bg-purple-600 text-white text-sm font-medium rounded hover:bg-purple-700">
                          <FileCheck className="w-4 h-4 mr-2" /> Verify
                      </button>
                  )}
                  {canProcess && (
                      <button onClick={() => onProcess(req.id)} className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700">
                          <CheckCircle2 className="w-4 h-4 mr-2" /> Process & Sign
                      </button>
                  )}
                  {canReject && (
                      <button onClick={() => onRejectTrigger(req.id)} className="flex items-center px-3 py-1.5 bg-red-50 text-red-600 text-sm font-medium rounded hover:bg-red-100 border border-red-200">
                          <XCircle className="w-4 h-4 mr-2" /> Reject
                      </button>
                  )}

                  {/* Return Actions */}
                  {canActionReturn && (
                      <div className="flex gap-2">
                           <button onClick={() => onReturnAction(req.id, 'Good')} className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700" title="Return to Stock">
                              <ThumbsUp className="w-4 h-4 mr-2" /> Good
                          </button>
                          <button onClick={() => onReturnAction(req.id, 'Damaged')} className="flex items-center px-3 py-1.5 bg-amber-600 text-white text-sm font-medium rounded hover:bg-amber-700" title="Mark Damaged">
                              <ThumbsDown className="w-4 h-4 mr-2" /> Damaged
                          </button>
                      </div>
                  )}
              </div>
          )}
      </div>
  );
};

const RequestQueue: React.FC<RequestQueueProps> = ({ 
    requests, items, currentUser, onClaim, onVerify, onReject, onProcess, onReturnAction, onInitiateReturnById
}) => {

  const [tab, setTab] = useState<'take' | 'return'>('take');
  const [searchUID, setSearchUID] = useState('');
  const [returnMsg, setReturnMsg] = useState('');
  const [returnQty, setReturnQty] = useState<number | ''>('');

  // Rejection Dialog State
  const [rejectingReqId, setRejectingReqId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  // History Filtering
  const [historyTypeFilter, setHistoryTypeFilter] = useState<'all' | 'take' | 'return'>('all');
  const [historyStatusFilter, setHistoryStatusFilter] = useState<'all' | 'processed' | 'rejected' | 'returned'>('all');

  // Filter logic
  const isStandardUser = currentUser.role === UserRole.STANDARD;
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;

  const myRequests = useMemo(() => {
    return requests.filter(r => r.userId === currentUser.id);
  }, [requests, currentUser.id]);

  const filteredHistory = useMemo(() => {
    const base = isStandardUser 
      ? myRequests 
      : requests.filter(r => r.status === RequestStatus.PROCESSED || r.status === RequestStatus.RETURNED || r.status === RequestStatus.REJECTED);

    return base.filter(r => {
      const typeMatch = historyTypeFilter === 'all' || r.type.toLowerCase() === historyTypeFilter;
      const statusMatch = historyStatusFilter === 'all' || r.status.toLowerCase() === historyStatusFilter;
      return typeMatch && statusMatch;
    }).slice(0, 30);
  }, [requests, myRequests, isStandardUser, historyTypeFilter, historyStatusFilter]);

  const takeRequests = requests.filter(r => r.type === RequestType.TAKE);
  const returnRequests = requests.filter(r => r.type === RequestType.RETURN);

  // Take Filtering
  const pendingRequests = takeRequests.filter(r => r.status === RequestStatus.PENDING);
  const claimedRequests = takeRequests.filter(r => r.status === RequestStatus.CLAIMED);
  const verifiedRequests = takeRequests.filter(r => r.status === RequestStatus.VERIFIED);

  // Return Filtering (Active)
  const pendingReturns = returnRequests.filter(r => r.status === RequestStatus.PENDING);

  const handleReturnById = (e: React.FormEvent) => {
    e.preventDefault();
    const target = requests.find(r => r.requestUID === searchUID && r.type === RequestType.TAKE);
    if (!target) {
        alert("Request ID not found or is not a Take request.");
        return;
    }
    if (target.status !== RequestStatus.PROCESSED) {
        alert("This request has not been fully processed yet.");
        return;
    }

    onInitiateReturnById(target.itemId, returnQty || target.quantity, returnMsg || "Returning via ID lookup", target.requestUID);
    setSearchUID('');
    setReturnMsg('');
    setReturnQty('');
  };

  const handleConfirmReject = (e: React.FormEvent) => {
    e.preventDefault();
    if (rejectingReqId && rejectionReason.trim()) {
        onReject(rejectingReqId, rejectionReason);
        setRejectingReqId(null);
        setRejectionReason('');
    }
  };

  // Helper for rendering list
  const renderList = (list: Request[], emptyMsg: string, actions: boolean) => (
      <div className="space-y-3">
          {list.length === 0 && <p className="text-sm text-slate-500 italic py-4">{emptyMsg}</p>}
          {list.map(req => (
              <RequestCard 
                  key={req.id} 
                  req={req} 
                  showActions={actions}
                  items={items}
                  currentUser={currentUser}
                  onClaim={onClaim}
                  onVerify={onVerify}
                  onRejectTrigger={setRejectingReqId}
                  onProcess={onProcess}
                  onReturnAction={onReturnAction}
              />
          ))}
      </div>
  );

  return (
    <div className="space-y-8">

        {/* Quick Return Section - Hidden for Super Admins */}
        {!isSuperAdmin && (
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden relative">
              <div className="absolute top-0 left-0 w-1 h-full bg-blue-600"></div>
              <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest mb-4 flex items-center gap-2">
                  <RotateCcw className="w-4 h-4 text-blue-600" /> Quick Return via Request ID
              </h3>
              <form onSubmit={handleReturnById} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Request ID</label>
                      <input 
                          type="text" 
                          required 
                          placeholder="e.g. REQ-1001" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none" 
                          value={searchUID}
                          onChange={(e) => setSearchUID(e.target.value.toUpperCase())}
                      />
                  </div>
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Qty to Return</label>
                      <input 
                          type="number" 
                          placeholder="Max" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm outline-none" 
                          value={returnQty}
                          onChange={(e) => setReturnQty(e.target.value === '' ? '' : parseInt(e.target.value))}
                      />
                  </div>
                  <div className="md:col-span-1">
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Condition Note</label>
                      <input 
                          type="text" 
                          placeholder="e.g. Unused" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm outline-none" 
                          value={returnMsg}
                          onChange={(e) => setReturnMsg(e.target.value)}
                      />
                  </div>
                  <button type="submit" className="bg-blue-600 text-white font-bold py-2.5 px-4 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 text-sm shadow-sm">
                      <ArrowRight className="w-4 h-4" /> Initiate Return
                  </button>
              </form>
          </div>
        )}

        {/* Admin Queue Section */}
        {!isStandardUser && (
            <div className="space-y-6">
                <div className="flex items-center justify-between">
                    <h2 className="text-2xl font-bold text-slate-800">
                        {isSuperAdmin ? 'Request Overview (Read Only)' : 'Approval Queue'}
                    </h2>
                    <div className="flex bg-slate-100 p-1 rounded-lg">
                        <button 
                            onClick={() => setTab('take')} 
                            className={`px-4 py-1.5 text-sm font-medium rounded-md transition-colors ${tab === 'take' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-600'}`}
                        >
                            Take Requests
                        </button>
                        <button 
                             onClick={() => setTab('return')} 
                             className={`px-4 py-1.5 text-sm font-medium rounded-md transition-colors ${tab === 'return' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-600'}`}
                        >
                            Returns {pendingReturns.length > 0 && `(${pendingReturns.length})`}
                        </button>
                    </div>
                </div>

                {tab === 'take' && (
                    <div className="animate-in fade-in duration-300 space-y-6">
                        {verifiedRequests.length > 0 && (
                            <div className="bg-green-50 rounded-xl p-4 border border-green-100">
                                <h3 className="text-sm font-bold text-green-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                                    <CheckCircle2 className="w-4 h-4" /> Ready for Processing
                                </h3>
                                {renderList(verifiedRequests, "No items ready for processing.", !isSuperAdmin)}
                            </div>
                        )}

                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                            <div className="bg-yellow-50 rounded-xl p-4 border border-yellow-100">
                                <h3 className="text-sm font-bold text-yellow-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                                    <Clock className="w-4 h-4" /> Pending Requests
                                </h3>
                                {renderList(pendingRequests, "No pending requests.", !isSuperAdmin)}
                            </div>

                            <div className="bg-blue-50 rounded-xl p-4 border border-blue-100">
                                <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                                    <UserCheck className="w-4 h-4" /> Claimed / In Progress
                                </h3>
                                {renderList(claimedRequests, "No claimed items.", !isSuperAdmin)}
                            </div>
                        </div>
                    </div>
                )}

                {tab === 'return' && (
                    <div className="animate-in fade-in duration-300 bg-indigo-50 rounded-xl p-4 border border-indigo-100">
                         <h3 className="text-sm font-bold text-indigo-800 uppercase tracking-wide mb-3 flex items-center gap-2">
                            <RotateCcw className="w-4 h-4" /> Returns Pending Acceptance
                        </h3>
                        {renderList(pendingReturns, "No pending returns.", !isSuperAdmin)}
                    </div>
                )}
            </div>
        )}

        {/* User History Section with Improved Filters */}
        <div className="pt-8 border-t border-slate-200">
             <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
                 <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                    <History className="w-5 h-5 text-slate-400" />
                    {isStandardUser ? 'My Request History' : 'Recent System History'}
                 </h2>

                 <div className="flex flex-wrap gap-2">
                    <div className="relative">
                        <select 
                          value={historyTypeFilter}
                          onChange={(e) => setHistoryTypeFilter(e.target.value as any)}
                          className="pl-3 pr-8 py-2 border border-slate-300 rounded-lg bg-white text-xs font-bold text-slate-600 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm"
                        >
                          <option value="all">All Types</option>
                          <option value="take">Takes Only</option>
                          <option value="return">Returns Only</option>
                        </select>
                        <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                    </div>

                    <div className="relative">
                        <select 
                          value={historyStatusFilter}
                          onChange={(e) => setHistoryStatusFilter(e.target.value as any)}
                          className="pl-3 pr-8 py-2 border border-slate-300 rounded-lg bg-white text-xs font-bold text-slate-600 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm"
                        >
                          <option value="all">All Statuses</option>
                          <option value="processed">Processed</option>
                          <option value="rejected">Rejected</option>
                          <option value="returned">Returned</option>
                        </select>
                        <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                    </div>
                 </div>
             </div>

             <div className="space-y-3">
                 {renderList(filteredHistory, "No records found matching your filters.", false)}
             </div>
        </div>

        {/* Rejection Modal */}
        {rejectingReqId && (
            <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
                <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-red-50">
                        <h3 className="text-lg font-bold text-red-800 flex items-center gap-2">
                            <XCircle className="w-5 h-5" /> Reject Request
                        </h3>
                        <button onClick={() => setRejectingReqId(null)} className="text-slate-400 hover:text-slate-600">
                            <X className="w-6 h-6" />
                        </button>
                    </div>
                    <form onSubmit={handleConfirmReject} className="p-6 space-y-4">
                        <p className="text-sm text-slate-600 leading-relaxed">Please provide a reason for rejecting request <strong>{requests.find(r => r.id === rejectingReqId)?.requestUID}</strong>. The user will see this in their history.</p>
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">Rejection Reason</label>
                            <textarea 
                                required 
                                autoFocus
                                placeholder="e.g. Purpose details insufficient, item needed for higher priority project..."
                                className="w-full border border-slate-300 rounded-xl p-3 text-sm focus:ring-4 focus:ring-red-500/10 outline-none min-h-[120px] shadow-inner"
                                value={rejectionReason}
                                onChange={(e) => setRejectionReason(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-3 pt-2">
                            <button 
                                type="button" 
                                onClick={() => setRejectingReqId(null)} 
                                className="flex-1 py-3 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit" 
                                className="flex-1 py-3 bg-red-600 text-white font-bold rounded-xl hover:bg-red-700 shadow-lg shadow-red-200 transition-all active:scale-95"
                            >
                                Confirm Rejection
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        )}
    </div>
  );
};

export default RequestQueue;

import React, { useState, useMemo } from 'react';
import { InventoryItem, User, UserRole, WorkPurpose } from '../types';
import { Search, Info, Box, MapPin, Tag, Fingerprint, X, AlertCircle, CheckCircle2, Filter, FileSpreadsheet, ChevronDown } from 'lucide-react';
import { canViewPrices, canViewThreshold } from '../services/stateService';

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, onRequestItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [activeItems, setActiveItems] = useState<InventoryItem[]>([]);
  const [mode, setMode] = useState<'request' | 'info'>('request');

  // Role checks
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;

  // Advanced Filters
  const [statusFilter, setStatusFilter] = useState<'all' | 'low' | 'out'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('All Categories');

  const [reqQtyMap, setReqQtyMap] = useState<Record<string, number>>({});
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);

  const categories = useMemo(() => {
    const cats = new Set(items.map(i => i.category));
    return ['All Categories', ...Array.from(cats)];
  }, [items]);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = (
        item.name.toLowerCase().includes(search) ||
        item.itemCode.toLowerCase().includes(search) ||
        item.partNumber.toLowerCase().includes(search) ||
        item.inventoryUID.toLowerCase().includes(search) ||
        item.description.toLowerCase().includes(search) ||
        item.location.toLowerCase().includes(search)
      );

      const matchesCategory = categoryFilter === 'All Categories' || item.category === categoryFilter;

      let matchesStatus = true;
      if (statusFilter === 'low') matchesStatus = item.quantity <= item.minThreshold && item.quantity > 0;
      if (statusFilter === 'out') matchesStatus = item.quantity === 0;

      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [items, searchTerm, categoryFilter, statusFilter]);

  const exportToExcel = () => {
    const headers = ["UID", "Code", "Name", "P/N", "Category", "Location", "Quantity", "Price"];
    const rows = filteredItems.map(i => [
      i.inventoryUID, i.itemCode, i.name, i.partNumber, i.category, i.location, i.quantity, i.price
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Inventory_Export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const toggleSelect = (id: string) => {
    if (isSuperAdmin) return; // Super Admins cannot select for requesting
    const newSelection = new Set(selectedIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedIds(newSelection);
  };

  const openModal = (itemsToAct: InventoryItem[], action: 'request' | 'info') => {
    // Force 'info' mode for Super Admins
    const finalAction = isSuperAdmin ? 'info' : action;
    setActiveItems(itemsToAct);
    setMode(finalAction);
    const initialQtys: Record<string, number> = {};
    itemsToAct.forEach(i => initialQtys[i.id] = 1);
    setReqQtyMap(initialQtys);
    resetFormFields();
  };

  const resetFormFields = () => {
    setReqPurpose('');
    setReqSpecific('');
    setIsEmergency(false);
  };

  const closeAndClear = () => {
    setActiveItems([]);
    setSelectedIds(new Set());
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isSuperAdmin) return;
    if (activeItems.length > 0) {
      activeItems.forEach(item => {
        const qty = reqQtyMap[item.id] || 1;
        onRequestItem(item.id, qty, reqPurpose, reqSpecific, isEmergency);
      });
      closeAndClear();
    }
  };

  const HeaderCell = ({ label, className = "" }: { label: string; className?: string }) => (
    <th className={`px-4 py-3 border-r border-slate-400 last:border-r-0 ${className}`}>
      <span className="font-bold text-slate-900 text-xs whitespace-nowrap uppercase">{label}</span>
    </th>
  );

  return (
    <div className="space-y-4 lg:space-y-6 pb-24">
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6">
        <div className="space-y-4 flex-1">
          <div>
              <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Inventory Dashboard</h2>
              <p className="text-sm text-slate-500">Secure track of industrial assets and procurement.</p>
          </div>

          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="UID, code, name, desc..." 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-base text-slate-900 shadow-sm transition-all"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="relative">
              <select 
                value={categoryFilter}
                onChange={(e) => setCategoryFilter(e.target.value)}
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 border border-slate-300 rounded-xl bg-white text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm cursor-pointer"
              >
                {categories.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
            <button 
              onClick={exportToExcel}
              className="flex items-center gap-2 px-4 py-2 bg-green-50 text-green-700 border border-green-200 rounded-xl text-xs font-bold hover:bg-green-100 transition-all"
            >
              <FileSpreadsheet className="w-4 h-4" /> Export CSV
            </button>
        </div>
      </div>

      {/* Stock Status Pills */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button 
            onClick={() => setStatusFilter('all')}
            className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'all' ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}
          >
            All Items ({items.length})
          </button>
          <button 
            onClick={() => setStatusFilter('low')}
            className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'low' ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}
          >
            Low Stock ({items.filter(i => i.quantity <= i.minThreshold && i.quantity > 0).length})
          </button>
          <button 
            onClick={() => setStatusFilter('out')}
            className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'out' ? 'bg-red-100 text-red-700 border-red-200' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}
          >
            Out of Stock ({items.filter(i => i.quantity === 0).length})
          </button>
      </div>

      {/* Selection Floating Bar - Hidden for Super Admins */}
      {selectedIds.size > 0 && !isSuperAdmin && (
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-[90%] max-w-2xl bg-slate-900 text-white rounded-2xl shadow-2xl p-4 flex items-center justify-between z-[60] animate-in slide-in-from-bottom duration-300">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center font-bold text-lg">
                {selectedIds.size}
             </div>
             <div>
                <p className="font-bold text-sm">Items Selected</p>
                <button onClick={() => setSelectedIds(new Set())} className="text-[10px] text-slate-400 hover:text-white uppercase font-black tracking-widest">Clear Selection</button>
             </div>
          </div>
          <div className="flex gap-2">
             {selectedIds.size === 1 && (
               <button 
                onClick={() => {
                  const item = items.find(i => i.id === Array.from(selectedIds)[0]);
                  if (item) openModal([item], 'info');
                }}
                className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-800 hover:bg-slate-700 font-bold text-sm transition-colors border border-slate-700"
               >
                 <Info className="w-4 h-4" /> Info
               </button>
             )}
             <button 
              onClick={() => {
                const selectedItems = items.filter(i => selectedIds.has(i.id));
                openModal(selectedItems, 'request');
              }}
              className="flex items-center gap-2 px-6 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 font-bold text-sm shadow-lg transition-transform active:scale-95"
             >
                Request Access
             </button>
          </div>
        </div>
      )}

      {/* Desktop Table */}
      <div className="hidden lg:block bg-white rounded-xl shadow-lg border border-slate-400 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-[#FFD966] border-b-2 border-slate-600">
              <tr>
                <th className="px-4 py-3 border-r border-slate-400 w-10 text-center"></th>
                <HeaderCell label="Inventory_ID" />
                <HeaderCell label="Item Code" />
                <HeaderCell label="Item Name" />
                <HeaderCell label="Item P/N" />
                <HeaderCell label="Location" />
                <HeaderCell label="Qty" />
                {canViewThreshold(currentUser) && <HeaderCell label="Min Level" />}
                {canViewPrices(currentUser) && <th className="px-4 py-3 border-r border-slate-400 font-bold text-slate-900 text-xs uppercase">Price</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredItems.map(item => (
                <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.has(item.id) && !isSuperAdmin ? 'bg-blue-50/50' : ''}`}>
                  <td className="px-4 py-4 border-r border-slate-100 text-center">
                    {!isSuperAdmin && (
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-0 cursor-pointer" 
                        checked={selectedIds.has(item.id)}
                        onChange={() => toggleSelect(item.id)}
                      />
                    )}
                  </td>
                  <td className="px-4 py-4 font-mono text-blue-700 font-black border-r border-slate-100">{item.inventoryUID}</td>
                  <td className="px-4 py-4 text-slate-800 font-medium border-r border-slate-100">{item.itemCode}</td>
                  <td className="px-4 py-4 border-r border-slate-100">
                    <button 
                      onClick={() => openModal([item], 'info')}
