};

export default InventoryView;

export enum UserRole {
  STANDARD = 'Standard User',
  ADMIN_L1 = 'Admin Level 1',
  ADMIN_L2 = 'Super Admin',
  OWNER = 'Owner',
}

export enum RequestStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export enum RequestType {
  TAKE = 'Take',
  RETURN = 'Return'
}

export interface User {
  id: string;
  name: string;
  recordCardNumber: string; // Unique employee card/record ID
  role: UserRole;
  isSpecialAdmin?: boolean; // Can process requests like owner
}

export interface InventoryItem {
  id: string;
  inventoryUID: string; // Unique generated internal code (e.g. ST-0001)
  itemCode: string;
  name: string;
  description: string;
  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number; // Hidden from Standard users
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  requestUID: string; // Unique transaction number (e.g. REQ-1001)
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId?: string; // Optional for returns
  specificPurpose?: string; // Optional for returns
  status: RequestStatus;
  type: RequestType;
  isEmergency: boolean; // "Item Already Taken" (Only for Takes)
  timestamp: string;
  claimedBy?: string; // Admin ID
  verifiedBy?: string; // Admin ID
  processedBy?: string; // Owner/Special Admin ID
  rejectedBy?: string; // Admin ID
  rejectionReason?: string;
  returnCondition?: 'Good' | 'Damaged';
  referenceRequestUID?: string; // Linking a return to a specific Take request
}

export interface Movement {
  id: string;
  itemUID: string;
  itemName: string;
  fromLocation: string;
  toLocation: string;
  quantity: number;
  movedBy: string;
  date: string;
  status: 'Draft' | 'In Transit' | 'Completed';
  sheetReference: string; // Reference to the external Excel/Google Sheet
}

export interface AuditLogEntry {
  id: string;
  timestamp: string;
  action: string;
  itemId: string;
  itemName: string;
  quantityChange: number;
  performedBy: string; // User Name
  details: string;
}

export interface PurchaseOrder {
  id: string;
  prNumber: string;
  prDate: string;
  poNumber: string;
  status: 'Draft' | 'Approved' | 'Ordered' | 'Received' | 'Closed';
  supplier: string;
  totalCost: number;
  date: string; // PO Creation Date
  receivedDate?: string;
}

