import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
