const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const handleSyncMovements = () => {
    alert("Syncing with Master Movements Google Sheet...\n\nUpdating records from external source.");
    // Simulate a sync by updating a record or adding a timestamp
    setMovements(prev => prev.map(m => m.id === 'mv2' ? { ...m, status: 'Completed' as const } : m));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'MOVEMENT_SYNC',
        itemId: 'N/A',
        itemName: 'Movements Sheet',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: 'Manual sync triggered with external Master Movements tracker.'
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific} [${newRequest.requestUID}]`
    };
    setAuditLog(prev => [log, ...prev]);

    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    // Lookup original purpose from reference request to ensure financial accuracy
    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) {
        purposeId = originalReq.purposeId;
      }
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId, // Carrying over purpose for financial tracking
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason, // Reusing field for reason
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { 
            ...req, 
            status: RequestStatus.REJECTED, 
            rejectedBy: currentUser.id,
            rejectionReason: reason 
        } : req
    ));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_REJECTED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Rejected request ${request.requestUID}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE [${request.requestUID}]:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed take request ${request.requestUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      const newStatus = RequestStatus.RETURNED;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: newStatus, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          // Add back to stock
          setInventory(prev => prev.map(i => 
              i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i
          ));
      }

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: condition === 'Good' ? request.quantity : 0,
        performedBy: currentUser.name,
        details: `Return ${request.requestUID} accepted. Condition: ${condition}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    console.log("Manual adjust", itemId, newQty, reason);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    const logDetails = [];
    if (qty !== 0) logDetails.push(`Stock Adjusted: ${qty > 0 ? '+' : ''}${qty} (${note})`);
    if (newDescription !== undefined && newDescription !== item.description) logDetails.push('Technical description updated');
    if (newLocation !== undefined && newLocation !== item.location) logDetails.push(`Location moved from ${item.location} to ${newLocation}`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'INVENTORY_ADJUSTMENT',
        itemId: itemId,
        itemName: item.name,
        quantityChange: qty,
        performedBy: currentUser.name,
        details: logDetails.join('. ') || 'No significant changes recorded.'
    };
    setAuditLog(prev => [log, ...prev]);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'ITEM_CREATED',
        itemId: id,
        itemName: newItem.name,
        quantityChange: newItem.quantity,
        performedBy: currentUser.name,
        details: `New Item Created with UID ${inventoryUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- User Management ---
  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_CREATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Created new user ${user.name} (Role: ${user.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));

    // If the updated user is the current user, update the state to reflect changes immediately
    if (updatedUser.id === currentUser.id) {
        setCurrentUser(updatedUser);
    }

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_UPDATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Updated security settings for ${updatedUser.name} (${updatedUser.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    if (id === currentUser.id) {
        alert("Cannot delete the currently logged in user.");
        return;
    }
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;

    setUsers(prev => prev.filter(u => u.id !== id));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_DELETED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Deleted user ${targetUser.name}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
              onCreateItem={handleCreateItem}
          />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onReject={handleReject}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
            onInitiateReturnById={handleReturnItem}
        />
      )}

      {currentView === 'movements' && (
        <MovementsView 
            movements={movements}
            currentUser={currentUser}
            onSync={handleSyncMovements}
        />
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'user-management' && (
        <UserManagementView 
          users={users} 
          currentUser={currentUser} 
          onAddUser={handleAddUser} 
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser} 
        />
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
                <button 
                  onClick={exportAuditLog}
                  className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <FileSpreadsheet className="w-4 h-4 text-green-400" /> Export CSV
                </button>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                      <td className="px-6 py-4 text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4">
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                                          log.action.includes('REJECTED') ? 'bg-red-100 text-red-700' :
                                          log.action.includes('CREATED') ? 'bg-blue-100 text-blue-700' :
                                          log.action.includes('DEDUCTED') ? 'bg-amber-100 text-amber-700' :
                                          'bg-slate-100 text-slate-700'
                                        }`}>
                                          {log.action.replace(/_/g, ' ')}
                                        </span>
                                      </td>
                                      <td className="px-6 py-4 text-slate-600 font-medium">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600 truncate max-w-[150px]">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-black ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-400'}`}>
                                          {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs" title={log.details}>{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

