  const isOwner = currentUser.role === UserRole.OWNER;
  const isSpecialAdmin = !!currentUser.isSpecialAdmin;
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;
  const canModify = isOwner || isSpecialAdmin;

  const filteredMovements = movements.filter(mv => 
    mv.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    mv.itemDescription.toLowerCase().includes(searchTerm.toLowerCase()) ||
    mv.moveOrderNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openCreateModal = () => {
    setEditingId(null);
    setForm({
      itemCode: '',
      itemDescription: '',
      requestedQty: 0,
      receivedQty: 0,
      location: '',
      createdBy: currentUser.name,
      createdDate: new Date().toISOString().split('T')[0],
      receivedDate: '-',
      moveOrderNumber: `MO-${Math.floor(1000 + Math.random() * 9000)}`,
      remarks: 'Not Completed'
    });
    setIsModalOpen(true);
  };

  const openEditModal = (mv: Movement) => {
    if (mv.remarks === 'Completed') return;
    setEditingId(mv.id);
    setForm({ ...mv });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      onUpdateMovement({ ...form, id: editingId });
    } else {
      onCreateMovement(form);
    }
    setIsModalOpen(false);
  };

  const getRemarkBadge = (remark: MovementRemark) => {
    const base = "px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ";
    switch (remark) {
      case 'Completed': return <span className={base + "bg-green-100 text-green-700"}>Completed</span>;
      case 'Out of Stock': return <span className={base + "bg-red-100 text-red-700"}>Out of Stock</span>;
      default: return <span className={base + "bg-amber-100 text-amber-700"}>Not Completed</span>;
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800 flex items-center gap-3">
            <Truck className="w-8 h-8 text-blue-600" /> Move Order Tracking
          </h2>
          <p className="text-sm text-slate-500">Standalone external tracking sync (Master_Movements.xlsx)</p>
        </div>

        <div className="flex gap-2 w-full lg:w-auto">
          {canModify && (
            <button 
              onClick={openCreateModal}
              className="flex-1 lg:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95 transition-all"
            >
              <Plus className="w-4 h-4" /> New Move Order
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by Code, Description, or Order #..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white px-4 py-2.5 rounded-xl border border-slate-100">
            <FileSpreadsheet className="w-4 h-4 text-green-500" /> Master_Movements.xlsx
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4">Item Code / Description</th>
                <th className="px-4 py-4">Qty (Req/Rec)</th>
                <th className="px-4 py-4">Location</th>
                <th className="px-4 py-4">Creation (By/Date)</th>
                <th className="px-4 py-4">Received Date</th>
                <th className="px-4 py-4">Order #</th>
                <th className="px-4 py-4">Remarks</th>
                {canModify && <th className="px-4 py-4 text-right">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredMovements.map(mv => (
                <tr key={mv.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-black text-blue-700 text-xs">{mv.itemCode}</span>
                      <span className="text-slate-600 text-xs truncate max-w-[150px]">{mv.itemDescription}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex items-center gap-2">
                       <span className="font-bold text-slate-800">{mv.requestedQty}</span>
                       <span className="text-slate-300">/</span>
                       <span className={`font-bold ${mv.receivedQty === mv.requestedQty ? 'text-green-600' : 'text-slate-400'}`}>{mv.receivedQty}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] font-bold text-slate-600">{mv.location}</span>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 text-xs">{mv.createdBy}</span>
                      <span className="text-slate-400 text-[10px]">{mv.createdDate}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4 font-medium text-slate-500 text-xs">{mv.receivedDate}</td>
                  <td className="px-4 py-4 font-mono font-black text-slate-900 text-xs">{mv.moveOrderNumber}</td>
                  <td className="px-4 py-4">{getRemarkBadge(mv.remarks)}</td>
                  {canModify && (
                    <td className="px-4 py-4 text-right">
                      {mv.remarks !== 'Completed' ? (
                        <button 
                          onClick={() => openEditModal(mv)}
                          className="p-2 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                          <Edit3 className="w-4 h-4" />
                        </button>
                      ) : (
                        <CheckCircle2 className="w-4 h-4 text-green-400 ml-auto mr-2" />
                      )}
                    </td>
                  )}
                </tr>
              ))}
              {filteredMovements.length === 0 && (
                <tr>
                  <td colSpan={canModify ? 8 : 7} className="px-6 py-20 text-center text-slate-400 font-medium italic">No tracking records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Standalone Tracking Note */}
      <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl flex items-start gap-4">
        <AlertTriangle className="w-6 h-6 text-amber-600 shrink-0 mt-1" />
        <div>
          <h4 className="font-bold text-amber-900">Important Operational Note</h4>
          <p className="text-sm text-amber-700 leading-relaxed mt-1">
            This module is for <strong>Tracking Only</strong>. Move orders entered here do not affect main warehouse inventory counts. Use this list to verify physical stock location changes against the master Excel tracker. Once a Move Order is marked <strong>Completed</strong>, it is locked for audit integrity.
          </p>
        </div>
      </div>

      {/* Create/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/50">
                  <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                    <Package className="w-5 h-5 text-blue-600" />
                    {editingId ? 'Edit Move Order' : 'Create New Move Order'}
                  </h3>
                  <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                    <X className="w-6 h-6" />
                  </button>
              </div>

              <form onSubmit={handleSubmit} className="p-6 space-y-5">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Item Code</label>
                        <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.itemCode} onChange={e => setForm({...form, itemCode: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Move Order Number</label>
                        <input type="text" readOnly className="w-full border border-slate-200 rounded-xl p-3.5 text-sm bg-slate-50 font-mono font-bold" value={form.moveOrderNumber} />
                      </div>
                  </div>

                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Item Description</label>
                    <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.itemDescription} onChange={e => setForm({...form, itemDescription: e.target.value})} />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Requested Qty</label>
                        <input type="number" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.requestedQty} onChange={e => setForm({...form, requestedQty: parseInt(e.target.value) || 0})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Qty</label>
                        <input type="number" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.receivedQty} onChange={e => setForm({...form, receivedQty: parseInt(e.target.value) || 0})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Location</label>
                        <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.location} onChange={e => setForm({...form, location: e.target.value})} />
                      </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Date</label>
                      <input type="text" placeholder="DD/MM/YYYY or '-'" className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.receivedDate} onChange={e => setForm({...form, receivedDate: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Remarks / Status</label>
                      <select className="w-full border border-slate-200 rounded-xl p-3.5 text-sm font-bold bg-slate-50 focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none" value={form.remarks} onChange={e => setForm({...form, remarks: e.target.value as MovementRemark})}>
                        <option value="Not Completed">Not Completed</option>
                        <option value="Completed">Completed</option>
                        <option value="Out of Stock">Out of Stock</option>
                      </select>
                    </div>
                  </div>

                  {form.remarks === 'Completed' && (
                    <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3">
                       <AlertTriangle className="w-5 h-5 text-red-600" />
                       <p className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Warning: Saving as 'Completed' will lock this record permanently.</p>
                    </div>
                  )}

                  <div className="flex gap-3 pt-4">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50">Cancel</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all">
                      {editingId ? 'Save Changes' : 'Create Record'}
                    </button>
                  </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default MovementsView;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import UserManagementView from './components/UserManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Truck } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'MOVEMENT_CREATED',
        itemId: 'N/A',
        itemName: mv.itemCode,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Standalone Move Order ${mv.moveOrderNumber} created.`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'MOVEMENT_UPDATED',
        itemId: 'N/A',
        itemName: mv.itemCode,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Move Order ${mv.moveOrderNumber} updated. Remark: ${mv.remarks}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific} [${newRequest.requestUID}]`
    };
    setAuditLog(prev => [log, ...prev]);

    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    // Lookup original purpose from reference request to ensure financial accuracy
    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) {
        purposeId = originalReq.purposeId;
      }
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId, // Carrying over purpose for financial tracking
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason, // Reusing field for reason
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { 
            ...req, 
            status: RequestStatus.REJECTED, 
            rejectedBy: currentUser.id,
            rejectionReason: reason 
        } : req
    ));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_REJECTED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Rejected request ${request.requestUID}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE [${request.requestUID}]:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed take request ${request.requestUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      const newStatus = RequestStatus.RETURNED;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: newStatus, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          // Add back to stock
          setInventory(prev => prev.map(i => 
              i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i
          ));
      }

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: condition === 'Good' ? request.quantity : 0,
        performedBy: currentUser.name,
        details: `Return ${request.requestUID} accepted. Condition: ${condition}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    console.log("Manual adjust", itemId, newQty, reason);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    const logDetails = [];
    if (qty !== 0) logDetails.push(`Stock Adjusted: ${qty > 0 ? '+' : ''}${qty} (${note})`);
    if (newDescription !== undefined && newDescription !== item.description) logDetails.push('Technical description updated');
    if (newLocation !== undefined && newLocation !== item.location) logDetails.push(`Location moved from ${item.location} to ${newLocation}`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'INVENTORY_ADJUSTMENT',
        itemId: itemId,
        itemName: item.name,
        quantityChange: qty,
        performedBy: currentUser.name,
        details: logDetails.join('. ') || 'No significant changes recorded.'
    };
    setAuditLog(prev => [log, ...prev]);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'ITEM_CREATED',
        itemId: id,
        itemName: newItem.name,
        quantityChange: newItem.quantity,
        performedBy: currentUser.name,
        details: `New Item Created with UID ${inventoryUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- User Management ---
  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_CREATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Created new user ${user.name} (Role: ${user.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));

    // If the updated user is the current user, update the state to reflect changes immediately
    if (updatedUser.id === currentUser.id) {
        setCurrentUser(updatedUser);
    }

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_UPDATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Updated security settings for ${updatedUser.name} (${updatedUser.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    if (id === currentUser.id) {
        alert("Cannot delete the currently logged in user.");
        return;
    }
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;

    setUsers(prev => prev.filter(u => u.id !== id));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_DELETED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Deleted user ${targetUser.name}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
              onCreateItem={handleCreateItem}
          />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onReject={handleReject}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
            onInitiateReturnById={handleReturnItem}
        />
      )}

      {currentView === 'movements' && (
        <MovementsView 
            movements={movements}
            currentUser={currentUser}
            onCreateMovement={handleCreateMovement}
            onUpdateMovement={handleUpdateMovement}
        />
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'user-management' && (
        <UserManagementView 
          users={users} 
          currentUser={currentUser} 
          onAddUser={handleAddUser} 
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser} 
        />
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
                <button 
                  onClick={exportAuditLog}
                  className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <FileSpreadsheet className="w-4 h-4 text-green-400" /> Export CSV
                </button>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                      <td className="px-6 py-4 text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4">
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                                          log.action.includes('REJECTED') ? 'bg-red-100 text-red-700' :
                                          log.action.includes('CREATED') ? 'bg-blue-100 text-blue-700' :
                                          log.action.includes('DEDUCTED') ? 'bg-amber-100 text-amber-700' :
                                          'bg-slate-100 text-slate-700'
                                        }`}>
                                          {log.action.replace(/_/g, ' ')}
                                        </span>
                                      </td>
                                      <td className="px-6 py-4 text-slate-600 font-medium">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600 truncate max-w-[150px]">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-black ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-400'}`}>
                                          {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs" title={log.details}>{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

