                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">General Store Location</label>
                        <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.location} onChange={e => setForm({...form, location: e.target.value})} />
                      </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Date</label>
                      <input type="text" placeholder="DD/MM/YYYY or '-'" className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.receivedDate} onChange={e => setForm({...form, receivedDate: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Remarks / Status</label>
                      <select className="w-full border border-slate-200 rounded-xl p-3.5 text-sm font-bold bg-slate-50 focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none" value={form.remarks} onChange={e => setForm({...form, remarks: e.target.value as MovementRemark})}>
                        <option value="Not Completed">Not Completed</option>
                        <option value="Completed">Completed</option>
                        <option value="Out of Stock">Out of Stock</option>
                      </select>
                    </div>
                  </div>

                  {form.remarks === 'Completed' && (
                    <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3">
                       <AlertTriangle className="w-5 h-5 text-red-600" />
                       <p className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Warning: Saving as 'Completed' will lock this record permanently.</p>
                    </div>
                  )}

                  <div className="flex gap-3 pt-4">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50">Cancel</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all">
                      {editingId ? 'Save Changes' : 'Create Record'}
                    </button>
                  </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

