    itemDescription: '',
    requestedQty: 0,
    receivedQty: 0,
    location: '',
    createdBy: currentUser.name,
    createdDate: new Date().toISOString().split('T')[0],
    receivedDate: '-',
    moveOrderNumber: '',
    remarks: 'Not Completed'
  });

  const [isOtherSelected, setIsOtherSelected] = useState(false);
  const [customRemark, setCustomRemark] = useState('');

  const isOwner = currentUser.role === UserRole.OWNER;
  const isSpecialAdmin = !!currentUser.isSpecialAdmin;
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;
  const canModify = isOwner || isSpecialAdmin;

  const standardRemarks = ['Completed', 'Not Completed', 'Out of Stock'];

  const filteredMovements = movements.filter(mv => 
    mv.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
    mv.itemDescription.toLowerCase().includes(searchTerm.toLowerCase()) ||
    mv.moveOrderNumber.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openCreateModal = () => {
    setEditingId(null);
    setIsOtherSelected(false);
    setCustomRemark('');
    setForm({
      itemCode: '',
      itemDescription: '',
      requestedQty: 0,
      receivedQty: 0,
      location: '',
      createdBy: currentUser.name,
      createdDate: new Date().toISOString().split('T')[0],
      receivedDate: '-',
      moveOrderNumber: `MO-${Math.floor(1000 + Math.random() * 9000)}`,
      remarks: 'Not Completed'
    });
    setIsModalOpen(true);
  };

  const openEditModal = (mv: Movement) => {
    if (mv.remarks === 'Completed') return;
    setEditingId(mv.id);
    setForm({ ...mv });

    if (!standardRemarks.includes(mv.remarks)) {
      setIsOtherSelected(true);
      setCustomRemark(mv.remarks);
    } else {
      setIsOtherSelected(false);
      setCustomRemark('');
    }

    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalRemarks = isOtherSelected ? customRemark : form.remarks;

    const payload = { ...form, remarks: finalRemarks || 'Not Completed' };

    if (editingId) {
      onUpdateMovement({ ...payload, id: editingId });
    } else {
      onCreateMovement(payload);
    }
    setIsModalOpen(false);
  };

  const getRemarkBadge = (remark: MovementRemark) => {
    const base = "px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ";
    switch (remark) {
      case 'Completed': return <span className={base + "bg-green-100 text-green-700"}>Completed</span>;
      case 'Out of Stock': return <span className={base + "bg-red-100 text-red-700"}>Out of Stock</span>;
      case 'Not Completed': return <span className={base + "bg-amber-100 text-amber-700"}>Not Completed</span>;
      default: return <span className={base + "bg-slate-100 text-slate-700 border border-slate-200"}>{remark}</span>;
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800 flex items-center gap-3">
            <Truck className="w-8 h-8 text-blue-600" /> Move Order Tracking
          </h2>
          <p className="text-sm text-slate-500">Standalone external tracking sync (Master_Movements.xlsx)</p>
        </div>

        <div className="flex gap-2 w-full lg:w-auto">
          {canModify && (
            <button 
              onClick={openCreateModal}
              className="flex-1 lg:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95 transition-all"
            >
              <Plus className="w-4 h-4" /> New Move Order
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by Code, Description, or Order #..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white px-4 py-2.5 rounded-xl border border-slate-100">
            <FileSpreadsheet className="w-4 h-4 text-green-500" /> Master_Movements.xlsx
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4">Item Code / Description</th>
                <th className="px-4 py-4">Qty (Req/Rec)</th>
                <th className="px-4 py-4">Location</th>
                <th className="px-4 py-4">Creation (By/Date)</th>
                <th className="px-4 py-4">Received Date</th>
                <th className="px-4 py-4">Order #</th>
                <th className="px-4 py-4">Remarks</th>
                {canModify && <th className="px-4 py-4 text-right">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredMovements.map(mv => (
                <tr key={mv.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-black text-blue-700 text-xs">{mv.itemCode}</span>
                      <span className="text-slate-600 text-xs truncate max-w-[150px]">{mv.itemDescription}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex items-center gap-2">
                       <span className="font-bold text-slate-800">{mv.requestedQty}</span>
                       <span className="text-slate-300">/</span>
                       <span className={`font-bold ${mv.receivedQty === mv.requestedQty ? 'text-green-600' : 'text-slate-400'}`}>{mv.receivedQty}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] font-bold text-slate-600">{mv.location}</span>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 text-xs">{mv.createdBy}</span>
                      <span className="text-slate-400 text-[10px]">{mv.createdDate}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4 font-medium text-slate-500 text-xs">{mv.receivedDate}</td>
                  <td className="px-4 py-4 font-mono font-black text-slate-900 text-xs">{mv.moveOrderNumber}</td>
                  <td className="px-4 py-4">{getRemarkBadge(mv.remarks)}</td>
                  {canModify && (
                    <td className="px-4 py-4 text-right">
                      {mv.remarks !== 'Completed' ? (
                        <button 
                          onClick={() => openEditModal(mv)}
                          className="p-2 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                          <Edit3 className="w-4 h-4" />
                        </button>
                      ) : (
                        <CheckCircle2 className="w-4 h-4 text-green-400 ml-auto mr-2" />
                      )}
                    </td>
                  )}
                </tr>
              ))}
              {filteredMovements.length === 0 && (
                <tr>
                  <td colSpan={canModify ? 8 : 7} className="px-6 py-20 text-center text-slate-400 font-medium italic">No tracking records found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Standalone Tracking Note */}
      <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl flex items-start gap-4">
        <AlertTriangle className="w-6 h-6 text-amber-600 shrink-0 mt-1" />
        <div>
          <h4 className="font-bold text-amber-900">Important Operational Note</h4>
          <p className="text-sm text-amber-700 leading-relaxed mt-1">
            This module is for <strong>Tracking Only</strong>. Move orders entered here do not affect main warehouse inventory counts. Use this list to verify physical stock location changes against the master Excel tracker. Once a Move Order is marked <strong>Completed</strong>, it is locked for audit integrity.
          </p>
        </div>
      </div>

      {/* Create/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
              <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/50">
                  <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                    <Package className="w-5 h-5 text-blue-600" />
                    {editingId ? 'Edit Move Order' : 'Create New Move Order'}
                  </h3>
                  <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                    <X className="w-6 h-6" />
                  </button>
              </div>

              <form onSubmit={handleSubmit} className="p-6 space-y-5">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Item Code</label>
                        <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.itemCode} onChange={e => setForm({...form, itemCode: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Move Order Number</label>
                        <input type="text" readOnly className="w-full border border-slate-200 rounded-xl p-3.5 text-sm bg-slate-50 font-mono font-bold" value={form.moveOrderNumber} />
                      </div>
                  </div>

                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Item Description</label>
                    <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.itemDescription} onChange={e => setForm({...form, itemDescription: e.target.value})} />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Requested Qty</label>
                        <input type="number" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.requestedQty} onChange={e => setForm({...form, requestedQty: parseInt(e.target.value) || 0})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Qty</label>
                        <input type="number" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.receivedQty} onChange={e => setForm({...form, receivedQty: parseInt(e.target.value) || 0})} />
                      </div>
                      <div className="space-y-2">
                        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">General Store Location</label>
                        <input type="text" required className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.location} onChange={e => setForm({...form, location: e.target.value})} />
                      </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Date</label>
                      <input type="text" placeholder="DD/MM/YYYY or '-'" className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none" value={form.receivedDate} onChange={e => setForm({...form, receivedDate: e.target.value})} />
                    </div>
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Remarks / Status</label>
                      <div className="relative">
                        <select 
                          className="w-full border border-slate-200 rounded-xl p-3.5 text-sm font-bold bg-slate-50 focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none" 
                          value={isOtherSelected ? 'Other' : form.remarks} 
                          onChange={e => {
                            if (e.target.value === 'Other') {
                              setIsOtherSelected(true);
                            } else {
                              setIsOtherSelected(false);
                              setForm({...form, remarks: e.target.value});
                            }
                          }}
                        >
                          <option value="Not Completed">Not Completed</option>
                          <option value="Completed">Completed</option>
                          <option value="Out of Stock">Out of Stock</option>
                          <option value="Other">Other (Manual Entry)</option>
                        </select>
                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                      </div>
                    </div>
                  </div>

                  {isOtherSelected && (
                    <div className="space-y-2 animate-in slide-in-from-top-1 duration-200">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Custom Remark</label>
                      <div className="relative">
                        <MessageSquare className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input 
                          type="text" 
                          required 
                          placeholder="Type your manual remark here..." 
                          className="w-full border border-slate-200 rounded-xl pl-10 p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none shadow-inner bg-blue-50/10" 
                          value={customRemark} 
                          onChange={e => setCustomRemark(e.target.value)} 
                        />
                      </div>
                    </div>
                  )}

                  {(form.remarks === 'Completed' || (isOtherSelected && customRemark === 'Completed')) && (
                    <div className="bg-red-50 border border-red-100 p-4 rounded-2xl flex items-center gap-3">
                       <AlertTriangle className="w-5 h-5 text-red-600" />
                       <p className="text-[10px] font-bold text-red-700 uppercase tracking-wider">Warning: Saving as 'Completed' will lock this record permanently.</p>
                    </div>
                  )}

                  <div className="flex gap-3 pt-4">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50">Cancel</button>
                    <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all">
                      {editingId ? 'Save Changes' : 'Create Record'}
                    </button>
                  </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default MovementsView;

export enum UserRole {
  STANDARD = 'Standard User',
  ADMIN_L1 = 'Admin Level 1',
  ADMIN_L2 = 'Super Admin',
  OWNER = 'Owner',
}

export enum RequestStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export enum RequestType {
  TAKE = 'Take',
  RETURN = 'Return'
}

export interface User {
  id: string;
  name: string;
  recordCardNumber: string;
  contactNumber: string;
  role: UserRole;
  isSpecialAdmin?: boolean;
}

export interface InventoryItem {
  id: string;
  inventoryUID: string;
  itemCode: string;
  name: string;
  description: string;
  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number;
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  requestUID: string;
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId?: string;
  specificPurpose?: string;
  status: RequestStatus;
  type: RequestType;
  isEmergency: boolean;
  timestamp: string;
  claimedBy?: string;
  verifiedBy?: string;
  processedBy?: string;
  rejectedBy?: string;
  rejectionReason?: string;
  returnCondition?: 'Good' | 'Damaged';
  referenceRequestUID?: string;
}

export type MovementRemark = string;

export interface Movement {
  id: string;
  itemCode: string;
  itemDescription: string;
  requestedQty: number;
  receivedQty: number;
  location: string;
  createdBy: string;
  createdDate: string;
  receivedDate: string;
  moveOrderNumber: string;
  remarks: MovementRemark;
}

export interface AuditLogEntry {
  id: string;
  timestamp: string;
  action: string;
  itemId: string;
  itemName: string;
  quantityChange: number;
  performedBy: string;
  details: string;
}

export interface PurchaseOrder {
  id: string;
  prNumber: string;
  prDate: string;
  poNumber: string;
  status: 'Draft' | 'Approved' | 'Ordered' | 'Received' | 'Closed';
  supplier: string;
  totalCost: number;
  date: string;
  receivedDate?: string;
}

import React, { useState, useMemo } from 'react';
import { User, UserRole } from '../types';
import { Users, UserPlus, Search, Trash2, Edit3, Shield, ShieldAlert, ShieldCheck, X, ChevronDown, IdCard, AlertCircle, Phone } from 'lucide-react';

interface UserManagementViewProps {
  users: User[];
  currentUser: User;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string, reason: string) => void;
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ users, currentUser, onAddUser, onUpdateUser, onDeleteUser }) => {
  const [searchTerm, setSearchTerm] = useState('');

  // Modals
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deletingUser, setDeletingUser] = useState<User | null>(null);

  // Form States
  const [userName, setUserName] = useState('');
  const [userCardNum, setUserCardNum] = useState('');
  const [userContact, setUserContact] = useState('');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.STANDARD);
  const [isSpecial, setIsSpecial] = useState(false);
  const [deleteReason, setDeleteReason] = useState('');

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.recordCardNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.role.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (u.contactNumber && u.contactNumber.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [users, searchTerm]);

  const openAddModal = () => {
    setUserName('');
    setUserCardNum('');
    setUserContact('');
    setUserRole(UserRole.STANDARD);
    setIsSpecial(false);
    setIsAddModalOpen(true);
  };

  const openEditModal = (user: User) => {
    setEditingUser(user);
    setUserName(user.name);
    setUserCardNum(user.recordCardNumber);
    setUserContact(user.contactNumber || '');
    setUserRole(user.role);
    setIsSpecial(!!user.isSpecialAdmin);
  };

  const handleAddSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userName.trim() || !userCardNum.trim()) return;
    onAddUser({ 
      name: userName, 
      recordCardNumber: userCardNum, 
      contactNumber: userContact,
      role: userRole, 
      isSpecialAdmin: isSpecial 
    });
    setIsAddModalOpen(false);
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      onUpdateUser({ 
        ...editingUser, 
        name: userName, 
        recordCardNumber: userCardNum, 
        contactNumber: userContact,
        role: userRole, 
        isSpecialAdmin: isSpecial 
      });
      setEditingUser(null);
    }
  };

  const handleDeleteSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (deletingUser && deleteReason.trim()) {
      onDeleteUser(deletingUser.id, deleteReason);
      setDeletingUser(null);
      setDeleteReason('');
    }
  };

  const getRoleBadge = (role: UserRole, special?: boolean) => {
    const baseClasses = "px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ";
    switch (role) {
      case UserRole.OWNER:
        return <span className={baseClasses + "bg-purple-100 text-purple-700 border-purple-200"}>Owner</span>;
      case UserRole.ADMIN_L2:
        return <span className={baseClasses + "bg-red-100 text-red-700 border-red-200"}>Super Admin</span>;
      case UserRole.ADMIN_L1:
        return (
          <div className="flex gap-1 items-center">
            <span className={baseClasses + "bg-blue-100 text-blue-700 border-blue-200"}>Admin L1</span>
            {special && <span className={baseClasses + "bg-amber-100 text-amber-700 border-amber-200"}>Special</span>}
          </div>
        );
      default:
        return <span className={baseClasses + "bg-slate-100 text-slate-600 border-slate-200"}>Standard</span>;
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800">User Management</h2>
          <p className="text-sm text-slate-500">Configure access control and authority levels.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-700 transition-transform active:scale-95"
        >
          <UserPlus className="w-5 h-5" /> Add New User
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by name, record card, phone or role..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-6 py-4">User Details</th>
                <th className="px-6 py-4">Security Level</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredUsers.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold">
                        {user.name.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900">{user.name}</p>
                        <div className="flex flex-wrap gap-x-3 gap-y-1 mt-0.5">
                            <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-medium">
                                <IdCard className="w-3 h-3" />
                                <span>Card: {user.recordCardNumber}</span>
                            </div>
                            {user.contactNumber && (
                              <div className="flex items-center gap-1.5 text-[10px] text-slate-400 font-medium">
                                  <Phone className="w-3 h-3" />
                                  <span>{user.contactNumber}</span>
                              </div>
                            )}
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {getRoleBadge(user.role, user.isSpecialAdmin)}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => openEditModal(user)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit User"
                      >
                        <Edit3 className="w-5 h-5" />
                      </button>
                      {user.id !== currentUser.id && user.role !== UserRole.OWNER && (
                        <button 
                          onClick={() => {
                            setDeletingUser(user);
                            setDeleteReason('');
                          }}
                          className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                          title="Delete User"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredUsers.length === 0 && (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400 italic">No users found matching your search.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit User Modal */}
      {(isAddModalOpen || editingUser) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                {editingUser ? <Edit3 className="w-5 h-5 text-blue-600" /> : <UserPlus className="w-5 h-5 text-blue-600" />}
                {editingUser ? 'Edit User Security' : 'Create New User'}
              </h3>
              <button onClick={() => { setIsAddModalOpen(false); setEditingUser(null); }} className="text-slate-400 hover:text-slate-600">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={editingUser ? handleEditSubmit : handleAddSubmit} className="p-6 space-y-5">
              <div className="grid grid-cols-1 gap-5">
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Name</label>
                  <input 
                    type="text" 
                    required 
                    placeholder="e.g. Michael Smith"
                    className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm"
                    value={userName}
                    onChange={(e) => setUserName(e.target.value)}
                  />
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Record Card Number</label>
                      <div className="relative">
                        <IdCard className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input 
                          type="text" 
                          required 
                          placeholder="e.g. RC-5001"
                          className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm"
                          value={userCardNum}
                          onChange={(e) => setUserCardNum(e.target.value)}
                        />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Contact Number</label>
                      <div className="relative">
                        <Phone className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input 
                          type="tel" 
                          placeholder="e.g. +1 234 567"
                          className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-xl text-sm focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm"
                          value={userContact}
                          onChange={(e) => setUserContact(e.target.value)}
                        />
                      </div>
                    </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Assigned Role</label>
                <div className="relative">
                  <select 
                    value={userRole}
                    onChange={(e) => setUserRole(e.target.value as UserRole)}
                    className="w-full pl-4 pr-10 py-3.5 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-500/10 outline-none appearance-none cursor-pointer bg-slate-50"
                  >
                    <option value={UserRole.STANDARD}>Standard User</option>
                    <option value={UserRole.ADMIN_L1}>Admin Level 1</option>
                    <option value={UserRole.ADMIN_L2}>Super Admin (L2)</option>
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                </div>
              </div>

              {userRole === UserRole.ADMIN_L1 && (
                <div className="bg-amber-50 border border-amber-100 rounded-2xl p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-xs font-black text-amber-800 flex items-center gap-2">
                        <ShieldAlert className="w-4 h-4" /> Special Admin Status
                      </p>
                      <p className="text-[10px] text-amber-600 font-medium">Grant "Owner-level" processing rights.</p>
                    </div>
                    <label className="relative inline-flex items-center cursor-pointer">
                      <input 
                        type="checkbox" 
                        className="sr-only peer" 
                        checked={isSpecial}
                        onChange={(e) => setIsSpecial(e.target.checked)}
                      />
                      <div className="w-11 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-amber-500"></div>
                    </label>
                  </div>
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={() => { setIsAddModalOpen(false); setEditingUser(null); }} 
                  className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  {editingUser ? 'Save Changes' : 'Create User'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-red-50">
              <h3 className="text-lg font-bold text-red-800 flex items-center gap-2">
                <Trash2 className="w-5 h-5" /> Terminate User Access
              </h3>
              <button onClick={() => setDeletingUser(null)} className="text-slate-400 hover:text-slate-600">
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleDeleteSubmit} className="p-6 space-y-5">
              <div className="flex items-start gap-3 bg-red-50 p-4 rounded-2xl border border-red-100">
                 <AlertCircle className="w-5 h-5 text-red-600 shrink-0 mt-0.5" />
                 <div>
                    <p className="text-sm font-bold text-red-900">Confirm permanent deletion</p>
                    <p className="text-xs text-red-700 mt-1">You are about to remove <strong>{deletingUser.name}</strong> from the system. This action is recorded in the master audit trail.</p>
                 </div>
              </div>

              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Reason for Deletion</label>
                <textarea 
                  required 
                  autoFocus
                  placeholder="e.g. Employee resignation, role change, end of contract..."
                  className="w-full border border-slate-200 rounded-xl p-3.5 text-sm focus:ring-4 focus:ring-red-500/10 outline-none transition-all shadow-sm min-h-[100px]"
                  value={deleteReason}
                  onChange={(e) => setDeleteReason(e.target.value)}
                />
              </div>

              <div className="flex gap-3 pt-2">
                <button 
                  type="button" 
                  onClick={() => setDeletingUser(null)} 
                  className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-red-600 text-white font-black rounded-xl hover:bg-red-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  Confirm Delete
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManagementView;

import React, { useState, useMemo } from 'react';
import { Movement, User, UserRole, MovementRemark } from '../types';
import { Truck, FileSpreadsheet, Search, Edit3, Plus, X, CheckCircle2, AlertTriangle, Package, MessageSquare, Filter, Calendar, MapPin, Tag, ChevronDown } from 'lucide-react';

interface MovementsViewProps {
  movements: Movement[];
  currentUser: User;
  onCreateMovement: (mv: Omit<Movement, 'id'>) => void;
  onUpdateMovement: (mv: Movement) => void;
}

const MovementsView: React.FC<MovementsViewProps> = ({ movements, currentUser, onCreateMovement, onUpdateMovement }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Filter State
  const [filterLocation, setFilterLocation] = useState('');
  const [filterCreatedFrom, setFilterCreatedFrom] = useState('');
  const [filterCreatedTo, setFilterCreatedTo] = useState('');
  const [filterReceivedFrom, setFilterReceivedFrom] = useState('');
  const [filterReceivedTo, setFilterReceivedTo] = useState('');
  const [filterRemark, setFilterRemark] = useState<string>('All Statuses');

  // Form State
  const [form, setForm] = useState<Omit<Movement, 'id'>>({
    itemCode: '',
    itemDescription: '',
    requestedQty: 0,
    receivedQty: 0,
    location: '',
    createdBy: currentUser.name,
    createdDate: new Date().toISOString().split('T')[0],
    receivedDate: '-',
    moveOrderNumber: '',
    remarks: 'Not Completed'
  });

  const [isOtherSelected, setIsOtherSelected] = useState(false);
  const [customRemark, setCustomRemark] = useState('');

  const isOwner = currentUser.role === UserRole.OWNER;
  const isSpecialAdmin = !!currentUser.isSpecialAdmin;
  const canModify = isOwner || isSpecialAdmin;

  const standardRemarks = ['Completed', 'Not Completed', 'Out of Stock'];
  const allPossibleRemarks = useMemo(() => {
    const set = new Set(standardRemarks);
    movements.forEach(m => set.add(m.remarks));
    return Array.from(set);
  }, [movements]);

  const filteredMovements = useMemo(() => {
    return movements.filter(mv => {
      // Basic Search
      const searchMatch = !searchTerm || 
        mv.itemCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
        mv.itemDescription.toLowerCase().includes(searchTerm.toLowerCase()) ||
        mv.moveOrderNumber.toLowerCase().includes(searchTerm.toLowerCase());

      // Location Filter
      const locationMatch = !filterLocation || 
        mv.location.toLowerCase().includes(filterLocation.toLowerCase());

      // Remark Filter
      const remarkMatch = filterRemark === 'All Statuses' || mv.remarks === filterRemark;

      // Created Date Range
      const createdDate = new Date(mv.createdDate);
      const createdFromMatch = !filterCreatedFrom || createdDate >= new Date(filterCreatedFrom);
      const createdToMatch = !filterCreatedTo || createdDate <= new Date(filterCreatedTo);

      // Received Date Range
      let receivedMatch = true;
      if (mv.receivedDate !== '-' && mv.receivedDate !== '') {
        const receivedDate = new Date(mv.receivedDate);
        const receivedFromMatch = !filterReceivedFrom || receivedDate >= new Date(filterReceivedFrom);
        const receivedToMatch = !filterReceivedTo || receivedDate <= new Date(filterReceivedTo);
        receivedMatch = receivedFromMatch && receivedToMatch;
      } else if (filterReceivedFrom || filterReceivedTo) {
        receivedMatch = false; // Filter set but no date available
      }

      return searchMatch && locationMatch && remarkMatch && createdFromMatch && createdToMatch && receivedMatch;
    });
  }, [movements, searchTerm, filterLocation, filterRemark, filterCreatedFrom, filterCreatedTo, filterReceivedFrom, filterReceivedTo]);

  const openCreateModal = () => {
    setEditingId(null);
    setIsOtherSelected(false);
    setCustomRemark('');
    setForm({
      itemCode: '',
      itemDescription: '',
      requestedQty: 0,
      receivedQty: 0,
      location: '',
      createdBy: currentUser.name,
      createdDate: new Date().toISOString().split('T')[0],
      receivedDate: '-',
      moveOrderNumber: `MO-${Math.floor(1000 + Math.random() * 9000)}`,
      remarks: 'Not Completed'
    });
    setIsModalOpen(true);
  };

  const openEditModal = (mv: Movement) => {
    if (mv.remarks === 'Completed') return;
    setEditingId(mv.id);
    setForm({ ...mv });

    if (!standardRemarks.includes(mv.remarks)) {
      setIsOtherSelected(true);
      setCustomRemark(mv.remarks);
    } else {
      setIsOtherSelected(false);
      setCustomRemark('');
    }

    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalRemarks = isOtherSelected ? customRemark : form.remarks;
    const payload = { ...form, remarks: finalRemarks || 'Not Completed' };

    if (editingId) {
      onUpdateMovement({ ...payload, id: editingId });
    } else {
      onCreateMovement(payload);
    }
    setIsModalOpen(false);
  };

  const resetFilters = () => {
    setFilterLocation('');
    setFilterCreatedFrom('');
    setFilterCreatedTo('');
    setFilterReceivedFrom('');
    setFilterReceivedTo('');
    setFilterRemark('All Statuses');
    setSearchTerm('');
  };

  const getRemarkBadge = (remark: MovementRemark) => {
    const base = "px-2 py-1 rounded text-[10px] font-black uppercase tracking-wider ";
    switch (remark) {
      case 'Completed': return <span className={base + "bg-green-100 text-green-700"}>Completed</span>;
      case 'Out of Stock': return <span className={base + "bg-red-100 text-red-700"}>Out of Stock</span>;
      case 'Not Completed': return <span className={base + "bg-amber-100 text-amber-700"}>Not Completed</span>;
      default: return <span className={base + "bg-slate-100 text-slate-700 border border-slate-200"}>{remark}</span>;
    }
  };

  return (
    <div className="space-y-6 pb-24">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800 flex items-center gap-3">
            <Truck className="w-8 h-8 text-blue-600" /> Move Order Tracking
          </h2>
          <p className="text-sm text-slate-500">Standalone external tracking sync (Master_Movements.xlsx)</p>
        </div>

        <div className="flex gap-2 w-full lg:w-auto">
          <button 
            onClick={() => setIsFilterPanelOpen(!isFilterPanelOpen)}
            className={`flex items-center justify-center gap-2 px-6 py-3 font-bold rounded-xl border transition-all ${isFilterPanelOpen ? 'bg-slate-800 text-white border-slate-800 shadow-lg' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
          >
            <Filter className="w-4 h-4" /> {isFilterPanelOpen ? 'Hide Filters' : 'Advanced Filters'}
          </button>
          {canModify && (
            <button 
              onClick={openCreateModal}
              className="flex-1 lg:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 shadow-xl shadow-blue-100 active:scale-95 transition-all"
            >
              <Plus className="w-4 h-4" /> New Move Order
            </button>
          )}
        </div>
      </div>

      {/* Advanced Filter Panel */}
      {isFilterPanelOpen && (
        <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm animate-in slide-in-from-top-2 duration-200">
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">General Store Location</label>
                <div className="relative">
                  <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Filter by location..." 
                    className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                    value={filterLocation}
                    onChange={(e) => setFilterLocation(e.target.value)}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Remark / Status</label>
                <div className="relative">
                  <Tag className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                  <select 
                    className="w-full pl-10 pr-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                    value={filterRemark}
                    onChange={(e) => setFilterRemark(e.target.value)}
                  >
                    <option value="All Statuses">All Statuses</option>
                    {allPossibleRemarks.map(rem => <option key={rem} value={rem}>{rem}</option>)}
                  </select>
                  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                </div>
              </div>

              <div className="space-y-2 lg:col-span-2">
                <div className="flex justify-between">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Creation Date Range</label>
                  <button onClick={() => {setFilterCreatedFrom(''); setFilterCreatedTo('');}} className="text-[9px] text-blue-600 font-bold hover:underline">Clear</button>
                </div>
                <div className="flex items-center gap-2">
                  <div className="relative flex-1">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="date" 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none"
                      value={filterCreatedFrom}
                      onChange={(e) => setFilterCreatedFrom(e.target.value)}
                    />
                  </div>
                  <span className="text-slate-300 text-xs font-bold">to</span>
                  <div className="relative flex-1">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="date" 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none"
                      value={filterCreatedTo}
                      onChange={(e) => setFilterCreatedTo(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              <div className="space-y-2 lg:col-span-2">
                <div className="flex justify-between">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Received Date Range</label>
                  <button onClick={() => {setFilterReceivedFrom(''); setFilterReceivedTo('');}} className="text-[9px] text-blue-600 font-bold hover:underline">Clear</button>
                </div>
                <div className="flex items-center gap-2">
                  <div className="relative flex-1">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="date" 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none"
                      value={filterReceivedFrom}
                      onChange={(e) => setFilterReceivedFrom(e.target.value)}
                    />
                  </div>
                  <span className="text-slate-300 text-xs font-bold">to</span>
                  <div className="relative flex-1">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="date" 
                      className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none"
                      value={filterReceivedTo}
                      onChange={(e) => setFilterReceivedTo(e.target.value)}
                    />
                  </div>
                </div>
              </div>

              <div className="lg:col-span-4 flex justify-end pt-2 border-t border-slate-100">
                <button 
                  onClick={resetFilters}
                  className="px-6 py-2.5 text-xs font-black text-slate-500 hover:text-red-600 uppercase tracking-widest transition-colors"
                >
                  Reset All Filters
                </button>
              </div>
           </div>
        </div>
      )}

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/30 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by Code, Description, or Order #..." 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-4">
            <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white px-4 py-2.5 rounded-xl border border-slate-100 flex items-center gap-2">
              <FileSpreadsheet className="w-4 h-4 text-green-500" /> Master_Movements.xlsx
            </div>
            {filteredMovements.length !== movements.length && (
              <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-3 py-1 rounded-full border border-blue-100 animate-pulse">
                Filtered: {filteredMovements.length} / {movements.length}
              </span>
            )}
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
              <tr>
                <th className="px-4 py-4">Item Code / Description</th>
                <th className="px-4 py-4">Qty (Req/Rec)</th>
                <th className="px-4 py-4">Location</th>
                <th className="px-4 py-4">Creation (By/Date)</th>
                <th className="px-4 py-4">Received Date</th>
                <th className="px-4 py-4">Order #</th>
                <th className="px-4 py-4">Remarks</th>
                {canModify && <th className="px-4 py-4 text-right">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredMovements.map(mv => (
                <tr key={mv.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-black text-blue-700 text-xs">{mv.itemCode}</span>
                      <span className="text-slate-600 text-xs truncate max-w-[150px]">{mv.itemDescription}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex items-center gap-2">
                       <span className="font-bold text-slate-800">{mv.requestedQty}</span>
                       <span className="text-slate-300">/</span>
                       <span className={`font-bold ${mv.receivedQty === mv.requestedQty ? 'text-green-600' : 'text-slate-400'}`}>{mv.receivedQty}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4">
                    <span className="bg-slate-100 px-2 py-0.5 rounded text-[10px] font-bold text-slate-600">{mv.location}</span>
                  </td>
                  <td className="px-4 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-700 text-xs">{mv.createdBy}</span>
                      <span className="text-slate-400 text-[10px]">{mv.createdDate}</span>
                    </div>
                  </td>
                  <td className="px-4 py-4 font-medium text-slate-500 text-xs">{mv.receivedDate}</td>
                  <td className="px-4 py-4 font-mono font-black text-slate-900 text-xs">{mv.moveOrderNumber}</td>
                  <td className="px-4 py-4">{getRemarkBadge(mv.remarks)}</td>
                  {canModify && (
                    <td className="px-4 py-4 text-right">
                      {mv.remarks !== 'Completed' ? (
                        <button 
                          onClick={() => openEditModal(mv)}
                          className="p-2 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                          <Edit3 className="w-4 h-4" />
                        </button>
                      ) : (
                        <CheckCircle2 className="w-4 h-4 text-green-400 ml-auto mr-2" />
                      )}
                    </td>
                  )}
                </tr>
              ))}
              {filteredMovements.length === 0 && (
                <tr>
                  <td colSpan={canModify ? 8 : 7} className="px-6 py-20 text-center text-slate-400 font-medium italic flex flex-col items-center gap-2">
                    <Package className="w-10 h-10 text-slate-100" />
                    No tracking records match your criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Standalone Tracking Note */}
      <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl flex items-start gap-4">
        <AlertTriangle className="w-6 h-6 text-amber-600 shrink-0 mt-1" />
        <div>
          <h4 className="font-bold text-amber-900">Important Operational Note</h4>
          <p className="text-sm text-amber-700 leading-relaxed mt-1">
            This module is for <strong>Tracking Only</strong>. Move orders entered here do not affect main warehouse inventory counts. Use this list to verify physical stock location changes against the master Excel tracker. Once a Move Order is marked <strong>Completed</strong>, it is locked for audit integrity.
          </p>
        </div>
      </div>

      {/* Create/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
           <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
