        </button>
        <button 
          onClick={() => onChangeView('requests')}
          className={`flex-1 flex flex-col items-center py-2 px-1 ${currentView === 'requests' ? 'text-blue-600' : 'text-slate-500'}`}
        >
          <FileText className="w-6 h-6" />
