export default Layout;

import React, { useState, useMemo } from 'react';
import { Request, RequestStatus, User, UserRole, InventoryItem, RequestType } from '../types';
import { canVerifyRequest, canProcessRequest, canProcessReturn } from '../services/stateService';
import { CheckCircle2, Clock, AlertTriangle, UserCheck, FileCheck, XCircle, RotateCcw, ThumbsUp, ThumbsDown, Search, ArrowRight, X, Filter, History, ChevronDown, User as UserIcon, ShieldCheck } from 'lucide-react';

interface RequestQueueProps {
  requests: Request[];
  items: InventoryItem[];
  users: User[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onReject: (reqId: string, reason: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
  onInitiateReturnById: (itemId: string, qty: number, reason: string, refUID: string) => void;
}

const StatusBadge = ({ status, emergency, type }: { status: RequestStatus, emergency: boolean, type: RequestType }) => {
  if (type === RequestType.TAKE && emergency && status !== RequestStatus.PROCESSED) {
      return <span className="px-2 py-1 rounded text-xs font-bold bg-red-100 text-red-700 border border-red-200">ALREADY TAKEN</span>;
  }
  const styles = {
      [RequestStatus.PENDING]: 'bg-yellow-100 text-yellow-800',
      [RequestStatus.CLAIMED]: 'bg-blue-100 text-blue-800',
      [RequestStatus.VERIFIED]: 'bg-purple-100 text-purple-800',
      [RequestStatus.PROCESSED]: 'bg-green-100 text-green-800',
      [RequestStatus.REJECTED]: 'bg-red-100 text-red-800',
      [RequestStatus.RETURNED]: 'bg-indigo-100 text-indigo-800',
  };
  return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${styles[status] || 'bg-gray-100'}`}>{status}</span>;
};

interface RequestCardProps {
  req: Request;
  showActions: boolean;
  items: InventoryItem[];
  users: User[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onRejectTrigger: (reqId: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
}

const RequestCard: React.FC<RequestCardProps> = ({ 
  req, showActions, items, users, currentUser, onClaim, onVerify, onRejectTrigger, onProcess, onReturnAction 
}) => {
  const item = items.find(i => i.id === req.itemId);

  // Permissions
  const isTake = req.type === RequestType.TAKE;

  // Take Permissions
  const canClaim = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.PENDING;
  const canVerify = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id;
  const canProcess = isTake && canProcessRequest(currentUser) && req.status === RequestStatus.VERIFIED;
  const canReject = isTake && canVerifyRequest(currentUser) && (req.status === RequestStatus.PENDING || (req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id));

  // Return Permissions
  const canActionReturn = !isTake && canProcessReturn(currentUser) && req.status === RequestStatus.PENDING;

  const getAuthorizerName = (id?: string) => {
    if (!id) return null;
    return users.find(u => u.id === id)?.name || id;
  };

  return (
      <div className={`p-4 rounded-lg border shadow-sm flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between transition-all ${req.type === RequestType.RETURN ? 'bg-indigo-50 border-indigo-100' : (req.status === RequestStatus.REJECTED ? 'bg-red-50 border-red-100 shadow-inner' : 'bg-white border-slate-200 hover:border-slate-300')}`}>
          <div className="flex-1">
              <div className="flex items-center gap-3 mb-1">
                  <span className="font-mono text-[10px] bg-slate-100 px-1.5 py-0.5 rounded font-black text-slate-500">{req.requestUID}</span>
                  {req.type === RequestType.RETURN && <RotateCcw className="w-3 h-3 text-indigo-600" />}
                  <span className="font-bold text-slate-800">{item?.name || 'Unknown Item'}</span>
                  <span className="text-xs text-slate-500">Qty: {req.quantity}</span>
                  <StatusBadge status={req.status} emergency={req.isEmergency} type={req.type} />
              </div>
              <div className="text-sm text-slate-600">
                  <span className="font-semibold text-slate-700">{req.userName}</span> 
                  {req.specificPurpose ? ` • ${req.specificPurpose}` : ''}
                  {req.referenceRequestUID && <span className="text-xs text-indigo-600 font-bold ml-2">(Ref Take: {req.referenceRequestUID})</span>}
              </div>
              <div className="text-xs text-slate-400 mt-1">
                  {req.type === RequestType.TAKE ? 'Requested' : 'Return Initiated'}: {new Date(req.timestamp).toLocaleString()}
              </div>

              {/* Authorized Chain Info */}
              <div className="flex flex-wrap gap-x-4 gap-y-1 mt-2 border-t border-slate-100 pt-2">
                {req.claimedBy && (
                  <div className="text-[10px] text-blue-600 font-medium flex items-center gap-1">
                    <UserCheck className="w-3 h-3" /> Claimed: {getAuthorizerName(req.claimedBy)}
                  </div>
                )}
                {req.verifiedBy && (
                  <div className="text-[10px] text-purple-600 font-medium flex items-center gap-1">
                    <FileCheck className="w-3 h-3" /> Verified: {getAuthorizerName(req.verifiedBy)}
                  </div>
                )}
                {req.processedBy && (
                  <div className="text-[10px] text-green-600 font-medium flex items-center gap-1">
                    <CheckCircle2 className="w-3 h-3" /> Processed: {getAuthorizerName(req.processedBy)}
                  </div>
                )}
                {req.rejectedBy && (
                  <div className="text-[10px] text-red-600 font-medium flex items-center gap-1">
                    <XCircle className="w-3 h-3" /> Rejected: {getAuthorizerName(req.rejectedBy)}
                  </div>
                )}
              </div>

              {req.returnCondition && <div className="text-xs font-bold mt-1 text-slate-700">Condition: {req.returnCondition}</div>}
              {req.status === RequestStatus.REJECTED && req.rejectionReason && (
                <div className="mt-3 p-3 bg-red-100/40 rounded-xl text-xs text-red-700 font-medium border border-red-100 flex gap-2 items-start">
                   <AlertTriangle className="w-4 h-4 shrink-0 mt-0.5" />
                   <div>
                    <span className="font-bold uppercase tracking-tight text-[10px] block mb-0.5">Rejection Reason:</span>
                    {req.rejectionReason}
                   </div>
                </div>
              )}
          </div>

          {showActions && (
              <div className="flex gap-2 flex-wrap sm:flex-nowrap">
                  {/* Take Actions */}
                  {canClaim && (
                      <button onClick={() => onClaim(req.id)} className="flex items-center px-3 py-1.5 bg-blue-600 text-white text-sm font-medium rounded hover:bg-blue-700 shadow-sm active:scale-95 transition-all">
                          <UserCheck className="w-4 h-4 mr-2" /> Claim
                      </button>
                  )}
                  {canVerify && (
                      <button onClick={() => onVerify(req.id)} className="flex items-center px-3 py-1.5 bg-purple-600 text-white text-sm font-medium rounded hover:bg-purple-700 shadow-sm active:scale-95 transition-all">
                          <FileCheck className="w-4 h-4 mr-2" /> Verify
                      </button>
                  )}
                  {canVerifyRequest(currentUser) && (req.status === RequestStatus.PENDING || (req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id)) && (
                      <button onClick={() => onRejectTrigger(req.id)} className="flex items-center px-3 py-1.5 bg-red-50 text-red-600 text-sm font-medium rounded hover:bg-red-100 border border-red-200 active:scale-95 transition-all">
                          <XCircle className="w-4 h-4 mr-2" /> Reject
                      </button>
                  )}
                  {canProcess && (
                      <button onClick={() => onProcess(req.id)} className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700 shadow-sm active:scale-95 transition-all">
                          <CheckCircle2 className="w-4 h-4 mr-2" /> Process & Sign
                      </button>
                  )}

                  {/* Return Actions */}
                  {canActionReturn && (
                      <div className="flex gap-2">
                           <button onClick={() => onReturnAction(req.id, 'Good')} className="flex items-center px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded hover:bg-green-700 shadow-sm active:scale-95 transition-all" title="Return to Stock">
                              <ThumbsUp className="w-4 h-4 mr-2" /> Good
                          </button>
                          <button onClick={() => onReturnAction(req.id, 'Damaged')} className="flex items-center px-3 py-1.5 bg-amber-600 text-white text-sm font-medium rounded hover:bg-amber-700 shadow-sm active:scale-95 transition-all" title="Mark Damaged">
                              <ThumbsDown className="w-4 h-4 mr-2" /> Damaged
                          </button>
                      </div>
                  )}
              </div>
          )}
      </div>
  );
};

const RequestQueue: React.FC<RequestQueueProps> = ({ 
    requests, items, users, currentUser, onClaim, onVerify, onReject, onProcess, onReturnAction, onInitiateReturnById
}) => {

  const [tab, setTab] = useState<'take' | 'return'>('take');
  const [searchUID, setSearchUID] = useState('');
  const [returnMsg, setReturnMsg] = useState('');
  const [returnQty, setReturnQty] = useState<number | ''>('');

  // Rejection Dialog State
  const [rejectingReqId, setRejectingReqId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');

  // History Filtering
  const [historyTypeFilter, setHistoryTypeFilter] = useState<'all' | 'take' | 'return'>('all');
  const [historyStatusFilter, setHistoryStatusFilter] = useState<'all' | 'processed' | 'rejected' | 'returned'>('all');
  const [historyRequesterFilter, setHistoryRequesterFilter] = useState<string>('all');
  const [historyApproverFilter, setHistoryApproverFilter] = useState<string>('all');

  // Filter logic
  const isStandardUser = currentUser.role === UserRole.STANDARD;
  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;
  const isOwner = currentUser.role === UserRole.OWNER;
  const isAdminL1 = currentUser.role === UserRole.ADMIN_L1;
  const isSpecialAdmin = !!currentUser.isSpecialAdmin;

  // Visibility logic: Standard users see only their own. Others see all.
  const visibleRequests = useMemo(() => {
    return isStandardUser ? requests.filter(r => r.userId === currentUser.id) : requests;
  }, [requests, isStandardUser, currentUser.id]);

  const filteredHistory = useMemo(() => {
    // Only terminal states for history usually, but standard users see all their history regardless of status
    const base = isStandardUser 
      ? visibleRequests 
      : visibleRequests.filter(r => r.status === RequestStatus.PROCESSED || r.status === RequestStatus.RETURNED || r.status === RequestStatus.REJECTED || r.status === RequestStatus.VERIFIED);

    return base.filter(r => {
      const typeMatch = historyTypeFilter === 'all' || r.type.toLowerCase() === historyTypeFilter;
      const statusMatch = historyStatusFilter === 'all' || r.status.toLowerCase() === historyStatusFilter;
      const requesterMatch = historyRequesterFilter === 'all' || r.userId === historyRequesterFilter;

      // Approver filter checks verifiedBy, processedBy, or rejectedBy
      const approverMatch = historyApproverFilter === 'all' || 
        r.verifiedBy === historyApproverFilter || 
        r.processedBy === historyApproverFilter || 
        r.rejectedBy === historyApproverFilter;

      return typeMatch && statusMatch && requesterMatch && approverMatch;
    }).slice(0, 50);
  }, [visibleRequests, isStandardUser, historyTypeFilter, historyStatusFilter, historyRequesterFilter, historyApproverFilter]);

  // Filtering for active approval queues (Only for Admins/Owners)
  const pendingRequests = useMemo(() => visibleRequests.filter(r => r.type === RequestType.TAKE && r.status === RequestStatus.PENDING), [visibleRequests]);
  const claimedRequests = useMemo(() => visibleRequests.filter(r => r.type === RequestType.TAKE && r.status === RequestStatus.CLAIMED), [visibleRequests]);
  const verifiedRequests = useMemo(() => visibleRequests.filter(r => r.type === RequestType.TAKE && r.status === RequestStatus.VERIFIED), [visibleRequests]);
  const pendingReturns = useMemo(() => visibleRequests.filter(r => r.type === RequestType.RETURN && r.status === RequestStatus.PENDING), [visibleRequests]);

  const handleReturnById = (e: React.FormEvent) => {
    e.preventDefault();
    const target = visibleRequests.find(r => r.requestUID === searchUID && r.type === RequestType.TAKE);
    if (!target) {
        alert("Request ID not found in your accessible records.");
        return;
    }
    if (target.status !== RequestStatus.PROCESSED) {
        alert("This request has not been fully processed yet.");
        return;
    }

    onInitiateReturnById(target.itemId, returnQty || target.quantity, returnMsg || "Returning via ID lookup", target.requestUID);
    setSearchUID('');
    setReturnMsg('');
    setReturnQty('');
  };

  const handleConfirmReject = (e: React.FormEvent) => {
    e.preventDefault();
    if (rejectingReqId && rejectionReason.trim()) {
        onReject(rejectingReqId, rejectionReason);
        setRejectingReqId(null);
        setRejectionReason('');
    }
  };

  const renderList = (list: Request[], emptyMsg: string, actions: boolean) => (
      <div className="space-y-3">
          {list.length === 0 && <p className="text-sm text-slate-500 italic py-4">{emptyMsg}</p>}
          {list.map(req => (
              <RequestCard 
                  key={req.id} 
                  req={req} 
                  showActions={actions}
                  items={items}
                  users={users}
                  currentUser={currentUser}
                  onClaim={onClaim}
                  onVerify={onVerify}
                  onRejectTrigger={setRejectingReqId}
                  onProcess={onProcess}
                  onReturnAction={onReturnAction}
              />
          ))}
      </div>
  );

  return (
    <div className="space-y-8 pb-20">

        {/* Quick Return Section - Hidden for Super Admins */}
        {!isSuperAdmin && (
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden relative">
              <div className="absolute top-0 left-0 w-1 h-full bg-blue-600"></div>
              <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest mb-4 flex items-center gap-2">
                  <RotateCcw className="w-4 h-4 text-blue-600" /> Quick Return via Request ID
              </h3>
              <form onSubmit={handleReturnById} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Request ID</label>
                      <input 
                          type="text" 
                          required 
                          placeholder="e.g. REQ-1001" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm focus:ring-2 focus:ring-blue-500 outline-none" 
                          value={searchUID}
                          onChange={(e) => setSearchUID(e.target.value.toUpperCase())}
                      />
                  </div>
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Qty to Return</label>
                      <input 
                          type="number" 
                          placeholder="Max" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm outline-none" 
                          value={returnQty}
                          onChange={(e) => setReturnQty(e.target.value === '' ? '' : parseInt(e.target.value))}
                      />
                  </div>
                  <div className="md:col-span-1">
                      <label className="block text-[10px] font-bold text-slate-500 uppercase mb-1">Condition Note</label>
                      <input 
                          type="text" 
                          placeholder="e.g. Unused" 
                          className="w-full border border-slate-300 rounded-lg p-2.5 text-sm outline-none" 
                          value={returnMsg}
                          onChange={(e) => setReturnMsg(e.target.value)}
                      />
                  </div>
                  <button type="submit" className="bg-blue-600 text-white font-bold py-2.5 px-4 rounded-lg hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 text-sm shadow-sm active:scale-95">
                      <ArrowRight className="w-4 h-4" /> Initiate Return
                  </button>
              </form>
          </div>
        )}

        {/* Admin Queue Section */}
        {!isStandardUser && (
            <div className="space-y-6">
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                        <ShieldCheck className="w-8 h-8 text-blue-600" />
                        {isSuperAdmin ? 'Global Queue Oversight' : 'Master Approval Hub'}
                    </h2>
                    <div className="flex bg-slate-100 p-1 rounded-lg self-stretch sm:self-auto">
                        <button 
                            onClick={() => setTab('take')} 
                            className={`flex-1 sm:flex-none px-6 py-2 text-sm font-bold rounded-md transition-all ${tab === 'take' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
                        >
                            Take Reqs {(pendingRequests.length + verifiedRequests.length) > 0 && `(${pendingRequests.length + verifiedRequests.length})`}
                        </button>
                        <button 
                             onClick={() => setTab('return')} 
                             className={`flex-1 sm:flex-none px-6 py-2 text-sm font-bold rounded-md transition-all ${tab === 'return' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
                        >
                            Returns {pendingReturns.length > 0 && `(${pendingReturns.length})`}
                        </button>
                    </div>
                </div>

                {tab === 'take' && (
                    <div className="animate-in fade-in slide-in-from-top-2 duration-300 space-y-6">
                        {verifiedRequests.length > 0 && (
                            <div className="bg-green-50 rounded-2xl p-4 border border-green-100 shadow-sm">
                                <h3 className="text-[10px] font-black text-green-800 uppercase tracking-widest mb-3 flex items-center gap-2 px-1">
                                    <CheckCircle2 className="w-4 h-4" /> Ready for Final Processing (Deduct)
                                </h3>
                                {renderList(verifiedRequests, "No items ready for final sign-off.", !isSuperAdmin)}
                            </div>
                        )}

                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                            <div className="bg-white rounded-2xl p-4 border border-slate-200 shadow-sm">
                                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2 px-1">
                                    <Clock className="w-4 h-4 text-yellow-500" /> Unclaimed Pending Requests
                                </h3>
                                {renderList(pendingRequests, "No new pending requests.", !isSuperAdmin)}
                            </div>

                            <div className="bg-blue-50/50 rounded-2xl p-4 border border-blue-100 shadow-sm">
                                <h3 className="text-[10px] font-black text-blue-800 uppercase tracking-widest mb-3 flex items-center gap-2 px-1">
                                    <UserCheck className="w-4 h-4" /> Your Active Claims / In Progress
                                </h3>
                                {renderList(claimedRequests, "No active claims assigned.", !isSuperAdmin)}
                            </div>
                        </div>
                    </div>
                )}

                {tab === 'return' && (
                    <div className="animate-in fade-in slide-in-from-top-2 duration-300 bg-indigo-50/50 rounded-2xl p-4 border border-indigo-100 shadow-sm">
                         <h3 className="text-[10px] font-black text-indigo-800 uppercase tracking-widest mb-3 flex items-center gap-2 px-1">
                            <RotateCcw className="w-4 h-4" /> Physical Stock Returns Waiting Verification
                        </h3>
                        {renderList(pendingReturns, "No items currently awaiting return processing.", !isSuperAdmin)}
                    </div>
                )}
            </div>
        )}

        {/* User History Section with Improved Filters */}
        <div className="pt-8 border-t border-slate-200">
             <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 mb-8">
                 <div>
                    <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                        <History className="w-6 h-6 text-slate-400" />
                        {isStandardUser ? 'My Transaction Log' : 'Master Operational History'}
                    </h2>
                    <p className="text-xs text-slate-500 mt-1">Audit trail of all processed and rejected item movements.</p>
                 </div>

                 <div className="flex flex-wrap items-center gap-3">
                    <div className="relative group">
                        <span className="absolute -top-2 left-2 px-1 bg-slate-50 text-[8px] font-black text-slate-400 uppercase z-10">Type</span>
                        <select 
                          value={historyTypeFilter}
                          onChange={(e) => setHistoryTypeFilter(e.target.value as any)}
                          className="pl-3 pr-8 py-2.5 border border-slate-300 rounded-xl bg-white text-[10px] font-black text-slate-600 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm min-w-[100px] uppercase tracking-wider"
                        >
                          <option value="all">All</option>
                          <option value="take">Take</option>
                          <option value="return">Return</option>
                        </select>
                        <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                    </div>

                    <div className="relative group">
                        <span className="absolute -top-2 left-2 px-1 bg-slate-50 text-[8px] font-black text-slate-400 uppercase z-10">Status</span>
                        <select 
                          value={historyStatusFilter}
                          onChange={(e) => setHistoryStatusFilter(e.target.value as any)}
                          className="pl-3 pr-8 py-2.5 border border-slate-300 rounded-xl bg-white text-[10px] font-black text-slate-600 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm min-w-[120px] uppercase tracking-wider"
                        >
                          <option value="all">All</option>
                          <option value="processed">Processed</option>
                          <option value="verified">Verified</option>
                          <option value="rejected">Rejected</option>
                          <option value="returned">Returned</option>
                        </select>
                        <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                    </div>

                    {!isStandardUser && (
                      <>
                        <div className="relative group">
                            <span className="absolute -top-2 left-2 px-1 bg-slate-50 text-[8px] font-black text-slate-400 uppercase z-10">Requester</span>
                            <div className="relative">
                                <UserIcon className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400" />
                                <select 
                                  value={historyRequesterFilter}
                                  onChange={(e) => setHistoryRequesterFilter(e.target.value)}
                                  className="pl-7 pr-8 py-2.5 border border-slate-300 rounded-xl bg-white text-[10px] font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm min-w-[150px]"
                                >
                                  <option value="all">Global (All Users)</option>
                                  {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                                </select>
                                <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                            </div>
                        </div>

                        <div className="relative group">
                            <span className="absolute -top-2 left-2 px-1 bg-slate-50 text-[8px] font-black text-slate-400 uppercase z-10">Authorized By</span>
                            <div className="relative">
                                <ShieldCheck className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400" />
                                <select 
                                  value={historyApproverFilter}
                                  onChange={(e) => setHistoryApproverFilter(e.target.value)}
                                  className="pl-7 pr-8 py-2.5 border border-slate-300 rounded-xl bg-white text-[10px] font-bold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 appearance-none shadow-sm min-w-[150px]"
                                >
                                  <option value="all">Any Admin</option>
                                  {users.filter(u => u.role !== UserRole.STANDARD).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                                </select>
                                <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
                            </div>
                        </div>
                      </>
                    )}

                    {(historyTypeFilter !== 'all' || historyStatusFilter !== 'all' || historyRequesterFilter !== 'all' || historyApproverFilter !== 'all') && (
                       <button 
                        onClick={() => {
                          setHistoryTypeFilter('all');
                          setHistoryStatusFilter('all');
                          setHistoryRequesterFilter('all');
                          setHistoryApproverFilter('all');
                        }}
                        className="p-2.5 bg-slate-100 text-slate-400 hover:text-red-600 rounded-xl transition-colors shadow-sm"
                        title="Reset Filters"
                       >
                         <X className="w-4 h-4" />
                       </button>
                    )}
                 </div>
             </div>

             <div className="space-y-3">
                 {renderList(filteredHistory, "No records found matching your specific filters.", false)}
             </div>
        </div>

        {/* Rejection Modal */}
        {rejectingReqId && (
            <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
                <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-red-50">
                        <h3 className="text-lg font-bold text-red-800 flex items-center gap-2">
                            <XCircle className="w-5 h-5" /> Terminate Request
                        </h3>
                        <button onClick={() => setRejectingReqId(null)} className="text-slate-400 hover:text-slate-600">
                            <X className="w-6 h-6" />
                        </button>
                    </div>
                    <form onSubmit={handleConfirmReject} className="p-6 space-y-4">
                        <div className="bg-red-50 p-4 rounded-2xl border border-red-100 flex gap-3 items-start">
                          <AlertTriangle className="w-5 h-5 text-red-600 shrink-0 mt-0.5" />
                          <p className="text-xs text-red-900 font-medium leading-relaxed">
                            You are rejecting Request <strong>{visibleRequests.find(r => r.id === rejectingReqId)?.requestUID}</strong>. This is a final action and will be logged in the permanent audit trail.
                          </p>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Detailed Rejection Reason</label>
                            <textarea 
                                required 
                                autoFocus
                                placeholder="e.g. Insufficient project priority, incorrect quantity requested, item reserved for emergency..."
                                className="w-full border border-slate-200 rounded-2xl p-4 text-sm focus:ring-4 focus:ring-red-500/10 outline-none min-h-[140px] shadow-inner bg-slate-50 transition-all focus:bg-white"
                                value={rejectionReason}
                                onChange={(e) => setRejectionReason(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-3 pt-2">
                            <button 
                                type="button" 
                                onClick={() => setRejectingReqId(null)} 
                                className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors"
                            >
                                Cancel
                            </button>
                            <button 
                                type="submit" 
                                className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all active:scale-95"
                            >
                                Confirm Rejection
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        )}
    </div>
  );
};

export default RequestQueue;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import UserManagementView from './components/UserManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Truck } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Actions ---

  const handleLogout = () => {
    // Cycle through users for demo purposes
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory'); // Reset view on switch
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'MOVEMENT_CREATED',
        itemId: 'N/A',
        itemName: mv.itemCode,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Standalone Move Order ${mv.moveOrderNumber} created.`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'MOVEMENT_UPDATED',
        itemId: 'N/A',
        itemName: mv.itemCode,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Move Order ${mv.moveOrderNumber} updated. Remark: ${mv.remarks}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_CREATED',
        itemId: item.id,
        itemName: item.name,
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Requested ${qty} for ${specific} [${newRequest.requestUID}]`
    };
    setAuditLog(prev => [log, ...prev]);

    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    // Lookup original purpose from reference request to ensure financial accuracy
    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) {
        purposeId = originalReq.purposeId;
      }
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId, // Carrying over purpose for financial tracking
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason, // Reusing field for reason
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { 
            ...req, 
            status: RequestStatus.REJECTED, 
            rejectedBy: currentUser.id,
            rejectionReason: reason 
        } : req
    ));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'REQUEST_REJECTED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Rejected request ${request.requestUID}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    // 1. Update Request
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    // 2. Update Inventory
    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => 
            i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i
        ));
    }

    // 3. Generate PDF Mock
    alert(`PROCESSING COMPLETE [${request.requestUID}]:\n\nStock deducted: ${request.quantity}\nPDF Generated for Signature.\n\nPlease print, sign, and upload to close.`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'STOCK_DEDUCTED',
        itemId: request.itemId,
        itemName: item?.name || 'Unknown',
        quantityChange: -request.quantity,
        performedBy: currentUser.name,
        details: `Processed take request ${request.requestUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      const newStatus = RequestStatus.RETURNED;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: newStatus, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          // Add back to stock
          setInventory(prev => prev.map(i => 
              i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i
          ));
      }

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED',
        itemId: request.itemId,
        itemName: inventory.find(i => i.id === request.itemId)?.name || 'Unknown',
        quantityChange: condition === 'Good' ? request.quantity : 0,
        performedBy: currentUser.name,
        details: `Return ${request.requestUID} accepted. Condition: ${condition}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleManualAdjust = (itemId: string, newQty: number, reason: string) => {
    console.log("Manual adjust", itemId, newQty, reason);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    const logDetails = [];
    if (qty !== 0) logDetails.push(`Stock Adjusted: ${qty > 0 ? '+' : ''}${qty} (${note})`);
    if (newDescription !== undefined && newDescription !== item.description) logDetails.push('Technical description updated');
    if (newLocation !== undefined && newLocation !== item.location) logDetails.push(`Location moved from ${item.location} to ${newLocation}`);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'INVENTORY_ADJUSTMENT',
        itemId: itemId,
        itemName: item.name,
        quantityChange: qty,
        performedBy: currentUser.name,
        details: logDetails.join('. ') || 'No significant changes recorded.'
    };
    setAuditLog(prev => [log, ...prev]);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);

      const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'ITEM_CREATED',
        itemId: id,
        itemName: newItem.name,
        quantityChange: newItem.quantity,
        performedBy: currentUser.name,
        details: `New Item Created with UID ${inventoryUID}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- User Management ---
  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_CREATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Created new user ${user.name} (Role: ${user.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));

    // If the updated user is the current user, update the state to reflect changes immediately
    if (updatedUser.id === currentUser.id) {
        setCurrentUser(updatedUser);
    }

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_UPDATED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Updated security settings for ${updatedUser.name} (${updatedUser.role})`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    if (id === currentUser.id) {
        alert("Cannot delete the currently logged in user.");
        return;
    }
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;

    setUsers(prev => prev.filter(u => u.id !== id));

    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action: 'USER_DELETED',
        itemId: 'N/A',
        itemName: 'User System',
        quantityChange: 0,
        performedBy: currentUser.name,
        details: `Deleted user ${targetUser.name}. Reason: ${reason}`
    };
    setAuditLog(prev => [log, ...prev]);
  };

  // --- Render ---

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={handleManualAdjust}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
              onCreateItem={handleCreateItem}
          />
      )}

      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            users={users}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onReject={handleReject}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
            onInitiateReturnById={handleReturnItem}
        />
      )}

      {currentView === 'movements' && (
        <MovementsView 
            movements={movements}
            currentUser={currentUser}
            onCreateMovement={handleCreateMovement}
            onUpdateMovement={handleUpdateMovement}
        />
      )}

      {currentView === 'financials' && (
        <FinancialDashboard 
            items={inventory}
            requests={requests}
            purposes={WORK_PURPOSES}
        />
      )}

      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} />
      )}

      {currentView === 'user-management' && (
        <UserManagementView 
          users={users} 
          currentUser={currentUser} 
          onAddUser={handleAddUser} 
          onUpdateUser={handleUpdateUser}
          onDeleteUser={handleDeleteUser} 
        />
      )}

      {currentView === 'audit' && (
          <div className="space-y-6">
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-bold text-slate-800">System Audit Log</h2>
                <button 
                  onClick={exportAuditLog}
                  className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <FileSpreadsheet className="w-4 h-4 text-green-400" /> Export CSV
                </button>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                  <table className="w-full text-left text-sm">
                      <thead className="bg-slate-50 border-b border-slate-200">
                          <tr>
                              <th className="px-6 py-4">Time</th>
                              <th className="px-6 py-4">Action</th>
                              <th className="px-6 py-4">User</th>
                              <th className="px-6 py-4">Item</th>
                              <th className="px-6 py-4">Change</th>
                              <th className="px-6 py-4">Details</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                          {auditLog.length === 0 ? (
                              <tr><td colSpan={6} className="px-6 py-8 text-center text-slate-400">No activity recorded yet.</td></tr>
                          ) : (
                              auditLog.map(log => (
                                  <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                      <td className="px-6 py-4 text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleString()}</td>
                                      <td className="px-6 py-4">
                                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                                          log.action.includes('REJECTED') ? 'bg-red-100 text-red-700' :
                                          log.action.includes('CREATED') ? 'bg-blue-100 text-blue-700' :
                                          log.action.includes('DEDUCTED') ? 'bg-amber-100 text-amber-700' :
                                          'bg-slate-100 text-slate-700'
                                        }`}>
                                          {log.action.replace(/_/g, ' ')}
                                        </span>
                                      </td>
                                      <td className="px-6 py-4 text-slate-600 font-medium">{log.performedBy}</td>
                                      <td className="px-6 py-4 text-slate-600 truncate max-w-[150px]">{log.itemName}</td>
                                      <td className={`px-6 py-4 font-black ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-400'}`}>
                                          {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '-'}
                                      </td>
                                      <td className="px-6 py-4 text-slate-500 truncate max-w-xs" title={log.details}>{log.details}</td>
                                  </tr>
                              ))
                          )}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

    </Layout>
  );
};

