import React, { useState, useMemo } from 'react';
import { Request, RequestStatus, User, UserRole, InventoryItem, RequestType } from '../types';
import { canVerifyRequest, canProcessRequest, canProcessReturn } from '../services/stateService';
import { CheckCircle2, Clock, AlertTriangle, UserCheck, FileCheck, XCircle, RotateCcw, ThumbsUp, ThumbsDown, Search, ArrowRight, X, Filter, History, ChevronDown, User as UserIcon, ShieldCheck } from 'lucide-react';

interface RequestQueueProps {
  requests: Request[];
  items: InventoryItem[];
  users: User[];
  currentUser: User;
  onClaim: (reqId: string) => void;
  onVerify: (reqId: string) => void;
  onReject: (reqId: string, reason: string) => void;
  onProcess: (reqId: string) => void;
  onReturnAction: (reqId: string, condition: 'Good' | 'Damaged') => void;
  onInitiateReturnById: (itemId: string, qty: number, reason: string, refUID: string) => void;
}

const StatusBadge = ({ status, emergency, type }: { status: RequestStatus, emergency: boolean, type: RequestType }) => {
  if (type === RequestType.TAKE && emergency && status !== RequestStatus.PROCESSED) return <span className="px-2 py-1 rounded text-xs font-bold bg-red-100 text-red-700 border border-red-200">ALREADY TAKEN</span>;
  const styles = {
      [RequestStatus.PENDING]: 'bg-yellow-100 text-yellow-800', [RequestStatus.CLAIMED]: 'bg-blue-100 text-blue-800',
      [RequestStatus.VERIFIED]: 'bg-purple-100 text-purple-800', [RequestStatus.PROCESSED]: 'bg-green-100 text-green-800',
      [RequestStatus.REJECTED]: 'bg-red-100 text-red-800', [RequestStatus.RETURNED]: 'bg-indigo-100 text-indigo-800',
  };
  return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${styles[status] || 'bg-gray-100'}`}>{status}</span>;
};

const RequestCard = ({ req, showActions, items, users, currentUser, onClaim, onVerify, onRejectTrigger, onProcess, onReturnAction }: any) => {
  const item = items.find((i: any) => i.id === req.itemId);
  const isTake = req.type === RequestType.TAKE;
  const canClaim = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.PENDING;
  const canVerify = isTake && canVerifyRequest(currentUser) && req.status === RequestStatus.CLAIMED && req.claimedBy === currentUser.id;
  const canProcess = isTake && canProcessRequest(currentUser) && req.status === RequestStatus.VERIFIED;
  const canActionReturn = !isTake && canProcessReturn(currentUser) && req.status === RequestStatus.PENDING;

  const getAuthorizerName = (id: string) => users.find((u: any) => u.id === id)?.name || id;

  return (
      <div className={`p-4 rounded-lg border shadow-sm flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between transition-all ${req.type === RequestType.RETURN ? 'bg-indigo-50' : 'bg-white'}`}>
          <div className="flex-1">
              <div className="flex items-center gap-3 mb-1"><span className="font-mono text-[10px] bg-slate-100 px-1.5 py-0.5 rounded font-black text-slate-500">{req.requestUID}</span><span className="font-bold text-slate-800">{item?.name || 'Unknown'}</span><StatusBadge status={req.status} emergency={req.isEmergency} type={req.type} /></div>
              <div className="text-sm text-slate-600"><span className="font-semibold text-slate-700">{req.userName}</span> {req.specificPurpose && ` • ${req.specificPurpose}`}</div>
              <div className="flex flex-wrap gap-x-4 gap-y-1 mt-2 pt-2 border-t border-slate-100">
                {req.claimedBy && <div className="text-[10px] text-blue-600 flex items-center gap-1"><UserCheck className="w-3 h-3" /> Claimed: {getAuthorizerName(req.claimedBy)}</div>}
                {req.verifiedBy && <div className="text-[10px] text-purple-600 flex items-center gap-1"><FileCheck className="w-3 h-3" /> Verified: {getAuthorizerName(req.verifiedBy)}</div>}
                {req.processedBy && <div className="text-[10px] text-green-600 flex items-center gap-1"><CheckCircle2 className="w-3 h-3" /> Processed: {getAuthorizerName(req.processedBy)}</div>}
              </div>
          </div>
          {showActions && (
              <div className="flex gap-2">
                  {canClaim && <button onClick={() => onClaim(req.id)} className="px-3 py-1.5 bg-blue-600 text-white text-sm font-medium rounded">Claim</button>}
                  {canVerify && <button onClick={() => onVerify(req.id)} className="px-3 py-1.5 bg-purple-600 text-white text-sm font-medium rounded">Verify</button>}
                  {canProcess && <button onClick={() => onProcess(req.id)} className="px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded">Process</button>}
                  {canActionReturn && <button onClick={() => onReturnAction(req.id, 'Good')} className="px-3 py-1.5 bg-green-600 text-white text-sm font-medium rounded">Accept Good</button>}
              </div>
          )}
      </div>
  );
};

const RequestQueue: React.FC<RequestQueueProps> = ({ requests, items, users, currentUser, onClaim, onVerify, onReject, onProcess, onReturnAction, onInitiateReturnById }) => {
  const [tab, setTab] = useState<'take' | 'return'>('take');
  const [hType, setHType] = useState('all');
  const [hStatus, setHStatus] = useState('all');
  const [hRequester, setHRequester] = useState('all');
  const [hApprover, setHApprover] = useState('all');

  const isStandard = currentUser.role === UserRole.STANDARD;
  const visibleRequests = useMemo(() => isStandard ? requests.filter(r => r.userId === currentUser.id) : requests, [requests, isStandard, currentUser.id]);

  const filteredHistory = useMemo(() => {
    return visibleRequests.filter(r => {
      const tMatch = hType === 'all' || r.type.toLowerCase() === hType;
      const sMatch = hStatus === 'all' || r.status.toLowerCase() === hStatus;
      const rMatch = hRequester === 'all' || r.userId === hRequester;
      const aMatch = hApprover === 'all' || r.verifiedBy === hApprover || r.processedBy === hApprover || r.rejectedBy === hApprover;
      return tMatch && sMatch && rMatch && aMatch;
    });
  }, [visibleRequests, hType, hStatus, hRequester, hApprover]);

  return (
    <div className="space-y-8 pb-20">
        {!isStandard && (
            <div className="space-y-4">
                <div className="flex justify-between items-center"><h2 className="text-xl font-bold">Approval Queue</h2><div className="flex bg-slate-100 p-1 rounded-lg"><button onClick={() => setTab('take')} className={`px-4 py-1 text-sm rounded ${tab === 'take' ? 'bg-white shadow' : ''}`}>Take</button><button onClick={() => setTab('return')} className={`px-4 py-1 text-sm rounded ${tab === 'return' ? 'bg-white shadow' : ''}`}>Return</button></div></div>
                {visibleRequests.filter(r => r.type.toLowerCase() === tab && r.status === RequestStatus.PENDING).map(r => <RequestCard key={r.id} req={r} showActions={true} items={items} users={users} currentUser={currentUser} onClaim={onClaim} onVerify={onVerify} onProcess={onProcess} onReturnAction={onReturnAction} />)}
            </div>
        )}
        <div className="pt-8 border-t"><h3 className="font-bold mb-4">Transaction History</h3>
          <div className="flex flex-wrap gap-2 mb-4">
            <select className="p-2 border rounded text-xs" value={hType} onChange={e => setHType(e.target.value)}><option value="all">All Types</option><option value="take">Take</option><option value="return">Return</option></select>
            <select className="p-2 border rounded text-xs" value={hStatus} onChange={e => setHStatus(e.target.value)}><option value="all">All Status</option><option value="processed">Processed</option><option value="rejected">Rejected</option></select>
            {!isStandard && <select className="p-2 border rounded text-xs" value={hRequester} onChange={e => setHRequester(e.target.value)}><option value="all">All Requesters</option>{users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select>}
            {!isStandard && <select className="p-2 border rounded text-xs" value={hApprover} onChange={e => setHApprover(e.target.value)}><option value="all">All Approvers</option>{users.filter(u => u.role !== UserRole.STANDARD).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select>}
          </div>
          <div className="space-y-2">{filteredHistory.map(r => <RequestCard key={r.id} req={r} showActions={false} items={items} users={users} currentUser={currentUser} />)}</div>
        </div>
    </div>
  );
};

export default RequestQueue;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Request, RequestStatus, WorkPurpose, RequestType } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {
  const currentYear = new Date().getFullYear();
  const [fromYear, setFromYear] = useState(currentYear);
  const [toYear, setToYear] = useState(currentYear);

  const filteredData = useMemo(() => {
    const data = purposes.map(p => {
      const val = requests.filter(r => r.purposeId === p.id && r.status === RequestStatus.PROCESSED).reduce((sum, r) => {
        const item = items.find(i => i.id === r.itemId);
        return sum + (item ? item.price * r.quantity : 0);
      }, 0);
      return { name: p.title, cost: val };
    });
    const total = data.reduce((s, i) => s + i.cost, 0);
    return { data, total };
  }, [items, requests, purposes]);

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  return (
    <div className="space-y-8 pb-10">
      <h2 className="text-2xl font-bold">Financial Intelligence</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-4">Allocation by Project</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={filteredData.data}><CartesianGrid strokeDasharray="3 3" vertical={false} /><XAxis dataKey="name" hide /><YAxis /><Tooltip /><Bar dataKey="cost" fill="#3b82f6" /></BarChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-4">Cost Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart><Pie data={filteredData.data.filter(d => d.cost > 0)} cx="50%" cy="50%" innerRadius={60} outerRadius={80} dataKey="cost">{filteredData.data.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}</Pie><Tooltip /><Legend /></PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FinancialDashboard;

