import React, { useState } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import UserManagementView from './components/UserManagementView';
import MovementsView from './components/MovementsView';
import { InventoryItem, Request, User, RequestStatus, AuditLogEntry, RequestType, Movement } from './types';
import { MOCK_USERS, INITIAL_INVENTORY, INITIAL_REQUESTS, WORK_PURPOSES, MOCK_POS, MOCK_MOVEMENTS } from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [currentView, setCurrentView] = useState('inventory');
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    setCurrentUser(users[(currentIndex + 1) % users.length]);
    setCurrentView('inventory');
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const newReq: Request = { id: generateId(), requestUID: generateRequestUID(requests), itemId, userId: currentUser.id, userName: currentUser.name, quantity: qty, purposeId, specificPurpose: specific, status: RequestStatus.PENDING, type: RequestType.TAKE, isEmergency, timestamp: new Date().toISOString() };
    setRequests(prev => [newReq, ...prev]);
  };

  const handleAddStock = (itemId: string, qty: number, note: string) => {
    setInventory(prev => prev.map(i => i.id === itemId ? { ...i, quantity: i.quantity + qty } : i));
  };

  const handleCreateItem = (newItem: any) => {
    const id = generateId();
    setInventory(prev => [...prev, { ...newItem, id, inventoryUID: generateInventoryUID(inventory) }]);
  };

  const handleAddUser = (user: any) => setUsers(prev => [...prev, { ...user, id: generateId() }]);

  return (
    <Layout currentUser={currentUser} onLogout={handleLogout} currentView={currentView} onChangeView={setCurrentView}>
      {currentView === 'inventory' && <InventoryView items={inventory} currentUser={currentUser} purposes={WORK_PURPOSES} onRequestItem={handleRequestItem} onManualAdjust={() => {}} />}
      {currentView === 'requests' && <RequestQueue requests={requests} items={inventory} users={users} currentUser={currentUser} onClaim={() => {}} onVerify={() => {}} onReject={() => {}} onProcess={() => {}} onReturnAction={() => {}} onInitiateReturnById={() => {}} />}
      {currentView === 'add-inventory' && <AddInventoryView items={inventory} currentUser={currentUser} onAddStock={handleAddStock} onCreateItem={handleCreateItem} />}
      {currentView === 'movements' && <MovementsView movements={movements} currentUser={currentUser} onCreateMovement={() => {}} onUpdateMovement={() => {}} />}
      {currentView === 'financials' && <FinancialDashboard items={inventory} requests={requests} purposes={WORK_PURPOSES} />}
      {currentView === 'procurement' && <ProcurementTable pos={MOCK_POS} />}
      {currentView === 'user-management' && <UserManagementView users={users} currentUser={currentUser} onAddUser={handleAddUser} onUpdateUser={() => {}} onDeleteUser={() => {}} />}
    </Layout>
  );
};

