export default ProcurementTable;

import React, { useState, useMemo } from 'react';
import { PurchaseOrder } from '../types';
import { 
  FileSpreadsheet, 
  FileText, 
  LayoutList, 
  DollarSign, 
  Upload, 
  Eye, 
  CheckCircle2, 
  XCircle, 
  Clock, 
  AlertCircle,
  FileSearch,
  X,
  ChevronDown,
  Filter,
  Calendar,
  ArrowUpDown,
  ListFilter
} from 'lucide-react';

interface ProcurementTableProps {
  pos: PurchaseOrder[];
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);

  // Date Filtering State
  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 10 }, (_, i) => currentYear - i);
  const months = [
    { value: 0, label: 'January' }, { value: 1, label: 'February' },
    { value: 2, label: 'March' }, { value: 3, label: 'April' },
    { value: 4, label: 'May' }, { value: 5, label: 'June' },
    { value: 6, label: 'July' }, { value: 7, label: 'August' },
    { value: 8, label: 'September' }, { value: 9, label: 'October' },
    { value: 10, label: 'November' }, { value: 11, label: 'December' },
  ];

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);

  // New Filter/Sort States
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  const filteredPos = useMemo(() => {
    let result = [...pos];

    // Apply Date Range Filter if not "Show All"
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => {
        const date = new Date(po.prDate);
        return date >= startDate && date <= endDate;
      });
    }

    // Sort by PR Date
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });

    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => {
    return filteredPos.reduce((sum, po) => sum + po.usdAmount, 0);
  }, [filteredPos]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) {
      setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    }
    alert("PDF Uploaded successfully (Simulated)");
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    const isApproved = po.techApprovalStatus === 'Approved';
    const isIssued = po.poStatus === 'Issued';
    const hasPoNo = po.poNumber && po.poNumber.trim() !== '';

    if (isApproved && isIssued && hasPoNo) {
      return {
        remarks: 'Order Received',
        followUp: 'CLOSED'
      };
    }
    return {
      remarks: po.manualRemarks || '-',
      followUp: 'Follow up needed'
    };
  };

  const SelectGroup = ({ label, yearValue, yearSetter, monthValue, monthSetter, disabled }: any) => (
    <div className={`space-y-1.5 flex-1 min-w-[140px] transition-opacity ${disabled ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</label>
      <div className="flex gap-2">
        <div className="relative flex-1">
          <select 
            value={monthValue} 
            onChange={(e) => monthSetter(parseInt(e.target.value))}
            className="w-full pl-3 pr-8 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
          >
            {months.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
          </select>
          <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative w-24">
          <select 
            value={yearValue} 
            onChange={(e) => yearSetter(parseInt(e.target.value))}
            className="w-full pl-3 pr-8 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none appearance-none cursor-pointer"
          >
            {years.map(y => <option key={y} value={y}>{y}</option>)}
          </select>
          <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
        </div>
      </div>
    </div>
  );

  const MasterSheet = () => (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-300">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-[11px] border-collapse min-w-[1200px]">
          <thead className="bg-[#4472C4] text-white font-bold border-b border-slate-300">
            <tr>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PR NO</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Description</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PR Issued By</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PR Created Date</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PR Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Tech Approval Date</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Tech Approval Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO NO</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Remarks</th>
              <th className="px-3 py-3 whitespace-nowrap">Follow Up</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredPos.map(po => {
              const { remarks, followUp } = getDerivedFields(po);
              return (
                <tr 
                  key={po.id} 
                  className="hover:bg-slate-50 cursor-pointer transition-colors group"
                  onClick={() => setSelectedPO(po)}
                >
                  <td className="px-3 py-4 font-black text-blue-600 border-r border-slate-100 group-hover:underline">
                    {po.prNumber}
                    {po.pdfUrl && <FileText className="w-3 h-3 inline ml-1 text-green-500" />}
                  </td>
                  <td className="px-3 py-4 font-medium border-r border-slate-100 truncate max-w-[200px]">{po.description}</td>
                  <td className="px-3 py-4 border-r border-slate-100">{po.issuedBy}</td>
                  <td className="px-3 py-4 border-r border-slate-100 whitespace-nowrap font-bold text-slate-500">{po.prDate}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
                    <span className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-600 font-bold">{po.prStatus}</span>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 whitespace-nowrap">{po.techApprovalDate}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
