                      {po.techApprovalStatus === 'Approved' ? <CheckCircle2 className="w-3 h-3 text-green-500" /> : po.techApprovalStatus === 'Rejected' ? <XCircle className="w-3 h-3 text-red-500" /> : <Clock className="w-3 h-3 text-amber-500" />}
                      <span className={po.techApprovalStatus === 'Approved' ? 'text-green-600' : po.techApprovalStatus === 'Rejected' ? 'text-red-600' : 'text-amber-600'}>
                        {po.techApprovalStatus}
                      </span>
                    </div>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold">{po.poStatus}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-mono font-bold text-slate-900">{po.poNumber || '-'}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold text-slate-600">{remarks}</td>
                  <td className="px-3 py-4">
                    <span className={`px-2 py-1 rounded font-black tracking-tight ${followUp === 'CLOSED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700 animate-pulse'}`}>
                      {followUp}
                    </span>
                  </td>
                </tr>
              );
            })}
            {filteredPos.length === 0 && (
               <tr>
                <td colSpan={11} className="px-6 py-20 text-center text-slate-400 font-medium italic">
                  <ListFilter className="w-12 h-12 text-slate-200 mx-auto mb-3" />
                  No records found for the selected criteria.
                </td>
               </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const AmountsPage = () => (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in duration-300">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm border-collapse">
          <thead className="bg-[#4472C4] text-white font-bold">
            <tr>
              <th className="px-6 py-4">PR NO</th>
              <th className="px-6 py-4">PO NO</th>
              <th className="px-6 py-4">Net Amount</th>
              <th className="px-6 py-4 text-right">$ Amount</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredPos.map(po => (
              <tr key={po.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-black text-slate-800">{po.prNumber}</td>
                <td className="px-6 py-4 font-mono font-bold text-slate-500">{po.poNumber || 'N/A'}</td>
                <td className="px-6 py-4 font-bold text-blue-700">
                  {po.netAmount.toLocaleString()} <span className="text-[10px] text-slate-400 font-black">{po.currency}</span>
                </td>
                <td className="px-6 py-4 text-right font-black text-slate-900">
                  ${po.usdAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ))}
            {filteredPos.length > 0 ? (
              <tr className="bg-slate-50 font-black border-t-2 border-slate-200">
                <td colSpan={3} className="px-6 py-6 text-right text-slate-500 uppercase tracking-widest text-xs">Total Spent ($ Amount)</td>
                <td className="px-6 py-6 text-right text-lg text-blue-700">
                  ${totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                </td>
              </tr>
            ) : (
               <tr>
                <td colSpan={4} className="px-6 py-20 text-center text-slate-400 font-medium italic">
                  <DollarSign className="w-12 h-12 text-slate-200 mx-auto mb-3" />
                  No financial data found for the selected criteria.
                </td>
               </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800 flex items-center gap-2">
            <LayoutList className="w-6 h-6 text-blue-600" />
            Procurement Lifecycle
          </h2>
          <p className="text-sm text-slate-500">Track PR issued items and financial reconciliation.</p>
        </div>

        <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
          <button 
            onClick={() => setActivePage('master')}
            className={`flex items-center gap-2 px-6 py-2 rounded-lg text-xs font-black uppercase tracking-wider transition-all ${activePage === 'master' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <FileSpreadsheet className="w-4 h-4" /> Master Sheet
          </button>
          <button 
            onClick={() => setActivePage('amounts')}
            className={`flex items-center gap-2 px-6 py-2 rounded-lg text-xs font-black uppercase tracking-wider transition-all ${activePage === 'amounts' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <DollarSign className="w-4 h-4" /> Procurement Values
          </button>
        </div>
      </div>

      {/* Advanced Filter & Sorting Control Bar */}
      <div className="bg-white p-4 lg:p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden relative">
        <div className="absolute top-0 left-0 w-1 h-full bg-[#4472C4]"></div>

        <div className="flex flex-col lg:flex-row gap-6">
          {/* Date Controls */}
          <div className="flex flex-col md:flex-row gap-6 items-start md:items-end flex-1">
            <SelectGroup 
              label="From Period" 
              yearValue={fromYear} 
              yearSetter={setFromYear} 
              monthValue={fromMonth} 
              monthSetter={setFromMonth} 
              disabled={showAllData}
            />
            <div className="hidden lg:flex items-center pb-3 text-slate-300">
               <div className="w-4 h-[2px] bg-slate-200"></div>
            </div>
            <SelectGroup 
              label="To Period" 
              yearValue={toYear} 
              yearSetter={setToYear} 
              monthValue={toMonth} 
              monthSetter={setToMonth} 
              disabled={showAllData}
            />
          </div>

          {/* Visibility & Sort Toggles */}
          <div className="flex flex-wrap items-end gap-4 lg:border-l lg:border-slate-100 lg:pl-6">
            {/* Show All Toggle */}
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Global Visibility</label>
              <button 
                onClick={() => setShowAllData(!showAllData)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all border ${showAllData ? 'bg-blue-600 text-white border-blue-600 shadow-lg' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
              >
