                {showAllData ? 'Showing All Data' : 'Show All Data'}
              </button>
            </div>

            {/* Sort Order Toggle */}
            <div className="space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Chronological Sort</label>
              <button 
                onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')}
                className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 transition-all shadow-md"
              >
                <ArrowUpDown className="w-4 h-4" />
                {sortOrder === 'newest' ? 'Newest First' : 'Oldest First'}
              </button>
            </div>
          </div>
        </div>

        {/* Current Filter Badge */}
        {!showAllData && (
          <div className="mt-6 pt-4 border-t border-slate-50 flex items-center gap-3">
             <div className="bg-blue-50 p-2 rounded-lg">
               <Calendar className="w-3 h-3 text-blue-600" />
             </div>
             <p className="text-[10px] font-bold text-slate-500">
               Filtered Range: <span className="text-blue-700 font-black">{months[fromMonth].label} {fromYear} — {months[toMonth].label} {toYear}</span>
             </p>
          </div>
        )}
        {showAllData && (
          <div className="mt-6 pt-4 border-t border-slate-50 flex items-center gap-3">
             <div className="bg-green-50 p-2 rounded-lg">
               <CheckCircle2 className="w-3 h-3 text-green-600" />
             </div>
             <p className="text-[10px] font-black text-green-700 uppercase tracking-widest">Global Database Visibility Enabled</p>
          </div>
        )}
      </div>

      {activePage === 'master' ? <MasterSheet /> : <AmountsPage />}

      {/* Item Detail & PDF Viewer Modal */}
      {selectedPO && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/50">
              <div>
                <h3 className="text-lg font-black text-slate-800 flex items-center gap-2">
                  <FileSearch className="w-5 h-5 text-blue-600" />
                  Request Details: {selectedPO.prNumber}
                </h3>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{selectedPO.description}</p>
              </div>
              <button onClick={() => setSelectedPO(null)} className="text-slate-400 hover:text-slate-600">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-8 space-y-8">
               <div className="grid grid-cols-2 md:grid-cols-3 gap-6">
                  <div className="space-y-1">
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">PR Status</span>
                    <p className="text-sm font-bold text-slate-800">{selectedPO.prStatus}</p>
                  </div>
                  <div className="space-y-1">
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">PO Number</span>
                    <p className="text-sm font-mono font-black text-blue-600">{selectedPO.poNumber || 'PENDING'}</p>
                  </div>
                  <div className="space-y-1">
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Currency Basis</span>
                    <p className="text-sm font-bold text-slate-800">{selectedPO.netAmount.toLocaleString()} {selectedPO.currency}</p>
                  </div>
               </div>

               <div className="space-y-4">
                  <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <FileText className="w-4 h-4 text-blue-600" />
                    PO Document (PDF)
                  </h4>

                  {selectedPO.pdfUrl ? (
                    <div className="bg-slate-50 border border-slate-200 rounded-2xl p-8 flex flex-col items-center justify-center text-center space-y-4">
                        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center">
                          <FileText className="w-10 h-10 text-green-600" />
                        </div>
                        <div>
                          <p className="font-bold text-slate-800">PO_{selectedPO.poNumber || selectedPO.prNumber}.pdf</p>
                          <p className="text-xs text-slate-400">Attached and Verified</p>
                        </div>
                        <div className="flex gap-3">
                          <button className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white font-bold rounded-xl text-xs hover:bg-slate-800 transition-all">
                            <Eye className="w-4 h-4" /> View PDF
                          </button>
                          <button 
                            onClick={() => handleUploadPDF(selectedPO.id)}
                            className="flex items-center gap-2 px-6 py-2 border border-slate-200 text-slate-600 font-bold rounded-xl text-xs hover:bg-slate-50"
                          >
                            <Upload className="w-4 h-4" /> Replace
                          </button>
                        </div>
                    </div>
                  ) : (
                    <div className="bg-amber-50 border-2 border-dashed border-amber-200 rounded-2xl p-10 flex flex-col items-center justify-center text-center space-y-4">
                        <AlertCircle className="w-12 h-12 text-amber-500" />
                        <div>
                          <p className="font-bold text-amber-900">No Document Attached</p>
                          <p className="text-xs text-amber-700 max-w-[250px] mx-auto mt-1">Please upload the official PO PDF for this request to complete the audit cycle.</p>
                        </div>
                        <button 
                          onClick={() => handleUploadPDF(selectedPO.id)}
                          className="flex items-center gap-2 px-8 py-3 bg-amber-600 text-white font-black rounded-xl text-sm shadow-xl shadow-amber-200 hover:bg-amber-700 transition-all active:scale-95"
                        >
                          <Upload className="w-4 h-4" /> Upload PO PDF
                        </button>
                    </div>
                  )}
               </div>

               <div className="pt-4 flex justify-end">
                  <button 
                    onClick={() => setSelectedPO(null)}
                    className="px-8 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200"
                  >
                    Close Details
                  </button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProcurementTable;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import UserManagementView from './components/UserManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Truck, Search, Calendar, Filter, User as UserIcon, Activity, ChevronDown, X } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Audit Filter State ---
  const [auditSearch, setAuditSearch] = useState('');
  const [auditActionFilter, setAuditActionFilter] = useState('All');
  const [auditUserFilter, setAuditUserFilter] = useState('All');
  const [auditFromDate, setAuditFromDate] = useState('');
  const [auditToDate, setAuditToDate] = useState('');

  // --- Actions ---

  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory');
  };

  const createAuditEntry = (action: string, itemId: string, itemName: string, qtyChange: number, details: string) => {
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action,
        itemId,
        itemName,
        quantityChange: qtyChange,
        performedBy: currentUser.name,
        details
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);
    createAuditEntry('MOVEMENT_CREATED', 'N/A', mv.itemCode, 0, `Standalone Move Order ${mv.moveOrderNumber} created for ${mv.itemDescription}.`);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));
    createAuditEntry('MOVEMENT_UPDATED', 'N/A', mv.itemCode, 0, `Move Order ${mv.moveOrderNumber} updated. Remark: ${mv.remarks}`);
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('REQUEST_CREATED', item.id, item.name, 0, `User ${currentUser.name} requested ${qty} units for ${specific} [UID: ${newRequest.requestUID}].`);
    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) purposeId = originalReq.purposeId;
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason,
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('RETURN_INITIATED', item.id, item.name, 0, `User ${currentUser.name} initiated return of ${qty} units. Reason: ${reason} [Ref: ${refUID || 'None'}].`);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_CLAIMED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} claimed Request ${request.requestUID} (Requested by ${request.userName}).`);
  };

  const handleVerify = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_VERIFIED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} verified Request ${request.requestUID}. Ready for final processing.`);
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.REJECTED, rejectedBy: currentUser.id, rejectionReason: reason } : req
    ));

    createAuditEntry('REQUEST_REJECTED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} rejected Request ${request.requestUID}. Reason: ${reason}. Original requester: ${request.userName}.`);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i));
    }

    createAuditEntry('STOCK_DEDUCTED', request.itemId, item?.name || 'Unknown', -request.quantity, `Final processing of ${request.requestUID} by ${currentUser.name}. Stock reduced by ${request.quantity}.`);
    alert(`PROCESSING COMPLETE [${request.requestUID}]`);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: RequestStatus.RETURNED, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          setInventory(prev => prev.map(i => i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i));
      }

      createAuditEntry(condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED', request.itemId, 'Return Action', condition === 'Good' ? request.quantity : 0, `Return ${request.requestUID} finalized by ${currentUser.name}. Condition: ${condition}.`);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    createAuditEntry('INVENTORY_ADJUSTMENT', itemId, item.name, qty, `Manual adjustment by ${currentUser.name}. Change: ${qty}. Note: ${note}. Loc: ${newLocation || item.location}`);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);
      createAuditEntry('ITEM_CREATED', id, newItem.name, newItem.quantity, `New master record created: ${newItem.name} [UID: ${inventoryUID}] with initial stock ${newItem.quantity}.`);
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);
    createAuditEntry('USER_CREATED', 'N/A', 'User System', 0, `New user ${user.name} added with role ${user.role} by ${currentUser.name}.`);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (updatedUser.id === currentUser.id) setCurrentUser(updatedUser);
    createAuditEntry('USER_UPDATED', 'N/A', 'User System', 0, `User permissions/details updated for ${updatedUser.name} by ${currentUser.name}.`);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;
    setUsers(prev => prev.filter(u => u.id !== id));
    createAuditEntry('USER_DELETED', 'N/A', 'User System', 0, `User ${targetUser.name} removed from system by ${currentUser.name}. Reason: ${reason}`);
  };

  // --- Filtered Audit Log ---
  const filteredAuditLog = useMemo(() => {
    return auditLog.filter(log => {
      const search = auditSearch.toLowerCase();
      const matchesSearch = 
        log.performedBy.toLowerCase().includes(search) || 
        log.itemName.toLowerCase().includes(search) || 
        log.details.toLowerCase().includes(search) ||
        log.action.toLowerCase().includes(search);

      const matchesAction = auditActionFilter === 'All' || log.action === auditActionFilter;
      const matchesUser = auditUserFilter === 'All' || log.performedBy === auditUserFilter;

      const logDate = new Date(log.timestamp);
      const matchesFromDate = !auditFromDate || logDate >= new Date(auditFromDate);
      const matchesToDate = !auditToDate || logDate <= new Date(auditToDate + 'T23:59:59');

      return matchesSearch && matchesAction && matchesUser && matchesFromDate && matchesToDate;
    });
  }, [auditLog, auditSearch, auditActionFilter, auditUserFilter, auditFromDate, auditToDate]);

  const auditActionTypes = useMemo(() => ['All', ...Array.from(new Set(auditLog.map(l => l.action)))], [auditLog]);
  const auditUsers = useMemo(() => ['All', ...Array.from(new Set(auditLog.map(l => l.performedBy)))], [auditLog]);

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
        <InventoryView 
            items={inventory} 
            currentUser={currentUser}
            purposes={WORK_PURPOSES}
            onRequestItem={handleRequestItem}
            onManualAdjust={() => {}}
        />
      )}

      {currentView === 'add-inventory' && (
          <AddInventoryView 
              items={inventory}
              currentUser={currentUser}
              onAddStock={handleAddStock}
