import React, { useState, useMemo } from 'react';
import { User, UserRole, WorkPurpose } from '../types';
import { 
  Users, 
  UserPlus, 
  Search, 
  Trash2, 
  Edit3, 
  Shield, 
  ShieldAlert, 
  ShieldCheck, 
  X, 
  ChevronDown, 
  IdCard, 
  AlertCircle, 
  Phone, 
  Briefcase, 
  Plus, 
  Save,
  Trash
} from 'lucide-react';

interface ManagementViewProps {
  users: User[];
  workPurposes: WorkPurpose[];
  currentUser: User;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string, reason: string) => void;
  onAddPurpose: (title: string) => void;
  onUpdatePurpose: (purpose: WorkPurpose) => void;
  onDeletePurpose: (id: string) => void;
}

const ManagementView: React.FC<ManagementViewProps> = ({ 
  users, 
  workPurposes, 
  currentUser, 
  onAddUser, 
  onUpdateUser, 
  onDeleteUser,
  onAddPurpose,
  onUpdatePurpose,
  onDeletePurpose
}) => {
  const [activeTab, setActiveTab] = useState<'users' | 'purposes'>('users');
  const [searchTerm, setSearchTerm] = useState('');

  // Modals for Users
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deletingUser, setDeletingUser] = useState<User | null>(null);

  // User Form States
  const [userName, setUserName] = useState('');
  const [userCardNum, setUserCardNum] = useState('');
  const [userContact, setUserContact] = useState('');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.STANDARD);
  const [isSpecial, setIsSpecial] = useState(false);
  const [deleteReason, setDeleteReason] = useState('');

  // Purpose States
  const [isAddPurposeOpen, setIsAddPurposeOpen] = useState(false);
  const [newPurposeTitle, setNewPurposeTitle] = useState('');
  const [editingPurpose, setEditingPurpose] = useState<WorkPurpose | null>(null);

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.recordCardNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
      u.role.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [users, searchTerm]);

  const filteredPurposes = useMemo(() => {
    return workPurposes.filter(p => p.title.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [workPurposes, searchTerm]);

  // --- User Handlers ---
  const handleAddUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddUser({ name: userName, recordCardNumber: userCardNum, contactNumber: userContact, role: userRole, isSpecialAdmin: isSpecial });
    setIsAddUserModalOpen(false);
  };

  const handleEditUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingUser) {
      onUpdateUser({ ...editingUser, name: userName, recordCardNumber: userCardNum, contactNumber: userContact, role: userRole, isSpecialAdmin: isSpecial });
      setEditingUser(null);
    }
  };

  // --- Purpose Handlers ---
  const handleAddPurposeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPurposeTitle.trim()) {
      onAddPurpose(newPurposeTitle.trim());
      setNewPurposeTitle('');
      setIsAddPurposeOpen(false);
    }
  };

  const handleEditPurposeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingPurpose && newPurposeTitle.trim()) {
      onUpdatePurpose({ ...editingPurpose, title: newPurposeTitle.trim() });
      setEditingPurpose(null);
      setNewPurposeTitle('');
    }
  };

  const getRoleBadge = (role: UserRole, special?: boolean) => {
    const baseClasses = "px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ";
    switch (role) {
      case UserRole.OWNER: return <span className={baseClasses + "bg-purple-100 text-purple-700 border-purple-200"}>Owner</span>;
      case UserRole.ADMIN_L2: return <span className={baseClasses + "bg-red-100 text-red-700 border-red-200"}>Super Admin</span>;
      case UserRole.ADMIN_L1: return (
          <div className="flex gap-1 items-center">
            <span className={baseClasses + "bg-blue-100 text-blue-700 border-blue-200"}>Admin L1</span>
            {special && <span className={baseClasses + "bg-amber-100 text-amber-700 border-amber-200"}>Special</span>}
          </div>
        );
      default: return <span className={baseClasses + "bg-slate-100 text-slate-600 border-slate-200"}>Standard</span>;
    }
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl lg:text-2xl font-bold text-slate-800">System Management</h2>
          <p className="text-sm text-slate-500">Global configurations for personnel and project tracking.</p>
        </div>
        <div className="flex p-1 bg-slate-200/50 rounded-2xl w-full sm:w-auto">
            <button 
              onClick={() => setActiveTab('users')}
              className={`flex-1 sm:flex-none px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'users' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
            >
              Users
            </button>
            <button 
              onClick={() => setActiveTab('purposes')}
              className={`flex-1 sm:flex-none px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'purposes' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
            >
              Work Purposes
            </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 lg:p-6 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="relative w-full max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder={`Search ${activeTab === 'users' ? 'users' : 'purposes'}...`} 
              className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={() => activeTab === 'users' ? setIsAddUserModalOpen(true) : setIsAddPurposeOpen(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-700 transition-all active:scale-95"
          >
            {activeTab === 'users' ? <UserPlus className="w-4 h-4" /> : <Plus className="w-4 h-4" />}
            Add {activeTab === 'users' ? 'User' : 'Purpose'}
          </button>
        </div>

        <div className="overflow-x-auto">
          {activeTab === 'users' ? (
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4">User Details</th>
                  <th className="px-6 py-4">Security Level</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredUsers.map(user => (
                  <tr key={user.id} className="hover:bg-slate-50">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold uppercase">{user.name.charAt(0)}</div>
                        <div>
                          <p className="font-bold text-slate-900">{user.name}</p>
                          <div className="flex items-center gap-3 text-[10px] text-slate-400 font-medium">
                            <IdCard className="w-3 h-3" /> <span>{user.recordCardNumber}</span>
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">{getRoleBadge(user.role, user.isSpecialAdmin)}</td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2">
                        <button onClick={() => { setEditingUser(user); setUserName(user.name); setUserCardNum(user.recordCardNumber); setUserContact(user.contactNumber || ''); setUserRole(user.role); setIsSpecial(!!user.isSpecialAdmin); }} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"><Edit3 className="w-5 h-5" /></button>
                        {user.id !== currentUser.id && <button onClick={() => setDeletingUser(user)} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg"><Trash2 className="w-5 h-5" /></button>}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 text-slate-500 font-bold text-[10px] uppercase tracking-widest border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4">Title / Purpose Name</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredPurposes.map(purpose => (
                  <tr key={purpose.id} className="hover:bg-slate-50">
                    <td className="px-6 py-4 font-bold text-slate-900 flex items-center gap-3">
                      <Briefcase className="w-4 h-4 text-blue-400" />
                      {purpose.title}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2">
                        <button onClick={() => { setEditingPurpose(purpose); setNewPurposeTitle(purpose.title); }} className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"><Edit3 className="w-5 h-5" /></button>
                        <button onClick={() => onDeletePurpose(purpose.id)} className="p-2 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-lg"><Trash className="w-5 h-5" /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* --- Modals for User --- */}
      {(isAddUserModalOpen || editingUser) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-800">{editingUser ? 'Edit User' : 'Create New User'}</h3>
              <button onClick={() => { setIsAddUserModalOpen(false); setEditingUser(null); }} className="text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
            </div>
            <form onSubmit={editingUser ? handleEditUserSubmit : handleAddUserSubmit} className="p-6 space-y-4">
              <input type="text" required placeholder="Full Name" className="w-full border p-3 rounded-xl outline-none" value={userName} onChange={e => setUserName(e.target.value)} />
              <input type="text" required placeholder="Card Number" className="w-full border p-3 rounded-xl outline-none" value={userCardNum} onChange={e => setUserCardNum(e.target.value)} />
              <input type="tel" placeholder="Contact Number" className="w-full border p-3 rounded-xl outline-none" value={userContact} onChange={e => setUserContact(e.target.value)} />
              <select className="w-full border p-3 rounded-xl outline-none font-bold" value={userRole} onChange={e => setUserRole(e.target.value as UserRole)}>
                <option value={UserRole.STANDARD}>Standard User</option>
                <option value={UserRole.ADMIN_L1}>Admin Level 1</option>
                <option value={UserRole.ADMIN_L2}>Super Admin (L2)</option>
              </select>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => { setIsAddUserModalOpen(false); setEditingUser(null); }} className="flex-1 py-3 border rounded-xl font-bold">Cancel</button>
                <button type="submit" className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl">{editingUser ? 'Save' : 'Create'}</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* --- Modals for Purpose --- */}
      {(isAddPurposeOpen || editingPurpose) && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-800">{editingPurpose ? 'Edit Purpose' : 'Add Work Purpose'}</h3>
              <button onClick={() => { setIsAddPurposeOpen(false); setEditingPurpose(null); }} className="text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
            </div>
            <form onSubmit={editingPurpose ? handleEditPurposeSubmit : handleAddPurposeSubmit} className="p-6 space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Purpose Title</label>
                <input 
                  type="text" 
                  required 
                  autoFocus
                  placeholder="e.g. Jetty Rehabilitation Phase 1" 
                  className="w-full border border-slate-200 p-4 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold" 
                  value={newPurposeTitle} 
                  onChange={e => setNewPurposeTitle(e.target.value)} 
                />
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={() => { setIsAddPurposeOpen(false); setEditingPurpose(null); }} className="flex-1 py-3 border rounded-xl font-bold">Cancel</button>
                <button type="submit" className="flex-1 py-3 bg-blue-600 text-white font-bold rounded-xl">
                  {editingPurpose ? 'Update Purpose' : 'Register Purpose'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete User Confirmation */}
      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md p-6 space-y-4">
            <h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 className="w-5 h-5" /> Confirm Deletion</h3>
            <p className="text-sm text-slate-600">Enter reason for deleting user <strong>{deletingUser.name}</strong>:</p>
            <textarea className="w-full border p-3 rounded-xl text-sm" placeholder="Resignation, end of contract..." value={deleteReason} onChange={e => setDeleteReason(e.target.value)} />
            <div className="flex gap-3">
              <button onClick={() => setDeletingUser(null)} className="flex-1 py-3 border rounded-xl">Cancel</button>
              <button onClick={() => { if(deleteReason.trim()){ onDeleteUser(deletingUser.id, deleteReason); setDeletingUser(null); } }} className="flex-1 py-3 bg-red-600 text-white rounded-xl">Confirm Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagementView;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import ManagementView from './components/ManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement,
    WorkPurpose
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Truck, Search, Calendar, Filter, User as UserIcon, Activity, ChevronDown, X } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]); // Default to Standard User
  const [currentView, setCurrentView] = useState('inventory');

  // Data State (Simulating Database)
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [workPurposes, setWorkPurposes] = useState<WorkPurpose[]>(WORK_PURPOSES);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Audit Filter State ---
  const [auditSearch, setAuditSearch] = useState('');
  const [auditActionFilter, setAuditActionFilter] = useState('All');
  const [auditUserFilter, setAuditUserFilter] = useState('All');
  const [auditFromDate, setAuditFromDate] = useState('');
  const [auditToDate, setAuditToDate] = useState('');

  // --- Actions ---

  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory');
  };

  const createAuditEntry = (action: string, itemId: string, itemName: string, qtyChange: number, details: string) => {
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action,
        itemId,
        itemName,
        quantityChange: qtyChange,
        performedBy: currentUser.name,
        details
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);
    createAuditEntry('MOVEMENT_CREATED', 'N/A', mv.itemCode, 0, `Standalone Move Order ${mv.moveOrderNumber} created for ${mv.itemDescription}.`);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));
    createAuditEntry('MOVEMENT_UPDATED', 'N/A', mv.itemCode, 0, `Move Order ${mv.moveOrderNumber} updated. Remark: ${mv.remarks}`);
  };

  const exportAuditLog = () => {
    const headers = ["Timestamp", "Action", "User", "Item", "Change", "Details"];
    const rows = auditLog.map(l => [
      l.timestamp, l.action, l.performedBy, l.itemName, l.quantityChange, `"${l.details.replace(/"/g, '""')}"`
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `SecureTrack_AuditLog_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('REQUEST_CREATED', item.id, item.name, 0, `User ${currentUser.name} requested ${qty} units for ${specific} [UID: ${newRequest.requestUID}].`);
    alert(`Request ${newRequest.requestUID} submitted successfully.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    let purposeId = undefined;
    if (refUID) {
      const originalReq = requests.find(r => r.requestUID === refUID);
      if (originalReq) purposeId = originalReq.purposeId;
    }

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId: purposeId,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason,
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('RETURN_INITIATED', item.id, item.name, 0, `User ${currentUser.name} initiated return of ${qty} units. Reason: ${reason} [Ref: ${refUID || 'None'}].`);
    alert(`Return request ${newRequest.requestUID} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_CLAIMED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} claimed Request ${request.requestUID} (Requested by ${request.userName}).`);
  };

  const handleVerify = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_VERIFIED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} verified Request ${request.requestUID}. Ready for final processing.`);
  };

  const handleReject = (reqId: string, reason: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.REJECTED, rejectedBy: currentUser.id, rejectionReason: reason } : req
    ));

    createAuditEntry('REQUEST_REJECTED', request.itemId, 'Request Action', 0, `Admin ${currentUser.name} rejected Request ${request.requestUID}. Reason: ${reason}. Original requester: ${request.userName}.`);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request || request.type !== RequestType.TAKE) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i));
    }

    createAuditEntry('STOCK_DEDUCTED', request.itemId, item?.name || 'Unknown', -request.quantity, `Final processing of ${request.requestUID} by ${currentUser.name}. Stock reduced by ${request.quantity}.`);
    alert(`PROCESSING COMPLETE [${request.requestUID}]`);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request || request.type !== RequestType.RETURN) return;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: RequestStatus.RETURNED, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          setInventory(prev => prev.map(i => i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i));
      }

      createAuditEntry(condition === 'Good' ? 'RETURN_RESTOCKED' : 'RETURN_DAMAGED', request.itemId, 'Return Action', condition === 'Good' ? request.quantity : 0, `Return ${request.requestUID} finalized by ${currentUser.name}. Condition: ${condition}.`);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { 
          ...i, 
          quantity: i.quantity + qty, 
          description: newDescription !== undefined ? newDescription : i.description,
          location: newLocation !== undefined ? newLocation : i.location
        } : i
    ));

    createAuditEntry('INVENTORY_ADJUSTMENT', itemId, item.name, qty, `Manual adjustment by ${currentUser.name}. Change: ${qty}. Note: ${note}. Loc: ${newLocation || item.location}`);
    alert("Inventory Adjustment Successful");
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      const item: InventoryItem = { ...newItem, id, inventoryUID };
      setInventory(prev => [...prev, item]);
      createAuditEntry('ITEM_CREATED', id, newItem.name, newItem.quantity, `New master record created: ${newItem.name} [UID: ${inventoryUID}] with initial stock ${newItem.quantity}.`);
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: generateId() };
    setUsers(prev => [...prev, newUser]);
    createAuditEntry('USER_CREATED', 'N/A', 'User System', 0, `New user ${user.name} added with role ${user.role} by ${currentUser.name}.`);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (updatedUser.id === currentUser.id) setCurrentUser(updatedUser);
    createAuditEntry('USER_UPDATED', 'N/A', 'User System', 0, `User permissions/details updated for ${updatedUser.name} by ${currentUser.name}.`);
  };

  const handleDeleteUser = (id: string, reason: string) => {
    const targetUser = users.find(u => u.id === id);
    if (!targetUser) return;
    setUsers(prev => prev.filter(u => u.id !== id));
    createAuditEntry('USER_DELETED', 'N/A', 'User System', 0, `User ${targetUser.name} removed from system by ${currentUser.name}. Reason: ${reason}`);
  };

  // --- Work Purpose Actions ---
  const handleAddPurpose = (title: string) => {
    const newPurpose = { id: generateId(), title };
    setWorkPurposes(prev => [...prev, newPurpose]);
    createAuditEntry('PURPOSE_CREATED', 'N/A', 'Work Purpose', 0, `New Work Purpose '${title}' created by ${currentUser.name}.`);
  };

  const handleUpdatePurpose = (purpose: WorkPurpose) => {
    setWorkPurposes(prev => prev.map(p => p.id === purpose.id ? purpose : p));
    createAuditEntry('PURPOSE_UPDATED', 'N/A', 'Work Purpose', 0, `Work Purpose ID ${purpose.id} updated to '${purpose.title}' by ${currentUser.name}.`);
  };

  const handleDeletePurpose = (id: string) => {
    const p = workPurposes.find(p => p.id === id);
    setWorkPurposes(prev => prev.filter(p => p.id !== id));
    createAuditEntry('PURPOSE_DELETED', 'N/A', 'Work Purpose', 0, `Work Purpose '${p?.title}' removed from system by ${currentUser.name}.`);
  };

  // --- Filtered Audit Log ---
  const filteredAuditLog = useMemo(() => {
    return auditLog.filter(log => {
      const search = auditSearch.toLowerCase();
      const matchesSearch = 
        log.performedBy.toLowerCase().includes(search) || 
        log.itemName.toLowerCase().includes(search) || 
        log.details.toLowerCase().includes(search) ||
        log.action.toLowerCase().includes(search);

      const matchesAction = auditActionFilter === 'All' || log.action === auditActionFilter;
      const matchesUser = auditUserFilter === 'All' || log.performedBy === auditUserFilter;

      const logDate = new Date(log.timestamp);
      const matchesFromDate = !auditFromDate || logDate >= new Date(auditFromDate);
      const matchesToDate = !auditToDate || logDate <= new Date(auditToDate + 'T23:59:59');

      return matchesSearch && matchesAction && matchesUser && matchesFromDate && matchesToDate;
    });
  }, [auditLog, auditSearch, auditActionFilter, auditUserFilter, auditFromDate, auditToDate]);

  const auditActionTypes = useMemo(() => ['All', ...Array.from(new Set(auditLog.map(l => l.action)))], [auditLog]);
  const auditUsers = useMemo(() => ['All', ...Array.from(new Set(auditLog.map(l => l.performedBy)))], [auditLog]);

  return (
    <Layout 
      currentUser={currentUser} 
      onLogout={handleLogout}
      currentView={currentView}
      onChangeView={setCurrentView}
    >
      {currentView === 'inventory' && (
