      {currentView === 'requests' && (
        <RequestQueue 
            requests={requests}
            items={inventory}
            users={users}
            currentUser={currentUser}
            onClaim={handleClaim}
            onVerify={handleVerify}
            onReject={handleReject}
            onProcess={handleProcess}
            onReturnAction={handleReturnAction}
            onInitiateReturnById={handleReturnItem}
        />
