                            <tr>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Timestamp</th>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Action Event</th>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Operator</th>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Asset Reference</th>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">± Qty</th>
                                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Audit Trail Details</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {filteredAuditLog.length === 0 ? (
                                <tr>
                                  <td colSpan={6} className="px-6 py-20 text-center text-slate-400 italic">
                                    <Activity className="w-12 h-12 text-slate-100 mx-auto mb-3" />
                                    No audit entries found matching the specified filters.
                                  </td>
                                </tr>
                            ) : (
                                filteredAuditLog.map(log => (
                                    <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="px-6 py-4 text-slate-500 whitespace-nowrap text-xs">
                                          {new Date(log.timestamp).toLocaleDateString()}
                                          <br />
                                          <span className="font-bold">{new Date(log.timestamp).toLocaleTimeString()}</span>
                                        </td>
                                        <td className="px-6 py-4">
                                          <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                                            log.action.includes('REJECTED') || log.action.includes('DELETED') ? 'bg-red-100 text-red-700 border border-red-200' :
                                            log.action.includes('CREATED') || log.action.includes('INITIATED') ? 'bg-blue-100 text-blue-700 border border-blue-200' :
                                            log.action.includes('STOCK_DEDUCTED') ? 'bg-amber-100 text-amber-700 border border-amber-200' :
                                            log.action.includes('VERIFIED') || log.action.includes('CLAIMED') ? 'bg-purple-100 text-purple-700 border-purple-200' :
                                            'bg-slate-100 text-slate-700'
                                          }`}>
                                            {log.action.replace(/_/g, ' ')}
                                          </span>
                                        </td>
                                        <td className="px-6 py-4 text-slate-900 font-bold whitespace-nowrap">{log.performedBy}</td>
                                        <td className="px-6 py-4 text-slate-600 font-medium truncate max-w-[150px]" title={log.itemName}>{log.itemName}</td>
                                        <td className={`px-6 py-4 font-black text-xs ${log.quantityChange < 0 ? 'text-red-600' : log.quantityChange > 0 ? 'text-green-600' : 'text-slate-300'}`}>
                                            {log.quantityChange !== 0 ? (log.quantityChange > 0 ? `+${log.quantityChange}` : log.quantityChange) : '—'}
                                        </td>
                                        <td className="px-6 py-4">
                                           <div className="text-xs text-slate-500 leading-relaxed font-medium min-w-[300px]">
                                              {log.details}
                                           </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                  </div>
              </div>

              {/* Summary Statistics */}
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                  <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Logs in Range</p>
                      <p className="text-2xl font-black text-slate-800">{filteredAuditLog.length}</p>
                  </div>
                  <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Stock Movements</p>
                      <p className="text-2xl font-black text-blue-600">
                        {filteredAuditLog.filter(l => l.quantityChange !== 0).length}
                      </p>
                  </div>
                  <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Admin Approvals</p>
                      <p className="text-2xl font-black text-purple-600">
                        {filteredAuditLog.filter(l => l.action === 'REQUEST_VERIFIED' || l.action === 'STOCK_DEDUCTED').length}
                      </p>
                  </div>
              </div>
          </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { PurchaseOrder } from '../types';
import { 
  FileSpreadsheet, 
  FileText, 
  LayoutList, 
  DollarSign, 
  Upload, 
  Eye, 
  CheckCircle2, 
  XCircle, 
  Clock, 
  AlertCircle,
  FileSearch,
  X,
  ChevronDown,
  Calendar,
  ArrowUpDown,
  ListFilter,
  PieChart as PieChartIcon,
  TrendingUp
} from 'lucide-react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, Legend } from 'recharts';

interface ProcurementTableProps {
  pos: PurchaseOrder[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);

  // Date Filtering State
  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 10 }, (_, i) => currentYear - i);
  const months = [
    { value: 0, label: 'January' }, { value: 1, label: 'February' },
    { value: 2, label: 'March' }, { value: 3, label: 'April' },
    { value: 4, label: 'May' }, { value: 5, label: 'June' },
    { value: 6, label: 'July' }, { value: 7, label: 'August' },
    { value: 8, label: 'September' }, { value: 9, label: 'October' },
    { value: 10, label: 'November' }, { value: 11, label: 'December' },
  ];

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);

  // New Filter/Sort States
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  const filteredPos = useMemo(() => {
    let result = [...pos];

    // Apply Date Range Filter if not "Show All"
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => {
        const date = new Date(po.prDate);
        return date >= startDate && date <= endDate;
      });
    }

    // Sort by PR Date
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });

    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => {
    return filteredPos.reduce((sum, po) => sum + po.usdAmount, 0);
  }, [filteredPos]);

  // Expenditure contribution by Requester
  const contributionData = useMemo(() => {
    const map: Record<string, number> = {};
    filteredPos.forEach(po => {
      map[po.issuedBy] = (map[po.issuedBy] || 0) + po.usdAmount;
    });
    return Object.entries(map)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  }, [filteredPos]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) {
      setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    }
    alert("PDF Uploaded successfully (Simulated)");
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    const isApproved = po.techApprovalStatus === 'Approved';
    const isIssued = po.poStatus === 'Issued';
    const hasPoNo = po.poNumber && po.poNumber.trim() !== '';

    if (isApproved && isIssued && hasPoNo) {
      return {
        remarks: 'Order Received',
        followUp: 'CLOSED'
      };
    }
    return {
      remarks: po.manualRemarks || '-',
      followUp: 'Follow up needed'
    };
  };

  const SelectGroup = ({ label, yearValue, yearSetter, monthValue, monthSetter, disabled }: any) => (
    <div className={`space-y-1.5 flex-1 min-w-[140px] transition-opacity ${disabled ? 'opacity-30 pointer-events-none' : 'opacity-100'}`}>
