              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Tech Approval Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO NO</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Remarks</th>
              <th className="px-3 py-3 whitespace-nowrap">Follow Up</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredPos.map(po => {
