                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 whitespace-nowrap">{po.techApprovalDate}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
                    <div className="flex items-center gap-1.5 font-bold">
                      {po.techApprovalStatus === 'Approved' ? <CheckCircle2 className="w-3 h-3 text-green-500" /> : po.techApprovalStatus === 'Rejected' ? <XCircle className="w-3 h-3 text-red-500" /> : <Clock className="w-3 h-3 text-amber-500" />}
                      <span className={po.techApprovalStatus === 'Approved' ? 'text-green-600' : po.techApprovalStatus === 'Rejected' ? 'text-red-600' : 'text-amber-600'}>
                        {po.techApprovalStatus}
                      </span>
                    </div>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold">{po.poStatus}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-mono font-bold text-slate-900">{po.poNumber || '-'}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold text-slate-600">{remarks}</td>
                  <td className="px-3 py-4">
                    <span className={`px-2 py-1 rounded font-black tracking-tight ${followUp === 'CLOSED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700 animate-pulse'}`}>
                      {followUp}
                    </span>
                  </td>
                </tr>
              );
