  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  VERIFIED = 'Verified',
  PROCESSED = 'Processed',
  REJECTED = 'Rejected',
  RETURNED = 'Returned'
}

export enum RequestType {
  TAKE = 'Take',
  RETURN = 'Return'
}

export interface User {
  id: string;
  name: string;
  recordCardNumber: string;
  contactNumber: string;
