  partNumber: string;
  location: string;
  quantity: number;
  minThreshold: number;
  price: number;
  category: string;
}

export interface WorkPurpose {
  id: string;
  title: string;
}

export interface Request {
  id: string;
  requestUID: string;
  itemId: string;
  userId: string;
  userName: string;
  quantity: number;
  purposeId?: string;
  specificPurpose?: string;
  status: RequestStatus;
  type: RequestType;
  isEmergency: boolean;
  timestamp: string;
  claimedBy?: string;
  verifiedBy?: string;
  processedBy?: string;
  rejectedBy?: string;
  rejectionReason?: string;
  returnCondition?: 'Good' | 'Damaged';
  referenceRequestUID?: string;
