                    </div>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold">{po.poStatus}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-mono font-bold text-slate-900">{po.poNumber || '-'}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold text-slate-600">{remarks}</td>
                  <td className="px-3 py-4">
                    <span className={`px-2 py-1 rounded font-black tracking-tight ${followUp === 'CLOSED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700 animate-pulse'}`}>
                      {followUp}
                    </span>
                  </td>
                </tr>
              );
            })}
            {filteredPos.length === 0 && (
               <tr>
                <td colSpan={12} className="px-6 py-20 text-center text-slate-400 font-medium italic">
                  <ListFilter className="w-12 h-12 text-slate-200 mx-auto mb-3" />
                  No records found for the selected criteria.
                </td>
               </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const AmountsPage = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Contribution Metrics Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div className="space-y-4">
             <div className="bg-blue-50 w-12 h-12 rounded-2xl flex items-center justify-center">
               <TrendingUp className="w-6 h-6 text-blue-600" />
             </div>
             <div>
               <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Aggregate Procurement Value</h3>
               <p className="text-3xl font-black text-slate-900 mt-1">${totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
             </div>
          </div>

          <div className="pt-6 border-t border-slate-50 mt-6">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Expenditure by Work Purpose</h4>
            <div className="space-y-2">
              {contributionData.slice(0, 5).map((item, i) => (
                <div key={item.name} className="flex items-center justify-between">
                   <div className="flex items-center gap-2">
                     <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></div>
                     <span className="text-xs font-bold text-slate-600 truncate max-w-[120px]">{item.name}</span>
                   </div>
                   <span className="text-xs font-black text-slate-900">${item.value.toLocaleString()}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm h-[320px]">
           <div className="flex justify-between items-start mb-4">
             <h3 className="text-sm font-black text-slate-800 flex items-center gap-2">
               <PieChartIcon className="w-4 h-4 text-blue-600" />
