              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PR Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Tech Approval Date</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Tech Approval Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO Status</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">PO NO</th>
              <th className="px-3 py-3 border-r border-white/20 whitespace-nowrap">Remarks</th>
              <th className="px-3 py-3 whitespace-nowrap">Follow Up</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredPos.map(po => {
              const { remarks, followUp } = getDerivedFields(po);
              const purpose = purposes.find(p => p.id === po.purposeId);
              return (
                <tr 
                  key={po.id} 
                  className="hover:bg-slate-50 cursor-pointer transition-colors group"
                  onClick={() => setSelectedPO(po)}
                >
                  <td className="px-3 py-4 font-black text-blue-600 border-r border-slate-100 group-hover:underline">
                    {po.prNumber}
                    {po.pdfUrl && <FileText className="w-3 h-3 inline ml-1 text-green-500" />}
                  </td>
                  <td className="px-3 py-4 font-medium border-r border-slate-100 truncate max-w-[200px]">{po.description}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${purpose ? 'bg-blue-50 text-blue-700' : 'bg-slate-100 text-slate-400'}`}>
                      {purpose ? purpose.title : 'Unallocated'}
                    </span>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100">{po.issuedBy}</td>
                  <td className="px-3 py-4 border-r border-slate-100 whitespace-nowrap font-bold text-slate-500">{po.prDate}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
                    <span className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-600 font-bold">{po.prStatus}</span>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 whitespace-nowrap">{po.techApprovalDate}</td>
                  <td className="px-3 py-4 border-r border-slate-100">
                    <div className="flex items-center gap-1.5 font-bold">
                      {po.techApprovalStatus === 'Approved' ? <CheckCircle2 className="w-3 h-3 text-green-500" /> : po.techApprovalStatus === 'Rejected' ? <XCircle className="w-3 h-3 text-red-500" /> : <Clock className="w-3 h-3 text-amber-500" />}
                      <span className={po.techApprovalStatus === 'Approved' ? 'text-green-600' : po.techApprovalStatus === 'Rejected' ? 'text-red-600' : 'text-amber-600'}>
                        {po.techApprovalStatus}
                      </span>
                    </div>
                  </td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold">{po.poStatus}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-mono font-bold text-slate-900">{po.poNumber || '-'}</td>
                  <td className="px-3 py-4 border-r border-slate-100 font-bold text-slate-600">{remarks}</td>
                  <td className="px-3 py-4">
                    <span className={`px-2 py-1 rounded font-black tracking-tight ${followUp === 'CLOSED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700 animate-pulse'}`}>
                      {followUp}
                    </span>
                  </td>
                </tr>
              );
            })}
            {filteredPos.length === 0 && (
               <tr>
                <td colSpan={12} className="px-6 py-20 text-center text-slate-400 font-medium italic">
                  <ListFilter className="w-12 h-12 text-slate-200 mx-auto mb-3" />
                  No records found for the selected criteria.
                </td>
               </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const AmountsPage = () => (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Contribution Metrics Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between">
