             <div className="bg-blue-50 w-12 h-12 rounded-2xl flex items-center justify-center">
               <TrendingUp className="w-6 h-6 text-blue-600" />
             </div>
             <div>
               <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Aggregate Procurement Value</h3>
               <p className="text-3xl font-black text-slate-900 mt-1">${totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
             </div>
          </div>

          <div className="pt-6 border-t border-slate-50 mt-6">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Expenditure by Work Purpose</h4>
            <div className="space-y-2">
              {contributionData.slice(0, 5).map((item, i) => (
                <div key={item.name} className="flex items-center justify-between">
                   <div className="flex items-center gap-2">
                     <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></div>
                     <span className="text-xs font-bold text-slate-600 truncate max-w-[120px]">{item.name}</span>
                   </div>
                   <span className="text-xs font-black text-slate-900">${item.value.toLocaleString()}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="lg:col-span-2 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm h-[320px]">
           <div className="flex justify-between items-start mb-4">
             <h3 className="text-sm font-black text-slate-800 flex items-center gap-2">
               <PieChartIcon className="w-4 h-4 text-blue-600" />
               Spending Distribution Share
             </h3>
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">By Purpose Allocation</span>
           </div>

           <div className="h-full pb-8">
             {contributionData.length > 0 ? (
               <ResponsiveContainer width="100%" height="100%">
                 <PieChart>
                    <Pie
                      data={contributionData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={90}
                      paddingAngle={5}
                      dataKey="value"
                      animationDuration={1200}
                    >
                      {contributionData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip 
                      contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }}
                      formatter={(value: number) => [`$${value.toLocaleString()}`, 'Total Value']}
                    />
                    <Legend 
                      layout="vertical" 
                      align="right" 
                      verticalAlign="middle"
                      wrapperStyle={{ fontSize: '10px', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '0.05em' }}
                    />
                 </PieChart>
               </ResponsiveContainer>
             ) : (
               <div className="h-full flex items-center justify-center text-slate-300 text-xs font-bold">
                 Insufficient data for visualization
               </div>
             )}
           </div>
        </div>
      </div>

      {/* Detailed Values Table */}
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-[#4472C4] text-white font-bold">
              <tr>
                <th className="px-6 py-4">PR NO</th>
                <th className="px-6 py-4">PO NO</th>
                <th className="px-6 py-4">Assigned Purpose</th>
                <th className="px-6 py-4">Issued By</th>
                <th className="px-6 py-4">Net Amount</th>
                <th className="px-6 py-4 text-right">$ Amount</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredPos.map(po => {
                const purpose = purposes.find(p => p.id === po.purposeId);
                return (
                  <tr 
                    key={po.id} 
                    className="hover:bg-slate-50 transition-colors cursor-pointer group"
                    onClick={() => setSelectedPO(po)}
                  >
