import React, { useState, useMemo } from 'react';
import { InventoryItem, User, UserRole, WorkPurpose } from '../types';
import { Search, Info, Box, MapPin, Tag, Fingerprint, X, AlertCircle, CheckCircle2, Filter, FileSpreadsheet, ChevronDown } from 'lucide-react';
import { canViewPrices, canViewThreshold } from '../services/stateService';

const HeaderCell = ({ label, className = "" }: { label: string; className?: string }) => (
  <th className={`px-4 py-3 border-r border-slate-400 last:border-r-0 ${className}`}>
    <span className="font-bold text-slate-900 text-xs whitespace-nowrap uppercase">{label}</span>
  </th>
);

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, onRequestItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [activeItems, setActiveItems] = useState<InventoryItem[]>([]);
  const [mode, setMode] = useState<'request' | 'info'>('request');

  const isSuperAdmin = currentUser.role === UserRole.ADMIN_L2;

  const [statusFilter, setStatusFilter] = useState<'all' | 'low' | 'out'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('All Categories');

  const [reqQtyMap, setReqQtyMap] = useState<Record<string, number>>({});
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);

  const categories = useMemo(() => {
    const cats = new Set(items.map(i => i.category));
    return ['All Categories', ...Array.from(cats)];
  }, [items]);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      const search = searchTerm.toLowerCase();
      const matchesSearch = (
        item.name.toLowerCase().includes(search) ||
        item.itemCode.toLowerCase().includes(search) ||
        item.partNumber.toLowerCase().includes(search) ||
        item.inventoryUID.toLowerCase().includes(search) ||
        item.description.toLowerCase().includes(search) ||
        item.location.toLowerCase().includes(search)
      );
      const matchesCategory = categoryFilter === 'All Categories' || item.category === categoryFilter;
      let matchesStatus = true;
      if (statusFilter === 'low') matchesStatus = item.quantity <= item.minThreshold && item.quantity > 0;
      if (statusFilter === 'out') matchesStatus = item.quantity === 0;
      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [items, searchTerm, categoryFilter, statusFilter]);

  const exportToExcel = () => {
    const headers = ["UID", "Code", "Name", "P/N", "Category", "Location", "Quantity", "Price"];
    const rows = filteredItems.map(i => [
      i.inventoryUID, i.itemCode, i.name, i.partNumber, i.category, i.location, i.quantity, i.price
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `Inventory_Export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const toggleSelect = (id: string) => {
    if (isSuperAdmin) return;
    const newSelection = new Set(selectedIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedIds(newSelection);
  };

  const openModal = (itemsToAct: InventoryItem[], action: 'request' | 'info') => {
    const finalAction = isSuperAdmin ? 'info' : action;
    setActiveItems(itemsToAct);
    setMode(finalAction);
    const initialQtys: Record<string, number> = {};
    itemsToAct.forEach(i => initialQtys[i.id] = 1);
    setReqQtyMap(initialQtys);
    setReqPurpose('');
    setReqSpecific('');
    setIsEmergency(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isSuperAdmin) return;
    if (activeItems.length > 0) {
      activeItems.forEach(item => {
        const qty = reqQtyMap[item.id] || 1;
        onRequestItem(item.id, qty, reqPurpose, reqSpecific, isEmergency);
      });
      setActiveItems([]);
      setSelectedIds(new Set());
    }
  };

  return (
    <div className="space-y-4 lg:space-y-6 pb-24">
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6">
        <div className="space-y-4 flex-1">
          <div>
              <h2 className="text-xl lg:text-2xl font-bold text-slate-800">Inventory Dashboard</h2>
              <p className="text-sm text-slate-500">Secure track of industrial assets and procurement.</p>
          </div>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input type="text" placeholder="UID, code, name, desc..." className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-base text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <div className="relative">
              <select value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)} className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 border border-slate-300 rounded-xl bg-white text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none shadow-sm cursor-pointer">
                {categories.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>
        <div className="flex flex-wrap gap-2">
            <button onClick={exportToExcel} className="flex items-center gap-2 px-4 py-2 bg-green-50 text-green-700 border border-green-200 rounded-xl text-xs font-bold hover:bg-green-100 transition-all">
              <FileSpreadsheet className="w-4 h-4" /> Export CSV
            </button>
        </div>
      </div>

      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
          <button onClick={() => setStatusFilter('all')} className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'all' ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}>All Items ({items.length})</button>
          <button onClick={() => setStatusFilter('low')} className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'low' ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}>Low Stock ({items.filter(i => i.quantity <= i.minThreshold && i.quantity > 0).length})</button>
          <button onClick={() => setStatusFilter('out')} className={`px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${statusFilter === 'out' ? 'bg-red-100 text-red-700 border-red-200' : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}`}>Out of Stock ({items.filter(i => i.quantity === 0).length})</button>
      </div>

      {selectedIds.size > 0 && !isSuperAdmin && (
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-[90%] max-w-2xl bg-slate-900 text-white rounded-2xl shadow-2xl p-4 flex items-center justify-between z-[60] animate-in slide-in-from-bottom duration-300">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center font-bold text-lg">{selectedIds.size}</div>
             <div>
                <p className="font-bold text-sm">Items Selected</p>
                <button onClick={() => setSelectedIds(new Set())} className="text-[10px] text-slate-400 hover:text-white uppercase font-black tracking-widest">Clear Selection</button>
             </div>
          </div>
          <div className="flex gap-2">
             {selectedIds.size === 1 && (
               <button onClick={() => { const item = items.find(i => i.id === Array.from(selectedIds)[0]); if (item) openModal([item], 'info'); }} className="hidden sm:flex items-center gap-2 px-4 py-2 rounded-xl bg-slate-800 hover:bg-slate-700 font-bold text-sm transition-colors border border-slate-700">
                 <Info className="w-4 h-4" /> Info
               </button>
             )}
             <button onClick={() => openModal(items.filter(i => selectedIds.has(i.id)), 'request')} className="flex items-center gap-2 px-6 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 font-bold text-sm shadow-lg transition-transform active:scale-95">Request Access</button>
          </div>
        </div>
      )}

      <div className="hidden lg:block bg-white rounded-xl shadow-lg border border-slate-400 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-[#FFD966] border-b-2 border-slate-600">
              <tr>
                <th className="px-4 py-3 border-r border-slate-400 w-10 text-center"></th>
