interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {
  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 5 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);

  const filteredData = useMemo(() => {
    const startDate = new Date(fromYear, fromMonth, 1);
    const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
    const processedTakes = requests.filter(r => r.status === RequestStatus.PROCESSED && r.type === RequestType.TAKE && new Date(r.timestamp) >= startDate && new Date(r.timestamp) <= endDate);
    const returnedItems = requests.filter(r => r.status === RequestStatus.RETURNED && r.type === RequestType.RETURN && new Date(r.timestamp) >= startDate && new Date(r.timestamp) <= endDate);
    const purposeCosts = purposes.map(purpose => {
      const takesVal = processedTakes.filter(r => r.purposeId === purpose.id).reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
      const returnsVal = returnedItems.filter(r => r.purposeId === purpose.id).reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
      return { name: purpose.title, cost: Math.max(0, takesVal - returnsVal) };
    });
    const totalTakes = processedTakes.reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
    const totalReturns = returnedItems.reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
    return { purposeCosts, totalSpent: totalTakes - totalReturns, totalReturns, takesCount: processedTakes.length };
  }, [fromYear, fromMonth, toYear, toMonth, requests, items, purposes]);

  const totalInventoryValue = useMemo(() => items.reduce((sum, item) => sum + (item.price * item.quantity), 0), [items]);

  return (
    <div className="space-y-4 lg:space-y-8 pb-10">
      <div className="flex flex-col sm:flex-row justify-between gap-4"><h2 className="text-xl lg:text-2xl font-bold text-slate-800">Financial Intelligence</h2><div className="bg-blue-600 text-white px-4 py-2 rounded-xl text-xs font-bold shadow-lg flex items-center gap-2"><RefreshCw className="w-3 h-3" /> Auto-Updating</div></div>
      <div className="bg-white p-4 lg:p-6 rounded-2xl border border-slate-200 relative"><div className="absolute top-0 left-0 w-1 h-full bg-blue-600"></div><h3 className="text-sm font-bold text-slate-800 uppercase mb-4 flex items-center gap-2"><Filter className="w-4 h-4 text-blue-600" /> Select Financial Period</h3><div className="flex flex-wrap gap-6 items-end"><SelectGroup label="From" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} /><SelectGroup label="To" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} /><div className="bg-blue-50 px-4 py-2 rounded-xl border border-blue-100 flex items-center gap-2"><Calendar className="w-4 h-4 text-blue-500" /><span className="text-xs font-bold text-blue-700">{MONTHS[fromMonth].label} {fromYear} — {MONTHS[toMonth].label} {toYear}</span></div></div></div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4"><div className="bg-white p-6 rounded-2xl border"><h3 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2"><Landmark className="w-3 h-3" /> Asset Value</h3><p className="text-2xl font-black mt-1">${totalInventoryValue.toLocaleString()}</p></div><div className="bg-white p-6 rounded-2xl border"><h3 className="text-xs font-bold text-slate-400 uppercase flex items-center gap-2"><TrendingUp className="w-3 h-3 text-blue-500" /> Net Spent</h3><p className="text-2xl font-black text-blue-600 mt-1">${filteredData.totalSpent.toLocaleString()}</p></div><div className="bg-white p-6 rounded-2xl border"><h3 className="text-xs font-bold text-slate-400 uppercase">Returns</h3><p className="text-2xl font-black text-green-600 mt-1">${filteredData.totalReturns.toLocaleString()}</p></div><div className="bg-white p-6 rounded-2xl border"><h3 className="text-xs font-bold text-slate-400 uppercase">Transactions</h3><p className="text-2xl font-black text-purple-600 mt-1">{filteredData.takesCount}</p></div></div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8"><div className="bg-white p-4 lg:p-8 rounded-2xl border h-[450px]"><h3 className="text-lg font-bold mb-6">Allocation by Purpose (Net)</h3><ResponsiveContainer width="100%" height="85%"><BarChart data={filteredData.purposeCosts} margin={{ bottom: 80 }}><CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" /><XAxis dataKey="name" tick={{fontSize: 10, fontWeight: 700}} interval={0} angle={-45} textAnchor="end" stroke="#94a3b8" /><YAxis stroke="#94a3b8" tick={{fontSize: 10, fontWeight: 700}} /><Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}} formatter={(value: number) => [`$${value.toLocaleString()}`, 'Net Spend']} /><Bar dataKey="cost" fill="#3b82f6" radius={[8, 8, 0, 0]} /></BarChart></ResponsiveContainer></div><div className="bg-white p-4 lg:p-8 rounded-2xl border h-[450px]"><h3 className="text-lg font-bold mb-6">Cost Distribution</h3><ResponsiveContainer width="100%" height="85%"><PieChart><Pie data={filteredData.purposeCosts.filter(d => d.cost > 0)} cx="50%" cy="45%" innerRadius={70} outerRadius={110} paddingAngle={5} dataKey="cost">{filteredData.purposeCosts.filter(d => d.cost > 0).map((entry, index) => (<Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />))}</Pie><Tooltip contentStyle={{borderRadius: '16px', border: 'none'}} formatter={(value: number) => [`$${value.toLocaleString()}`, 'Share']} /><Legend verticalAlign="bottom" height={40} iconType="circle" wrapperStyle={{fontSize: '11px', fontWeight: 700, paddingTop: '30px'}} /></PieChart></ResponsiveContainer></div></div>
    </div>
  );
};

