interface ProcurementTableProps {
  pos: PurchaseOrder[];
  purposes: WorkPurpose[];
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos, purposes }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);

  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 10 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  const filteredPos = useMemo(() => {
    let result = [...pos];
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => { const date = new Date(po.prDate); return date >= startDate && date <= endDate; });
    }
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });
    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => filteredPos.reduce((sum, po) => sum + po.usdAmount, 0), [filteredPos]);
  const contributionData = useMemo(() => {
    const map: Record<string, number> = {};
    filteredPos.forEach(po => {
      const purpose = purposes.find(p => p.id === po.purposeId);
      const label = purpose ? purpose.title : 'Unallocated';
      map[label] = (map[label] || 0) + po.usdAmount;
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [filteredPos, purposes]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    alert("PDF Uploaded (Simulated)");
  };

  const handleAssignPurpose = (poId: string, purposeId: string) => {
    setPos(prev => prev.map(p => p.id === poId ? { ...p, purposeId } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, purposeId } : null);
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    if (po.techApprovalStatus === 'Approved' && po.poStatus === 'Issued' && po.poNumber?.trim()) return { remarks: 'Order Received', followUp: 'CLOSED' };
    return { remarks: po.manualRemarks || '-', followUp: 'Follow up needed' };
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col lg:flex-row justify-between items-start gap-4">
        <div><h2 className="text-xl lg:text-2xl font-bold text-slate-800 flex items-center gap-2"><LayoutList className="w-6 h-6 text-blue-600" /> Procurement Lifecycle</h2></div>
        <div className="flex bg-white p-1 rounded-xl border"><button onClick={() => setActivePage('master')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-xs font-black uppercase transition-all ${activePage === 'master' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}><FileSpreadsheet className="w-4 h-4" /> Master Sheet</button><button onClick={() => setActivePage('amounts')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-xs font-black uppercase transition-all ${activePage === 'amounts' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}><DollarSign className="w-4 h-4" /> Values</button></div>
      </div>
      <div className="bg-white p-4 lg:p-6 rounded-2xl border relative"><div className="absolute top-0 left-0 w-1 h-full bg-[#4472C4]"></div><div className="flex flex-col lg:flex-row gap-6"><div className="flex flex-col md:flex-row gap-6 items-end flex-1"><SelectGroup label="From" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} disabled={showAllData} /><SelectGroup label="To" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} disabled={showAllData} /></div><div className="flex flex-wrap items-end gap-4"><button onClick={() => setShowAllData(!showAllData)} className={`px-4 py-2 rounded-xl text-xs font-bold border ${showAllData ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600'}`}>{showAllData ? 'Showing All' : 'Show All'}</button><button onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold">Sort: {sortOrder}</button></div></div></div>
      {activePage === 'master' ? <MasterSheet filteredPos={filteredPos} purposes={purposes} setSelectedPO={setSelectedPO} getDerivedFields={getDerivedFields} /> : <AmountsPage filteredPos={filteredPos} purposes={purposes} totalSpent={totalSpent} contributionData={contributionData} setSelectedPO={setSelectedPO} />}
      {selectedPO && (
        <div className="fixed inset-0 bg-slate-900/60 z-[200] flex items-center justify-center p-4"><div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden"><div className="p-6 border-b flex justify-between items-center bg-blue-50/50"><div><h3 className="text-lg font-black text-slate-800 flex items-center gap-2"><FileSearch className="w-5 h-5 text-blue-600" /> {selectedPO.prNumber}</h3></div><button onClick={() => setSelectedPO(null)} className="text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button></div>
            <div className="p-8 space-y-8"><div className="grid grid-cols-2 md:grid-cols-3 gap-6"><div><span className="text-[9px] font-black text-slate-400 uppercase">PR Status</span><p className="text-sm font-bold">{selectedPO.prStatus}</p></div><div><span className="text-[9px] font-black text-slate-400 uppercase">PO NO</span><p className="text-sm font-mono font-black text-blue-600">{selectedPO.poNumber || 'PENDING'}</p></div><div><span className="text-[9px] font-black text-slate-400 uppercase">Amount</span><p className="text-sm font-bold">{selectedPO.netAmount.toLocaleString()} {selectedPO.currency}</p></div></div>
               <div className="space-y-3 bg-slate-50 p-4 rounded-2xl"><label className="text-[10px] font-black uppercase flex items-center gap-2"><Briefcase className="w-3 h-3 text-blue-600" /> Assign Purpose</label><select value={selectedPO.purposeId || ''} onChange={(e) => handleAssignPurpose(selectedPO.id, e.target.value)} className="w-full p-3 border rounded-xl text-sm font-bold"><option value="">Unallocated...</option>{purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}</select></div>
               <div className="space-y-4"><h4 className="text-xs font-black uppercase flex items-center gap-2"><FileText className="w-4 h-4 text-blue-600" /> Document</h4>
                  {selectedPO.pdfUrl ? (<div className="bg-slate-50 border p-8 rounded-2xl flex flex-col items-center gap-4"><FileText className="w-10 h-10 text-green-600" /><div className="flex gap-3"><button className="px-6 py-2 bg-slate-900 text-white font-bold rounded-xl text-xs">View PDF</button><button onClick={() => handleUploadPDF(selectedPO.id)} className="px-6 py-2 border rounded-xl text-xs">Replace</button></div></div>) : (<div className="bg-amber-50 border-2 border-dashed border-amber-200 p-10 rounded-2xl flex flex-col items-center gap-4"><AlertCircle className="w-12 h-12 text-amber-500" /><button onClick={() => handleUploadPDF(selectedPO.id)} className="px-8 py-3 bg-amber-600 text-white font-black rounded-xl text-sm">Upload PDF</button></div>)}
               </div><div className="flex justify-end"><button onClick={() => setSelectedPO(null)} className="px-8 py-3 bg-slate-100 font-bold rounded-xl">Close</button></div></div></div></div>
      )}
    </div>
  );
};

