};

// Helper to generate IDs
export const generateId = () => Math.random().toString(36).substr(2, 9);

// Helper to generate Unique Inventory Internal Codes (ST-XXXX)
export const generateInventoryUID = (currentItems: InventoryItem[]) => {
  const existingUids = currentItems.map(item => item.inventoryUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/ST-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `ST-${nextNumber}`;
};

// Helper to generate Unique Request Internal Codes (REQ-XXXX)
export const generateRequestUID = (currentRequests: Request[]) => {
  const existingUids = currentRequests.map(req => req.requestUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/REQ-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `REQ-${nextNumber}`;
};

