  const canRegisterNew = canCreateNewItem(currentUser);
  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');
  const [addLocation, setAddLocation] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: ''
  });

  const [previewUID, setPreviewUID] = useState('');

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
      setAddLocation(selectedItem.location || '');
      setAddQty(0);
      setAddNote('');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') setPreviewUID(generateInventoryUID(items));
  }, [activeTab, items]);

  const filteredItems = items.filter(item => {
    const s = searchTerm.toLowerCase();
    return item.name.toLowerCase().includes(s) || item.itemCode.toLowerCase().includes(s) || item.inventoryUID.toLowerCase().includes(s);
  });

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.category) return alert("Please select a category.");
    onCreateItem(newItem);
    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '' });
    setActiveTab('existing');
  };

  if (isReadOnly) return <div className="p-8 text-center text-slate-500">ReadOnly Access.</div>;

  return (
    <div className="space-y-6 pb-20">
      <h2 className="text-xl font-bold">Manage Stock</h2>
      <div className="flex p-1 bg-slate-200 rounded-2xl">
          <button onClick={() => setActiveTab('existing')} className={`flex-1 py-3 font-bold rounded-xl ${activeTab === 'existing' ? 'bg-white text-blue-600' : 'text-slate-500'}`}>Stock Adjustment</button>
          {canRegisterNew && <button onClick={() => setActiveTab('new')} className={`flex-1 py-3 font-bold rounded-xl ${activeTab === 'new' ? 'bg-white text-blue-600' : 'text-slate-500'}`}>New Item Registration</button>}
      </div>

      {activeTab === 'existing' ? (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-4">
                  <div className="relative"><Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" /><input type="text" placeholder="Search..." className="w-full pl-10 pr-4 py-3 border rounded-xl" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
                  <div className="bg-white rounded-2xl border divide-y overflow-y-auto max-h-[500px]">
                      {filteredItems.map(item => (
                          <div key={item.id} onClick={() => setSelectedItem(item)} className={`p-4 cursor-pointer hover:bg-slate-50 ${selectedItem?.id === item.id ? 'bg-blue-50 border-l-4 border-l-blue-600' : ''}`}>
                              <span className="text-xs font-mono font-black text-blue-600">{item.inventoryUID}</span>
                              <div className="font-bold text-slate-800">{item.name}</div>
                          </div>
                      ))}
                  </div>
              </div>
              <div className="bg-white p-6 rounded-2xl border h-fit">
                  {selectedItem ? (
                      <form onSubmit={e => { e.preventDefault(); onAddStock(selectedItem.id, addQty || 0, addNote, addDescription, addLocation); setSelectedItem(null); }} className="space-y-5">
                          <div className="bg-slate-50 p-4 rounded-xl font-black text-slate-900">{selectedItem.name}</div>
                          <input type="text" placeholder="Update Location" className="w-full border p-3 rounded-xl" value={addLocation} onChange={e => setAddLocation(e.target.value)} />
                          <textarea placeholder="Update Description" className="w-full border p-3 rounded-xl" value={addDescription} onChange={e => setAddDescription(e.target.value)} />
                          <input type="number" placeholder="Qty Change" className="w-full border p-3 rounded-xl font-bold" value={addQty === 0 ? '' : addQty} onChange={e => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} />
                          <input type="text" required={addQty !== 0} placeholder="Internal Note" className="w-full border p-3 rounded-xl" value={addNote} onChange={e => setAddNote(e.target.value)} />
                          <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-xl">Confirm Updates</button>
                      </form>
                  ) : <p className="text-center text-slate-400 py-10 font-bold uppercase tracking-widest">Select an item to begin</p>}
              </div>
          </div>
      ) : (
          <div className="bg-white p-10 rounded-3xl border max-w-2xl mx-auto shadow-sm">
              <form onSubmit={handleCreateSubmit} className="space-y-6">
                  <div className="flex justify-between items-center"><h3 className="text-lg font-bold">Register Asset</h3><span className="font-mono bg-blue-600 text-white px-2 py-1 rounded text-xs">{previewUID}</span></div>
                  <div className="grid grid-cols-2 gap-4">
                      <input type="text" required placeholder="Item Code" className="w-full border p-3 rounded-xl" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                      <input type="text" required placeholder="Part Number" className="w-full border p-3 rounded-xl" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                  </div>
                  <input type="text" required placeholder="Full Name" className="w-full border p-3 rounded-xl" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                  <div className="relative">
                    <select required className="w-full border p-3 rounded-xl font-bold appearance-none bg-white pr-10" value={newItem.category} onChange={e => setNewItem({...newItem, category: e.target.value})}>
                      <option value="">Select Category...</option>
                      {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 pointer-events-none" />
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                      <input type="number" required placeholder="Opening Qty" className="w-full border p-3 rounded-xl" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: parseInt(e.target.value) || 0})} />
                      <input type="number" required placeholder="Min Alert" className="w-full border p-3 rounded-xl" value={newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: parseInt(e.target.value) || 0})} />
                      <input type="number" step="0.01" required placeholder="Unit Price" className="w-full border p-3 rounded-xl" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: parseFloat(e.target.value) || 0})} />
                  </div>
                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-xl">Register Item</button>
              </form>
          </div>
      )}
    </div>
  );
};

export default AddInventoryView;

import React, { useState, useMemo } from 'react';
import { User, UserRole, WorkPurpose, InventoryCategory } from '../types';
import { 
  Users, UserPlus, Search, Trash2, Edit3, Shield, ShieldAlert, ShieldCheck, 
  X, ChevronDown, IdCard, AlertCircle, Phone, Briefcase, Plus, Save, Trash, Tag
} from 'lucide-react';

interface ManagementViewProps {
  users: User[];
  workPurposes: WorkPurpose[];
  categories: InventoryCategory[];
  currentUser: User;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string, reason: string) => void;
  onAddPurpose: (title: string) => void;
  onUpdatePurpose: (purpose: WorkPurpose) => void;
  onDeletePurpose: (id: string) => void;
  onAddCategory: (name: string) => void;
  onUpdateCategory: (cat: InventoryCategory) => void;
  onDeleteCategory: (id: string) => void;
}

const ManagementView: React.FC<ManagementViewProps> = ({ 
  users, workPurposes, categories, currentUser, 
  onAddUser, onUpdateUser, onDeleteUser,
  onAddPurpose, onUpdatePurpose, onDeletePurpose,
  onAddCategory, onUpdateCategory, onDeleteCategory
}) => {
  const [activeTab, setActiveTab] = useState<'users' | 'purposes' | 'categories'>('users');
  const [searchTerm, setSearchTerm] = useState('');

  // Modals for User
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deletingUser, setDeletingUser] = useState<User | null>(null);
  const [userForm, setUserForm] = useState({ name: '', card: '', phone: '', role: UserRole.STANDARD, special: false });
  const [deleteReason, setDeleteReason] = useState('');

  // Form for Purpose/Category
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<{id: string, name: string} | null>(null);
  const [formName, setFormName] = useState('');

  const isOwner = currentUser.role === UserRole.OWNER;

  const filteredItems = useMemo(() => {
    const s = searchTerm.toLowerCase();
    if (activeTab === 'users') return users.filter(u => u.name.toLowerCase().includes(s) || u.recordCardNumber.toLowerCase().includes(s));
    if (activeTab === 'purposes') return workPurposes.filter(p => p.title.toLowerCase().includes(s));
    return categories.filter(c => c.name.toLowerCase().includes(s));
  }, [activeTab, users, workPurposes, categories, searchTerm]);

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const data = { name: userForm.name, recordCardNumber: userForm.card, contactNumber: userForm.phone, role: userForm.role, isSpecialAdmin: userForm.special };
    if (editingUser) onUpdateUser({ ...editingUser, ...data });
    else onAddUser(data);
    setIsAddUserModalOpen(false);
    setEditingUser(null);
  };

  const handleSimpleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formName.trim()) return;
    if (activeTab === 'purposes') {
      if (editingItem) onUpdatePurpose({ id: editingItem.id, title: formName });
      else onAddPurpose(formName);
    } else {
      if (editingItem) onUpdateCategory({ id: editingItem.id, name: formName });
      else onAddCategory(formName);
    }
    setIsAddModalOpen(false);
    setEditingItem(null);
  };

  const getRoleBadge = (role: UserRole, special?: boolean) => {
    const base = "px-2 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider border ";
    if (role === UserRole.OWNER) return <span className={base + "bg-purple-100 text-purple-700 border-purple-200"}>Owner</span>;
    if (role === UserRole.ADMIN_L2) return <span className={base + "bg-red-100 text-red-700 border-red-200"}>Super Admin</span>;
    if (role === UserRole.ADMIN_L1) return <span className={base + "bg-blue-100 text-blue-700 border-blue-200"}>Admin L1 {special ? '(Special)' : ''}</span>;
    return <span className={base + "bg-slate-100 text-slate-600 border-slate-200"}>Standard</span>;
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <div><h2 className="text-xl lg:text-2xl font-bold">System Management</h2></div>
        <div className="flex p-1 bg-slate-200 rounded-2xl overflow-x-auto max-w-full">
            <button onClick={() => setActiveTab('users')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase ${activeTab === 'users' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}>Personnel</button>
            <button onClick={() => setActiveTab('purposes')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase ${activeTab === 'purposes' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}>Work Purposes</button>
            {isOwner && <button onClick={() => setActiveTab('categories')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase ${activeTab === 'categories' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}>Inventory Categories</button>}
        </div>
      </div>

      <div className="bg-white rounded-3xl border shadow-sm overflow-hidden">
        <div className="p-6 bg-slate-50/50 flex justify-between items-center gap-4 border-b">
          <input type="text" placeholder="Search..." className="flex-1 p-3 border rounded-xl" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
          <button onClick={() => { if(activeTab === 'users') { setIsAddUserModalOpen(true); setUserForm({name:'',card:'',phone:'',role:UserRole.STANDARD,special:false}); } else { setIsAddModalOpen(true); setFormName(''); setEditingItem(null); } }} className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2"><Plus className="w-4 h-4" /> Add</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 font-black text-[10px] uppercase border-b text-slate-400">
              <tr>
                <th className="px-6 py-4">{activeTab === 'users' ? 'User Identity' : 'Configuration Entry'}</th>
                {activeTab === 'users' && <th className="px-6 py-4">Authorization</th>}
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {filteredItems.map((item: any) => (
                <tr key={item.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 font-bold flex items-center gap-3">
                    {activeTab === 'users' ? (<><div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center">{item.name.charAt(0)}</div><div>{item.name}<div className="text-[10px] text-slate-400">RC: {item.recordCardNumber}</div></div></>) : (activeTab === 'purposes' ? <Briefcase className="w-4 h-4 text-blue-400" /> : <Tag className="w-4 h-4 text-orange-400" />)}
                    {activeTab !== 'users' && (item.title || item.name)}
                  </td>
                  {activeTab === 'users' && <td className="px-6 py-4">{getRoleBadge(item.role, item.isSpecialAdmin)}</td>}
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { if(activeTab==='users'){ setEditingUser(item); setUserForm({name:item.name,card:item.recordCardNumber,phone:item.contactNumber||'',role:item.role,special:!!item.isSpecialAdmin}); setIsAddUserModalOpen(true); } else { setEditingItem({id:item.id, name:item.title||item.name}); setFormName(item.title||item.name); setIsAddModalOpen(true); } }} className="p-2 text-slate-400 hover:text-blue-600"><Edit3 className="w-4 h-4" /></button>
                      {(activeTab !== 'users' || item.id !== currentUser.id) && <button onClick={() => { if(activeTab==='users'){ setDeletingUser(item); } else if(activeTab==='purposes'){ onDeletePurpose(item.id); } else { onDeleteCategory(item.id); } }} className="p-2 text-slate-300 hover:text-red-600"><Trash2 className="w-4 h-4" /></button>}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Simplified Common Modal for Category/Purpose */}
      {isAddModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center"><h3 className="text-lg font-bold">{editingItem ? 'Edit Entry' : `Add ${activeTab === 'purposes' ? 'Purpose' : 'Category'}`}</h3><button onClick={() => setIsAddModalOpen(false)}><X /></button></div>
            <form onSubmit={handleSimpleSubmit} className="p-6 space-y-4">
              <input type="text" required autoFocus className="w-full border p-4 rounded-xl font-bold" value={formName} onChange={e => setFormName(e.target.value)} />
              <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-xl">Save Configuration</button>
            </form>
          </div>
        </div>
      )}

      {/* User Modal */}
      {isAddUserModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center"><h3 className="text-lg font-bold">Personnel Security</h3><button onClick={() => setIsAddUserModalOpen(false)}><X /></button></div>
            <form onSubmit={handleUserSubmit} className="p-6 space-y-4">
              <input type="text" placeholder="Full Name" className="w-full border p-3 rounded-xl" value={userForm.name} onChange={e => setUserForm({...userForm, name: e.target.value})} />
              <input type="text" placeholder="Card Number" className="w-full border p-3 rounded-xl" value={userForm.card} onChange={e => setUserForm({...userForm, card: e.target.value})} />
              <select className="w-full border p-3 rounded-xl font-bold" value={userForm.role} onChange={e => setUserForm({...userForm, role: e.target.value as UserRole})}>
                <option value={UserRole.STANDARD}>Standard User</option>
                <option value={UserRole.ADMIN_L1}>Admin Level 1</option>
                <option value={UserRole.ADMIN_L2}>Super Admin (Level 2)</option>
              </select>
              {userForm.role === UserRole.ADMIN_L1 && <label className="flex items-center gap-2 text-xs font-bold bg-amber-50 p-3 rounded-xl"><input type="checkbox" checked={userForm.special} onChange={e => setUserForm({...userForm, special: e.target.checked})} /> Grant Special Processing Authority</label>}
              <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black rounded-xl">Save Credentials</button>
            </form>
          </div>
        </div>
      )}

      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center p-4 z-[210]"><div className="bg-white p-6 rounded-3xl shadow-2xl max-w-md w-full space-y-4"><h3 className="text-lg font-bold text-red-700">Delete {deletingUser.name}?</h3><p className="text-sm">Action recorded in audit log.</p><div className="flex gap-2"><button onClick={() => setDeletingUser(null)} className="flex-1 py-3 border rounded-xl">Cancel</button><button onClick={() => { onDeleteUser(deletingUser.id, 'Manager removal'); setDeletingUser(null); }} className="flex-1 py-3 bg-red-600 text-white rounded-xl">Delete</button></div></div></div>
      )}
    </div>
  );
};

