                      {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Specific Reason / Destination</label>
                  <input 
                    type="text" 
                    required 
                    placeholder="e.g. Jetty Pump #2 Emergency Repair" 
                    className="w-full border border-slate-200 p-4 rounded-xl font-medium text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500 shadow-inner" 
                    value={reqSpecific} 
                    onChange={e => setReqSpecific(e.target.value)} 
                  />
                </div>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setActiveItems([])} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors">Discard</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95">Send for Approval</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

