interface FinancialDashboardProps {
  items: InventoryItem[];
  requests: Request[];
  purposes: WorkPurpose[];
}

const FinancialDashboard: React.FC<FinancialDashboardProps> = ({ items, requests, purposes }) => {
  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 5 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);

  const filteredData = useMemo(() => {
    const startDate = new Date(fromYear, fromMonth, 1);
    const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
    const processedTakes = requests.filter(r => r.status === RequestStatus.PROCESSED && r.type === RequestType.TAKE && new Date(r.timestamp) >= startDate && new Date(r.timestamp) <= endDate);
    const returnedItems = requests.filter(r => r.status === RequestStatus.RETURNED && r.type === RequestType.RETURN && new Date(r.timestamp) >= startDate && new Date(r.timestamp) <= endDate);
    const purposeCosts = purposes.map(purpose => {
      const takesVal = processedTakes.filter(r => r.purposeId === purpose.id).reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
      const returnsVal = returnedItems.filter(r => r.purposeId === purpose.id).reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
      return { name: purpose.title, cost: Math.max(0, takesVal - returnsVal) };
    });
    const totalTakes = processedTakes.reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
    const totalReturns = returnedItems.reduce((sum, r) => sum + ((items.find(i => i.id === r.itemId)?.price || 0) * r.quantity), 0);
    return { purposeCosts, totalSpent: totalTakes - totalReturns, totalReturns, takesCount: processedTakes.length };
  }, [fromYear, fromMonth, toYear, toMonth, requests, items, purposes]);

  const totalInventoryValue = useMemo(() => items.reduce((sum, item) => sum + (item.price * item.quantity), 0), [items]);

  return (
    <div className="space-y-4 lg:space-y-8 pb-10 text-slate-900">
      <div className="flex flex-col sm:flex-row justify-between gap-4">
        <h2 className="text-xl lg:text-2xl font-bold text-slate-900">Financial Intelligence</h2>
        <div className="bg-blue-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center gap-2">
          <RefreshCw className="w-3 h-3" /> Real-time Calculation
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] border border-slate-200 relative shadow-sm">
        <div className="absolute top-0 left-0 w-1.5 h-full bg-blue-600 rounded-l-[32px]"></div>
        <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2 ml-1">
          <Filter className="w-4 h-4 text-blue-600" /> Aggregation Window
        </h3>
        <div className="flex flex-wrap gap-8 items-end">
          <SelectGroup label="Start Period" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} />
          <SelectGroup label="End Period" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} />
          <div className="bg-blue-50 px-5 py-3 rounded-2xl border border-blue-100 flex items-center gap-3">
            <Calendar className="w-4 h-4 text-blue-500" />
            <span className="text-sm font-black text-blue-700 uppercase tracking-tight">
              {MONTHS[fromMonth].label} {fromYear} — {MONTHS[toMonth].label} {toYear}
            </span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-7 rounded-[32px] border border-slate-200 shadow-sm">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-2">
            <Landmark className="w-3 h-3 text-slate-300" /> Asset Value
          </h3>
          <p className="text-2xl font-black text-slate-900">${totalInventoryValue.toLocaleString()}</p>
        </div>
        <div className="bg-white p-7 rounded-[32px] border border-slate-200 shadow-sm">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-2">
            <TrendingUp className="w-3 h-3 text-blue-500" /> Net Expenditure
          </h3>
          <p className="text-2xl font-black text-blue-600">${filteredData.totalSpent.toLocaleString()}</p>
        </div>
        <div className="bg-white p-7 rounded-[32px] border border-slate-200 shadow-sm">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Returns Value</h3>
          <p className="text-2xl font-black text-green-600">${filteredData.totalReturns.toLocaleString()}</p>
        </div>
