interface ProcurementTableProps {
  pos: PurchaseOrder[];
  purposes: WorkPurpose[];
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos, purposes }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);

  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 10 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  const filteredPos = useMemo(() => {
    let result = [...pos];
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => { const date = new Date(po.prDate); return date >= startDate && date <= endDate; });
    }
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });
    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => filteredPos.reduce((sum, po) => sum + po.usdAmount, 0), [filteredPos]);
  const contributionData = useMemo(() => {
    const map: Record<string, number> = {};
    filteredPos.forEach(po => {
      const purpose = purposes.find(p => p.id === po.purposeId);
      const label = purpose ? purpose.title : 'Unallocated';
      map[label] = (map[label] || 0) + po.usdAmount;
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [filteredPos, purposes]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    alert("Official PO PDF uploaded successfully.");
  };

  const handleAssignPurpose = (poId: string, purposeId: string) => {
    setPos(prev => prev.map(p => p.id === poId ? { ...p, purposeId } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, purposeId } : null);
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    if (po.techApprovalStatus === 'Approved' && po.poStatus === 'Issued' && po.poNumber?.trim()) return { remarks: 'Order Received', followUp: 'CLOSED' };
    return { remarks: po.manualRemarks || '-', followUp: 'Follow up needed' };
  };

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start gap-4">
        <div>
            <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-3 uppercase tracking-tight">
                <LayoutList className="w-7 h-7 text-blue-600" /> Procurement Hub
            </h2>
            <p className="text-sm text-slate-500 font-medium">Reconciling PR/PO lifecycle and project costing.</p>
        </div>
        <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
            <button 
                onClick={() => setActivePage('master')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'master' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <FileSpreadsheet className="w-4 h-4" /> Master List
            </button>
            <button 
                onClick={() => setActivePage('amounts')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'amounts' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <DollarSign className="w-4 h-4" /> Value Analytics
            </button>
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] border border-slate-200 relative shadow-sm">
        <div className="absolute top-0 left-0 w-1.5 h-full bg-[#4472C4] rounded-l-[32px]"></div>
        <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex flex-col md:flex-row gap-8 items-end flex-1">
                <SelectGroup label="From Period" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} disabled={showAllData} />
                <SelectGroup label="To Period" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} disabled={showAllData} />
            </div>
            <div className="flex flex-wrap items-end gap-3 lg:border-l lg:pl-8 lg:border-slate-100">
                <button 
                    onClick={() => setShowAllData(!showAllData)} 
                    className={`px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAllData ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-100' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                    {showAllData ? 'Showing Global History' : 'Enable Full Database View'}
                </button>
                <button 
                    onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                    className="px-6 py-3.5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-slate-100 flex items-center gap-2"
                >
                    <ArrowUpDown className="w-3 h-3" /> Order: {sortOrder}
                </button>
            </div>
        </div>
      </div>

      {activePage === 'master' ? (
          <MasterSheet filteredPos={filteredPos} purposes={purposes} setSelectedPO={setSelectedPO} getDerivedFields={getDerivedFields} />
      ) : (
          <AmountsPage filteredPos={filteredPos} purposes={purposes} totalSpent={totalSpent} contributionData={contributionData} setSelectedPO={setSelectedPO} />
      )}

      {selectedPO && (
        <div className="fixed inset-0 bg-slate-900/70 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
                <div className="p-8 border-b flex justify-between items-center bg-blue-50/50">
                    <div>
                        <h3 className="text-xl font-black text-slate-900 flex items-center gap-3">
                            <FileSearch className="w-6 h-6 text-blue-600" /> {selectedPO.prNumber}
                        </h3>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Official Request Details</p>
                    </div>
                    <button onClick={() => setSelectedPO(null)} className="text-slate-400 hover:text-slate-600 transition-colors p-2"><X className="w-7 h-7" /></button>
                </div>
                <div className="p-10 space-y-10">
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-8">
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Request Status</span>
                            <p className="text-sm font-black text-slate-900 uppercase">{selectedPO.prStatus}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Associated PO</span>
                            <p className="text-sm font-mono font-black text-blue-700">{selectedPO.poNumber || 'PENDING ASSIGNMENT'}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Financial Impact</span>
                            <p className="text-sm font-black text-slate-900">{selectedPO.netAmount.toLocaleString()} <span className="text-slate-400">{selectedPO.currency}</span></p>
                        </div>
