            {isOwner && (
                <button 
                    onClick={() => setActiveTab('categories')} 
                    className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'categories' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    Asset Categories
                </button>
            )}
        </div>
      </div>

      <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4 border-b border-slate-100">
          <div className="relative flex-1 w-full max-w-md">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search directory..." 
              className="w-full pl-11 pr-4 py-3 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-white" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
            />
          </div>
          <button 
            onClick={() => { 
                if(activeTab === 'users') { 
                    setIsAddUserModalOpen(true); 
                    setUserForm({name:'',card:'',phone:'',role:UserRole.STANDARD,special:false}); 
                } else { 
                    setIsAddModalOpen(true); 
                    setFormName(''); 
                    setEditingItem(null); 
                } 
            }} 
            className="bg-blue-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center gap-2 hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
          >
            <Plus className="w-4 h-4" /> Add New {activeTab === 'users' ? 'User' : (activeTab === 'purposes' ? 'Purpose' : 'Category')}
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 font-black text-[10px] uppercase border-b border-slate-100 text-slate-400 tracking-widest">
