                    <p className="text-[9px] text-amber-600 font-bold leading-tight">Grant Owner-level operational processing rights.</p>
                  </div>
                  <input type="checkbox" className="w-6 h-6 rounded-lg border-amber-300 text-amber-600" checked={userForm.special} onChange={e => setUserForm({...userForm, special: e.target.checked})} />
                </div>
              )}

              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-[24px] uppercase tracking-widest text-xs shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                Commit Credentials
              </button>
            </form>
          </div>
        </div>
      )}

      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-[210]">
            <div className="bg-white p-10 rounded-[40px] shadow-2xl max-w-md w-full text-center space-y-6 animate-in zoom-in duration-200">
                <div className="w-20 h-20 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-2">
                    <Trash2 className="w-10 h-10" />
                </div>
                <div>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Terminate User Access?</h3>
                    <p className="text-sm text-slate-500 font-medium mt-2">You are removing <span className="text-slate-900 font-bold">{deletingUser.name}</span>. This action will be logged in the master audit file.</p>
                </div>
                <div className="flex gap-4">
                    <button onClick={() => setDeletingUser(null)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-black rounded-2xl hover:bg-slate-50 transition-all">Abort</button>
                    <button onClick={() => { onDeleteUser(deletingUser.id, 'Management Termination'); setDeletingUser(null); }} className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all active:scale-95">Confirm Termination</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

