const HeaderCell = ({ label, className = "" }: { label: string; className?: string }) => (
  <th className={`px-4 py-3 border-r border-slate-400 last:border-r-0 ${className}`}>
    <span className="font-bold text-slate-900 text-xs whitespace-nowrap uppercase tracking-tight">{label}</span>
  </th>
);

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  categories: InventoryCategory[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, categories, onRequestItem, onManualAdjust }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [activeItems, setActiveItems] = useState<InventoryItem[]>([]);
  const [mode, setMode] = useState<'request' | 'info'>('request');

  const [statusFilter, setStatusFilter] = useState<'all' | 'low' | 'out'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('All Categories');

  const [reqQtyMap, setReqQtyMap] = useState<Record<string, number>>({});
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      // Filter out pending items that haven't been approved by the Owner yet
      if (item.status === 'pending_approval') return false;

      const search = searchTerm.toLowerCase();
      const matchesSearch = (
        item.name.toLowerCase().includes(search) ||
        item.itemCode.toLowerCase().includes(search) ||
        item.partNumber.toLowerCase().includes(search) ||
        item.inventoryUID.toLowerCase().includes(search) ||
        item.description.toLowerCase().includes(search)
      );
      const matchesCategory = categoryFilter === 'All Categories' || item.category === categoryFilter;
      let matchesStatus = true;
      if (statusFilter === 'low') matchesStatus = item.quantity <= item.minThreshold && item.quantity > 0;
      if (statusFilter === 'out') matchesStatus = item.quantity === 0;
      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [items, searchTerm, categoryFilter, statusFilter]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeItems.length > 0) {
      activeItems.forEach(item => {
        const qty = reqQtyMap[item.id] || 1;
        onRequestItem(item.id, qty, reqPurpose, reqSpecific, isEmergency);
      });
      setActiveItems([]);
      setSelectedIds(new Set());
    }
  };

  return (
    <div className="space-y-4 lg:space-y-6 pb-24 text-slate-900">
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6">
        <div className="space-y-4 flex-1">
          <div>
            <h2 className="text-xl lg:text-2xl font-bold text-slate-900">Inventory Dashboard</h2>
            <p className="text-sm text-slate-500 font-medium">Tracking industrial assets and site materials.</p>
          </div>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="Search items..." 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 bg-white text-slate-900 font-medium shadow-sm" 
                value={searchTerm} 
                onChange={(e) => setSearchTerm(e.target.value)} 
              />
            </div>
            <div className="relative">
              <select 
                value={categoryFilter} 
                onChange={(e) => setCategoryFilter(e.target.value)} 
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 border border-slate-300 rounded-xl bg-white text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm cursor-pointer"
              >
                <option value="All Categories">All Categories</option>
                {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
              </select>
              <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>
      </div>

      <div className="hidden lg:block bg-white rounded-xl shadow-lg border border-slate-400 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-[#FFD966] border-b-2 border-slate-600">
              <tr>
                <th className="px-4 py-3 border-r border-slate-400 w-10 text-center"></th>
                <HeaderCell label="Inventory ID" />
                <HeaderCell label="Item Code" />
                <HeaderCell label="Description" />
                <HeaderCell label="Name" />
                <HeaderCell label="Item Part Number" />
                <HeaderCell label="Location" />
                <HeaderCell label="Quantity" />
                {canViewThreshold(currentUser) && <HeaderCell label="Min Alert" />}
                {canViewPrices(currentUser) && <th className="px-4 py-3 font-bold text-slate-900 text-xs uppercase tracking-tight">Price</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredItems.map(item => (
                <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.has(item.id) ? 'bg-blue-50/50' : ''}`}>
                  <td className="px-4 py-4 text-center">
                    <input 
                      type="checkbox" 
                      className="w-4 h-4 rounded border-slate-300 text-blue-600 cursor-pointer" 
                      checked={selectedIds.has(item.id)} 
                      onChange={() => { 
                        const s = new Set(selectedIds); 
                        if(s.has(item.id)) s.delete(item.id); 
                        else s.add(item.id); 
                        setSelectedIds(s); 
                      }} 
                    />
                  </td>
                  <td className="px-4 py-4 font-mono text-blue-700 font-black border-r border-slate-100">{item.inventoryUID}</td>
                  <td className="px-4 py-4 text-slate-700 font-medium border-r border-slate-100">{item.itemCode}</td>
                  <td className="px-4 py-4 text-slate-600 text-xs max-w-[200px] border-r border-slate-100">
                    <div className="line-clamp-2" title={item.description}>{item.description}</div>
                  </td>
                  <td className="px-4 py-4 font-bold text-slate-900 border-r border-slate-100">
                    {item.name}
                    <div className="text-[9px] text-slate-400 font-black uppercase tracking-widest">{item.category}</div>
                  </td>
                  <td className="px-4 py-4 text-slate-700 font-medium border-r border-slate-100">{item.partNumber}</td>
                  <td className="px-4 py-4 text-slate-600 font-medium border-r border-slate-100">{item.location}</td>
                  <td className="px-4 py-4 border-r border-slate-100">
                    <span className={`inline-block px-3 py-1 rounded-lg font-black ${item.quantity <= item.minThreshold ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-800'}`}>
                      {item.quantity}
                    </span>
                  </td>
                  {canViewThreshold(currentUser) && <td className="px-4 py-4 text-slate-500 font-bold border-r border-slate-100">{item.minThreshold}</td>}
                  {canViewPrices(currentUser) && <td className="px-4 py-4 font-black text-slate-900">${item.price.toFixed(2)}</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredItems.length === 0 && (
          <div className="p-12 text-center text-slate-400 font-bold uppercase tracking-widest bg-slate-50">
            No items match selected filters
          </div>
        )}
      </div>

      <div className="lg:hidden space-y-3">
        {filteredItems.map(item => (
          <div key={item.id} className={`bg-white p-4 rounded-2xl border ${selectedIds.has(item.id) ? 'border-blue-500 ring-2 ring-blue-100' : 'border-slate-200'} shadow-sm space-y-3 relative`} onClick={() => { const s = new Set(selectedIds); if(s.has(item.id)) s.delete(item.id); else s.add(item.id); setSelectedIds(s); }}>
             <div className="flex justify-between items-start">
               <div>
                 <span className="text-[10px] font-black text-blue-600 uppercase mb-1 block">{item.inventoryUID}</span>
                 <h3 className="font-bold text-slate-900">{item.name}</h3>
                 <p className="text-xs text-slate-500 font-medium">{item.itemCode} • {item.location}</p>
                 <p className="text-[10px] text-slate-400 mt-1 line-clamp-1">{item.description}</p>
               </div>
               <span className={`px-3 py-1 rounded-lg font-black text-sm ${item.quantity <= item.minThreshold ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-800'}`}>{item.quantity}</span>
             </div>
             <div className="flex justify-between items-center pt-2 border-t border-slate-50">
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{item.category}</span>
               {canViewPrices(currentUser) && <span className="text-xs font-black text-slate-900">${item.price.toFixed(2)}</span>}
             </div>
          </div>
        ))}
      </div>

      {selectedIds.size > 0 && (
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-[90%] max-w-2xl bg-slate-900 text-white rounded-3xl shadow-2xl p-4 flex items-center justify-between z-[60] animate-in slide-in-from-bottom duration-300">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center font-black text-lg">{selectedIds.size}</div>
            <div>
              <p className="font-bold text-sm">Items Ready</p>
              <button onClick={() => setSelectedIds(new Set())} className="text-[10px] text-slate-400 hover:text-white font-black uppercase tracking-widest">Cancel All</button>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => { setActiveItems(items.filter(i => selectedIds.has(i.id))); setMode('request'); }} className="px-8 py-3 rounded-2xl bg-blue-600 hover:bg-blue-500 font-black text-sm shadow-xl transition-all active:scale-95">Initiate Request</button>
          </div>
        </div>
      )}

      {activeItems.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/70 flex items-center justify-center z-[100] p-4 backdrop-blur-md">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-900">Operational Material Request</h3>
              <button onClick={() => setActiveItems([])} className="text-slate-400 hover:text-slate-600 transition-colors p-1"><X /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="space-y-2 max-h-[30vh] overflow-y-auto bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Selected Stock Breakdown</label>
                  {activeItems.map(item => (
                    <div key={item.id} className="flex items-center justify-between bg-white p-3 rounded-xl border border-slate-100 shadow-sm mb-2 last:mb-0">
                      <div className="flex-1 min-w-0 pr-4">
                        <span className="text-xs font-bold text-slate-900 truncate block">{item.name}</span>
                        <span className="text-[10px] text-slate-400 font-medium">Available: {item.quantity}</span>
                      </div>
                      <input 
                        type="number" 
                        min="1" 
                        max={item.quantity} 
                        className="w-20 p-2 border border-slate-200 rounded-lg text-sm font-black text-center text-slate-900 focus:ring-2 focus:ring-blue-500" 
                        value={reqQtyMap[item.id] || 1} 
                        onChange={e => setReqQtyMap({...reqQtyMap, [item.id]: parseInt(e.target.value) || 1})} 
                      />
                    </div>
                  ))}
              </div>
              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Assigned Work Purpose</label>
                  <div className="relative">
                    <select 
                      required 
                      className="w-full border border-slate-200 p-4 rounded-xl font-bold text-slate-900 bg-slate-50 appearance-none outline-none focus:ring-2 focus:ring-blue-500" 
                      value={reqPurpose} 
                      onChange={e => setReqPurpose(e.target.value)}
                    >
                      <option value="">Select Purpose...</option>
                      {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Specific Reason / Destination</label>
                  <input 
                    type="text" 
                    required 
                    placeholder="e.g. Jetty Pump #2 Emergency Repair" 
                    className="w-full border border-slate-200 p-4 rounded-xl font-medium text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500 shadow-inner" 
                    value={reqSpecific} 
                    onChange={e => setReqSpecific(e.target.value)} 
                  />
                </div>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setActiveItems([])} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors">Discard</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95">Send for Approval</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;

import React, { useState, useEffect } from 'react';
import { InventoryItem, User, InventoryCategory, UserRole } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID, canViewPrices, canViewThreshold } from '../services/stateService';
import { Search, Plus, Save, Package, AlertCircle, Fingerprint, FileText, MapPin, ChevronDown, Tag, Hash, Info, ShieldAlert } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  categories: InventoryCategory[];
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, categories, onAddStock, onCreateItem }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const isOwner = currentUser.role === UserRole.OWNER;

  const [activeTab, setActiveTab] = useState<'existing' | 'new'>('existing');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');
  const [addLocation, setAddLocation] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: '',
      status: 'active' as 'active' | 'pending_approval' // Default type, overridden on submit
  });

  const [previewUID, setPreviewUID] = useState('');

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
      setAddLocation(selectedItem.location || '');
      setAddQty(0);
      setAddNote('');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') setPreviewUID(generateInventoryUID(items));
  }, [activeTab, items]);

  const filteredItems = items.filter(item => {
    // Only show active items for adjustment
    if (item.status === 'pending_approval') return false;
    const s = searchTerm.toLowerCase();
    return item.name.toLowerCase().includes(s) || item.itemCode.toLowerCase().includes(s) || item.inventoryUID.toLowerCase().includes(s);
  });

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.category) return alert("Please select a valid category from the system list.");

    // Status Logic: Only Owners create active items immediately. Others create pending.
    const status = isOwner ? 'active' : 'pending_approval';

    onCreateItem({ ...newItem, status });

    if (!isOwner) {
      alert("New asset submitted for Owner Verification. It will appear in the inventory list once approved.");
    }

    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '', status: 'active' });
    setActiveTab('existing');
  };

  if (isReadOnly) return (
    <div className="p-20 text-center text-slate-500 flex flex-col items-center gap-4">
      <AlertCircle className="w-12 h-12 text-slate-300" />
      <div>
        <h3 className="text-lg font-bold text-slate-700">Restricted Access</h3>
        <p className="text-sm font-medium">You do not have administrative authority to modify inventory.</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-2 uppercase tracking-tight">
          <Package className="w-7 h-7 text-blue-600" /> Stock Adjustment Center
        </h2>
      </div>

      <div className="flex p-1.5 bg-slate-200 rounded-2xl w-full max-w-lg">
          <button 
            onClick={() => setActiveTab('existing')} 
            className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Update Existing
          </button>
          {canRegisterNew && (
            <button 
              onClick={() => setActiveTab('new')} 
              className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Register New Asset
            </button>
          )}
      </div>

      {activeTab === 'existing' ? (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-300">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="text" 
                      placeholder="Search for item to adjust..." 
                      className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-white shadow-sm" 
                      value={searchTerm} 
                      onChange={e => setSearchTerm(e.target.value)} 
                    />
                  </div>
                  <div className="bg-white rounded-3xl border border-slate-200 divide-y divide-slate-50 overflow-y-auto max-h-[550px] shadow-sm">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)} 
                            className={`p-5 cursor-pointer hover:bg-slate-50 transition-colors flex items-center justify-between ${selectedItem?.id === item.id ? 'bg-blue-50/50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div>
                                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest block mb-1">{item.inventoryUID}</span>
                                <div className="font-bold text-slate-900">{item.name}</div>
                                <div className="text-[10px] text-slate-400 font-bold">{item.itemCode} • {item.location}</div>
                              </div>
                              <div className="text-right">
                                <span className={`text-sm font-black ${item.quantity <= item.minThreshold ? 'text-red-600' : 'text-green-600'}`}>{item.quantity}</span>
                              </div>
                          </div>
                      ))}
                      {filteredItems.length === 0 && (
                        <div className="p-10 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                          No items found
                        </div>
                      )}
                  </div>
              </div>

              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm h-fit sticky top-8">
                  {selectedItem ? (
                      <form onSubmit={e => { e.preventDefault(); onAddStock(selectedItem.id, addQty || 0, addNote, addDescription, addLocation); setSelectedItem(null); }} className="space-y-6">
                          <div className="flex items-center gap-3 pb-4 border-b border-slate-100">
                             <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black">{selectedItem.name.charAt(0)}</div>
                             <div>
                               <h3 className="font-black text-slate-900">{selectedItem.name}</h3>
                               <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{selectedItem.inventoryUID} Adjustment</p>
                             </div>
                          </div>

                          <div className="grid grid-cols-1 gap-4">
                            <div className="space-y-1.5">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Current Bin Location</label>
                              <div className="relative">
                                <MapPin className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                                <input type="text" className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold" value={addLocation} onChange={e => setAddLocation(e.target.value)} />
                              </div>
                            </div>
                            <div className="space-y-1.5">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Asset Description</label>
                              <div className="relative">
                                <FileText className="absolute left-3.5 top-4 w-4 h-4 text-slate-400" />
                                <textarea className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium min-h-[100px]" value={addDescription} onChange={e => setAddDescription(e.target.value)} />
                              </div>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Quantity Delta (+/-)</label>
                                <input type="number" placeholder="Enter change..." className="w-full border border-slate-200 p-3.5 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={addQty === 0 ? '' : addQty} onChange={e => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} />
                              </div>
                              <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Adjustment Reason</label>
                                <input type="text" required={addQty !== 0} placeholder="e.g. Audit Correct, Received..." className="w-full border border-slate-200 p-3.5 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium" value={addNote} onChange={e => setAddNote(e.target.value)} />
                              </div>
                            </div>
                          </div>

                          <button type="submit" className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl shadow-slate-200 hover:bg-slate-800 transition-all active:scale-95">
                            Process Inventory Update
                          </button>
                      </form>
                  ) : (
                    <div className="py-24 text-center space-y-4">
                      <Search className="w-12 h-12 text-slate-100 mx-auto" />
                      <div>
                        <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Search & Select</p>
                        <p className="text-sm text-slate-300 font-medium mt-1">Select an item from the left panel to begin adjustment.</p>
                      </div>
                    </div>
                  )}
              </div>
          </div>
      ) : (
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-2xl mx-auto shadow-sm animate-in zoom-in duration-300">
              <form onSubmit={handleCreateSubmit} className="space-y-8">
                  <div className="flex justify-between items-start pb-4 border-b border-slate-100">
                    <div>
                      <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">New Asset Registration</h3>
                      <p className="text-xs text-slate-400 font-bold mt-1 uppercase tracking-widest">Adding to Master System Database</p>
                    </div>
                    <div className="text-right">
                       <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1">Inventory ID</label>
                       <span className="font-mono bg-blue-600 text-white px-4 py-2 rounded-2xl text-xs font-black shadow-lg shadow-blue-100">{previewUID}</span>
                    </div>
                  </div>

                  {!isOwner && (
                    <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100 flex items-start gap-3">
                      <ShieldAlert className="w-5 h-5 text-amber-600 mt-0.5 shrink-0" />
                      <div>
                        <p className="text-sm font-black text-amber-800">Verification Required</p>
                        <p className="text-xs text-amber-700 mt-1 leading-relaxed">
                          As you are not the System Owner, this new asset will be created in a <strong>Pending Approval</strong> state. The Owner must verify and activate it before it appears in the active inventory list.
                        </p>
                      </div>
                    </div>
                  )}

                  <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Code</label>
                          <div className="relative">
                            <Hash className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input type="text" required placeholder="AXXX-XXXX" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                          </div>
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Part Number</label>
                          <div className="relative">
                            <Tag className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input type="text" required placeholder="Part #" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                          </div>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Name</label>
                      <input type="text" required placeholder="Enter primary identification name..." className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                    </div>

                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Description</label>
                      <div className="relative">
                        <Info className="absolute left-3.5 top-4 w-4 h-4 text-slate-400" />
                        <textarea required placeholder="Detailed asset description..." className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium bg-slate-50 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location</label>
                        <div className="relative">
                          <MapPin className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                          <input type="text" required placeholder="Bin / Shelf / Site Bin" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                        </div>
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Physical Category</label>
                        <div className="relative">
                          <select 
                            required 
                            className="w-full border border-slate-200 p-4 rounded-2xl font-bold appearance-none bg-slate-50 text-slate-900 pr-10 outline-none focus:ring-2 focus:ring-blue-500" 
                            value={newItem.category} 
                            onChange={e => setNewItem({...newItem, category: e.target.value})}
                          >
                            <option value="">Select Category...</option>
                            {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-5 p-6 bg-blue-50/50 rounded-[32px] border border-blue-50">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Quantity</label>
                          <input type="number" required placeholder="0" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: parseInt(e.target.value) || 0})} />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Min Alert</label>
                          <input type="number" required placeholder="5" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: parseInt(e.target.value) || 0})} />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Price (Unit)</label>
                          <input type="number" step="0.01" required placeholder="0.00" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: parseFloat(e.target.value) || 0})} />
                        </div>
                    </div>
                  </div>

                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-3xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                    {isOwner ? 'Finalize Item Registration' : 'Submit for Owner Verification'}
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

export default AddInventoryView;

import React, { useState, useMemo } from 'react';
import { User, UserRole, WorkPurpose, InventoryCategory, InventoryItem } from '../types';
import { 
  Users, UserPlus, Search, Trash2, Edit3, Shield, ShieldAlert, ShieldCheck, 
  X, ChevronDown, IdCard, AlertCircle, Phone, Briefcase, Plus, Save, Trash, Tag,
  PackageCheck, CheckCircle2, XCircle
} from 'lucide-react';

const RoleBadge = ({ role, special }: { role: UserRole, special?: boolean }) => {
  const base = "px-2.5 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ";
  if (role === UserRole.OWNER) return <span className={base + "bg-purple-100 text-purple-700 border-purple-200"}>System Owner</span>;
  if (role === UserRole.ADMIN_L2) return <span className={base + "bg-red-100 text-red-700 border-red-200"}>Super Admin (L2)</span>;
  if (role === UserRole.ADMIN_L1) return <span className={base + "bg-blue-100 text-blue-700 border-blue-200"}>Site Admin L1 {special ? '(Special)' : ''}</span>;
  return <span className={base + "bg-slate-100 text-slate-600 border-slate-200"}>Standard Operator</span>;
};

interface ManagementViewProps {
  users: User[];
  workPurposes: WorkPurpose[];
  categories: InventoryCategory[];
  pendingItems: InventoryItem[];
  currentUser: User;
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onDeleteUser: (id: string, reason: string) => void;
  onAddPurpose: (title: string) => void;
  onUpdatePurpose: (purpose: WorkPurpose) => void;
  onDeletePurpose: (id: string) => void;
  onAddCategory: (name: string) => void;
  onUpdateCategory: (cat: InventoryCategory) => void;
  onDeleteCategory: (id: string) => void;
  onApproveItem: (id: string) => void;
  onRejectItem: (id: string) => void;
}

const ManagementView: React.FC<ManagementViewProps> = ({ 
  users, workPurposes, categories, pendingItems, currentUser, 
  onAddUser, onUpdateUser, onDeleteUser,
  onAddPurpose, onUpdatePurpose, onDeletePurpose,
  onAddCategory, onUpdateCategory, onDeleteCategory,
  onApproveItem, onRejectItem
}) => {
  const [activeTab, setActiveTab] = useState<'users' | 'purposes' | 'categories' | 'approvals'>('users');
  const [searchTerm, setSearchTerm] = useState('');

  // Modals for User
  const [isAddUserModalOpen, setIsAddUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deletingUser, setDeletingUser] = useState<User | null>(null);
  const [userForm, setUserForm] = useState({ name: '', card: '', phone: '', role: UserRole.STANDARD, special: false });

  // Form for Purpose/Category
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<{id: string, name: string} | null>(null);
  const [formName, setFormName] = useState('');

  const isOwner = currentUser.role === UserRole.OWNER;

  const filteredItems = useMemo(() => {
    const s = searchTerm.toLowerCase();
    if (activeTab === 'users') return users.filter(u => u.name.toLowerCase().includes(s) || u.recordCardNumber.toLowerCase().includes(s));
    if (activeTab === 'purposes') return workPurposes.filter(p => p.title.toLowerCase().includes(s));
    if (activeTab === 'categories') return categories.filter(c => c.name.toLowerCase().includes(s));
    if (activeTab === 'approvals') return pendingItems.filter(i => i.name.toLowerCase().includes(s) || i.itemCode.toLowerCase().includes(s));
    return [];
  }, [activeTab, users, workPurposes, categories, pendingItems, searchTerm]);

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const data = { name: userForm.name, recordCardNumber: userForm.card, contactNumber: userForm.phone, role: userForm.role, isSpecialAdmin: userForm.special };
    if (editingUser) onUpdateUser({ ...editingUser, ...data });
    else onAddUser(data);
    setIsAddUserModalOpen(false);
    setEditingUser(null);
  };

  const handleSimpleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formName.trim()) return;
    if (activeTab === 'purposes') {
      if (editingItem) onUpdatePurpose({ id: editingItem.id, title: formName });
      else onAddPurpose(formName);
    } else {
      if (editingItem) onUpdateCategory({ id: editingItem.id, name: formName });
      else onAddCategory(formName);
    }
    setIsAddModalOpen(false);
    setEditingItem(null);
  };

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <h2 className="text-xl lg:text-2xl font-black text-slate-900 uppercase tracking-tight">System Configuration</h2>
          <p className="text-sm text-slate-500 font-medium mt-1">Personnel authority and global site settings.</p>
        </div>
        <div className="flex p-1.5 bg-slate-200 rounded-2xl overflow-x-auto max-w-full shadow-inner">
            <button 
                onClick={() => setActiveTab('users')} 
                className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'users' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
                Personnel
            </button>
            <button 
                onClick={() => setActiveTab('purposes')} 
                className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'purposes' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
                Work Purposes
            </button>
            {isOwner && (
                <>
                  <button 
                      onClick={() => setActiveTab('categories')} 
                      className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === 'categories' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                      Asset Categories
                  </button>
                  <button 
                      onClick={() => setActiveTab('approvals')} 
                      className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap flex items-center gap-2 ${activeTab === 'approvals' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                  >
                      Pending Assets
                      {pendingItems.length > 0 && <span className="bg-red-500 text-white text-[9px] px-1.5 py-0.5 rounded-full">{pendingItems.length}</span>}
                  </button>
                </>
            )}
        </div>
      </div>

      <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 bg-slate-50/50 flex flex-col md:flex-row justify-between items-center gap-4 border-b border-slate-100">
          <div className="relative flex-1 w-full max-w-md">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search directory..." 
              className="w-full pl-11 pr-4 py-3 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-white" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
            />
          </div>
          {activeTab !== 'approvals' && (
            <button 
              onClick={() => { 
                  if(activeTab === 'users') { 
                      setIsAddUserModalOpen(true); 
                      setUserForm({name:'',card:'',phone:'',role:UserRole.STANDARD,special:false}); 
                  } else { 
                      setIsAddModalOpen(true); 
                      setFormName(''); 
                      setEditingItem(null); 
                  } 
              }} 
              className="bg-blue-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase tracking-widest text-xs flex items-center gap-2 hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
            >
              <Plus className="w-4 h-4" /> Add New {activeTab === 'users' ? 'User' : (activeTab === 'purposes' ? 'Purpose' : 'Category')}
            </button>
          )}
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-slate-50 font-black text-[10px] uppercase border-b border-slate-100 text-slate-400 tracking-widest">
              <tr>
                <th className="px-8 py-5">{activeTab === 'users' ? 'Identity & Credentials' : (activeTab === 'approvals' ? 'Pending Asset Details' : 'Configuration Label')}</th>
                {activeTab === 'users' && <th className="px-8 py-5">System Authorization</th>}
                {activeTab === 'approvals' && <th className="px-8 py-5">Specs</th>}
                <th className="px-8 py-5 text-right">Management Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {activeTab === 'approvals' ? (
                // PENDING APPROVALS LIST
                filteredItems.map((item: any) => (
                  <tr key={item.id} className="hover:bg-amber-50/30 transition-colors">
                    <td className="px-8 py-5">
                      <div className="flex items-center gap-3">
                         <div className="w-10 h-10 bg-amber-100 text-amber-600 rounded-xl flex items-center justify-center">
                            <PackageCheck className="w-5 h-5" />
                         </div>
                         <div>
                            <p className="font-black text-slate-900">{item.name}</p>
                            <p className="text-xs text-slate-500 font-medium">{item.itemCode} • {item.location}</p>
                         </div>
                      </div>
                    </td>
                    <td className="px-8 py-5">
                       <span className="bg-slate-100 text-slate-600 text-[10px] font-bold px-2 py-1 rounded mr-2">{item.category}</span>
                       <span className="bg-slate-100 text-slate-600 text-[10px] font-bold px-2 py-1 rounded">Qty: {item.quantity}</span>
                    </td>
                    <td className="px-8 py-5 text-right">
                       <div className="flex justify-end gap-2">
                          <button onClick={() => onApproveItem(item.id)} className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-xs font-bold hover:bg-green-700 transition-colors">
                             <CheckCircle2 className="w-4 h-4" /> Approve
                          </button>
                          <button onClick={() => onRejectItem(item.id)} className="flex items-center gap-2 px-4 py-2 bg-red-100 text-red-600 rounded-lg text-xs font-bold hover:bg-red-200 transition-colors">
                             <XCircle className="w-4 h-4" /> Reject
                          </button>
                       </div>
                    </td>
                  </tr>
                ))
              ) : (
                // STANDARD LISTS (Users, Purposes, Categories)
                filteredItems.map((item: any) => (
                  <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-8 py-5 font-bold flex items-center gap-4 text-slate-900">
                      {activeTab === 'users' ? (
                          <>
                              <div className="w-10 h-10 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center font-black">{item.name.charAt(0)}</div>
                              <div>
                                  <div className="font-black text-slate-900">{item.name}</div>
                                  <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ID Card: {item.recordCardNumber}</div>
                              </div>
                          </>
                      ) : (
                          activeTab === 'purposes' ? <Briefcase className="w-4 h-4 text-blue-400" /> : <Tag className="w-4 h-4 text-orange-400" />
                      )}
                      {activeTab !== 'users' && (
                          <span className="font-black uppercase tracking-tight text-slate-800">
                              {item.title || item.name}
                          </span>
                      )}
                    </td>
                    {activeTab === 'users' && (
                      <td className="px-8 py-5">
                          <RoleBadge role={item.role} special={item.isSpecialAdmin} />
                      </td>
                    )}
                    <td className="px-8 py-5 text-right">
                      <div className="flex justify-end gap-3">
                        <button 
                          onClick={() => { 
                              if(activeTab==='users'){ 
                                  setEditingUser(item); 
                                  setUserForm({name:item.name,card:item.recordCardNumber,phone:item.contactNumber||'',role:item.role,special:!!item.isSpecialAdmin}); 
                                  setIsAddUserModalOpen(true); 
                              } else { 
                                  setEditingItem({id:item.id, name:item.title||item.name}); 
                                  setFormName(item.title||item.name); 
                                  setIsAddModalOpen(true); 
                              } 
                          }} 
                          className="p-2.5 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                        >
                          <Edit3 className="w-4 h-4" />
                        </button>
                        {(activeTab !== 'users' || item.id !== currentUser.id) && (
                          <button 
                              onClick={() => { 
                                  if(activeTab==='users'){ 
                                      setDeletingUser(item); 
                                  } else if(activeTab==='purposes'){ 
                                      onDeletePurpose(item.id); 
                                  } else { 
                                      onDeleteCategory(item.id); 
                                  } 
                              }} 
                              className="p-2.5 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                          >
                              <Trash2 className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
              {filteredItems.length === 0 && (
                <tr>
                    <td colSpan={activeTab === 'users' ? 3 : 2} className="px-8 py-20 text-center text-slate-300 font-black uppercase tracking-widest text-xs italic">
                        {activeTab === 'approvals' ? 'No pending new assets found.' : 'The directory is currently empty'}
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Common Modal for Category/Purpose */}
      {isAddModalOpen && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-blue-50/50">
                <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">
                    {editingItem ? 'Edit Configuration' : `Add System ${activeTab === 'purposes' ? 'Purpose' : 'Category'}`}
                </h3>
                <button onClick={() => setIsAddModalOpen(false)} className="text-slate-400 p-1 hover:text-slate-600 transition-colors"><X /></button>
            </div>
            <form onSubmit={handleSimpleSubmit} className="p-10 space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Configuration Label</label>
                <input 
                    type="text" 
                    required 
                    autoFocus 
                    className="w-full border border-slate-200 p-5 rounded-3xl font-black text-slate-900 bg-slate-50 outline-none focus:ring-4 focus:ring-blue-500/10 shadow-inner" 
                    value={formName} 
                    onChange={e => setFormName(e.target.value)} 
                />
              </div>
              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-[24px] uppercase tracking-widest text-xs shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                Apply System Update
              </button>
            </form>
          </div>
        </div>
      )}

      {/* User Authority Modal */}
      {isAddUserModalOpen && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-blue-50/50">
                <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Personnel Access Control</h3>
                <button onClick={() => setIsAddUserModalOpen(false)} className="text-slate-400 p-1 hover:text-slate-600 transition-colors"><X /></button>
            </div>
            <form onSubmit={handleUserSubmit} className="p-10 space-y-6">
              <div className="space-y-5">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Personnel Full Name</label>
                  <input type="text" required placeholder="Enter name..." className="w-full border border-slate-200 p-4 rounded-2xl font-bold text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500" value={userForm.name} onChange={e => setUserForm({...userForm, name: e.target.value})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Site Record Card #</label>
                  <input type="text" required placeholder="RC-XXXX" className="w-full border border-slate-200 p-4 rounded-2xl font-bold text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500" value={userForm.card} onChange={e => setUserForm({...userForm, card: e.target.value})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Operational Authority Level</label>
                  <div className="relative">
                    <select 
                        className="w-full border border-slate-200 p-4 rounded-2xl font-black text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500 appearance-none pr-10" 
                        value={userForm.role} 
                        onChange={e => setUserForm({...userForm, role: e.target.value as UserRole})}
                    >
                        <option value={UserRole.STANDARD}>Standard Operator</option>
                        <option value={UserRole.ADMIN_L1}>Site Admin (L1)</option>
                        <option value={UserRole.ADMIN_L2}>Super Admin (L2)</option>
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                  </div>
                </div>
              </div>

              {userForm.role === UserRole.ADMIN_L1 && (
                <div className="bg-amber-50 border border-amber-100 p-5 rounded-3xl flex items-center justify-between">
                  <div className="flex-1">
                    <p className="text-[11px] font-black text-amber-900 uppercase tracking-tight">Special Admin Override</p>
                    <p className="text-[9px] text-amber-600 font-bold leading-tight">Grant Owner-level operational processing rights.</p>
                  </div>
                  <input type="checkbox" className="w-6 h-6 rounded-lg border-amber-300 text-amber-600" checked={userForm.special} onChange={e => setUserForm({...userForm, special: e.target.checked})} />
                </div>
              )}

              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-[24px] uppercase tracking-widest text-xs shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                Commit Credentials
              </button>
            </form>
          </div>
        </div>
      )}

      {deletingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-[210]">
            <div className="bg-white p-10 rounded-[40px] shadow-2xl max-w-md w-full text-center space-y-6 animate-in zoom-in duration-200">
                <div className="w-20 h-20 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-2">
                    <Trash2 className="w-10 h-10" />
                </div>
                <div>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Terminate User Access?</h3>
                    <p className="text-sm text-slate-500 font-medium mt-2">You are removing <span className="text-slate-900 font-bold">{deletingUser.name}</span>. This action will be logged in the master audit file.</p>
                </div>
                <div className="flex gap-4">
                    <button onClick={() => setDeletingUser(null)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-black rounded-2xl hover:bg-slate-50 transition-all">Abort</button>
                    <button onClick={() => { onDeleteUser(deletingUser.id, 'Management Termination'); setDeletingUser(null); }} className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all active:scale-95">Confirm Termination</button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default ManagementView;

import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import ManagementView from './components/ManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement,
    WorkPurpose,
    InventoryCategory
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS,
    INITIAL_CATEGORIES
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Search, Calendar, Filter, User as UserIcon, Activity, ChevronDown, X } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [currentView, setCurrentView] = useState('inventory');

  // Data State
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [workPurposes, setWorkPurposes] = useState<WorkPurpose[]>(WORK_PURPOSES);
  const [categories, setCategories] = useState<InventoryCategory[]>(INITIAL_CATEGORIES);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Audit Filter State ---
  const [auditSearch, setAuditSearch] = useState('');
  const [auditActionFilter, setAuditActionFilter] = useState('All');
  const [auditUserFilter, setAuditUserFilter] = useState('All');
  const [auditFromDate, setAuditFromDate] = useState('');
  const [auditToDate, setAuditToDate] = useState('');

  // --- Actions ---
  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory');
  };

  const createAuditEntry = (action: string, itemId: string, itemName: string, qtyChange: number, details: string) => {
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action,
        itemId,
        itemName,
        quantityChange: qtyChange,
        performedBy: currentUser.name,
        details
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);
    createAuditEntry('MOVEMENT_CREATED', 'N/A', mv.itemCode, 0, `Standalone Move Order ${mv.moveOrderNumber} created.`);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));
    createAuditEntry('MOVEMENT_UPDATED', 'N/A', mv.itemCode, 0, `Move Order ${mv.moveOrderNumber} updated.`);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('REQUEST_CREATED', item.id, item.name, 0, `User requested ${qty} units.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason,
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('RETURN_INITIATED', item.id, item.name, 0, `Return of ${qty} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_CLAIMED', 'N/A', 'Request', 0, `Admin claimed request.`);
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_VERIFIED', 'N/A', 'Request', 0, `Request verified.`);
  };

  const handleReject = (reqId: string, reason: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.REJECTED, rejectedBy: currentUser.id, rejectionReason: reason } : req
    ));
    createAuditEntry('REQUEST_REJECTED', 'N/A', 'Request', 0, `Request rejected: ${reason}`);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i));
    }
    createAuditEntry('STOCK_DEDUCTED', request.itemId, item?.name || 'Item', -request.quantity, `Stock deducted.`);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request) return;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: RequestStatus.RETURNED, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          setInventory(prev => prev.map(i => i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i));
      }
      createAuditEntry('RETURN_PROCESSED', request.itemId, 'Item', condition === 'Good' ? request.quantity : 0, `Return finalized as ${condition}`);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDesc?: string, newLoc?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { ...i, quantity: i.quantity + qty, description: newDesc ?? i.description, location: newLoc ?? i.location } : i
    ));
    createAuditEntry('INVENTORY_ADJUSTMENT', itemId, item.name, qty, note);
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      setInventory(prev => [...prev, { ...newItem, id, inventoryUID }]);

      const msg = newItem.status === 'pending_approval' ? 'New item sent for verification.' : 'New record created immediately.';
      createAuditEntry('ITEM_CREATED', id, newItem.name, newItem.quantity, msg);
  };

  const handleApproveItem = (id: string) => {
    setInventory(prev => prev.map(i => i.id === id ? { ...i, status: 'active' } : i));
    createAuditEntry('ITEM_APPROVED', id, 'New Asset', 0, 'Owner approved pending asset.');
  };

  const handleRejectItem = (id: string) => {
    setInventory(prev => prev.filter(i => i.id !== id));
    createAuditEntry('ITEM_REJECTED', id, 'New Asset', 0, 'Owner rejected pending asset.');
  };

  // --- Category Actions ---
  const handleAddCategory = (name: string) => {
    const newCat = { id: generateId(), name };
    setCategories(prev => [...prev, newCat]);
    createAuditEntry('CATEGORY_CREATED', 'N/A', 'Category', 0, `Category '${name}' created.`);
  };

  const handleUpdateCategory = (cat: InventoryCategory) => {
    setCategories(prev => prev.map(c => c.id === cat.id ? cat : c));
    createAuditEntry('CATEGORY_UPDATED', 'N/A', 'Category', 0, `Category updated to '${cat.name}'.`);
  };

  const handleDeleteCategory = (id: string) => {
    const cat = categories.find(c => c.id === id);
    setCategories(prev => prev.filter(c => c.id !== id));
    createAuditEntry('CATEGORY_DELETED', 'N/A', 'Category', 0, `Category '${cat?.name}' deleted.`);
  };

  // --- Audit Filters ---
  const filteredAuditLog = useMemo(() => {
    return auditLog.filter(log => {
      const search = auditSearch.toLowerCase();
      const matchesSearch = log.performedBy.toLowerCase().includes(search) || log.itemName.toLowerCase().includes(search) || log.details.toLowerCase().includes(search);
      const matchesAction = auditActionFilter === 'All' || log.action === auditActionFilter;
      const matchesUser = auditUserFilter === 'All' || log.performedBy === auditUserFilter;
      const logDate = new Date(log.timestamp);
      const matchesFromDate = !auditFromDate || logDate >= new Date(auditFromDate);
      const matchesToDate = !auditToDate || logDate <= new Date(auditToDate + 'T23:59:59');
      return matchesSearch && matchesAction && matchesUser && matchesFromDate && matchesToDate;
    });
  }, [auditLog, auditSearch, auditActionFilter, auditUserFilter, auditFromDate, auditToDate]);

  return (
    <Layout currentUser={currentUser} onLogout={handleLogout} currentView={currentView} onChangeView={setCurrentView}>
      {currentView === 'inventory' && (
        <InventoryView items={inventory} currentUser={currentUser} purposes={workPurposes} categories={categories} onRequestItem={handleRequestItem} onManualAdjust={() => {}} />
      )}
      {currentView === 'add-inventory' && (
        <AddInventoryView items={inventory} currentUser={currentUser} categories={categories} onAddStock={handleAddStock} onCreateItem={handleCreateItem} />
      )}
      {currentView === 'requests' && (
        <RequestQueue requests={requests} items={inventory} users={users} currentUser={currentUser} onClaim={handleClaim} onVerify={handleVerify} onReject={handleReject} onProcess={handleProcess} onReturnAction={handleReturnAction} onInitiateReturnById={handleReturnItem} />
      )}
      {currentView === 'movements' && (
        <MovementsView movements={movements} currentUser={currentUser} onCreateMovement={handleCreateMovement} onUpdateMovement={handleUpdateMovement} />
      )}
      {currentView === 'financials' && (
        <FinancialDashboard items={inventory} requests={requests} purposes={workPurposes} />
      )}
      {currentView === 'procurement' && (
        <ProcurementTable pos={MOCK_POS} purposes={workPurposes} />
      )}
      {currentView === 'management' && (
        <ManagementView 
          users={users} workPurposes={workPurposes} categories={categories} currentUser={currentUser} pendingItems={inventory.filter(i => i.status === 'pending_approval')}
          onAddUser={u => setUsers([...users, { ...u, id: generateId() }])} 
          onUpdateUser={u => setUsers(users.map(x => x.id === u.id ? u : x))}
          onDeleteUser={id => setUsers(users.filter(x => x.id !== id))}
          onAddPurpose={t => setWorkPurposes([...workPurposes, { id: generateId(), title: t }])}
          onUpdatePurpose={p => setWorkPurposes(workPurposes.map(x => x.id === p.id ? p : x))}
          onDeletePurpose={id => setWorkPurposes(workPurposes.filter(x => x.id !== id))}
          onAddCategory={handleAddCategory} onUpdateCategory={handleUpdateCategory} onDeleteCategory={handleDeleteCategory}
          onApproveItem={handleApproveItem} onRejectItem={handleRejectItem}
        />
      )}
      {currentView === 'audit' && (
          <div className="space-y-6">
              <h2 className="text-2xl font-bold flex items-center gap-2"><Activity className="w-7 h-7 text-blue-600" /> Audit Trail</h2>
              <div className="bg-white p-6 rounded-3xl border shadow-sm space-y-4">
                  <div className="flex flex-col lg:flex-row gap-4">
                      <input type="text" placeholder="Search..." className="flex-1 p-3 bg-slate-50 border rounded-xl" value={auditSearch} onChange={e => setAuditSearch(e.target.value)} />
                      <select value={auditActionFilter} onChange={e => setAuditActionFilter(e.target.value)} className="p-3 bg-slate-50 border rounded-xl">
                        <option value="All">All Actions</option>
                        {Array.from(new Set(auditLog.map(l => l.action))).map(a => <option key={a} value={a}>{a}</option>)}
                      </select>
                  </div>
              </div>
              <div className="bg-white rounded-3xl border overflow-hidden">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 border-b">
                    <tr><th className="px-6 py-4">Timestamp</th><th className="px-6 py-4">Action</th><th className="px-6 py-4">Operator</th><th className="px-6 py-4">Details</th></tr>
                  </thead>
                  <tbody className="divide-y">
                    {filteredAuditLog.map(log => (
                      <tr key={log.id} className="hover:bg-slate-50"><td className="px-6 py-4">{new Date(log.timestamp).toLocaleString()}</td><td className="px-6 py-4 font-bold">{log.action}</td><td className="px-6 py-4">{log.performedBy}</td><td className="px-6 py-4 text-slate-500">{log.details}</td></tr>
                    ))}
                  </tbody>
                </table>
              </div>
          </div>
      )}
    </Layout>
  );
};

