  currentView: string;
  icon: any;
  label: string;
  onChangeView: (view: string) => void;
  onClick?: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ view, currentView, icon: Icon, label, onChangeView, onClick }) => (
  <button
    onClick={() => {
      onChangeView(view);
      if (onClick) onClick();
    }}
    className={`flex items-center w-full px-4 py-3 mb-1 text-sm font-medium transition-colors rounded-lg ${
      currentView === view
        ? 'bg-blue-600 text-white shadow-md'
        : 'text-slate-600 hover:bg-slate-100'
    }`}
  >
    <Icon className={`w-5 h-5 mr-3 ${currentView === view ? 'text-white' : 'text-slate-400'}`} />
    {label}
