                    {showProcurement && <NavItem view="procurement" currentView={currentView} onChangeView={onChangeView} icon={FileText} label="Procurement" onClick={() => setIsMobileMenuOpen(false)} />}
                    {showFinancials && <NavItem view="financials" currentView={currentView} onChangeView={onChangeView} icon={BarChart3} label="Financials" onClick={() => setIsMobileMenuOpen(false)} />}
