                >
                    {showAllData ? 'Showing Global History' : 'Enable Full Database View'}
                </button>
                <button 
                    onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                    className="px-6 py-3.5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-slate-100 flex items-center gap-2"
                >
                    <ArrowUpDown className="w-3 h-3" /> Order: {sortOrder}
                </button>
            </div>
        </div>
      </div>

      {activePage === 'master' ? (
          <MasterSheet filteredPos={filteredPos} purposes={purposes} setSelectedPO={setSelectedPO} getDerivedFields={getDerivedFields} />
