                                onChange={(e) => handleAssignPurpose(selectedPO.id, e.target.value)} 
                                className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm appearance-none"
                            >
                                <option value="">Unallocated / External Cost</option>
                                {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                            </select>
                            <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
