                                <div className="flex gap-4">
                                    <button className="px-8 py-3 bg-slate-900 text-white font-black rounded-2xl text-xs hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-100 flex items-center gap-2">
                                        <Eye className="w-4 h-4" /> Open Document
