                                    <button onClick={() => handleUploadPDF(selectedPO.id)} className="px-8 py-3 border border-slate-200 bg-white text-slate-600 font-black rounded-2xl text-xs hover:bg-slate-50 transition-all flex items-center gap-2">
                                        <Upload className="w-4 h-4" /> Replace
