// Helper to generate IDs
export const generateId = () => Math.random().toString(36).substr(2, 9);

// Helper to generate Unique Inventory Internal Codes (ST-XXXX)
export const generateInventoryUID = (currentItems: InventoryItem[]) => {
  const existingUids = currentItems.map(item => item.inventoryUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/ST-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `ST-${nextNumber}`;
};

// Helper to generate Unique Request Internal Codes (REQ-XXXX)
export const generateRequestUID = (currentRequests: Request[]) => {
  const existingUids = currentRequests.map(req => req.requestUID);
  let nextNumber = 1001;

  existingUids.forEach(uid => {
    const match = uid.match(/REQ-(\d+)/);
    if (match) {
      const num = parseInt(match[1]);
      if (num >= nextNumber) nextNumber = num + 1;
    }
  });

  return `REQ-${nextNumber}`;
};

import { InventoryItem, PurchaseOrder } from '../types';

// Headers defined by user request
export const INVENTORY_HEADERS = [
  'ITEM CODE', 'DESCRIPTION', 'NAME', 'ITEM PART NUMBER', 'LOCATION', 'QUANTITY', 'MINIMUM THRESHOLD ALERT QTY', 'PRICE', 'CATEGORY'
];

export const PROCUREMENT_HEADERS = [
  'PR NO', 'DESCRIPTION', 'WORK PURPOSE', 'ISSUED BY', 'DATE ISSUED', 'PR STATUS', 'TECH APPROVAL STATUS', 'PO STATUS', 'PO NO', 'MANUAL REMARKS', 'NET AMOUNT', 'CURRENCY'
];

export const downloadTemplate = (type: 'inventory' | 'procurement') => {
  const headers = type === 'inventory' ? INVENTORY_HEADERS : PROCUREMENT_HEADERS;
  const csvContent = "data:text/csv;charset=utf-8," + headers.join(",");
  const encodedUri = encodeURI(csvContent);
  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", `SecureTrack_${type === 'inventory' ? 'Inventory' : 'Procurement'}_Template.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const parseInventoryCSV = (text: string, existingCategories: any[]): Partial<InventoryItem>[] => {
  const lines = text.split('\n');
  const result: Partial<InventoryItem>[] = [];

  // Skip header row (index 0)
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // Simple split by comma (assuming no commas in descriptions for this prototype, or handled by Excel export)
    // For robust parsing, we'd use a regex or library, but simple split works for standard Google Sheets CSV export
    const cols = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/); 

    if (cols.length < 8) continue; // Basic validation

    const clean = (val: string) => val ? val.replace(/^"|"$/g, '').trim() : '';

    result.push({
      itemCode: clean(cols[0]),
      description: clean(cols[1]),
      name: clean(cols[2]),
      partNumber: clean(cols[3]),
      location: clean(cols[4]),
      quantity: parseInt(clean(cols[5])) || 0,
      minThreshold: parseInt(clean(cols[6])) || 0,
      price: parseFloat(clean(cols[7])) || 0,
      category: clean(cols[8]) || 'General',
      status: 'active'
    });
  }
  return result;
};

export const parseProcurementCSV = (text: string, purposes: any[]): Partial<PurchaseOrder>[] => {
  const lines = text.split('\n');
  const result: Partial<PurchaseOrder>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    const cols = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);
    if (cols.length < 10) continue;

    const clean = (val: string) => val ? val.replace(/^"|"$/g, '').trim() : '';

    // Attempt to match purpose name to ID, else leave undefined
    const purposeName = clean(cols[2]);
    const purposeId = purposes.find(p => p.title.toLowerCase() === purposeName.toLowerCase())?.id;

    result.push({
      prNumber: clean(cols[0]),
      description: clean(cols[1]),
      purposeId: purposeId, // This might need manual mapping if not found
      issuedBy: clean(cols[3]),
      prDate: clean(cols[4]) || new Date().toISOString().split('T')[0],
      prStatus: clean(cols[5]),
      techApprovalStatus: (clean(cols[6]) as any) || 'Pending',
      poStatus: (clean(cols[7]) as any) || 'Draft',
      poNumber: clean(cols[8]),
      manualRemarks: clean(cols[9]),
      netAmount: parseFloat(clean(cols[10])) || 0,
      currency: clean(cols[11]) || 'USD',
      usdAmount: parseFloat(clean(cols[10])) || 0, // Simplified assumption for import
    });
  }
  return result;
};

import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import ManagementView from './components/ManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement,
    WorkPurpose,
    InventoryCategory,
    PurchaseOrder
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS,
    INITIAL_CATEGORIES
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Search, Calendar, Filter, User as UserIcon, Activity, ChevronDown, X } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [currentView, setCurrentView] = useState('inventory');

  // Data State
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [pos, setPos] = useState<PurchaseOrder[]>(MOCK_POS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [workPurposes, setWorkPurposes] = useState<WorkPurpose[]>(WORK_PURPOSES);
  const [categories, setCategories] = useState<InventoryCategory[]>(INITIAL_CATEGORIES);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Audit Filter State ---
  const [auditSearch, setAuditSearch] = useState('');
  const [auditActionFilter, setAuditActionFilter] = useState('All');
  const [auditUserFilter, setAuditUserFilter] = useState('All');
  const [auditFromDate, setAuditFromDate] = useState('');
  const [auditToDate, setAuditToDate] = useState('');

  // --- Actions ---
  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory');
  };

  const createAuditEntry = (action: string, itemId: string, itemName: string, qtyChange: number, details: string) => {
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action,
        itemId,
        itemName,
        quantityChange: qtyChange,
        performedBy: currentUser.name,
        details
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);
    createAuditEntry('MOVEMENT_CREATED', 'N/A', mv.itemCode, 0, `Standalone Move Order ${mv.moveOrderNumber} created.`);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));
    createAuditEntry('MOVEMENT_UPDATED', 'N/A', mv.itemCode, 0, `Move Order ${mv.moveOrderNumber} updated.`);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('REQUEST_CREATED', item.id, item.name, 0, `User requested ${qty} units.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason,
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('RETURN_INITIATED', item.id, item.name, 0, `Return of ${qty} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_CLAIMED', 'N/A', 'Request', 0, `Admin claimed request.`);
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_VERIFIED', 'N/A', 'Request', 0, `Request verified.`);
  };

  const handleReject = (reqId: string, reason: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.REJECTED, rejectedBy: currentUser.id, rejectionReason: reason } : req
    ));
    createAuditEntry('REQUEST_REJECTED', 'N/A', 'Request', 0, `Request rejected: ${reason}`);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i));
    }
    createAuditEntry('STOCK_DEDUCTED', request.itemId, item?.name || 'Item', -request.quantity, `Stock deducted.`);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request) return;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: RequestStatus.RETURNED, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          setInventory(prev => prev.map(i => i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i));
      }
      createAuditEntry('RETURN_PROCESSED', request.itemId, 'Item', condition === 'Good' ? request.quantity : 0, `Return finalized as ${condition}`);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDesc?: string, newLoc?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { ...i, quantity: i.quantity + qty, description: newDesc ?? i.description, location: newLoc ?? i.location } : i
    ));
    createAuditEntry('INVENTORY_ADJUSTMENT', itemId, item.name, qty, note);
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      setInventory(prev => [...prev, { ...newItem, id, inventoryUID }]);

      const msg = newItem.status === 'pending_approval' ? 'New item sent for verification.' : 'New record created immediately.';
      createAuditEntry('ITEM_CREATED', id, newItem.name, newItem.quantity, msg);
  };

  const handleBulkCreateItems = (newItems: Omit<InventoryItem, 'id' | 'inventoryUID'>[]) => {
      const timestamp = new Date().getTime();
      const itemsToAdd: InventoryItem[] = [];

      // We need to generate sequential ST codes, so we do it in loop
      let currentInventory = [...inventory];

      newItems.forEach((item, index) => {
          const id = generateId() + index;
          const inventoryUID = generateInventoryUID(currentInventory);
          const completeItem = { ...item, id, inventoryUID };
          itemsToAdd.push(completeItem);
          currentInventory.push(completeItem);
      });

      setInventory(prev => [...prev, ...itemsToAdd]);
      createAuditEntry('BULK_IMPORT', 'N/A', 'Multiple Items', itemsToAdd.length, `Bulk imported ${itemsToAdd.length} items from Google Sheets.`);
  };

  const handleBulkCreatePOs = (newPos: Omit<PurchaseOrder, 'id'>[]) => {
      const posToAdd = newPos.map((po, index) => ({
          ...po,
          id: generateId() + index
      }));
      setPos(prev => [...prev, ...posToAdd]);
      createAuditEntry('BULK_IMPORT_PO', 'N/A', 'Multiple POs', posToAdd.length, `Bulk imported ${posToAdd.length} PR/PO records.`);
  };

  const handleApproveItem = (id: string) => {
    setInventory(prev => prev.map(i => i.id === id ? { ...i, status: 'active' } : i));
    createAuditEntry('ITEM_APPROVED', id, 'New Asset', 0, 'Owner approved pending asset.');
  };

  const handleRejectItem = (id: string) => {
    setInventory(prev => prev.filter(i => i.id !== id));
    createAuditEntry('ITEM_REJECTED', id, 'New Asset', 0, 'Owner rejected pending asset.');
  };

  // --- Category Actions ---
  const handleAddCategory = (name: string) => {
    const newCat = { id: generateId(), name };
    setCategories(prev => [...prev, newCat]);
    createAuditEntry('CATEGORY_CREATED', 'N/A', 'Category', 0, `Category '${name}' created.`);
  };

  const handleUpdateCategory = (cat: InventoryCategory) => {
    setCategories(prev => prev.map(c => c.id === cat.id ? cat : c));
    createAuditEntry('CATEGORY_UPDATED', 'N/A', 'Category', 0, `Category updated to '${cat.name}'.`);
  };

  const handleDeleteCategory = (id: string) => {
    const cat = categories.find(c => c.id === id);
    setCategories(prev => prev.filter(c => c.id !== id));
    createAuditEntry('CATEGORY_DELETED', 'N/A', 'Category', 0, `Category '${cat?.name}' deleted.`);
  };

  // --- Audit Filters ---
  const filteredAuditLog = useMemo(() => {
    return auditLog.filter(log => {
      const search = auditSearch.toLowerCase();
      const matchesSearch = log.performedBy.toLowerCase().includes(search) || log.itemName.toLowerCase().includes(search) || log.details.toLowerCase().includes(search);
      const matchesAction = auditActionFilter === 'All' || log.action === auditActionFilter;
      const matchesUser = auditUserFilter === 'All' || log.performedBy === auditUserFilter;
      const logDate = new Date(log.timestamp);
      const matchesFromDate = !auditFromDate || logDate >= new Date(auditFromDate);
      const matchesToDate = !auditToDate || logDate <= new Date(auditToDate + 'T23:59:59');
      return matchesSearch && matchesAction && matchesUser && matchesFromDate && matchesToDate;
    });
  }, [auditLog, auditSearch, auditActionFilter, auditUserFilter, auditFromDate, auditToDate]);

  return (
    <Layout currentUser={currentUser} onLogout={handleLogout} currentView={currentView} onChangeView={setCurrentView}>
      {currentView === 'inventory' && (
        <InventoryView items={inventory} currentUser={currentUser} purposes={workPurposes} categories={categories} onRequestItem={handleRequestItem} onManualAdjust={() => {}} />
      )}
      {currentView === 'add-inventory' && (
        <AddInventoryView 
          items={inventory} 
          currentUser={currentUser} 
          categories={categories} 
          onAddStock={handleAddStock} 
          onCreateItem={handleCreateItem} 
          onBulkImport={handleBulkCreateItems}
        />
      )}
      {currentView === 'requests' && (
        <RequestQueue requests={requests} items={inventory} users={users} currentUser={currentUser} onClaim={handleClaim} onVerify={handleVerify} onReject={handleReject} onProcess={handleProcess} onReturnAction={handleReturnAction} onInitiateReturnById={handleReturnItem} />
      )}
      {currentView === 'movements' && (
        <MovementsView movements={movements} currentUser={currentUser} onCreateMovement={handleCreateMovement} onUpdateMovement={handleUpdateMovement} />
      )}
      {currentView === 'financials' && (
        <FinancialDashboard items={inventory} requests={requests} purposes={workPurposes} />
      )}
      {currentView === 'procurement' && (
        <ProcurementTable pos={pos} purposes={workPurposes} onImportPOs={handleBulkCreatePOs} />
      )}
      {currentView === 'management' && (
        <ManagementView 
          users={users} workPurposes={workPurposes} categories={categories} currentUser={currentUser} pendingItems={inventory.filter(i => i.status === 'pending_approval')}
          onAddUser={u => setUsers([...users, { ...u, id: generateId() }])} 
          onUpdateUser={u => setUsers(users.map(x => x.id === u.id ? u : x))}
          onDeleteUser={id => setUsers(users.filter(x => x.id !== id))}
          onAddPurpose={t => setWorkPurposes([...workPurposes, { id: generateId(), title: t }])}
          onUpdatePurpose={p => setWorkPurposes(workPurposes.map(x => x.id === p.id ? p : x))}
          onDeletePurpose={id => setWorkPurposes(workPurposes.filter(x => x.id !== id))}
          onAddCategory={handleAddCategory} onUpdateCategory={handleUpdateCategory} onDeleteCategory={handleDeleteCategory}
          onApproveItem={handleApproveItem} onRejectItem={handleRejectItem}
        />
      )}
      {currentView === 'audit' && (
          <div className="space-y-6 pb-20 text-slate-900">
              <h2 className="text-2xl font-bold flex items-center gap-2 text-slate-900"><Activity className="w-7 h-7 text-blue-600" /> Audit Trail</h2>
              <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-4">
                  <div className="flex flex-col lg:flex-row gap-4">
                      <input type="text" placeholder="Search..." className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 font-medium" value={auditSearch} onChange={e => setAuditSearch(e.target.value)} />
                      <select value={auditActionFilter} onChange={e => setAuditActionFilter(e.target.value)} className="p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 font-bold">
                        <option value="All">All Actions</option>
                        {Array.from(new Set(auditLog.map(l => l.action))).map(a => <option key={a} value={a}>{a}</option>)}
                      </select>
                  </div>
              </div>
              <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Timestamp</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Action</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Operator</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Details</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredAuditLog.map(log => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 text-slate-900 font-medium text-xs">{new Date(log.timestamp).toLocaleString()}</td>
                        <td className="px-6 py-4 font-bold text-slate-900 text-xs">{log.action}</td>
                        <td className="px-6 py-4 text-slate-900 font-bold text-xs">{log.performedBy}</td>
                        <td className="px-6 py-4 text-slate-900 text-xs">{log.details}</td>
                      </tr>
                    ))}
                    {filteredAuditLog.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                          No audit records found
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
          </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { InventoryItem, User, InventoryCategory, UserRole } from '../types';
import { canManageInventory, canCreateNewItem, generateInventoryUID } from '../services/stateService';
import { downloadTemplate, parseInventoryCSV } from '../services/importService';
import { Search, Package, AlertCircle, FileText, MapPin, ChevronDown, Tag, Hash, Info, ShieldAlert, FileSpreadsheet, Upload, Download } from 'lucide-react';

interface AddInventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  categories: InventoryCategory[];
  onAddStock: (itemId: string, qty: number, note: string, newDescription?: string, newLocation?: string) => void;
  onCreateItem: (item: Omit<InventoryItem, 'id' | 'inventoryUID'>) => void;
  onBulkImport: (items: Omit<InventoryItem, 'id' | 'inventoryUID'>[]) => void;
}

const AddInventoryView: React.FC<AddInventoryViewProps> = ({ items, currentUser, categories, onAddStock, onCreateItem, onBulkImport }) => {
  const isReadOnly = !canManageInventory(currentUser);
  const canRegisterNew = canCreateNewItem(currentUser);
  const isOwner = currentUser.role === UserRole.OWNER;
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [activeTab, setActiveTab] = useState<'existing' | 'new' | 'import'>('existing');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [addQty, setAddQty] = useState<number | "">(0);
  const [addNote, setAddNote] = useState('');
  const [addDescription, setAddDescription] = useState('');
  const [addLocation, setAddLocation] = useState('');

  const [newItem, setNewItem] = useState({
      itemCode: '',
      name: '',
      description: '',
      partNumber: '',
      location: '',
      quantity: 0,
      minThreshold: 5,
      price: 0,
      category: '',
      status: 'active' as 'active' | 'pending_approval'
  });

  const [previewUID, setPreviewUID] = useState('');

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
      setAddLocation(selectedItem.location || '');
      setAddQty(0);
      setAddNote('');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') setPreviewUID(generateInventoryUID(items));
  }, [activeTab, items]);

  const filteredItems = items.filter(item => {
    if (item.status === 'pending_approval') return false;
    const s = searchTerm.toLowerCase();
    return item.name.toLowerCase().includes(s) || item.itemCode.toLowerCase().includes(s) || item.inventoryUID.toLowerCase().includes(s);
  });

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.category) return alert("Please select a valid category from the system list.");

    const status = isOwner ? 'active' : 'pending_approval';

    onCreateItem({ ...newItem, status });

    if (!isOwner) {
      alert("New asset submitted for Owner Verification. It will appear in the inventory list once approved.");
    }

    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '', status: 'active' });
    setActiveTab('existing');
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
        const text = event.target?.result as string;
        try {
            const parsedItems = parseInventoryCSV(text, categories);
            if (parsedItems.length === 0) {
                alert("No valid items found in the file. Please check the template format.");
                return;
            }
            // Ensure all required fields are present (basic check)
            const validItems = parsedItems.filter(i => i.name && i.itemCode) as Omit<InventoryItem, 'id' | 'inventoryUID'>[];

            if (validItems.length < parsedItems.length) {
                if (!window.confirm(`${parsedItems.length - validItems.length} items were incomplete and will be skipped. Continue?`)) return;
            }

            onBulkImport(validItems);
            alert(`Successfully queued ${validItems.length} items for import.`);
            setActiveTab('existing');
        } catch (err) {
            alert("Failed to parse file. Please ensure it is a valid CSV.");
        }
    };
    reader.readAsText(file);
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  if (isReadOnly) return (
    <div className="p-20 text-center text-slate-500 flex flex-col items-center gap-4">
      <AlertCircle className="w-12 h-12 text-slate-300" />
      <div>
        <h3 className="text-lg font-bold text-slate-700">Restricted Access</h3>
        <p className="text-sm font-medium">You do not have administrative authority to modify inventory.</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-2 uppercase tracking-tight">
          <Package className="w-7 h-7 text-blue-600" /> Stock Adjustment Center
        </h2>
      </div>

      <div className="flex p-1.5 bg-slate-200 rounded-2xl w-full max-w-2xl">
          <button 
            onClick={() => setActiveTab('existing')} 
            className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Update Existing
          </button>
          {canRegisterNew && (
            <button 
              onClick={() => setActiveTab('new')} 
              className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Register New Asset
            </button>
          )}
          {canRegisterNew && (
            <button 
              onClick={() => setActiveTab('import')} 
              className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'import' ? 'bg-green-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
               Google Sheets Import
            </button>
          )}
      </div>

      {activeTab === 'import' && (
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-2xl mx-auto shadow-sm animate-in zoom-in duration-300 text-center space-y-8">
               <div>
                 <div className="w-16 h-16 bg-green-100 text-green-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
                    <FileSpreadsheet className="w-8 h-8" />
                 </div>
                 <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Bulk Inventory Import</h3>
                 <p className="text-sm text-slate-500 font-medium mt-2 max-w-md mx-auto">
                    Seamlessly add thousands of items by syncing with Google Sheets.
                 </p>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 text-left">
                  <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 hover:border-blue-300 transition-colors group cursor-pointer" onClick={() => downloadTemplate('inventory')}>
                      <div className="flex items-center gap-3 mb-2">
                          <Download className="w-5 h-5 text-blue-500" />
                          <h4 className="font-black text-slate-800">Step 1: Download</h4>
                      </div>
                      <p className="text-xs text-slate-500">Get the official Google Sheets CSV template with the required headers.</p>
                      <button className="mt-4 text-xs font-black text-blue-600 uppercase tracking-widest group-hover:underline">Download Template</button>
                  </div>

                  <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 hover:border-green-300 transition-colors group relative">
                      <div className="flex items-center gap-3 mb-2">
                          <Upload className="w-5 h-5 text-green-500" />
                          <h4 className="font-black text-slate-800">Step 2: Upload</h4>
                      </div>
                      <p className="text-xs text-slate-500">Export your Google Sheet as .CSV and drop it here to populate the system.</p>
                      <input 
                        type="file" 
                        accept=".csv"
                        ref={fileInputRef}
                        onChange={handleFileUpload}
                        className="absolute inset-0 opacity-0 cursor-pointer" 
                      />
                      <button className="mt-4 text-xs font-black text-green-600 uppercase tracking-widest group-hover:underline">Select File</button>
                  </div>
               </div>

               <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3 text-left">
                  <Info className="w-5 h-5 text-amber-600 mt-0.5 shrink-0" />
                  <div>
                      <p className="text-xs font-bold text-amber-800">Formatting Guide</p>
                      <p className="text-[10px] text-amber-700 mt-1">
                          Ensure headers match the template exactly: <strong>ITEM CODE, DESCRIPTION, NAME, ITEM PART NUMBER, LOCATION, QUANTITY, MINIMUM THRESHOLD ALERT QTY, PRICE, CATEGORY</strong>.
                      </p>
                  </div>
               </div>
          </div>
      )}

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-300">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="text" 
                      placeholder="Search for item to adjust..." 
                      className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-white shadow-sm" 
                      value={searchTerm} 
                      onChange={e => setSearchTerm(e.target.value)} 
                    />
                  </div>
                  <div className="bg-white rounded-3xl border border-slate-200 divide-y divide-slate-50 overflow-y-auto max-h-[550px] shadow-sm">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)} 
                            className={`p-5 cursor-pointer hover:bg-slate-50 transition-colors flex items-center justify-between ${selectedItem?.id === item.id ? 'bg-blue-50/50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div>
                                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest block mb-1">{item.inventoryUID}</span>
                                <div className="font-bold text-slate-900">{item.name}</div>
                                <div className="text-[10px] text-slate-400 font-bold">{item.itemCode} • {item.location}</div>
                              </div>
                              <div className="text-right">
                                <span className={`text-sm font-black ${item.quantity <= item.minThreshold ? 'text-red-600' : 'text-green-600'}`}>{item.quantity}</span>
                              </div>
                          </div>
                      ))}
                      {filteredItems.length === 0 && (
                        <div className="p-10 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                          No items found
                        </div>
                      )}
                  </div>
              </div>

              <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm h-fit sticky top-8">
                  {selectedItem ? (
                      <form onSubmit={e => { e.preventDefault(); onAddStock(selectedItem.id, addQty || 0, addNote, addDescription, addLocation); setSelectedItem(null); }} className="space-y-6">
                          <div className="flex items-center gap-3 pb-4 border-b border-slate-100">
                             <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black">{selectedItem.name.charAt(0)}</div>
                             <div>
                               <h3 className="font-black text-slate-900">{selectedItem.name}</h3>
                               <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{selectedItem.inventoryUID} Adjustment</p>
                             </div>
                          </div>

                          <div className="grid grid-cols-1 gap-4">
                            <div className="space-y-1.5">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Current Bin Location</label>
                              <div className="relative">
                                <MapPin className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                                <input type="text" className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold" value={addLocation} onChange={e => setAddLocation(e.target.value)} />
                              </div>
                            </div>
                            <div className="space-y-1.5">
                              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Asset Description</label>
                              <div className="relative">
                                <FileText className="absolute left-3.5 top-4 w-4 h-4 text-slate-400" />
                                <textarea className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium min-h-[100px]" value={addDescription} onChange={e => setAddDescription(e.target.value)} />
                              </div>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                              <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Quantity Delta (+/-)</label>
                                <input type="number" placeholder="Enter change..." className="w-full border border-slate-200 p-3.5 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={addQty === 0 ? '' : addQty} onChange={e => setAddQty(e.target.value === '' ? '' : parseInt(e.target.value))} />
                              </div>
                              <div className="space-y-1.5">
                                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Adjustment Reason</label>
                                <input type="text" required={addQty !== 0} placeholder="e.g. Audit Correct, Received..." className="w-full border border-slate-200 p-3.5 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium" value={addNote} onChange={e => setAddNote(e.target.value)} />
                              </div>
                            </div>
                          </div>

                          <button type="submit" className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl shadow-slate-200 hover:bg-slate-800 transition-all active:scale-95">
                            Process Inventory Update
                          </button>
                      </form>
                  ) : (
                    <div className="py-24 text-center space-y-4">
                      <Search className="w-12 h-12 text-slate-100 mx-auto" />
                      <div>
                        <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Search & Select</p>
                        <p className="text-sm text-slate-300 font-medium mt-1">Select an item from the left panel to begin adjustment.</p>
                      </div>
                    </div>
                  )}
              </div>
          </div>
      )}

      {activeTab === 'new' && (
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-2xl mx-auto shadow-sm animate-in zoom-in duration-300">
              <form onSubmit={handleCreateSubmit} className="space-y-8">
                  <div className="flex justify-between items-start pb-4 border-b border-slate-100">
                    <div>
                      <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">New Asset Registration</h3>
                      <p className="text-xs text-slate-400 font-bold mt-1 uppercase tracking-widest">Adding to Master System Database</p>
                    </div>
                    <div className="text-right">
                       <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1">Inventory ID</label>
                       <span className="font-mono bg-blue-600 text-white px-4 py-2 rounded-2xl text-xs font-black shadow-lg shadow-blue-100">{previewUID}</span>
                    </div>
                  </div>

                  {!isOwner && (
                    <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100 flex items-start gap-3">
                      <ShieldAlert className="w-5 h-5 text-amber-600 mt-0.5 shrink-0" />
                      <div>
                        <p className="text-sm font-black text-amber-800">Verification Required</p>
                        <p className="text-xs text-amber-700 mt-1 leading-relaxed">
                          As you are not the System Owner, this new asset will be created in a <strong>Pending Approval</strong> state. The Owner must verify and activate it before it appears in the active inventory list.
                        </p>
                      </div>
                    </div>
                  )}

                  <div className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Code</label>
                          <div className="relative">
                            <Hash className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input type="text" required placeholder="AXXX-XXXX" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.itemCode} onChange={e => setNewItem({...newItem, itemCode: e.target.value})} />
                          </div>
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Part Number</label>
                          <div className="relative">
                            <Tag className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input type="text" required placeholder="Part #" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.partNumber} onChange={e => setNewItem({...newItem, partNumber: e.target.value})} />
                          </div>
                        </div>
                    </div>

                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Item Name</label>
                      <input type="text" required placeholder="Enter primary identification name..." className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.name} onChange={e => setNewItem({...newItem, name: e.target.value})} />
                    </div>

                    <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Description</label>
                      <div className="relative">
                        <Info className="absolute left-3.5 top-4 w-4 h-4 text-slate-400" />
                        <textarea required placeholder="Detailed asset description..." className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium bg-slate-50 min-h-[100px]" value={newItem.description} onChange={e => setNewItem({...newItem, description: e.target.value})} />
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location</label>
                        <div className="relative">
