interface ProcurementTableProps {
  pos: PurchaseOrder[];
  purposes: WorkPurpose[];
  onImportPOs?: (pos: Omit<PurchaseOrder, 'id'>[]) => void;
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos, purposes, onImportPOs }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts' | 'import'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 10 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  const filteredPos = useMemo(() => {
    let result = [...pos];
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => { const date = new Date(po.prDate); return date >= startDate && date <= endDate; });
    }
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });
    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => filteredPos.reduce((sum, po) => sum + po.usdAmount, 0), [filteredPos]);
  const contributionData = useMemo(() => {
    const map: Record<string, number> = {};
    filteredPos.forEach(po => {
      const purpose = purposes.find(p => p.id === po.purposeId);
      const label = purpose ? purpose.title : 'Unallocated';
      map[label] = (map[label] || 0) + po.usdAmount;
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [filteredPos, purposes]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    alert("Official PO PDF uploaded successfully.");
  };

  const handleAssignPurpose = (poId: string, purposeId: string) => {
    setPos(prev => prev.map(p => p.id === poId ? { ...p, purposeId } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, purposeId } : null);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onImportPOs) return;

    const reader = new FileReader();
    reader.onload = (event) => {
        const text = event.target?.result as string;
        try {
            const parsedPos = parseProcurementCSV(text, purposes);
            if (parsedPos.length === 0) {
                alert("No valid POs found. Check the template.");
                return;
            }
            const validPos = parsedPos.filter(p => p.prNumber) as Omit<PurchaseOrder, 'id'>[];
            onImportPOs(validPos);
            alert(`Imported ${validPos.length} procurement records.`);
            setActivePage('master');
        } catch(err) {
            alert("Failed to parse CSV.");
        }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    if (po.techApprovalStatus === 'Approved' && po.poStatus === 'Issued' && po.poNumber?.trim()) return { remarks: 'Order Received', followUp: 'CLOSED' };
    return { remarks: po.manualRemarks || '-', followUp: 'Follow up needed' };
  };

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start gap-4">
        <div>
            <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-3 uppercase tracking-tight">
                <LayoutList className="w-7 h-7 text-blue-600" /> Procurement Hub
            </h2>
            <p className="text-sm text-slate-500 font-medium">Reconciling PR/PO lifecycle and project costing.</p>
        </div>
        <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
            <button 
                onClick={() => setActivePage('master')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'master' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <FileSpreadsheet className="w-4 h-4" /> Master List
            </button>
            <button 
                onClick={() => setActivePage('amounts')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'amounts' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <DollarSign className="w-4 h-4" /> Value Analytics
            </button>
            {onImportPOs && (
                <button 
                    onClick={() => setActivePage('import')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'import' ? 'bg-green-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                    <FileSpreadsheet className="w-4 h-4" /> Google Sheets
                </button>
            )}
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] border border-slate-200 relative shadow-sm">
        <div className="absolute top-0 left-0 w-1.5 h-full bg-[#4472C4] rounded-l-[32px]"></div>
        <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex flex-col md:flex-row gap-8 items-end flex-1">
                <SelectGroup label="From Period" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} disabled={showAllData} />
                <SelectGroup label="To Period" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} disabled={showAllData} />
            </div>
            <div className="flex flex-wrap items-end gap-3 lg:border-l lg:pl-8 lg:border-slate-100">
                <button 
                    onClick={() => setShowAllData(!showAllData)} 
                    className={`px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAllData ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-100' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                    {showAllData ? 'Showing Global History' : 'Enable Full Database View'}
                </button>
                <button 
                    onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                    className="px-6 py-3.5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-slate-100 flex items-center gap-2"
                >
                    <ArrowUpDown className="w-3 h-3" /> Order: {sortOrder}
                </button>
            </div>
        </div>
      </div>

      {activePage === 'master' && (
          <MasterSheet filteredPos={filteredPos} purposes={purposes} setSelectedPO={setSelectedPO} getDerivedFields={getDerivedFields} />
      )}

      {activePage === 'amounts' && (
          <AmountsPage filteredPos={filteredPos} purposes={purposes} totalSpent={totalSpent} contributionData={contributionData} setSelectedPO={setSelectedPO} />
      )}

      {activePage === 'import' && (
           <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-2xl mx-auto shadow-sm animate-in zoom-in duration-300 text-center space-y-8">
               <div>
                 <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
                    <LayoutList className="w-8 h-8" />
                 </div>
                 <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Google Sheets Procurement Sync</h3>
                 <p className="text-sm text-slate-500 font-medium mt-2 max-w-md mx-auto">
                    Update the Master PR/PO Log by uploading a CSV exported from the Procurement Tab of your Google Sheet.
                 </p>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 text-left">
                  <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 hover:border-blue-300 transition-colors group cursor-pointer" onClick={() => downloadTemplate('procurement')}>
                      <div className="flex items-center gap-3 mb-2">
                          <Download className="w-5 h-5 text-blue-500" />
                          <h4 className="font-black text-slate-800">Step 1: Get Template</h4>
                      </div>
                      <p className="text-xs text-slate-500">Download the standardized CSV structure for PR/PO data entry.</p>
                      <button className="mt-4 text-xs font-black text-blue-600 uppercase tracking-widest group-hover:underline">Download CSV</button>
                  </div>

                  <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 hover:border-green-300 transition-colors group relative">
                      <div className="flex items-center gap-3 mb-2">
                          <Upload className="w-5 h-5 text-green-500" />
                          <h4 className="font-black text-slate-800">Step 2: Sync Log</h4>
                      </div>
                      <p className="text-xs text-slate-500">Upload the filled CSV to bulk-create or update procurement records.</p>
                      <input 
                        type="file" 
                        accept=".csv"
                        ref={fileInputRef}
                        onChange={handleFileUpload}
                        className="absolute inset-0 opacity-0 cursor-pointer" 
                      />
                      <button className="mt-4 text-xs font-black text-green-600 uppercase tracking-widest group-hover:underline">Select File</button>
                  </div>
               </div>
          </div>
      )}

      {selectedPO && (
        <div className="fixed inset-0 bg-slate-900/70 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
                <div className="p-8 border-b flex justify-between items-center bg-blue-50/50">
                    <div>
                        <h3 className="text-xl font-black text-slate-900 flex items-center gap-3">
                            <FileSearch className="w-6 h-6 text-blue-600" /> {selectedPO.prNumber}
                        </h3>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Official Request Details</p>
                    </div>
                    <button onClick={() => setSelectedPO(null)} className="text-slate-400 hover:text-slate-600 transition-colors p-2"><X className="w-7 h-7" /></button>
                </div>
                <div className="p-10 space-y-10">
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-8">
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Request Status</span>
                            <p className="text-sm font-black text-slate-900 uppercase">{selectedPO.prStatus}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Associated PO</span>
                            <p className="text-sm font-mono font-black text-blue-700">{selectedPO.poNumber || 'PENDING ASSIGNMENT'}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Financial Impact</span>
                            <p className="text-sm font-black text-slate-900">{selectedPO.netAmount.toLocaleString()} <span className="text-slate-400">{selectedPO.currency}</span></p>
                        </div>
                    </div>

                    <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Briefcase className="w-3.5 h-3.5 text-blue-600" /> Assign Project/Work Purpose
                        </label>
                        <div className="relative">
                            <select 
                                value={selectedPO.purposeId || ''} 
                                onChange={(e) => handleAssignPurpose(selectedPO.id, e.target.value)} 
                                className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm appearance-none"
                            >
                                <option value="">Unallocated / External Cost</option>
                                {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                            </select>
                            <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>

                    <div className="space-y-6">
                        <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest flex items-center gap-2 border-l-4 border-blue-600 pl-3">
                            Supporting Documentation
                        </h4>
                        {selectedPO.pdfUrl ? (
                            <div className="bg-green-50/50 border border-green-100 p-10 rounded-[40px] flex flex-col items-center gap-6">
                                <FileText className="w-14 h-14 text-green-600" />
                                <div className="text-center">
                                    <p className="font-black text-slate-900">PO_DOCUMENT_ATTACHED.pdf</p>
                                    <p className="text-[10px] text-green-700 font-bold uppercase tracking-widest mt-1">Verified for audit</p>
                                </div>
                                <div className="flex gap-4">
                                    <button className="px-8 py-3 bg-slate-900 text-white font-black rounded-2xl text-xs hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-100 flex items-center gap-2">
                                        <Eye className="w-4 h-4" /> Open Document
                                    </button>
                                    <button onClick={() => handleUploadPDF(selectedPO.id)} className="px-8 py-3 border border-slate-200 bg-white text-slate-600 font-black rounded-2xl text-xs hover:bg-slate-50 transition-all flex items-center gap-2">
                                        <Upload className="w-4 h-4" /> Replace
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-amber-50 border-2 border-dashed border-amber-200 p-12 rounded-[40px] flex flex-col items-center gap-6">
                                <AlertCircle className="w-14 h-14 text-amber-500" />
                                <div className="text-center space-y-1">
                                    <p className="font-black text-amber-900 uppercase text-sm tracking-tight">Missing Procurement PDF</p>
                                    <p className="text-[10px] text-amber-700 font-bold uppercase tracking-widest">Attachment required for financial processing</p>
                                </div>
                                <button onClick={() => handleUploadPDF(selectedPO.id)} className="px-10 py-4 bg-amber-600 text-white font-black rounded-[24px] text-sm hover:bg-amber-700 shadow-xl shadow-amber-100 transition-all active:scale-95 flex items-center gap-2">
                                    <Upload className="w-5 h-5" /> Upload PO PDF
                                </button>
                            </div>
                        )}
                    </div>

                    <div className="flex justify-end pt-4">
                        <button onClick={() => setSelectedPO(null)} className="px-10 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition-colors uppercase tracking-widest text-xs">
                            Close Workspace
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default ProcurementTable;

import React, { useState, useMemo } from 'react';
import Layout from './components/Layout';
import InventoryView from './components/InventoryView';
import RequestQueue from './components/RequestQueue';
import FinancialDashboard from './components/FinancialDashboard';
import ProcurementTable from './components/ProcurementTable';
import AddInventoryView from './components/AddInventoryView';
import ManagementView from './components/ManagementView';
import MovementsView from './components/MovementsView';
import { 
    InventoryItem, 
    Request, 
    User, 
    UserRole,
    RequestStatus, 
    AuditLogEntry,
    RequestType,
    Movement,
    WorkPurpose,
    InventoryCategory,
    PurchaseOrder
} from './types';
import { 
    MOCK_USERS, 
    INITIAL_INVENTORY, 
    INITIAL_REQUESTS, 
    WORK_PURPOSES, 
    MOCK_POS,
    MOCK_MOVEMENTS,
    INITIAL_CATEGORIES
} from './constants';
import { generateId, generateInventoryUID, generateRequestUID } from './services/stateService';
import { FileSpreadsheet, Search, Calendar, Filter, User as UserIcon, Activity, ChevronDown, X } from 'lucide-react';

const App: React.FC = () => {
  // --- App State ---
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [currentUser, setCurrentUser] = useState<User>(MOCK_USERS[0]);
  const [currentView, setCurrentView] = useState('inventory');

  // Data State
  const [inventory, setInventory] = useState<InventoryItem[]>(INITIAL_INVENTORY);
  const [requests, setRequests] = useState<Request[]>(INITIAL_REQUESTS);
  const [pos, setPos] = useState<PurchaseOrder[]>(MOCK_POS);
  const [movements, setMovements] = useState<Movement[]>(MOCK_MOVEMENTS);
  const [workPurposes, setWorkPurposes] = useState<WorkPurpose[]>(WORK_PURPOSES);
  const [categories, setCategories] = useState<InventoryCategory[]>(INITIAL_CATEGORIES);
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);

  // --- Audit Filter State ---
  const [auditSearch, setAuditSearch] = useState('');
  const [auditActionFilter, setAuditActionFilter] = useState('All');
  const [auditUserFilter, setAuditUserFilter] = useState('All');
  const [auditFromDate, setAuditFromDate] = useState('');
  const [auditToDate, setAuditToDate] = useState('');

  // --- Actions ---
  const handleLogout = () => {
    const currentIndex = users.findIndex(u => u.id === currentUser.id);
    const nextIndex = (currentIndex + 1) % users.length;
    setCurrentUser(users[nextIndex]);
    setCurrentView('inventory');
  };

  const createAuditEntry = (action: string, itemId: string, itemName: string, qtyChange: number, details: string) => {
    const log: AuditLogEntry = {
        id: generateId(),
        timestamp: new Date().toISOString(),
        action,
        itemId,
        itemName,
        quantityChange: qtyChange,
        performedBy: currentUser.name,
        details
    };
    setAuditLog(prev => [log, ...prev]);
  };

  const handleCreateMovement = (mv: Omit<Movement, 'id'>) => {
    const newMv = { ...mv, id: generateId() };
    setMovements(prev => [newMv, ...prev]);
    createAuditEntry('MOVEMENT_CREATED', 'N/A', mv.itemCode, 0, `Standalone Move Order ${mv.moveOrderNumber} created.`);
  };

  const handleUpdateMovement = (mv: Movement) => {
    setMovements(prev => prev.map(m => m.id === mv.id ? mv : m));
    createAuditEntry('MOVEMENT_UPDATED', 'N/A', mv.itemCode, 0, `Move Order ${mv.moveOrderNumber} updated.`);
  };

  const handleRequestItem = (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        purposeId,
        specificPurpose: specific,
        status: RequestStatus.PENDING, 
        type: RequestType.TAKE,
        isEmergency,
        timestamp: new Date().toISOString()
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('REQUEST_CREATED', item.id, item.name, 0, `User requested ${qty} units.`);
  };

  const handleReturnItem = (itemId: string, qty: number, reason: string, refUID?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    const newRequest: Request = {
        id: generateId(),
        requestUID: generateRequestUID(requests),
        itemId,
        userId: currentUser.id,
        userName: currentUser.name,
        quantity: qty,
        status: RequestStatus.PENDING,
        type: RequestType.RETURN,
        specificPurpose: reason,
        isEmergency: false,
        timestamp: new Date().toISOString(),
        referenceRequestUID: refUID
    };

    setRequests(prev => [newRequest, ...prev]);
    createAuditEntry('RETURN_INITIATED', item.id, item.name, 0, `Return of ${qty} initiated.`);
  };

  const handleClaim = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.CLAIMED, claimedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_CLAIMED', 'N/A', 'Request', 0, `Admin claimed request.`);
  };

  const handleVerify = (reqId: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.VERIFIED, verifiedBy: currentUser.id } : req
    ));
    createAuditEntry('REQUEST_VERIFIED', 'N/A', 'Request', 0, `Request verified.`);
  };

  const handleReject = (reqId: string, reason: string) => {
    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.REJECTED, rejectedBy: currentUser.id, rejectionReason: reason } : req
    ));
    createAuditEntry('REQUEST_REJECTED', 'N/A', 'Request', 0, `Request rejected: ${reason}`);
  };

  const handleProcess = (reqId: string) => {
    const request = requests.find(r => r.id === reqId);
    if (!request) return;

    setRequests(prev => prev.map(req => 
        req.id === reqId ? { ...req, status: RequestStatus.PROCESSED, processedBy: currentUser.id } : req
    ));

    const item = inventory.find(i => i.id === request.itemId);
    if (item) {
        setInventory(prev => prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity - request.quantity } : i));
    }
    createAuditEntry('STOCK_DEDUCTED', request.itemId, item?.name || 'Item', -request.quantity, `Stock deducted.`);
  };

  const handleReturnAction = (reqId: string, condition: 'Good' | 'Damaged') => {
      const request = requests.find(r => r.id === reqId);
      if (!request) return;

      setRequests(prev => prev.map(req => 
          req.id === reqId ? { ...req, status: RequestStatus.RETURNED, returnCondition: condition } : req
      ));

      if (condition === 'Good') {
          setInventory(prev => prev.map(i => i.id === request.itemId ? { ...i, quantity: i.quantity + request.quantity } : i));
      }
      createAuditEntry('RETURN_PROCESSED', request.itemId, 'Item', condition === 'Good' ? request.quantity : 0, `Return finalized as ${condition}`);
  };

  const handleAddStock = (itemId: string, qty: number, note: string, newDesc?: string, newLoc?: string) => {
    const item = inventory.find(i => i.id === itemId);
    if (!item) return;

    setInventory(prev => prev.map(i => 
        i.id === itemId ? { ...i, quantity: i.quantity + qty, description: newDesc ?? i.description, location: newLoc ?? i.location } : i
    ));
    createAuditEntry('INVENTORY_ADJUSTMENT', itemId, item.name, qty, note);
  };

  const handleDeleteItem = (itemId: string, reason: string) => {
    const item = inventory.find(i => i.id === itemId);
    setInventory(prev => prev.filter(i => i.id !== itemId));
    createAuditEntry('ITEM_DELETED', itemId, item?.name || 'Unknown', -(item?.quantity || 0), `Item deleted from master list. Reason: ${reason}`);
  };

  const handleCreateItem = (newItem: Omit<InventoryItem, 'id' | 'inventoryUID'>) => {
      const id = generateId();
      const inventoryUID = generateInventoryUID(inventory);
      setInventory(prev => [...prev, { ...newItem, id, inventoryUID }]);

      const msg = newItem.status === 'pending_approval' ? 'New item sent for verification.' : 'New record created immediately.';
      createAuditEntry('ITEM_CREATED', id, newItem.name, newItem.quantity, msg);
  };

  const handleBulkCreateItems = (newItems: Omit<InventoryItem, 'id' | 'inventoryUID'>[]) => {
      const timestamp = new Date().getTime();
      const itemsToAdd: InventoryItem[] = [];

      // We need to generate sequential ST codes, so we do it in loop
      let currentInventory = [...inventory];

      newItems.forEach((item, index) => {
          const id = generateId() + index;
          const inventoryUID = generateInventoryUID(currentInventory);
          const completeItem = { ...item, id, inventoryUID };
          itemsToAdd.push(completeItem);
          currentInventory.push(completeItem);
      });

      setInventory(prev => [...prev, ...itemsToAdd]);
      createAuditEntry('BULK_IMPORT', 'N/A', 'Multiple Items', itemsToAdd.length, `Bulk imported ${itemsToAdd.length} items from Google Sheets.`);
  };

  const handleBulkCreatePOs = (newPos: Omit<PurchaseOrder, 'id'>[]) => {
      const posToAdd = newPos.map((po, index) => ({
          ...po,
          id: generateId() + index
      }));
      setPos(prev => [...prev, ...posToAdd]);
      createAuditEntry('BULK_IMPORT_PO', 'N/A', 'Multiple POs', posToAdd.length, `Bulk imported ${posToAdd.length} PR/PO records.`);
  };

  const handleApproveItem = (id: string) => {
    setInventory(prev => prev.map(i => i.id === id ? { ...i, status: 'active' } : i));
    createAuditEntry('ITEM_APPROVED', id, 'New Asset', 0, 'Owner approved pending asset.');
  };

  const handleRejectItem = (id: string) => {
    setInventory(prev => prev.filter(i => i.id !== id));
    createAuditEntry('ITEM_REJECTED', id, 'New Asset', 0, 'Owner rejected pending asset.');
  };

  // --- Category Actions ---
  const handleAddCategory = (name: string) => {
    const newCat = { id: generateId(), name };
    setCategories(prev => [...prev, newCat]);
    createAuditEntry('CATEGORY_CREATED', 'N/A', 'Category', 0, `Category '${name}' created.`);
  };

  const handleUpdateCategory = (cat: InventoryCategory) => {
    setCategories(prev => prev.map(c => c.id === cat.id ? cat : c));
    createAuditEntry('CATEGORY_UPDATED', 'N/A', 'Category', 0, `Category updated to '${cat.name}'.`);
  };

  const handleDeleteCategory = (id: string) => {
    const cat = categories.find(c => c.id === id);
    setCategories(prev => prev.filter(c => c.id !== id));
    createAuditEntry('CATEGORY_DELETED', 'N/A', 'Category', 0, `Category '${cat?.name}' deleted.`);
  };

  // --- Audit Filters ---
  const filteredAuditLog = useMemo(() => {
    return auditLog.filter(log => {
      const search = auditSearch.toLowerCase();
      const matchesSearch = log.performedBy.toLowerCase().includes(search) || log.itemName.toLowerCase().includes(search) || log.details.toLowerCase().includes(search);
      const matchesAction = auditActionFilter === 'All' || log.action === auditActionFilter;
      const matchesUser = auditUserFilter === 'All' || log.performedBy === auditUserFilter;
      const logDate = new Date(log.timestamp);
      const matchesFromDate = !auditFromDate || logDate >= new Date(auditFromDate);
      const matchesToDate = !auditToDate || logDate <= new Date(auditToDate + 'T23:59:59');
      return matchesSearch && matchesAction && matchesUser && matchesFromDate && matchesToDate;
    });
  }, [auditLog, auditSearch, auditActionFilter, auditUserFilter, auditFromDate, auditToDate]);

  return (
    <Layout currentUser={currentUser} onLogout={handleLogout} currentView={currentView} onChangeView={setCurrentView}>
      {currentView === 'inventory' && (
        <InventoryView 
          items={inventory} 
          currentUser={currentUser} 
          purposes={workPurposes} 
          categories={categories} 
          onRequestItem={handleRequestItem} 
          onManualAdjust={() => {}} 
          onDelete={handleDeleteItem}
        />
      )}
      {currentView === 'add-inventory' && (
        <AddInventoryView 
          items={inventory} 
          currentUser={currentUser} 
          categories={categories} 
          onAddStock={handleAddStock} 
          onCreateItem={handleCreateItem} 
          onBulkImport={handleBulkCreateItems}
        />
      )}
      {currentView === 'requests' && (
        <RequestQueue requests={requests} items={inventory} users={users} currentUser={currentUser} onClaim={handleClaim} onVerify={handleVerify} onReject={handleReject} onProcess={handleProcess} onReturnAction={handleReturnAction} onInitiateReturnById={handleReturnItem} />
      )}
      {currentView === 'movements' && (
        <MovementsView movements={movements} currentUser={currentUser} onCreateMovement={handleCreateMovement} onUpdateMovement={handleUpdateMovement} />
      )}
      {currentView === 'financials' && (
        <FinancialDashboard items={inventory} requests={requests} purposes={workPurposes} />
      )}
      {currentView === 'procurement' && (
        <ProcurementTable pos={pos} purposes={workPurposes} onImportPOs={handleBulkCreatePOs} />
      )}
      {currentView === 'management' && (
        <ManagementView 
          users={users} workPurposes={workPurposes} categories={categories} currentUser={currentUser} pendingItems={inventory.filter(i => i.status === 'pending_approval')}
          onAddUser={u => setUsers([...users, { ...u, id: generateId() }])} 
          onUpdateUser={u => setUsers(users.map(x => x.id === u.id ? u : x))}
          onDeleteUser={id => setUsers(users.filter(x => x.id !== id))}
          onAddPurpose={t => setWorkPurposes([...workPurposes, { id: generateId(), title: t }])}
          onUpdatePurpose={p => setWorkPurposes(workPurposes.map(x => x.id === p.id ? p : x))}
          onDeletePurpose={id => setWorkPurposes(workPurposes.filter(x => x.id !== id))}
          onAddCategory={handleAddCategory} onUpdateCategory={handleUpdateCategory} onDeleteCategory={handleDeleteCategory}
          onApproveItem={handleApproveItem} onRejectItem={handleRejectItem}
        />
      )}
      {currentView === 'audit' && (
          <div className="space-y-6 pb-20 text-slate-900">
              <h2 className="text-2xl font-bold flex items-center gap-2 text-slate-900"><Activity className="w-7 h-7 text-blue-600" /> Audit Trail</h2>
              <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-4">
                  <div className="flex flex-col lg:flex-row gap-4">
                      <input type="text" placeholder="Search..." className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 font-medium" value={auditSearch} onChange={e => setAuditSearch(e.target.value)} />
                      <select value={auditActionFilter} onChange={e => setAuditActionFilter(e.target.value)} className="p-3 bg-slate-50 border border-slate-200 rounded-xl text-slate-900 font-bold">
                        <option value="All">All Actions</option>
                        {Array.from(new Set(auditLog.map(l => l.action))).map(a => <option key={a} value={a}>{a}</option>)}
                      </select>
                  </div>
              </div>
              <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Timestamp</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Action</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Operator</th>
                      <th className="px-6 py-4 font-black text-slate-900 uppercase tracking-widest text-[10px]">Details</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredAuditLog.map(log => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 text-slate-900 font-medium text-xs">{new Date(log.timestamp).toLocaleString()}</td>
                        <td className="px-6 py-4 font-bold text-slate-900 text-xs">{log.action}</td>
                        <td className="px-6 py-4 text-slate-900 font-bold text-xs">{log.performedBy}</td>
                        <td className="px-6 py-4 text-slate-900 text-xs">{log.details}</td>
                      </tr>
                    ))}
                    {filteredAuditLog.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                          No audit records found
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
          </div>
      )}
