  // Load saved URL
  useEffect(() => {
    const savedUrl = localStorage.getItem('inventory_sheet_url');
    if (savedUrl) setSheetUrl(savedUrl);
  }, []);

  useEffect(() => {
    if (selectedItem) {
      setAddDescription(selectedItem.description || '');
      setAddLocation(selectedItem.location || '');
      setAddQty(0);
      setAddNote('');
    }
  }, [selectedItem]);

  useEffect(() => {
    if (activeTab === 'new') setPreviewUID(generateInventoryUID(items));
  }, [activeTab, items]);

  const filteredItems = items.filter(item => {
    if (item.status === 'pending_approval') return false;
    const s = searchTerm.toLowerCase();
    return item.name.toLowerCase().includes(s) || item.itemCode.toLowerCase().includes(s) || item.inventoryUID.toLowerCase().includes(s);
  });

  const handleCreateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.category) return alert("Please select a valid category from the system list.");

    const status = isOwner ? 'active' : 'pending_approval';

    onCreateItem({ ...newItem, status });

    if (!isOwner) {
      alert("New asset submitted for Owner Verification. It will appear in the inventory list once approved.");
    }

    setNewItem({ itemCode: '', name: '', description: '', partNumber: '', location: '', quantity: 0, minThreshold: 5, price: 0, category: '', status: 'active' });
    setActiveTab('existing');
  };

  const saveSheetUrl = () => {
      localStorage.setItem('inventory_sheet_url', sheetUrl);
      alert("Inventory Source URL saved successfully.");
  };

  const handleSync = async () => {
    if (!sheetUrl) return alert("Please save a valid Google Sheet CSV URL first.");
    setIsSyncing(true);
    try {
        const csvText = await fetchCSVFromUrl(sheetUrl);
        const parsedItems = parseInventoryCSV(csvText, categories);

        if (parsedItems.length === 0) {
            alert("No valid items found. Check the sheet formatting.");
            setIsSyncing(false);
            return;
        }

        const validItems = parsedItems.filter(i => i.name && i.itemCode) as Omit<InventoryItem, 'id' | 'inventoryUID'>[];
        onBulkImport(validItems);
        alert(`Sync Complete! ${validItems.length} items processed.`);
        setActiveTab('existing');
    } catch (error) {
        alert("Sync Failed. Please check the URL (Must be 'Published to Web' as CSV).");
    } finally {
        setIsSyncing(false);
    }
  };

  if (isReadOnly) return (
    <div className="p-20 text-center text-slate-500 flex flex-col items-center gap-4">
      <AlertCircle className="w-12 h-12 text-slate-300" />
      <div>
        <h3 className="text-lg font-bold text-slate-700">Restricted Access</h3>
        <p className="text-sm font-medium">You do not have administrative authority to modify inventory.</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-4">
        <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-2 uppercase tracking-tight">
          <Package className="w-7 h-7 text-blue-600" /> Stock Adjustment Center
        </h2>
      </div>

      <div className="flex p-1.5 bg-slate-200 rounded-2xl w-full max-w-2xl">
          <button 
            onClick={() => setActiveTab('existing')} 
            className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'existing' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
          >
            Update Existing
          </button>
          {canRegisterNew && (
            <button 
              onClick={() => setActiveTab('new')} 
              className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'new' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              Register New Asset
            </button>
          )}
          {canRegisterNew && (
            <button 
              onClick={() => setActiveTab('import')} 
              className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${activeTab === 'import' ? 'bg-green-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
               Google Sheets Sync
            </button>
          )}
      </div>

      {activeTab === 'import' && (
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-3xl mx-auto shadow-sm animate-in zoom-in duration-300 text-center space-y-8">
               <div>
                 <div className="w-16 h-16 bg-green-100 text-green-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
                    <FileSpreadsheet className="w-8 h-8" />
                 </div>
                 <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Auto-Sync Inventory</h3>
                 <p className="text-sm text-slate-500 font-medium mt-2 max-w-lg mx-auto">
                    Connect a "Published to Web" Google Sheet (CSV format) to instantly pull bulk data into the system without manual uploading.
                 </p>
               </div>

               <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 text-left space-y-4">
                  <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Source URL (Fixed)</label>
                      <div className="flex gap-2 mt-1">
                          <div className="relative flex-1">
                             <LinkIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                             <input 
                                type="text" 
                                placeholder="https://docs.google.com/spreadsheets/d/.../pub?output=csv" 
                                className="w-full pl-10 pr-4 py-3 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-green-500 outline-none"
                                value={sheetUrl}
                                onChange={(e) => setSheetUrl(e.target.value)}
                             />
                          </div>
                          <button onClick={saveSheetUrl} className="px-4 py-2 bg-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-300 transition-colors">
                              <Save className="w-5 h-5" />
                          </button>
                      </div>
                      <p className="text-[10px] text-slate-400 mt-2 font-medium">
                        * In Google Sheets: Go to <strong>File</strong> &gt; <strong>Share</strong> &gt; <strong>Publish to web</strong>. Select the sheet tab and choose <strong>Comma-separated values (.csv)</strong>. Copy that link here.
                      </p>
                  </div>

                  <div className="pt-4 border-t border-slate-200 flex gap-4">
                      <button onClick={() => downloadTemplate('inventory')} className="flex-1 py-4 border border-slate-200 text-slate-500 font-bold rounded-2xl hover:bg-white hover:border-blue-300 hover:text-blue-600 transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                          <Download className="w-4 h-4" /> Get Template
                      </button>
                      <button 
                        onClick={handleSync}
                        disabled={isSyncing || !sheetUrl}
                        className={`flex-1 py-4 font-black rounded-2xl text-white shadow-xl flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all active:scale-95 ${isSyncing ? 'bg-slate-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 shadow-green-100'}`}
                      >
                          {isSyncing ? <RefreshCw className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                          {isSyncing ? 'Syncing...' : 'Sync Now'}
                      </button>
                  </div>
               </div>
          </div>
      )}

      {activeTab === 'existing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-300">
              <div className="space-y-4">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input 
                      type="text" 
                      placeholder="Search for item to adjust..." 
                      className="w-full pl-10 pr-4 py-3.5 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-white shadow-sm" 
                      value={searchTerm} 
                      onChange={e => setSearchTerm(e.target.value)} 
                    />
                  </div>
                  <div className="bg-white rounded-3xl border border-slate-200 divide-y divide-slate-50 overflow-y-auto max-h-[550px] shadow-sm">
                      {filteredItems.map(item => (
                          <div 
                            key={item.id} 
                            onClick={() => setSelectedItem(item)} 
                            className={`p-5 cursor-pointer hover:bg-slate-50 transition-colors flex items-center justify-between ${selectedItem?.id === item.id ? 'bg-blue-50/50 border-l-4 border-l-blue-600' : ''}`}
                          >
                              <div>
                                <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest block mb-1">{item.inventoryUID}</span>
                                <div className="font-bold text-slate-900">{item.name}</div>
                                <div className="text-[10px] text-slate-400 font-bold">{item.itemCode} • {item.location}</div>
                              </div>
                              <div className="text-right">
