                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Location</label>
                        <div className="relative">
                          <MapPin className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                          <input type="text" required placeholder="Bin / Shelf / Site Bin" className="w-full border border-slate-200 p-4 pl-10 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-bold bg-slate-50" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} />
                        </div>
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Physical Category</label>
                        <div className="relative">
                          <select 
                            required 
                            className="w-full border border-slate-200 p-4 rounded-2xl font-bold appearance-none bg-slate-50 text-slate-900 pr-10 outline-none focus:ring-2 focus:ring-blue-500" 
                            value={newItem.category} 
                            onChange={e => setNewItem({...newItem, category: e.target.value})}
                          >
                            <option value="">Select Category...</option>
                            {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                          </select>
                          <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-5 p-6 bg-blue-50/50 rounded-[32px] border border-blue-50">
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Quantity</label>
                          <input type="number" required placeholder="0" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.quantity === 0 ? '' : newItem.quantity} onChange={e => setNewItem({...newItem, quantity: parseInt(e.target.value) || 0})} />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Min Alert</label>
                          <input type="number" required placeholder="5" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.minThreshold} onChange={e => setNewItem({...newItem, minThreshold: parseInt(e.target.value) || 0})} />
                        </div>
                        <div className="space-y-1.5">
                          <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Price (Unit)</label>
                          <input type="number" step="0.01" required placeholder="0.00" className="w-full border border-slate-200 p-4 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-black" value={newItem.price === 0 ? '' : newItem.price} onChange={e => setNewItem({...newItem, price: parseFloat(e.target.value) || 0})} />
                        </div>
                    </div>
                  </div>

                  <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-3xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                    {isOwner ? 'Finalize Item Registration' : 'Submit for Owner Verification'}
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

