                </td>
                <td className="px-4 py-5 font-bold text-slate-800 border-r border-slate-100 truncate max-w-[200px]">{po.description}</td>
                <td className="px-4 py-5 border-r border-slate-100">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${purpose ? 'bg-blue-50 text-blue-800' : 'bg-slate-100 text-slate-400'}`}>
                        {purpose ? purpose.title : 'Unallocated'}
