                    </div>
                </td>
                <td className="px-4 py-5 border-r border-slate-100 font-black text-slate-900 uppercase text-[10px]">{po.poStatus}</td>
                <td className="px-4 py-5 border-r border-slate-100 font-mono font-black text-blue-900">{po.poNumber || '-'}</td>
                <td className="px-4 py-5 border-r border-slate-100 font-bold text-slate-500 italic">{remarks}</td>
                <td className="px-4 py-5">
                    <span className={`px-2 py-1 rounded-lg text-[10px] font-black tracking-tight ${followUp === 'CLOSED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700 animate-pulse'}`}>
                        {followUp}
                    </span>
                </td>
              </tr>
            );
          })}
          {filteredPos.length === 0 && (
            <tr><td colSpan={11} className="px-6 py-24 text-center text-slate-400 italic font-black uppercase tracking-widest"><ListFilter className="w-12 h-12 text-slate-200 mx-auto mb-3" />No records found</td></tr>
          )}
        </tbody>
      </table>
    </div>
  </div>
);

