interface ProcurementTableProps {
  pos: PurchaseOrder[];
  purposes: WorkPurpose[];
  onImportPOs?: (pos: Omit<PurchaseOrder, 'id'>[]) => void;
}

const ProcurementTable: React.FC<ProcurementTableProps> = ({ pos: initialPos, purposes, onImportPOs }) => {
  const [activePage, setActivePage] = useState<'master' | 'amounts' | 'import'>('master');
  const [selectedPO, setSelectedPO] = useState<PurchaseOrder | null>(null);
  const [pos, setPos] = useState<PurchaseOrder[]>(initialPos);

  // Sync States
  const [sheetUrl, setSheetUrl] = useState('');
  const [isSyncing, setIsSyncing] = useState(false);

  const currentYear = new Date().getFullYear();
  const years = useMemo(() => Array.from({ length: 10 }, (_, i) => currentYear - i), [currentYear]);

  const [fromYear, setFromYear] = useState<number>(currentYear - 1);
  const [fromMonth, setFromMonth] = useState<number>(0);
  const [toYear, setToYear] = useState<number>(currentYear);
  const [toMonth, setToMonth] = useState<number>(11);
  const [showAllData, setShowAllData] = useState<boolean>(false);
  const [sortOrder, setSortOrder] = useState<'newest' | 'oldest'>('newest');

  useEffect(() => {
    const savedUrl = localStorage.getItem('procurement_sheet_url');
    if (savedUrl) setSheetUrl(savedUrl);
  }, []);

  const saveSheetUrl = () => {
    localStorage.setItem('procurement_sheet_url', sheetUrl);
    alert("Procurement Source URL saved successfully.");
  };

  const handleSync = async () => {
    if (!sheetUrl || !onImportPOs) return alert("Please save a valid Google Sheet CSV URL first.");
    setIsSyncing(true);
    try {
        const csvText = await fetchCSVFromUrl(sheetUrl);
        const parsedPos = parseProcurementCSV(csvText, purposes);

        if (parsedPos.length === 0) {
            alert("No valid POs found. Check the sheet formatting.");
            setIsSyncing(false);
            return;
        }

        const validPos = parsedPos.filter(p => p.prNumber) as Omit<PurchaseOrder, 'id'>[];
        onImportPOs(validPos);
        alert(`Sync Complete! ${validPos.length} procurement records processed.`);
        setActivePage('master');
    } catch (error) {
        alert("Sync Failed. Please check the URL (Must be 'Published to Web' as CSV).");
    } finally {
        setIsSyncing(false);
    }
  };

  const filteredPos = useMemo(() => {
    let result = [...pos];
    if (!showAllData) {
      const startDate = new Date(fromYear, fromMonth, 1);
      const endDate = new Date(toYear, toMonth + 1, 0, 23, 59, 59);
      result = result.filter(po => { const date = new Date(po.prDate); return date >= startDate && date <= endDate; });
    }
    result.sort((a, b) => {
      const dateA = new Date(a.prDate).getTime();
      const dateB = new Date(b.prDate).getTime();
      return sortOrder === 'newest' ? dateB - dateA : dateA - dateB;
    });
    return result;
  }, [pos, fromYear, fromMonth, toYear, toMonth, showAllData, sortOrder]);

  const totalSpent = useMemo(() => filteredPos.reduce((sum, po) => sum + po.usdAmount, 0), [filteredPos]);
  const contributionData = useMemo(() => {
    const map: Record<string, number> = {};
    filteredPos.forEach(po => {
      const purpose = purposes.find(p => p.id === po.purposeId);
      const label = purpose ? purpose.title : 'Unallocated';
      map[label] = (map[label] || 0) + po.usdAmount;
    });
    return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  }, [filteredPos, purposes]);

  const handleUploadPDF = (poId: string) => {
    const dummyUrl = `mock-pdf-${Math.random().toString(36).substr(2, 5)}`;
    setPos(prev => prev.map(p => p.id === poId ? { ...p, pdfUrl: dummyUrl } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, pdfUrl: dummyUrl } : null);
    alert("Official PO PDF uploaded successfully.");
  };

  const handleAssignPurpose = (poId: string, purposeId: string) => {
    setPos(prev => prev.map(p => p.id === poId ? { ...p, purposeId } : p));
    if (selectedPO?.id === poId) setSelectedPO(prev => prev ? { ...prev, purposeId } : null);
  };

  const getDerivedFields = (po: PurchaseOrder) => {
    if (po.techApprovalStatus === 'Approved' && po.poStatus === 'Issued' && po.poNumber?.trim()) return { remarks: 'Order Received', followUp: 'CLOSED' };
    return { remarks: po.manualRemarks || '-', followUp: 'Follow up needed' };
  };

  return (
    <div className="space-y-6 pb-20 text-slate-900">
      <div className="flex flex-col lg:flex-row justify-between items-start gap-4">
        <div>
            <h2 className="text-xl lg:text-2xl font-black text-slate-900 flex items-center gap-3 uppercase tracking-tight">
                <LayoutList className="w-7 h-7 text-blue-600" /> Procurement Hub
            </h2>
            <p className="text-sm text-slate-500 font-medium">Reconciling PR/PO lifecycle and project costing.</p>
        </div>
        <div className="flex bg-slate-200 p-1.5 rounded-2xl shadow-inner">
            <button 
                onClick={() => setActivePage('master')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'master' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <FileSpreadsheet className="w-4 h-4" /> Master List
            </button>
            <button 
                onClick={() => setActivePage('amounts')} 
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'amounts' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500'}`}
            >
                <DollarSign className="w-4 h-4" /> Value Analytics
            </button>
            {onImportPOs && (
                <button 
                    onClick={() => setActivePage('import')} 
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activePage === 'import' ? 'bg-green-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                    <FileSpreadsheet className="w-4 h-4" /> Google Sheets
                </button>
            )}
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] border border-slate-200 relative shadow-sm">
        <div className="absolute top-0 left-0 w-1.5 h-full bg-[#4472C4] rounded-l-[32px]"></div>
        <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex flex-col md:flex-row gap-8 items-end flex-1">
                <SelectGroup label="From Period" yearValue={fromYear} yearSetter={setFromYear} monthValue={fromMonth} monthSetter={setFromMonth} years={years} disabled={showAllData} />
                <SelectGroup label="To Period" yearValue={toYear} yearSetter={setToYear} monthValue={toMonth} monthSetter={setToMonth} years={years} disabled={showAllData} />
            </div>
            <div className="flex flex-wrap items-end gap-3 lg:border-l lg:pl-8 lg:border-slate-100">
                <button 
                    onClick={() => setShowAllData(!showAllData)} 
                    className={`px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all ${showAllData ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-100' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                    {showAllData ? 'Showing Global History' : 'Enable Full Database View'}
                </button>
                <button 
                    onClick={() => setSortOrder(sortOrder === 'newest' ? 'oldest' : 'newest')} 
                    className="px-6 py-3.5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-slate-100 flex items-center gap-2"
                >
                    <ArrowUpDown className="w-3 h-3" /> Order: {sortOrder}
                </button>
            </div>
        </div>
      </div>

      {activePage === 'master' && (
          <MasterSheet filteredPos={filteredPos} purposes={purposes} setSelectedPO={setSelectedPO} getDerivedFields={getDerivedFields} />
      )}

      {activePage === 'amounts' && (
          <AmountsPage filteredPos={filteredPos} purposes={purposes} totalSpent={totalSpent} contributionData={contributionData} setSelectedPO={setSelectedPO} />
      )}

      {activePage === 'import' && (
           <div className="bg-white p-10 rounded-[40px] border border-slate-200 max-w-3xl mx-auto shadow-sm animate-in zoom-in duration-300 text-center space-y-8">
               <div>
                 <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
                    <LayoutList className="w-8 h-8" />
                 </div>
                 <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Auto-Sync Procurement Log</h3>
                 <p className="text-sm text-slate-500 font-medium mt-2 max-w-lg mx-auto">
                    Connect the Master PR/PO Log via a fixed Google Sheet CSV link for one-click updates.
                 </p>
               </div>

               <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 text-left space-y-4">
                  <div>
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Source URL (Fixed)</label>
                      <div className="flex gap-2 mt-1">
                          <div className="relative flex-1">
                             <LinkIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                             <input 
                                type="text" 
                                placeholder="https://docs.google.com/spreadsheets/d/.../pub?output=csv" 
                                className="w-full pl-10 pr-4 py-3 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:ring-2 focus:ring-blue-500 outline-none"
                                value={sheetUrl}
                                onChange={(e) => setSheetUrl(e.target.value)}
                             />
                          </div>
                          <button onClick={saveSheetUrl} className="px-4 py-2 bg-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-300 transition-colors">
                              <Save className="w-5 h-5" />
                          </button>
                      </div>
                      <p className="text-[10px] text-slate-400 mt-2 font-medium">
                        * In Google Sheets: Go to <strong>File</strong> &gt; <strong>Share</strong> &gt; <strong>Publish to web</strong>. Select the sheet tab and choose <strong>Comma-separated values (.csv)</strong>. Copy that link here.
                      </p>
                  </div>

                  <div className="pt-4 border-t border-slate-200 flex gap-4">
                      <button onClick={() => downloadTemplate('procurement')} className="flex-1 py-4 border border-slate-200 text-slate-500 font-bold rounded-2xl hover:bg-white hover:border-blue-300 hover:text-blue-600 transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest">
                          <Download className="w-4 h-4" /> Get Template
                      </button>
                      <button 
                        onClick={handleSync}
                        disabled={isSyncing || !sheetUrl}
                        className={`flex-1 py-4 font-black rounded-2xl text-white shadow-xl flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all active:scale-95 ${isSyncing ? 'bg-slate-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-100'}`}
                      >
                          {isSyncing ? <RefreshCw className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                          {isSyncing ? 'Syncing...' : 'Sync Now'}
                      </button>
                  </div>
               </div>
          </div>
      )}

      {selectedPO && (
        <div className="fixed inset-0 bg-slate-900/70 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in duration-200">
                <div className="p-8 border-b flex justify-between items-center bg-blue-50/50">
                    <div>
                        <h3 className="text-xl font-black text-slate-900 flex items-center gap-3">
                            <FileSearch className="w-6 h-6 text-blue-600" /> {selectedPO.prNumber}
                        </h3>
                        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Official Request Details</p>
                    </div>
                    <button onClick={() => setSelectedPO(null)} className="text-slate-400 hover:text-slate-600 transition-colors p-2"><X className="w-7 h-7" /></button>
                </div>
                <div className="p-10 space-y-10">
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-8">
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Request Status</span>
                            <p className="text-sm font-black text-slate-900 uppercase">{selectedPO.prStatus}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Associated PO</span>
                            <p className="text-sm font-mono font-black text-blue-700">{selectedPO.poNumber || 'PENDING ASSIGNMENT'}</p>
                        </div>
                        <div className="space-y-1">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Financial Impact</span>
                            <p className="text-sm font-black text-slate-900">{selectedPO.netAmount.toLocaleString()} <span className="text-slate-400">{selectedPO.currency}</span></p>
                        </div>
                    </div>

                    <div className="space-y-4 bg-slate-50 p-6 rounded-3xl border border-slate-100">
                        <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                            <Briefcase className="w-3.5 h-3.5 text-blue-600" /> Assign Project/Work Purpose
                        </label>
                        <div className="relative">
                            <select 
                                value={selectedPO.purposeId || ''} 
                                onChange={(e) => handleAssignPurpose(selectedPO.id, e.target.value)} 
                                className="w-full p-4 bg-white border border-slate-200 rounded-2xl text-sm font-black text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm appearance-none"
                            >
                                <option value="">Unallocated / External Cost</option>
                                {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                            </select>
                            <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                        </div>
                    </div>

                    <div className="space-y-6">
                        <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest flex items-center gap-2 border-l-4 border-blue-600 pl-3">
                            Supporting Documentation
                        </h4>
                        {selectedPO.pdfUrl ? (
                            <div className="bg-green-50/50 border border-green-100 p-10 rounded-[40px] flex flex-col items-center gap-6">
                                <FileText className="w-14 h-14 text-green-600" />
                                <div className="text-center">
                                    <p className="font-black text-slate-900">PO_DOCUMENT_ATTACHED.pdf</p>
                                    <p className="text-[10px] text-green-700 font-bold uppercase tracking-widest mt-1">Verified for audit</p>
                                </div>
                                <div className="flex gap-4">
                                    <button className="px-8 py-3 bg-slate-900 text-white font-black rounded-2xl text-xs hover:bg-slate-800 transition-all active:scale-95 shadow-lg shadow-slate-100 flex items-center gap-2">
                                        <Eye className="w-4 h-4" /> Open Document
                                    </button>
                                    <button onClick={() => handleUploadPDF(selectedPO.id)} className="px-8 py-3 border border-slate-200 bg-white text-slate-600 font-black rounded-2xl text-xs hover:bg-slate-50 transition-all flex items-center gap-2">
                                        <Upload className="w-4 h-4" /> Replace
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <div className="bg-amber-50 border-2 border-dashed border-amber-200 p-12 rounded-[40px] flex flex-col items-center gap-6">
                                <AlertCircle className="w-14 h-14 text-amber-500" />
                                <div className="text-center space-y-1">
                                    <p className="font-black text-amber-900 uppercase text-sm tracking-tight">Missing Procurement PDF</p>
                                    <p className="text-[10px] text-amber-700 font-bold uppercase tracking-widest">Attachment required for financial processing</p>
                                </div>
                                <button onClick={() => handleUploadPDF(selectedPO.id)} className="px-10 py-4 bg-amber-600 text-white font-black rounded-[24px] text-sm hover:bg-amber-700 shadow-xl shadow-amber-100 transition-all active:scale-95 flex items-center gap-2">
                                    <Upload className="w-5 h-5" /> Upload PO PDF
                                </button>
                            </div>
                        )}
                    </div>

                    <div className="flex justify-end pt-4">
                        <button onClick={() => setSelectedPO(null)} className="px-10 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition-colors uppercase tracking-widest text-xs">
                            Close Workspace
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default ProcurementTable;

import React, { useState, useMemo } from 'react';
import { InventoryItem, User, UserRole, WorkPurpose, InventoryCategory } from '../types';
import { Search, Info, Box, MapPin, Tag, Fingerprint, X, AlertCircle, CheckCircle2, Filter, FileSpreadsheet, ChevronDown, Trash2 } from 'lucide-react';
import { canViewPrices, canViewThreshold } from '../services/stateService';

const HeaderCell = ({ label, className = "" }: { label: string; className?: string }) => (
  <th className={`px-4 py-3 border-r border-slate-400 last:border-r-0 ${className}`}>
    <span className="font-bold text-slate-900 text-xs whitespace-nowrap uppercase tracking-tight">{label}</span>
  </th>
);

interface InventoryViewProps {
  items: InventoryItem[];
  currentUser: User;
  purposes: WorkPurpose[];
  categories: InventoryCategory[];
  onRequestItem: (itemId: string, qty: number, purposeId: string, specific: string, isEmergency: boolean) => void;
  onManualAdjust: (itemId: string, newQty: number, reason: string) => void;
  onDelete: (itemId: string, reason: string) => void;
}

const InventoryView: React.FC<InventoryViewProps> = ({ items, currentUser, purposes, categories, onRequestItem, onManualAdjust, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [activeItems, setActiveItems] = useState<InventoryItem[]>([]);

  // Deletion State
  const [itemToDelete, setItemToDelete] = useState<InventoryItem | null>(null);
  const [deleteReason, setDeleteReason] = useState('');

  const [statusFilter, setStatusFilter] = useState<'all' | 'low' | 'out'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('All Categories');

  const [reqQtyMap, setReqQtyMap] = useState<Record<string, number>>({});
  const [reqPurpose, setReqPurpose] = useState('');
  const [reqSpecific, setReqSpecific] = useState('');
  const [isEmergency, setIsEmergency] = useState(false);

  const isOwner = currentUser.role === UserRole.OWNER;

  const filteredItems = useMemo(() => {
    return items.filter(item => {
      // Filter out pending items that haven't been approved by the Owner yet
      if (item.status === 'pending_approval') return false;

      const search = searchTerm.toLowerCase();
      const matchesSearch = (
        item.name.toLowerCase().includes(search) ||
        item.itemCode.toLowerCase().includes(search) ||
        item.partNumber.toLowerCase().includes(search) ||
        item.inventoryUID.toLowerCase().includes(search) ||
        item.description.toLowerCase().includes(search) ||
        item.location.toLowerCase().includes(search) ||
        item.category.toLowerCase().includes(search)
      );
      const matchesCategory = categoryFilter === 'All Categories' || item.category === categoryFilter;
      let matchesStatus = true;
      if (statusFilter === 'low') matchesStatus = item.quantity <= item.minThreshold && item.quantity > 0;
      if (statusFilter === 'out') matchesStatus = item.quantity === 0;
      return matchesSearch && matchesCategory && matchesStatus;
    });
  }, [items, searchTerm, categoryFilter, statusFilter]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeItems.length > 0) {
      activeItems.forEach(item => {
        const qty = reqQtyMap[item.id] || 1;
        onRequestItem(item.id, qty, reqPurpose, reqSpecific, isEmergency);
      });
      setActiveItems([]);
      setSelectedIds(new Set());
    }
  };

  const handleDeleteSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (itemToDelete && deleteReason) {
      onDelete(itemToDelete.id, deleteReason);
      setItemToDelete(null);
      setDeleteReason('');
    }
  };

  return (
    <div className="space-y-4 lg:space-y-6 pb-24 text-slate-900">
      <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6">
        <div className="space-y-4 flex-1">
          <div>
            <h2 className="text-xl lg:text-2xl font-bold text-slate-900">Inventory Dashboard</h2>
            <p className="text-sm text-slate-500 font-medium">Tracking industrial assets and site materials.</p>
          </div>
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="Search by name, location, category..." 
                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 bg-white text-slate-900 font-medium shadow-sm" 
                value={searchTerm} 
                onChange={(e) => setSearchTerm(e.target.value)} 
              />
            </div>
            <div className="relative">
              <select 
                value={categoryFilter} 
                onChange={(e) => setCategoryFilter(e.target.value)} 
                className="appearance-none w-full sm:w-48 pl-10 pr-10 py-3 border border-slate-300 rounded-xl bg-white text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm cursor-pointer"
              >
                <option value="All Categories">All Categories</option>
                {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
              </select>
              <Filter className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>
      </div>

      <div className="hidden lg:block bg-white rounded-xl shadow-lg border border-slate-400 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm border-collapse">
            <thead className="bg-[#FFD966] border-b-2 border-slate-600">
              <tr>
                <th className="px-4 py-3 border-r border-slate-400 w-10 text-center"></th>
                <HeaderCell label="Inventory ID" />
                <HeaderCell label="Item Code" />
                <HeaderCell label="Description" />
                <HeaderCell label="Name" />
                <HeaderCell label="Item Part Number" />
                <HeaderCell label="Location" />
                <HeaderCell label="Quantity" />
                {canViewThreshold(currentUser) && <HeaderCell label="Min Alert" />}
                {canViewPrices(currentUser) && <th className="px-4 py-3 font-bold text-slate-900 text-xs uppercase tracking-tight">Price</th>}
                {isOwner && <th className="px-4 py-3 font-bold text-slate-900 text-xs uppercase tracking-tight">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredItems.map(item => (
                <tr key={item.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.has(item.id) ? 'bg-blue-50/50' : ''}`}>
                  <td className="px-4 py-4 text-center">
                    <input 
                      type="checkbox" 
                      className="w-4 h-4 rounded border-slate-300 text-blue-600 cursor-pointer" 
                      checked={selectedIds.has(item.id)} 
                      onChange={() => { 
                        const s = new Set(selectedIds); 
                        if(s.has(item.id)) s.delete(item.id); 
                        else s.add(item.id); 
                        setSelectedIds(s); 
                      }} 
                    />
                  </td>
                  <td className="px-4 py-4 font-mono text-blue-700 font-black border-r border-slate-100">{item.inventoryUID}</td>
                  <td className="px-4 py-4 text-slate-700 font-medium border-r border-slate-100">{item.itemCode}</td>
                  <td className="px-4 py-4 text-slate-600 text-xs max-w-[200px] border-r border-slate-100">
                    <div className="line-clamp-2" title={item.description}>{item.description}</div>
                  </td>
                  <td className="px-4 py-4 font-bold text-slate-900 border-r border-slate-100">
                    {item.name}
                    <div className="text-[9px] text-slate-400 font-black uppercase tracking-widest">{item.category}</div>
                  </td>
                  <td className="px-4 py-4 text-slate-700 font-medium border-r border-slate-100">{item.partNumber}</td>
                  <td className="px-4 py-4 text-slate-600 font-medium border-r border-slate-100">{item.location}</td>
                  <td className="px-4 py-4 border-r border-slate-100">
                    <span className={`inline-block px-3 py-1 rounded-lg font-black ${item.quantity <= item.minThreshold ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-800'}`}>
                      {item.quantity}
                    </span>
                  </td>
                  {canViewThreshold(currentUser) && <td className="px-4 py-4 text-slate-500 font-bold border-r border-slate-100">{item.minThreshold}</td>}
                  {canViewPrices(currentUser) && <td className="px-4 py-4 font-black text-slate-900 border-r border-slate-100">${item.price.toFixed(2)}</td>}
                  {isOwner && (
                    <td className="px-4 py-4 text-center">
                        <button 
                            onClick={(e) => { e.stopPropagation(); setItemToDelete(item); }} 
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                            title="Delete Item"
                        >
                            <Trash2 className="w-4 h-4" />
                        </button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filteredItems.length === 0 && (
          <div className="p-12 text-center text-slate-400 font-bold uppercase tracking-widest bg-slate-50">
            No items match selected filters
          </div>
        )}
      </div>

      <div className="lg:hidden space-y-3">
        {filteredItems.map(item => (
          <div key={item.id} className={`bg-white p-4 rounded-2xl border ${selectedIds.has(item.id) ? 'border-blue-500 ring-2 ring-blue-100' : 'border-slate-200'} shadow-sm space-y-3 relative`} onClick={() => { const s = new Set(selectedIds); if(s.has(item.id)) s.delete(item.id); else s.add(item.id); setSelectedIds(s); }}>
             <div className="flex justify-between items-start">
               <div>
                 <span className="text-[10px] font-black text-blue-600 uppercase mb-1 block">{item.inventoryUID}</span>
                 <h3 className="font-bold text-slate-900">{item.name}</h3>
                 <p className="text-xs text-slate-500 font-medium">{item.itemCode} • {item.location}</p>
                 <p className="text-[10px] text-slate-400 mt-1 line-clamp-1">{item.description}</p>
               </div>
               <span className={`px-3 py-1 rounded-lg font-black text-sm ${item.quantity <= item.minThreshold ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-800'}`}>{item.quantity}</span>
             </div>
             <div className="flex justify-between items-center pt-2 border-t border-slate-50">
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{item.category}</span>
               <div className="flex items-center gap-3">
                  {canViewPrices(currentUser) && <span className="text-xs font-black text-slate-900">${item.price.toFixed(2)}</span>}
                  {isOwner && (
                    <button 
                        onClick={(e) => { e.stopPropagation(); setItemToDelete(item); }} 
                        className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded transition-colors"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                  )}
               </div>
             </div>
          </div>
        ))}
      </div>

      {selectedIds.size > 0 && (
        <div className="fixed bottom-20 left-1/2 -translate-x-1/2 w-[90%] max-w-2xl bg-slate-900 text-white rounded-3xl shadow-2xl p-4 flex items-center justify-between z-[60] animate-in slide-in-from-bottom duration-300">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center font-black text-lg">{selectedIds.size}</div>
            <div>
              <p className="font-bold text-sm">Items Ready</p>
              <button onClick={() => setSelectedIds(new Set())} className="text-[10px] text-slate-400 hover:text-white font-black uppercase tracking-widest">Cancel All</button>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => { setActiveItems(items.filter(i => selectedIds.has(i.id))); }} className="px-8 py-3 rounded-2xl bg-blue-600 hover:bg-blue-500 font-black text-sm shadow-xl transition-all active:scale-95">Initiate Request</button>
          </div>
        </div>
      )}

      {/* Delete Item Modal */}
      {itemToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in duration-200">
             <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-red-50">
                 <h3 className="text-lg font-black text-red-900 flex items-center gap-2">
                    <Trash2 className="w-5 h-5 text-red-600" /> Confirm Deletion
                 </h3>
                 <button onClick={() => setItemToDelete(null)} className="text-slate-400 hover:text-slate-600 p-1"><X className="w-6 h-6" /></button>
             </div>
             <form onSubmit={handleDeleteSubmit} className="p-6 space-y-4">
                 <div className="bg-red-50 p-4 rounded-2xl border border-red-100 flex gap-3 items-start">
                     <AlertCircle className="w-5 h-5 text-red-600 shrink-0 mt-0.5" />
                     <div>
                         <p className="text-sm font-bold text-red-900">Permanent Removal Warning</p>
                         <p className="text-xs text-red-700 mt-1">
                             You are about to delete <strong>{itemToDelete.name}</strong> ({itemToDelete.inventoryUID}) from the master database. This action cannot be undone.
                         </p>
                     </div>
                 </div>
                 <div className="space-y-2">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Reason for Deletion</label>
                     <textarea 
                        required 
                        autoFocus
                        placeholder="e.g. Obsolete, Scrapped, Data Entry Error..." 
                        className="w-full border border-slate-200 p-3.5 rounded-2xl outline-none focus:ring-2 focus:ring-red-500/20 text-slate-900 font-medium min-h-[100px]" 
                        value={deleteReason} 
                        onChange={e => setDeleteReason(e.target.value)} 
                     />
                 </div>
                 <div className="flex gap-3 pt-2">
                     <button type="button" onClick={() => setItemToDelete(null)} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors">Cancel</button>
                     <button type="submit" className="flex-1 py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 shadow-xl shadow-red-100 transition-all active:scale-95">Delete Item</button>
                 </div>
             </form>
          </div>
        </div>
      )}

      {/* Request Item Modal */}
      {activeItems.length > 0 && (
        <div className="fixed inset-0 bg-slate-900/70 flex items-center justify-center z-[100] p-4 backdrop-blur-md">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in duration-200">
            <div className="p-6 border-b flex justify-between items-center bg-blue-50/30">
              <h3 className="text-lg font-bold text-slate-900">Operational Material Request</h3>
              <button onClick={() => setActiveItems([])} className="text-slate-400 hover:text-slate-600 transition-colors p-1"><X /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="space-y-2 max-h-[30vh] overflow-y-auto bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Selected Stock Breakdown</label>
                  {activeItems.map(item => (
                    <div key={item.id} className="flex items-center justify-between bg-white p-3 rounded-xl border border-slate-100 shadow-sm mb-2 last:mb-0">
                      <div className="flex-1 min-w-0 pr-4">
                        <span className="text-xs font-bold text-slate-900 truncate block">{item.name}</span>
                        <span className="text-[10px] text-slate-400 font-medium">Available: {item.quantity}</span>
                      </div>
                      <input 
                        type="number" 
                        min="1" 
                        max={item.quantity} 
                        className="w-20 p-2 border border-slate-200 rounded-lg text-sm font-black text-center text-slate-900 focus:ring-2 focus:ring-blue-500" 
                        value={reqQtyMap[item.id] || 1} 
                        onChange={e => setReqQtyMap({...reqQtyMap, [item.id]: parseInt(e.target.value) || 1})} 
                      />
                    </div>
                  ))}
              </div>
              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Assigned Work Purpose</label>
                  <div className="relative">
                    <select 
                      required 
                      className="w-full border border-slate-200 p-4 rounded-xl font-bold text-slate-900 bg-slate-50 appearance-none outline-none focus:ring-2 focus:ring-blue-500" 
                      value={reqPurpose} 
                      onChange={e => setReqPurpose(e.target.value)}
                    >
                      <option value="">Select Purpose...</option>
                      {purposes.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                    </select>
                    <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Specific Reason / Destination</label>
                  <input 
                    type="text" 
                    required 
                    placeholder="e.g. Jetty Pump #2 Emergency Repair" 
                    className="w-full border border-slate-200 p-4 rounded-xl font-medium text-slate-900 bg-slate-50 outline-none focus:ring-2 focus:ring-blue-500 shadow-inner" 
                    value={reqSpecific} 
                    onChange={e => setReqSpecific(e.target.value)} 
                  />
                </div>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setActiveItems([])} className="flex-1 py-4 border border-slate-200 text-slate-600 font-bold rounded-2xl hover:bg-slate-50 transition-colors">Discard</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95">Send for Approval</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default InventoryView;
